  var tip = 'Serve Dominance Index (Tennis Abstract matchmx) — P1 ' + sd.p1.sdi + ' (pts service ' + sd.p1.serve_pts_won_pct + '%, ace ' + sd.p1.ace_pct + '%) vs P2 ' + sd.p2.sdi;
  return '<div title="' + tip.replace(/"/g, '&quot;') + '" style="font-size:9px;color:' + col + ';margin-top:3px;">SDI ' + sd.p1.sdi + '▸' + sd.p2.sdi + ' (' + sign + dl + ')</div>';
