    'greece':'gr','switzerland':'ch','czech republic':'cz','austria':'at',
    'poland':'pl','hungary':'hu','romania':'ro','croatia':'hr','serbia':'rs',
    'slovakia':'sk','finland':'fi','ireland':'ie','ukraine':'ua','russia':'ru',
    'bulgaria':'bg','slovenia':'si','lithuania':'lt','latvia':'lv','estonia':'ee',
    'albania':'al','bosnia':'ba','north macedonia':'mk','montenegro':'me',
    'iceland':'is','luxembourg':'lu','malta':'mt','cyprus':'cy','belarus':'by',
    'brazil':'br','argentina':'ar','mexico':'mx','usa':'us','etats-unis':'us','etats unis':'us','canada':'ca',
    'colombia':'co','chile':'cl','peru':'pe','ecuador':'ec','uruguay':'uy',
    'paraguay':'py','bolivia':'bo','venezuela':'ve','costa rica':'cr',
    'panama':'pa','jamaica':'jm','honduras':'hn','el salvador':'sv','guatemala':'gt',
    'japan':'jp','south korea':'kr','saudi arabia':'sa','uae':'ae','qatar':'qa',
    'china':'cn','india':'in','thailand':'th','indonesia':'id','vietnam':'vn',
    'australia':'au','new zealand':'nz',
    'morocco':'ma','egypt':'eg','south africa':'za','nigeria':'ng','senegal':'sn',
    'ghana':'gh','algeria':'dz','tunisia':'tn','cameroon':'cm','ivory coast':'ci',
    'kenya':'ke','ethiopia':'et','dr congo':'cd',
    'world':'world','europe':'eu','s. america':'xx','international':'int',
    // French aliases (normalized: no accents, lowercase)
    'angleterre':'gb-eng','espagne':'es','allemagne':'de','italie':'it',
    'pays-bas':'nl','pays bas':'nl','belgique':'be','ecosse':'gb-sct',
    'pays de galles':'gb-wls','turquie':'tr','danemark':'dk','norvege':'no',
    'suede':'se','grece':'gr','suisse':'ch','tcheque':'cz','tchequier':'cz',
    'republique tcheque':'cz','tchequie':'cz','autriche':'at','pologne':'pl','hongrie':'hu',
    'roumanie':'ro','croatie':'hr','serbie':'rs','slovaquie':'sk','finlande':'fi',
    'irlande':'ie','russie':'ru','bulgarie':'bg','slovenie':'si','lituanie':'lt',
    'lettonie':'lv','estonie':'ee','albanie':'al','macedoine':'mk',
    'macedoine du nord':'mk','islande':'is','malte':'mt','chypre':'cy',
    'bielorussie':'by','bresil':'br','argentine':'ar','mexique':'mx',
    'colombie':'co','chili':'cl','perou':'pe','equateur':'ec',
    'japon':'jp','coree du sud':'kr','arabie saoudite':'sa','emirats':'ae',
    'emirats arabes unis':'ae','maroc':'ma','egypte':'eg','afrique du sud':'za',
    'algerie':'dz','tunisie':'tn','cote d ivoire':'ci','cote divoire':'ci',
    'europe':'eu','amerique du sud':'xx','monde':'world',
