function setCountrySort(mode) {
  countrySortMode = mode;
  localStorage.setItem('ps_country_sort', mode);
  rebuildCountryChips();
}


function updateLiveCounters() {
  if (!allMatches || !allMatches.length) return;
  // Calculer le nombre de matchs live par pays
  var liveByCountry = {};
  allMatches.forEach(function(m) {
    if (!m.live_score) return;
    Object.keys(leaguesByCountry).forEach(function(c) {
      var keys = leaguesByCountry[c].map(function(l) { return l.odds_key; });
      if (keys.includes(m.sport)) liveByCountry[c] = (liveByCountry[c] || 0) + 1;
    });
  });
  // Mettre a jour les badges
  var wraps = document.querySelectorAll('#country-filter-row .country-chip-wrap');
  wraps.forEach(function(wrap) {
    var chip = wrap.querySelector('.country-chip');
    var badge = wrap.querySelector('.country-live-badge');
    if (!chip || !badge) return;
    var country = chip.dataset.country;
    var n = liveByCountry[country] || 0;
    if (n > 0) {
      badge.textContent = n;
      badge.classList.add('show');
    } else {
      badge.classList.remove('show');
    }
  });
}

function rebuildCountryChips() {
  var filterRow = document.getElementById('country-filter-row');
  var mobileSelect = document.getElementById('country-mobile-select');
  if (!filterRow) return;
  var countries = Object.keys(leaguesByCountry);
  // Trier selon countrySortMode
  if (countrySortMode === 'matches' && allMatches && allMatches.length) {
    var counts = {};
    countries.forEach(function(c) {
      var keys = (leaguesByCountry[c] || []).map(function(l) { return l.odds_key; });
      counts[c] = allMatches.filter(function(m) { return keys.includes(m.sport); }).length;
    });
    countries.sort(function(a, b) { return (counts[b] || 0) - (counts[a] || 0) || a.localeCompare(b); });
  } else if (countrySortMode === 'edge' && allMatches && allMatches.length) {
    var edges = {};
    countries.forEach(function(c) {
      var keys = (leaguesByCountry[c] || []).map(function(l) { return l.odds_key; });
      var cm = allMatches.filter(function(m) { return keys.includes(m.sport); });
      edges[c] = cm.length ? cm.reduce(function(s, m) { return s + (m.best_edge?.edge || 0); }, 0) / cm.length : 0;
    });
    countries.sort(function(a, b) { return (edges[b] || 0) - (edges[a] || 0) || a.localeCompare(b); });
  } else {
    // Priorite par defaut
    var COUNTRY_PRIORITY = ['France', 'Europe', 'England', 'Spain', 'Germany', 'Italy',
      'Netherlands', 'Portugal', 'Belgium', 'Turkey', 'Scotland', 'Greece', 'Switzerland',
      'Brazil', 'Argentina', 'Mexico', 'USA', 'Saudi Arabia', 'Japan', 'South Korea',
      'Denmark', 'Norway', 'Sweden', 'World'];
    countries.sort(function(a, b) {
      var ia = COUNTRY_PRIORITY.indexOf(a);
      var ib = COUNTRY_PRIORITY.indexOf(b);
      if (ia !== -1 && ib !== -1) return ia - ib;
      if (ia !== -1) return -1;
      if (ib !== -1) return 1;
      return a.localeCompare(b);
    });
  }
  allCountries = countries;

// Generer les chips (utilise getCountryFlag pour compat Windows)
  var chips = countries.map(function(country) {
    var fh = getCountryFlag(country);
    var leagueList = leaguesByCountry[country] || [];
    var leagueChips = leagueList.map(function(l) {
      return '<button class="country-league-chip" data-sport="' + l.odds_key + '" data-country="' + country + '">' +
        fh + ' ' + l.name + '<span class="league-tag">' + l.type + '</span></button>';
    }).join('');
    return '<span class="country-chip-wrap">' +
      '<button class="filter-chip country-chip" data-country="' + country + '">' +
        fh + ' ' + country +
        '<span class="country-live-badge"></span>' +
        '<span class="country-remove" onclick="removeCountry(event,\'' + country + '\')">\u2715</span>' +
        '<span class="country-arrow">&#x25BE;</span>' +
      '</button>' +
      '<div class="country-dropdown">' + leagueChips + '</div>' +
      '</span>';
  }).join('');
  filterRow.innerHTML = chips;

  // Restaurer la selection active
  syncCountryChipUI();

  // Remplir le select mobile (utilise getCountryFlag pour compat Windows)
  if (mobileSelect) {
    var optHtml = '<option value="all">' + String.fromCodePoint(0x1F30D) + ' Toutes les ligues</option>';
    countries.forEach(function(country) {
      optHtml += '<option value="' + country + '">' + getCountryFlag(country) + ' ' + country + '</option>';
      var ll = leaguesByCountry[country] || [];
      ll.forEach(function(l) {
        optHtml += '<option value="sport:' + l.odds_key + '">\xA0\xA0\xA0' + l.name + ' (' + l.type + ')</option>';
      });
    });
    mobileSelect.innerHTML = optHtml;
  }
  updateLiveCounters();
  if (typeof buildLeagueMS === 'function') buildLeagueMS();
}

function syncCountryChipUI() {
  // Met a jour les classes actives et le bouton remove sur les chips
  var chips = document.querySelectorAll('#country-filter-row .country-chip');
  var allBtn = document.querySelector('#league-filter-row .filter-chip[data-country="all"]');
  chips.forEach(function(c) {
    var country = c.dataset.country;
    if (activeCountries.includes(country)) {
      c.classList.add('active');
      c.querySelector('.country-remove').style.display = 'inline';
    } else {
      c.classList.remove('active');
      var rm = c.querySelector('.country-remove');
      if (rm) rm.style.display = 'none';
    }
  });
  if (allBtn) {
    if (activeCountries.length === 0) allBtn.classList.add('active');
    else allBtn.classList.remove('active');
  }
}

function removeCountry(e, country) {
  e.stopPropagation();
  e.preventDefault();
  activeCountries = activeCountries.filter(function(c) { return c !== country; });
  activeCountry = activeCountries.length === 1 ? activeCountries[0] : (activeCountries.length === 0 ? 'all' : activeCountries[0]);
  activeLeague = 'all';
  syncCountryChipUI();
  renderMatches(allMatches);
}

async function initLeagueFilters() {
  var filterRow = document.getElementById('country-filter-row');
  if (!filterRow) return;
  try {
    var res = await fetch('/leagues_config.json');
    if (!res.ok) return;
    var cfg = await res.json();
    var leagues = cfg.leagues || [];
    // Regrouper les ligues par pays
    leaguesByCountry = {};
    leagues.forEach(function(l) {
      var country = l.country || 'Autre';
      if (!leaguesByCountry[country]) leaguesByCountry[country] = [];
      leaguesByCountry[country].push(l);
    });
    // Trier ligues dans chaque pays : T1 puis T2, alphabetique
    Object.keys(leaguesByCountry).forEach(function(c) {
      leaguesByCountry[c].sort(function(a, b) {
        if (a.type !== b.type) return a.type === 'T1' ? -1 : 1;
        return a.name.localeCompare(b.name);
      });
    });
    // Appliquer le mode de tri au select
    var sortSel = document.getElementById('country-sort-select');
    if (sortSel) sortSel.value = countrySortMode;
    rebuildCountryChips();
  } catch (e) { console.error('initLeagueFilters error:', e); }
}



// ─── PRESSURE INDEX ──────────────────────────────────────────────────────────
function calcPressureIndex(m) {
  if (!m.live_score) return 0;
  const da = (m.live_dangerous_attacks?.home || 0) + (m.live_dangerous_attacks?.away || 0);
  const sh = (m.live_shots?.home || 0) + (m.live_shots?.away || 0);
  const co = (m.live_corners?.home || 0) + (m.live_corners?.away || 0);
  return Math.round(da * 0.5 + sh * 1.5 + co * 1.0);
}

// ─── SORT ────────────────────────────────────────────────────────────────────
function setSort(key, el) {
  if (sortKey === key) { sortDir *= -1; } else { sortKey = key; sortDir = -1; }
  document.querySelectorAll('.sortable').forEach(th => th.classList.remove('sort-asc', 'sort-desc'));
  el.classList.add(sortDir === -1 ? 'sort-desc' : 'sort-asc');
  renderMatches(allMatches);
}

// ═══════════════════════════════════════════════════════════════════════════════
//  CHARGEMENT DES DONNÉES — UN SEUL fetch()
// ═══════════════════════════════════════════════════════════════════════════════
async function loadMatches() {
  setLoading(true); clearError();
  var retries = 3;
  var delay = 2000;
  var lastError = null;

  for (var attempt = 0; attempt <= retries; attempt++) {
    try {
      // Health-check silencieux avant retry (juste pour diagnostic)
      if (attempt > 0) {
        try { await fetch('/api/v1/status', { signal: AbortSignal.timeout(3000) }); } catch {}
      }

      var res = await apiFetch(`/api/v1/matches?_t=${Date.now()}`).catch(err => {
        console.error('Erreur Fetch/Render:', err);
        throw err;
      });
      if (res.status === 403) {
        var errJson = null;
        try { errJson = await res.json(); } catch {}
        if (errJson && errJson.code === 'FREEMIUM_VIEW_QUOTA') {
          setLoading(false);
          var vb = document.getElementById('vb-body');
          if (vb) vb.innerHTML = '<tr><td colspan="30" style="padding:48px 20px;text-align:center;">'
            + '<div style="font-size:42px;margin-bottom:12px;">🔒</div>'
            + '<div style="font-family:var(--font-head);font-size:20px;font-weight:800;margin-bottom:6px;">Quota gratuit atteint</div>'
            + '<div style="color:var(--text3);font-size:14px;margin-bottom:20px;">10 consultations / jour en freemium (' + (errJson.used||10) + '/' + (errJson.limit||10) + '). Réinitialisation sous 24h.</div>'
            + '<button class="price-btn price-btn-green" style="padding:11px 22px;" onclick="showPage(\'tarifs\')">Passer Pro →</button> '
            + '<button class="price-btn price-btn-amber" style="padding:11px 22px;" onclick="buyMatchdayPass()">Matchday 1,50€</button>'
            + '</td></tr>';
          return;
        }
      }
      if (!res.ok) throw new Error('Serveur HTTP ' + res.status);

      var json = await res.json();
      allMatches = json.matches || [];
      // Verrou freemium : tableau foot limité à 5 ligues UE
      var _accM = (typeof psAccess === 'function') ? psAccess() : { footPro: true };
      document.body.classList.toggle('ps-free', !_accM.footPro);
      if (!_accM.footPro) {
        var PS_FREE_LEAGUES = ['soccer_france_ligue1','soccer_epl','soccer_spain_la_liga','soccer_germany_bundesliga','soccer_italy_serie_a'];
        allMatches = allMatches.filter(function(m) { return PS_FREE_LEAGUES.includes(m.sport); });
      }

      // Construire la map odds_key → ISO code (silencieux si fichier absent)
      try {
        var flagsRes = await fetch('/flags_config.json');
        if (flagsRes.ok) {
          var flagsJson = await flagsRes.json();
          sportFlagCodes = Object.fromEntries(
            (flagsJson.sports || []).map(function(s) { return [s.odds_key, s]; })
          );
        }
      } catch {}

      updateStatusBar(json.meta);
      renderMatches(allMatches);
      loadFavoritesFromAccount();
      document.getElementById('table-title').textContent = 'Matchs à venir — ' + allMatches.length + ' matchs';
      if (_accM.footPro) loadAIScout();
      lazyLoadButeurs(allMatches);
      startLiveTop5Refresh();
      startLivePredictionsRefresh();
      initSSE();
      if (matchesRetryTimer) {
        clearTimeout(matchesRetryTimer);
        matchesRetryTimer = null;
      }
      setLoading(false);
      return; // succès
    } catch(e) {
      console.error('Erreur Fetch/Render:', e);
      lastError = e;
      if (e.message && e.message.includes('429')) {
        showError('Quota API épuisé — données en cache');
        console.error('[PariScore]', e);
        setLoading(false);
        return;
      }
      // Fix V5 (ParisScorebis-amc) : si AUTH_REQUIRED, le token est mort
      // (déjà clear par apiFetch:401). Retry avec même token = boucle 401
      // perpétuelle → modal auth qui se rouvre 4x. On stop et on rend la main
      // au user (modal est déjà ouverte par apiFetch).
      if (e.message === 'AUTH_REQUIRED' || (e.status === 401)) {
        setLoading(false);
        const _es = document.getElementById('empty-state');
        if (_es) _es.textContent = 'Session expirée — reconnectez-vous pour voir les matchs.';
        return;
      }
      if (attempt < retries) {
        document.getElementById('empty-state').textContent = 'Tentative ' + (attempt + 1) + '/' + retries + ' — reconnexion dans ' + (delay / 1000) + 's...';
        await new Promise(function(r) { setTimeout(r, delay); });
      }
    }
  }

  // Toutes les tentatives ont échoué
  var msg = lastError ? (lastError.message || 'Erreur réseau') : 'Serveur injoignable';
  if (msg.includes('Failed to fetch') || msg.includes('NetworkError')) {
    msg = 'Impossible de contacter le serveur. Lancez: node server.js';
  }
  showError(msg);
  console.error('[PariScore]', lastError);
  if (!matchesRetryTimer) {
    matchesRetryTimer = setTimeout(function() {
      matchesRetryTimer = null;
      if (document.querySelector('.nav-links a.active')?.dataset?.page === 'matchs') {
        loadMatches();
      }
    }, 30000);
  }
  setLoading(false);
}

// ═══════════════════════════════════════════════════════════════════════════════
//  LIVE UPDATE V73 — Patch différentiel (standard industrie FlashScore/SofaScore)
//  Principe : on ne détruit JAMAIS le DOM. On cible les valeurs modifiées via data-*.
// ═══════════════════════════════════════════════════════════════════════════════

var _lastLiveSnapshot = null;
var _prevLiveIds = []; // V73: track previous live IDs for cleanup

function liveScoresChanged(matches) {
  // [P0] Signature etendue : score + minute + statut
  var liveMatches = matches.filter(function(m) { return isMatchInProgress(m); });
  var sig = '';
  for (var i = 0; i < liveMatches.length; i++) {
    var m = liveMatches[i];
    sig += m.id + ':' + (m.live_score || '') + ':' + (m.live_minute || '') + ':' + (m.status || '') + '|';
  }
  if (sig === _lastLiveSnapshot) return false;
  _lastLiveSnapshot = sig;
  return true;
}

// [P0] isMatchInProgress global — accessible depuis patchLiveMatches ET renderMatches
var _LIVE_STS = ['LIVE','IN_PLAY','INPLAY','IN_PROGRESS','INPROGRESS','PLAYING',
                 '1H','2H','HT','ET','P','BT','AWAITING_ET','AWAITING_PENALTIES',
                 'EXTRA_TIME','BREAK_TIME','PENALTY','PENALTIES','PEN_SHOOTOUT',
                 'LIVE_1H','LIVE_2H','PAUSED','PAUSE','FIRSTHALF','SECONDHALF',
                 '1ST_HALF','2ND_HALF','HALFTIME','SECOND_HALF','FIRST_HALF','EXTRA_TIME_HALF'];
function isMatchInProgress(m) {
  // [FIX live] espace/tiret → underscore : aligne avec statuts bruts BSD ("2nd half").
  var n = function(s) { return String(s || '').toUpperCase().replace(/[\s\-]+/g,'_').trim(); };
  if (_LIVE_STS.includes(n(m.status)) || _LIVE_STS.includes(n(m.live_status)) ||
      _LIVE_STS.includes(n(m.match_status)) || _LIVE_STS.includes(n(m.fixture_status))) return true;
  if (m.live_score) return parseInt(m.live_minute || 0) <= 130;
  if (m.live_minute != null) return parseInt(m.live_minute) <= 130;
  return false;
}

// [P0] Patch differentiel etendu — zero renderMatches sur Live tab sauf changement structurel
function patchLiveMatches(newMatches) {
  var liveMatches = newMatches.filter(function(m) { return isMatchInProgress(m); });
  var currentLiveIds = [];
  var hasStructuralChange = false;

  for (var i = 0; i < liveMatches.length; i++) {
    var m = liveMatches[i];
    currentLiveIds.push(m.id);
    var row = document.querySelector('tr[data-match-id="' + m.id + '"]');
    if (!row) { hasStructuralChange = true; continue; }

    // 1. Live score overlay — injection au premier but si container absent
    if (m.live_score) {
      var lc = row.querySelector('[data-live-container="' + m.id + '"]');
      if (!lc) {
        var td2 = row.querySelector('td:nth-child(2)');
        if (td2) {
          var iv = m.live_intensity || 0;
          var ic = iv >= 60 ? '#E2001A' : iv >= 30 ? '#ffa726' : '#29b6f6';
          lc = document.createElement('div');
          lc.setAttribute('data-live-container', m.id);
          lc.style.cssText = 'position:absolute;top:2px;right:4px;display:flex;flex-direction:column;align-items:flex-end;gap:2px;';
          lc.innerHTML = '<span data-live="' + m.id + '" style="font-size:9px;font-weight:700;color:#ff4d4d;background:rgba(255,77,77,0.15);padding:1px 5px;border-radius:4px;animation:pulse 1.5s infinite;">🔴 ' + m.live_score + (m.live_minute ? ' (' + m.live_minute + '′)' : '') + '</span>'
            + '<div style="width:50px;height:4px;background:#EAEAEA;border-radius:2px;overflow:hidden;">'
            + '<div data-intensity="' + m.id + '" style="width:' + iv + '%;height:100%;background:' + ic + ';border-radius:2px;"></div></div>'
            + '<span data-intensity-val="' + m.id + '" style="font-size:7px;color:var(--text3);">⚡' + iv + '</span>';
          td2.insertBefore(lc, td2.firstChild);
          var _nb = lc.querySelector('[data-live="' + m.id + '"]'); if (_nb) _nb.setAttribute('data-live-score', m.live_score); // [P1]
          startMinuteTick(m.id, parseInt(m.live_minute) || 0); // [P1] debut compteur
        }
      } else {
        var badge = lc.querySelector('[data-live="' + m.id + '"]');
        if (badge) {
          var prev = badge.getAttribute('data-prev-score');
          var nt = '🔴 ' + m.live_score + (m.live_minute ? ' (' + m.live_minute + '′)' : '');
          if (badge.innerHTML !== nt) {
            if (prev && prev !== m.live_score) { badge.classList.remove('score-flash'); void badge.offsetWidth; badge.classList.add('score-flash'); }
            badge.setAttribute('data-prev-score', m.live_score);
            badge.innerHTML = nt;
          }
          badge.setAttribute('data-live-score', m.live_score); // [P1] pour timer
          startMinuteTick(m.id, parseInt(m.live_minute) || 0); // [P1] sync serveur
        }
      }
    }

    // 2. Intensite
    var ib = row.querySelector('[data-intensity="' + m.id + '"]');
    var iv2 = row.querySelector('[data-intensity-val="' + m.id + '"]');
    if (ib && m.live_intensity != null) {
      var pct = Math.max(4, Math.min(100, m.live_intensity));
      var ic2 = m.live_intensity >= 60 ? '#E2001A' : m.live_intensity >= 30 ? '#ffa726' : '#29b6f6';
      ib.style.width = pct + '%'; ib.style.background = ic2;
      if (iv2) { iv2.textContent = '⚡' + m.live_intensity; iv2.style.color = ic2; }
    }

    // 3. Classe live
    if (!row.classList.contains('match-row-live') && m.live_score) row.classList.add('match-row-live');
  }

  // 4. Match fini / sorti du live → stop timer + rebuild
  for (var j = 0; j < _prevLiveIds.length; j++) {
    if (currentLiveIds.indexOf(_prevLiveIds[j]) === -1) {
      stopMinuteTick(_prevLiveIds[j]); // [P1] cleanup timer
      hasStructuralChange = true;
    }
  }
  _prevLiveIds = currentLiveIds;
  return hasStructuralChange;
}

// [P1] Compteur minute client-side — incremente localement entre les pushes SSE
var _minuteTimers = {};
function startMinuteTick(matchId, serverMinute) {
  if (_minuteTimers[matchId]) { _minuteTimers[matchId].minute = serverMinute; return; } // sync
  _minuteTimers[matchId] = { minute: serverMinute };
  _minuteTimers[matchId].tid = setInterval(function() {
    var s = _minuteTimers[matchId]; if (!s) return;
    s.minute = Math.min(s.minute + 1, 130);
    var b = document.querySelector('[data-live="' + matchId + '"]');
    if (b) { var sc = b.getAttribute('data-live-score') || ''; b.innerHTML = '🔴 ' + sc + (s.minute ? ' (' + s.minute + '′)' : ''); }
  }, 60000);
}
function stopMinuteTick(matchId) {
  if (_minuteTimers[matchId]) { clearInterval(_minuteTimers[matchId].tid); delete _minuteTimers[matchId]; }
}

// ── LIVE STRATEGY DASHBOARD v2 — AiScore Style ───────────────────────────────
var _activeLiveDashMatch = null;
var _fullMomentumData = {}; // matchId → { windows:[{min,home,away}], goals:[{min,team}], lastScore:[h,a] }

function _parseScore(scoreStr) {
  if (!scoreStr) return [0, 0];
  if (typeof scoreStr === 'object') return [parseInt(scoreStr.home)||0, parseInt(scoreStr.away)||0];
  var p = String(scoreStr).split(/[-:]/);
  return [parseInt(p[0])||0, parseInt(p[1])||0];
}

function _computeHomePressure(m) {
  var sc = _parseScore(m.live_score);
  var scoreBias = (sc[0] - sc[1]) * 12;
  var intensity = m.live_intensity != null ? parseInt(m.live_intensity) : 50;
  var da = m.live_dangerous_attacks;
  if (da && (da.home || da.away)) {
    var tot = (da.home||0) + (da.away||0);
    if (tot > 0) return Math.max(5, Math.min(95, Math.round(da.home/tot*100) + scoreBias*0.3));
  }
  return Math.max(5, Math.min(95, 50 + scoreBias + (intensity-50)*0.3));
}

function _recordMomentum(m) {
  if (!m || !m.id) return;
  var id = m.id;
  if (!_fullMomentumData[id]) _fullMomentumData[id] = { goals:[], lastScore:[0,0] };
  var data = _fullMomentumData[id];
  var min = parseInt(m.live_minute) || 0;
  var sc = _parseScore(m.live_score);
  // Détection buts uniquement (momentum vient de Sofascore)
  if (sc[0] > data.lastScore[0]) for (var i=0;i<sc[0]-data.lastScore[0];i++) data.goals.push({min:min,team:'home'});
  if (sc[1] > data.lastScore[1]) for (var i=0;i<sc[1]-data.lastScore[1];i++) data.goals.push({min:min,team:'away'});
  data.lastScore = sc;
}

// Cache ratings par matchId — évite re-fetch à chaque tick SSE
var _livePlayersCache = {};

function _fetchLivePlayers(matchId, callback) {
  if (_livePlayersCache[matchId]) { callback(_livePlayersCache[matchId]); return; }
  fetch('/api/v1/live-players/' + matchId)
    .then(function(r) { return r.ok ? r.json() : null; })
    .then(function(d) {
      if (d && d.success && d.top3) {
        _livePlayersCache[matchId] = d.top3;
        callback(d.top3);
      } else {
        callback(null);
      }
    })
    .catch(function() { callback(null); });
}

function _renderTopPerformers(m) {
  var el = document.getElementById('ld-performers-body');
  if (!el) return;
  _fetchLivePlayers(m.id, function(top3) {
    if (!top3 || (!top3.home.length && !top3.away.length)) {
      el.innerHTML = '<div class="ld-no-data" style="font-size:10px;">Stats joueurs<br>indisponibles</div>';
      return;
    }
    function badgeClass(r) { return r >= 7.5 ? 'great' : r >= 6.5 ? 'good' : 'avg'; }
    function rows(players) {
      return players.map(function(p) {
        return '<div class="ld-perf-row">'
          + '<span class="ld-perf-pos">' + p.position + '</span>'
          + '<span class="ld-perf-name">' + p.name + '</span>'
          + '<span class="ld-perf-badge ' + badgeClass(p.avg_rating) + '">' + safeFixed(p.avg_rating, 1) + '</span>'
          + '</div>';
      }).join('');
    }
    var boostHome = top3.homeAvg != null && top3.homeAvg > 8.0;
    var boostAway = top3.awayAvg != null && top3.awayAvg > 8.0;
    var html = '<div class="ld-perf-team home">' + (m.home_team || 'DOM').split(' ').slice(0,2).join(' ') + '</div>'
      + rows(top3.home)
      + '<div class="ld-perf-sep"></div>'
      + '<div class="ld-perf-team away">' + (m.away_team || 'EXT').split(' ').slice(0,2).join(' ') + '</div>'
      + rows(top3.away);
    if (boostHome) html += '<div class="ld-perf-boost">⚡ DOM en forme (+EV)</div>';
    else if (boostAway) html += '<div class="ld-perf-boost">⚡ EXT en forme (+EV)</div>';
    el.innerHTML = html;
    // Re-render bet panel with performers boost
    _renderBetPredictif(m, top3);
  });
}

function calculateLiveEdge(m, top3) {
  if (!m || !m.fair || !m.odds) return null;
  var sc = _parseScore(m.live_score);
  var minute = parseInt(m.live_minute) || 0;
  var remaining = Math.max(1, 90 - minute) / 90;
  var homeGoals = sc[0], awayGoals = sc[1];

  // Bayesian update: adjust pre-match fair probs given current score + time
  var fairHome = m.fair.home || 0.33;
  var fairDraw = m.fair.draw || 0.33;
  var fairAway = m.fair.away || 0.33;

  var scoreFactor = homeGoals - awayGoals;
  var timeWeight = 1 - remaining;

  var adjHome = fairHome + scoreFactor * 0.12 * timeWeight;
  var adjDraw = fairDraw - Math.abs(scoreFactor) * 0.08 * timeWeight;
  var adjAway = fairAway - scoreFactor * 0.12 * timeWeight;

  // Top performers boost (+4pp si top3 avg > 8.0, re-normalisé)
  var perfBoostHome = false, perfBoostAway = false;
  if (top3) {
    var hAvg = top3.homeAvg || 0, aAvg = top3.awayAvg || 0;
    if (hAvg > 8.0) { adjHome += 0.04; adjDraw -= 0.015; adjAway -= 0.025; perfBoostHome = true; }
    if (aAvg > 8.0) { adjAway += 0.04; adjDraw -= 0.015; adjHome -= 0.025; perfBoostAway = true; }
  }

  var total = adjHome + adjDraw + adjAway;
  if (total <= 0) return null;
  adjHome /= total; adjDraw /= total; adjAway /= total;

  var edges = [
    { label: m.home_team || 'Domicile', market: '1', adjProb: adjHome, odds: m.odds.home },
    { label: 'Nul', market: 'N', adjProb: adjDraw, odds: m.odds.draw },
    { label: m.away_team || 'Extérieur', market: '2', adjProb: adjAway, odds: m.odds.away }
  ].map(function(e) {
    e.edge = e.odds && e.adjProb ? (e.odds * e.adjProb - 1) * 100 : -99;
    return e;
  }).sort(function(a, b) { return b.edge - a.edge; });

  return { best: edges[0], adjHome: adjHome, adjDraw: adjDraw, adjAway: adjAway, remaining: remaining, perfBoostHome: perfBoostHome, perfBoostAway: perfBoostAway };
}

function _renderScoreHeader(m) {
  var sc = _parseScore(m.live_score);
  var el = function(id){return document.getElementById(id);};
  if (el('ld-home-name')) el('ld-home-name').textContent = m.home_team || '—';
  if (el('ld-away-name')) el('ld-away-name').textContent = m.away_team || '—';
  if (el('ld-home-sub')) el('ld-home-sub').textContent = m.home_rank ? 'Rang #'+m.home_rank : 'Domicile';
  if (el('ld-away-sub')) el('ld-away-sub').textContent = m.away_rank ? 'Rang #'+m.away_rank : 'Extérieur';
  if (el('ld-score-display')) el('ld-score-display').textContent = sc[0]+' : '+sc[1];
  if (el('ld-min-display')) {
    var st = (m.live_status||m.status||'').toUpperCase();
    var stLbl = st==='2H'?'2ème MT':st==='1H'?'1ère MT':st==='HT'?'Mi-Temps':st;
    el('ld-min-display').textContent = (m.live_minute||0)+"' · "+stLbl;
  }
  if (el('ld-intensity-display')) {
    var iv = parseInt(m.live_intensity)||0;
    var col = iv>=70?'#ff4d4d':iv>=40?'#ff8c00':iv>=20?'#ffd600':'var(--text3)';
    var lbl = iv>=70?'🔥 Bouillant':iv>=40?'⚡ Intensif':iv>=20?'🟡 Animé':'😴 Calme';
    el('ld-intensity-display').innerHTML = '<span style="font-size:12px;font-weight:700;color:'+col+';">'+lbl+' ('+iv+')</span>';
  }
}

function _renderMomentumBars(m) {
  var matchId = m.id, homeTeam = m.home_team, awayTeam = m.away_team;
  var goalData = _fullMomentumData[matchId] || { goals:[] };
  var svg = document.getElementById('ld-momentum-svg');
  if (!svg) return;
  var homeLbl = document.getElementById('ld-mom-home-lbl');
  var awayLbl = document.getElementById('ld-mom-away-lbl');
  if (homeLbl) homeLbl.textContent = (homeTeam||'DOM').split(' ').slice(0,2).join(' ');
  if (awayLbl) awayLbl.textContent = (awayTeam||'EXT').split(' ').slice(0,2).join(' ');

  var W=940, H=110, mL=10, mR=10, cY=54, maxH=cY-5;
  var minW=(W-mL-mR)/90;
  var bW=Math.max(minW*0.72, 3);
  var s='';

  // Lignes repère (15, 30, 60, 75)
  [15,30,60,75].forEach(function(mn){
    var x=(mL+mn*minW).toFixed(1);
    s+='<line x1="'+x+'" y1="4" x2="'+x+'" y2="'+(H-4)+'" stroke="rgba(255,255,255,0.05)" stroke-width="1"/>';
  });
  // Ligne centrale
  s+='<line x1="'+mL+'" y1="'+cY+'" x2="'+(W-mR)+'" y2="'+cY+'" stroke="rgba(255,255,255,0.12)" stroke-width="1"/>';
  s+='<text x="'+(mL+2)+'" y="'+(cY-6)+'" font-size="8" fill="rgba(0,230,118,0.5)" font-family="monospace">DOM</text>';
  s+='<text x="'+(mL+2)+'" y="'+(cY+13)+'" font-size="8" fill="rgba(41,182,246,0.5)" font-family="monospace">EXT</text>';
  // Ligne MT
  var htX=(mL+45*minW).toFixed(1);
  s+='<line x1="'+htX+'" y1="4" x2="'+htX+'" y2="'+(H-4)+'" stroke="rgba(255,255,255,0.28)" stroke-width="1.5" stroke-dasharray="3 3"/>';
  s+='<text x="'+(parseFloat(htX)+4)+'" y="14" font-size="8" fill="rgba(255,255,255,0.4)" font-family="monospace">MT</text>';

  // Barres momentum — Sofascore live_momentum [{min, v}] où v ∈ [-100, +100]
  // v > 0 = domicile domine (barre verte vers le haut), v < 0 = extérieur (barre bleue vers le bas)
  // bd 8c5 fix: Array.isArray guard contre objet BSD legacy ecraseur (forte couv La Liga).
  var sofaMomentum = Array.isArray(m.live_momentum) ? m.live_momentum : [];
  if (sofaMomentum.length > 0) {
    sofaMomentum.forEach(function(pt) {
      if (pt.min == null) return;
      var x = (mL + (pt.min - 0.5) * minW - bW/2).toFixed(1);
      var v = Math.max(-100, Math.min(100, pt.v || 0));
      if (v > 0) {
        var hH = ((v/100) * maxH).toFixed(1);
        if (parseFloat(hH) > 0.5) s+='<rect x="'+x+'" y="'+(cY-parseFloat(hH)).toFixed(1)+'" width="'+safeFixed(bW, 1)+'" height="'+hH+'" fill="rgba(0,230,118,0.75)" rx="1"/>';
      } else if (v < 0) {
        var aH = ((-v/100) * maxH).toFixed(1);
        if (parseFloat(aH) > 0.5) s+='<rect x="'+x+'" y="'+cY+'" width="'+safeFixed(bW, 1)+'" height="'+aH+'" fill="rgba(41,182,246,0.75)" rx="1"/>';
      }
    });
    // Indicateur minute courante
    var lastPt = sofaMomentum[sofaMomentum.length-1];
    if (lastPt && lastPt.min) {
      var curX = (mL + lastPt.min * minW).toFixed(1);
      s+='<line x1="'+curX+'" y1="4" x2="'+curX+'" y2="'+(H-4)+'" stroke="rgba(255,255,255,0.5)" stroke-width="1.5"/>';
      s+='<circle cx="'+curX+'" cy="'+cY+'" r="3" fill="white" opacity="0.85"/>';
      s+='<text x="'+curX+'" y="'+H+'" font-size="8" fill="rgba(255,255,255,0.45)" text-anchor="middle" font-family="monospace">'+lastPt.min+"'</text>";
    }
  } else {
    // Fallback : barre neutre si pas encore de données Sofascore
    var curMin = parseInt(m.live_minute) || 0;
    if (curMin > 0) {
      var curX2 = (mL + curMin * minW).toFixed(1);
      s+='<line x1="'+curX2+'" y1="4" x2="'+curX2+'" y2="'+(H-4)+'" stroke="rgba(255,255,255,0.3)" stroke-width="1.5" stroke-dasharray="2 3"/>';
      s+='<text x="'+curX2+'" y="'+H+'" font-size="8" fill="rgba(255,255,255,0.3)" text-anchor="middle" font-family="monospace">'+curMin+"'</text>";
    }
    // Texte "En attente données Sofascore"
    s+='<text x="'+(W/2)+'" y="'+(cY+4)+'" font-size="10" fill="rgba(255,255,255,0.2)" text-anchor="middle" font-family="monospace">En attente momentum Sofascore…</text>';
  }

  // Marqueurs buts (détectés localement)
  goalData.goals.forEach(function(g){
    var gx=(mL+g.min*minW).toFixed(1);
    var isH=g.team==='home';
    var gy=isH?(cY-maxH-6).toFixed(1):(cY+maxH+6).toFixed(1);
    var clr=isH?'#00e676':'#29b6f6';
    s+='<circle cx="'+gx+'" cy="'+gy+'" r="6" fill="'+clr+'" opacity="0.9"/>';
    s+='<text x="'+gx+'" y="'+(parseFloat(gy)+4)+'" font-size="9" fill="white" text-anchor="middle">⚽</text>';
  });

  svg.innerHTML = s;
}

function _renderStatsFlash(m) {
  var el = document.getElementById('ld-stats-body');
  if (!el) return;
  var ls = m.live_stats||{}, pos=m.live_possession||{}, sh=m.live_shots||{};
  var sot=m.live_shots_on_target||{}, co=m.live_corners||{}, da=m.live_dangerous_attacks||{};
  var stats=[
    {key:'possession', label:'Possession', h:pos.home||ls.possessionHome||50, a:pos.away||ls.possessionAway||50, unit:'%', pct:true},
    {key:'da',         label:'Att. Dang.', h:da.home||ls.dangerousAttacksHome||0, a:da.away||ls.dangerousAttacksAway||0},
    {key:'shots',      label:'Tirs',       h:sh.home||0, a:sh.away||0},
    {key:'sot',        label:'Cadrés',     h:sot.home||ls.shotsOnTargetHome||0, a:sot.away||ls.shotsOnTargetAway||0},
    {key:'corners',    label:'Corners',    h:co.home||0, a:co.away||0},
  ];

  // Premier rendu : construction HTML avec data-attributes pour update in-place
  if (!el.querySelector('[data-stat]')) {
    el.innerHTML = stats.map(function(s) {
      var tot = s.pct ? 100 : Math.max(s.h+s.a, 1);
      var hPct = Math.round(s.h/tot*100);
      return '<div class="ld-stat-row" data-stat="'+s.key+'">'
        +'<div><div class="ld-stat-val-h" data-vh>'+s.h+(s.unit||'')+'</div>'
        +'<div class="ld-stat-bar-h"><div class="ld-stat-bar-h-fill" data-bh style="width:'+hPct+'%;"></div></div></div>'
        +'<div class="ld-stat-label">'+s.label+'</div>'
        +'<div style="text-align:right;"><div class="ld-stat-val-a" data-va>'+s.a+(s.unit||'')+'</div>'
        +'<div class="ld-stat-bar-a"><div class="ld-stat-bar-a-fill" data-ba style="width:'+(100-hPct)+'%;"></div></div></div>'
        +'</div>';
    }).join('');
    return;
  }

  // Mises à jour in-place — aucun innerHTML rebuild, transitions CSS actives
  stats.forEach(function(s) {
    var row = el.querySelector('[data-stat="'+s.key+'"]');
    if (!row) return;
    var tot = s.pct ? 100 : Math.max(s.h+s.a, 1);
    var hPct = Math.round(s.h/tot*100);
    var vh = row.querySelector('[data-vh]');
    var bh = row.querySelector('[data-bh]');
    var va = row.querySelector('[data-va]');
    var ba = row.querySelector('[data-ba]');
    if (vh) vh.textContent = s.h+(s.unit||'');
    if (bh) bh.style.width = hPct+'%';
    if (va) va.textContent = s.a+(s.unit||'');
    if (ba) ba.style.width = (100-hPct)+'%';
  });
}

function _renderBetPredictif(m, top3) {
  var el = document.getElementById('ld-bet-body');
  if (!el) return;
  var edge = calculateLiveEdge(m, top3 || null);
  if (!edge||!edge.best) { el.innerHTML='<div class="ld-no-data">Cotes non disponibles.</div>'; return; }
  var best=edge.best, pos=best.edge>3, eStr=(best.edge>0?'+':'')+safeFixed(best.edge, 1)+'%';
  var prob=Math.round(best.adjProb*100);
  var bCol=pos?'#00e676':'#555', probCol=pos?'var(--green)':'var(--text2)';
  var eCol=best.edge>0?'var(--green)':'var(--red)';
  var bgCol=pos?'rgba(0,230,118,0.2)':'rgba(255,255,255,0.06)';
  var txtCol=pos?'var(--green)':'var(--text3)';
  var boostTag = (edge.perfBoostHome||edge.perfBoostAway)
    ? '<div style="font-size:9px;color:#ffd600;margin-top:4px;text-align:center;">⚡ Boost performers actif</div>'
    : '';
  el.innerHTML='<div class="ld-bet-verdict">'
    +'<span class="ld-bet-badge" style="background:'+bgCol+';color:'+txtCol+';">'+(pos?'✓ BET':'✗ SKIP')+'</span>'
    +'<span class="ld-bet-desc">'+best.label+(best.odds?' @ '+safeFixed(best.odds, 2):'')+'</span>'
    +'</div>'
    +'<div class="ld-bet-prob-row">'
    +'<div><div class="ld-bet-prob" style="color:'+probCol+';">'+prob+'%</div><div class="ld-bet-prob-lbl">Proba ajustée</div></div>'
    +'<div style="text-align:right;"><div class="ld-bet-prob" style="color:'+eCol+';">'+eStr+'</div><div class="ld-bet-prob-lbl">Edge no-vig</div></div>'
    +'</div>'
    +'<div class="ld-bet-edge-row">'
    +'<div class="ld-bet-edge-item"><div class="ld-bet-edge-val" style="color:var(--green);">'+Math.round(edge.adjHome*100)+'%</div><div class="ld-bet-edge-lbl">Dom.</div></div>'
    +'<div class="ld-bet-edge-item"><div class="ld-bet-edge-val" style="color:var(--text2);">'+Math.round(edge.adjDraw*100)+'%</div><div class="ld-bet-edge-lbl">Nul</div></div>'
    +'<div class="ld-bet-edge-item"><div class="ld-bet-edge-val" style="color:var(--blue);">'+Math.round(edge.adjAway*100)+'%</div><div class="ld-bet-edge-lbl">Ext.</div></div>'
    +'</div>'
    +boostTag;
}

function _renderDashForMatch(m) {
  if (!m) return;
  _recordMomentum(m);
  _renderScoreHeader(m);
  _renderMomentumBars(m);
  _renderLiveWS(m);
  _renderStatsFlash(m);
  _renderBetPredictif(m, _livePlayersCache[m.id] || null);
  _renderTopPerformers(m);
}

// ── BSD Live WS — mini-pitch + heatmap + bandeau situation ──────────────────
var _wsState = {}; // matchId -> { ball, situation, pressureH, pressureA, spark:[] }
function _renderLiveWSInto(P, m) {
  var sec = document.getElementById(P + '-section');
  if (!sec || !m) return;
  var st = _wsState[m.id];
  if (!st) { sec.style.display = 'none'; return; }
  sec.style.display = '';

  // Mini-pitch SVG : terrain + point ballon
  var pitch = document.getElementById(P + '-pitch');
  if (pitch) {
    var s = '';
    s += '<rect x="0" y="0" width="100" height="64" fill="#0c5c2a"/>';
    s += '<rect x="1" y="1" width="98" height="62" fill="none" stroke="rgba(255,255,255,.35)" stroke-width="0.5"/>';
    s += '<line x1="50" y1="1" x2="50" y2="63" stroke="rgba(255,255,255,.35)" stroke-width="0.5"/>';
    s += '<circle cx="50" cy="32" r="8" fill="none" stroke="rgba(255,255,255,.35)" stroke-width="0.5"/>';
    s += '<rect x="1" y="18" width="14" height="28" fill="none" stroke="rgba(255,255,255,.3)" stroke-width="0.5"/>';
    s += '<rect x="85" y="18" width="14" height="28" fill="none" stroke="rgba(255,255,255,.3)" stroke-width="0.5"/>';
    if (st.ball && st.ball.x != null) {
      var bx = Math.max(2, Math.min(98, st.ball.x));
      var by = Math.max(2, Math.min(62, (st.ball.y != null ? st.ball.y : 50) * 0.64));
      s += '<circle cx="' + safeFixed(bx, 1) + '" cy="' + safeFixed(by, 1) + '" r="2.6" fill="#fff" stroke="#E2001A" stroke-width="0.8"><animate attributeName="r" values="2.6;3.4;2.6" dur="1s" repeatCount="indefinite"/></circle>';
    } else {
      s += '<text x="50" y="34" font-size="5" fill="rgba(255,255,255,.5)" text-anchor="middle" font-family="monospace">position ballon indisponible</text>';
    }
    pitch.innerHTML = s;
  }

  // Heatmap territoriale
  var ph = (st.pressureH != null) ? Math.abs(st.pressureH) : null;
  var pa = (st.pressureA != null) ? Math.abs(st.pressureA) : null;
  if (ph != null || pa != null) {
    var tot = (ph || 0) + (pa || 0);
    var hPct = tot > 0 ? Math.round((ph || 0) / tot * 100) : 50;
    var aPct = 100 - hPct;
    var setW = function(id, v){ var e=document.getElementById(id); if(e) e.style.width=v+'%'; };
    var setT = function(id, v){ var e=document.getElementById(id); if(e) e.textContent=v+'%'; };
    setW(P + '-heat-h', hPct); setW(P + '-heat-a', aPct);
    setT(P + '-heat-h-pct', hPct); setT(P + '-heat-a-pct', aPct);
  }
  var hl=document.getElementById(P + '-heat-h-lbl'), al=document.getElementById(P + '-heat-a-lbl');
  if (hl) hl.textContent = (m.home_team||'DOM').split(' ')[0];
  if (al) al.textContent = (m.away_team||'EXT').split(' ')[0];

  // Bandeau situation
  _flashSituationBanner(st.situation, P + '-banner');
}

function _renderLiveWS(m) { _renderLiveWSInto('ld-ws', m); }

function _flashSituationBanner(sit, bannerId) {
  var b = document.getElementById(bannerId || 'ld-ws-banner');
  if (!b || !sit || !sit.type) return;
  if (Date.now() - (sit.ts || 0) > 8000) return; // périmé
  var cls = 's-danger';
  if (sit.type === 'PENALTY') cls = 's-penalty';
  else if (sit.type === 'CORNER') cls = 's-corner';
  else if (sit.type === 'COUP FRANC') cls = 's-fk';
  else if (sit.type === 'BUT') cls = 's-goal';
  b.className = 'ld-ws-banner show ' + cls;
  b.textContent = (sit.type === 'PENALTY' ? '⚠ ' : '') + sit.type + (sit.team ? ' · ' + (sit.team === 'home' ? 'DOM' : sit.team === 'away' ? 'EXT' : sit.team).toUpperCase() : '');
  clearTimeout(b._t);
  b._t = setTimeout(function(){ b.className = 'ld-ws-banner'; }, 5000);
}

function _wsTableSpark(id) {
  var st = _wsState[id]; if (!st) return;
  var row = document.querySelector('tr[data-match-id="' + id + '"]');
  if (!row) return;
  var btn = row.querySelector('.live-btn'); if (!btn) return;
  var holder = btn.parentNode.querySelector('.live-spark');
  if (!holder) {
    holder = document.createElement('span');
    holder.className = 'live-spark';
    btn.parentNode.appendChild(holder);
  }
  var arr = (st.spark || []).slice(-12);
  holder.innerHTML = arr.map(function(v){
    var h = Math.max(2, Math.min(12, Math.round(v / 100 * 12)));
    return '<i style="height:' + h + 'px"></i>';
  }).join('');
}

function _wsCoteFlash(id, side) {
  if (!side) return;
  var row = document.querySelector('tr[data-match-id="' + id + '"]'); if (!row) return;
  var cell = row.querySelector('.odds-' + side) || row.querySelector('[data-odds="' + side + '"]');
  if (!cell) { var oc = row.querySelector('.mc-odd, .vb-odds'); cell = oc || null; }
  if (!cell) return;
  cell.classList.remove('cote-flash'); void cell.offsetWidth;
  cell.classList.add('cote-flash');
  setTimeout(function(){ cell.classList.remove('cote-flash'); }, 3600);
}

function updateLiveDashboard(matches) {
  var liveMatches = (matches || []).filter(function(m) { return isMatchInProgress(m); });
  var emptyEl = document.getElementById('ld-empty');
  var contentEl = document.getElementById('ld-content');
  var stripEl = document.getElementById('ld-strip');

  if (!liveMatches.length) {
    if (emptyEl) emptyEl.style.display = '';
    if (contentEl) contentEl.style.display = 'none';
    return;
  }
  if (emptyEl) emptyEl.style.display = 'none';
  if (contentEl) contentEl.style.display = '';

  // Pick active match (keep selection if still live)
  var prevId = _activeLiveDashMatch;
  var activeM = liveMatches.find(function(m) { return m.id === _activeLiveDashMatch; });
  if (!activeM) { activeM = liveMatches[0]; _activeLiveDashMatch = activeM.id; }
  // Si match changé → reset stats body pour premier rendu propre
  if (prevId !== _activeLiveDashMatch) {
    var sb = document.getElementById('ld-stats-body');
    if (sb) sb.innerHTML = '<div class="ld-no-data">En attente…</div>';
  }

  // Build strip
  if (stripEl) {
    stripEl.innerHTML = liveMatches.map(function(m) {
      var sc = _parseScore(m.live_score);
      var isActive = m.id === _activeLiveDashMatch;
      return '<div class="ld-strip-card' + (isActive ? ' active' : '') + '" onclick="selectLiveDashMatch(\'' + m.id + '\')">'
        + '<div class="ld-strip-match">' + (m.home_team || '?') + ' v ' + (m.away_team || '?') + '</div>'
        + '<div class="ld-strip-score">' + sc[0] + ' — ' + sc[1] + '</div>'
        + '<div class="ld-strip-min">' + (m.live_minute ? m.live_minute + '′' : (m.live_status || '—')) + '</div>'
        + '</div>';
    }).join('');
  }

  _renderDashForMatch(activeM);
}

function selectLiveDashMatch(matchId) {
  _activeLiveDashMatch = matchId;
  var m = (allMatches || []).find(function(x) { return x.id === matchId; });
  if (!m) return;
  document.querySelectorAll('.ld-strip-card').forEach(function(card) { card.classList.remove('active'); });
  var cards = document.querySelectorAll('.ld-strip-card');
  var liveMatches = (allMatches || []).filter(function(x) { return isMatchInProgress(x); });
  var idx = liveMatches.findIndex(function(x) { return x.id === matchId; });
  if (cards[idx]) cards[idx].classList.add('active');
  // Reset stats body pour forcer premier rendu (nouveau match = nouvelles unités/lignes)
  var sb = document.getElementById('ld-stats-body');
  if (sb) sb.innerHTML = '<div class="ld-no-data">En attente…</div>';
  _renderDashForMatch(m);
}

// Toast non-intrusif
var liveUpdateToastTimer = null;
function flashLiveUpdateToast() {
  if (activeMatchTab !== 'live') return;
  var toast = document.getElementById('live-update-toast');
  if (!toast) return;
  toast.classList.add('visible');
  if (liveUpdateToastTimer) clearTimeout(liveUpdateToastTimer);
  liveUpdateToastTimer = setTimeout(function() { toast.classList.remove('visible'); }, 1800);
}

// Verrouillage scroll manuel — bloque tout mouvement automatique de la page
var _scrollLocked = false;
function toggleScrollLock() {
  _scrollLocked = !_scrollLocked;
  var btn = document.getElementById('scroll-lock-btn');
  if (_scrollLocked) {
    document.body.style.position = 'fixed';
    document.body.style.top = '-' + window.scrollY + 'px';
    document.body.style.width = '100%';
    if (btn) { btn.classList.add('locked'); btn.innerHTML = '\u{1F513} Déverrouiller'; }
    flashLiveUpdateToast();
  } else {
    var scrollY = parseInt(document.body.style.top || '0') * -1;
    document.body.style.position = '';
    document.body.style.top = '';
    document.body.style.width = '';
    window.scrollTo(0, scrollY);
    if (btn) { btn.classList.remove('locked'); btn.innerHTML = '\u{1F512} Verrouiller'; }
  }
}

// Protocole V73 : patch différentiel sur onglet LIVE, rebuild complet sur autres
function liveUpdateProtocol(newMatches, meta) {
  if (activeMatchTab === 'live') {
    if (!liveScoresChanged(newMatches)) return;
    allMatches = newMatches;
    if (meta) updateStatusBar(meta);
    // Dashboard strategy — no scroll, no DOM table patch
    updateLiveDashboard(allMatches);
    buildLiveTop5Panel();
    buildLivePredictionsPanel();
    lazyLoadButeurs(allMatches);
    flashLiveUpdateToast();
  } else {
    allMatches = newMatches;
    if (meta) updateStatusBar(meta);
    renderMatches(allMatches);
    lazyLoadButeurs(allMatches);
  }
}

// Auto-refresh polling 5 minutes (fallback)
let autoRefreshTimer = null;
function startAutoRefresh() {
  if (autoRefreshTimer) clearInterval(autoRefreshTimer);
  autoRefreshTimer = setInterval(async () => {
    if (document.visibilityState !== 'visible') return;
    try {
      const res = await apiFetch('/api/v1/matches');
      if (!res.ok) return;
      const json = await res.json();
      liveUpdateProtocol(json.matches || [], json.meta);
    } catch(e) { /* silencieux */ }
  }, 5 * 60 * 1000);
}

// v11.0 — Badge néon WebSocket BSD : helper + fetch initial
function updateWsStatusBadge(connected, subsCount, pending) {
  const dot = document.getElementById('ws-status-dot');
  if (!dot) return;
  dot.classList.remove('ws-on', 'ws-off');
  dot.classList.add(connected ? 'ws-on' : 'ws-off');
  const subs = Number(subsCount || 0), pend = Number(pending || 0);
  if (connected) {
    dot.title = '⚡ WebSocket BSD actif · ' + subs + ' match' + (subs > 1 ? 's' : '') + ' suivi' + (subs > 1 ? 's' : '') + ' en push <5s' + (pend ? ' (' + pend + ' en file)' : '');
  } else {
    dot.title = '⚠ WebSocket BSD déconnecté · fallback polling 60s';
  }
  const tab = document.getElementById('tab-live');
  if (tab) tab.classList.toggle('ws-connected', !!connected);
}

function fetchWsStatus() {
  fetch('/api/v1/live/ws-status')
    .then(r => r.ok ? r.json() : null)
    .then(d => {
      if (!d) return;
      updateWsStatusBadge(!!d.connected, (d.subs || []).length, d.pending || 0);
    })
    .catch(() => {});
}

// SSE — remplace le polling 5min quand disponible
let sseConnection = null;
function initSSE() {
  fetchWsStatus();
  setInterval(fetchWsStatus, 60000); // filet de sécurité si SSE ws_status manqué
  if (!window.EventSource) { startAutoRefresh(); return; } // fallback navigateurs anciens
  if (sseConnection) sseConnection.close();

  sseConnection = new EventSource('/api/v1/live');

  sseConnection.addEventListener('matches_update', e => {
    try {
      const data = JSON.parse(e.data);
      if (data.matches) {
        liveUpdateProtocol(data.matches, data.meta);
      }
    } catch(err) { console.warn('[SSE] Parse error', err); }
  });

  sseConnection.addEventListener('butteurs-ready', e => {
    try {
      const data = JSON.parse(e.data);
      if (data.buteurs && data.matchId) {
        updateButeursCell(data.matchId, data.buteurs);
      }
    } catch(err) { console.warn('[SSE] buteurs-ready parse error', err); }
  });

  // bd mpg — SSE pbp_update : refresh PBP section si modal détail tennis ouverte sur ce matchId.
  sseConnection.addEventListener('pbp_update', e => {
    try {
      const data = JSON.parse(e.data);
      if (!data || !data.match_id) return;
      const target = document.getElementById('tennis-pbp-enrich');
      if (!target) return;
      const openMatchId = target.getAttribute('data-match-id');
      if (openMatchId !== String(data.match_id)) return;
      if (typeof fetchTennisPBP === 'function') fetchTennisPBP(openMatchId);
    } catch(err) { console.warn('[SSE] pbp_update parse error', err); }
  });

  sseConnection.addEventListener('live_patch', e => {
    try {
      const data = JSON.parse(e.data);
      if (!data.patches || !data.patches.length) return;
      data.patches.forEach(function(p) {
        var m = allMatches.find(function(x) { return x.id === p.id; });
        if (!m) return;
        if (p.live_score            !== undefined) m.live_score            = p.live_score;
        if (p.live_minute           !== undefined) m.live_minute           = p.live_minute;
        if (p.live_intensity        !== undefined) {
          // bd 21m7 — Detecte transition tier intensity pour son alerte (avant overwrite)
          try { if (typeof psCheckIntensityTransition === 'function') psCheckIntensityTransition(m.id, p.live_intensity); } catch (_) {}
          m.live_intensity        = p.live_intensity;
        }
        // bd tvf — Trace pression dom/ext pour sparkline col Match (15 dernieres mises a jour)
        try { _footPressurePush(m.id, p.live_intensity, p.live_momentum || m.live_momentum); } catch (_) {}
        if (p.status)                              m.status                = p.status;
        if (p.live_possession       !== undefined) m.live_possession       = p.live_possession;
        if (p.live_shots            !== undefined) m.live_shots            = p.live_shots;
        if (p.live_shots_on_target  !== undefined) m.live_shots_on_target  = p.live_shots_on_target;
        if (p.live_corners          !== undefined) m.live_corners          = p.live_corners;
        if (p.live_dangerous_attacks !== undefined) m.live_dangerous_attacks = p.live_dangerous_attacks;
        if (p.live_xg               !== undefined) m.live_xg               = p.live_xg;
        if (p.live_cards            !== undefined) m.live_cards            = p.live_cards;
        // bd 8c5 — Garde array stricte : ne pas écraser un array Sofa local par un
        // null/objet provenant d'un tick BSD WS sans data momentum. Symptôme avant
        // fix : barres momentum redevenaient plates à chaque poll 30s.
        if (Array.isArray(p.live_momentum)) m.live_momentum = p.live_momentum;
        if (p.live_momentum_pct     !== undefined) m.live_momentum_pct     = p.live_momentum_pct;
        if (p.live_stats            !== undefined) m.live_stats            = p.live_stats;
      });
      // [FIX live] live_patch ne re-rendait jamais le tableau → un match qui
      // passe LIVE en cours de session n'avait ni bouton LIVE ni Bets Live
      // (fix v10.55 dans renderMatches contourné par ce chemin SSE). On force
      // un renderMatches ciblé quand un match patché est live mais que sa
      // ligne DOM n'a pas encore l'UI live (pas de .live-btn).
      var _needRerender = data.patches.some(function (p) {
        var mm = allMatches.find(function (x) { return x.id === p.id; });
        if (!mm) return false;
        var liveNow = (typeof isMatchInProgress === 'function') ? isMatchInProgress(mm) : !!mm.live_score;
        if (!liveNow) return false;
        var rw = document.querySelector('tr[data-match-id="' + p.id + '"]');
        return !rw || !rw.querySelector('.live-btn');
      });
      if (_needRerender && typeof renderMatches === 'function') {
        renderMatches(allMatches);
      }
      if (activeMatchTab === 'live') {
        updateLiveDashboard(allMatches);
        buildLiveTop5Panel();
        flashLiveUpdateToast();
      }
      // v9.8.8 — Modal Live Dashboard ouvert : push instant update (au lieu d'attendre polling 30s)
      if (typeof _liveDetailMatchId !== 'undefined' && _liveDetailMatchId) {
        const matchInPatch = data.patches.find(p => p.id === _liveDetailMatchId);
        if (matchInPatch && typeof refreshLiveDetailModal === 'function') {
          refreshLiveDetailModal(_liveDetailMatchId, { force: true }).catch(() => {});
        }
      }
    } catch(err) { console.warn('[SSE] live_patch error', err); }
  });

  // bd c0c — Market Divergence Pulse (UI-006)
  // SSE event 'market_divergence' → cellule edge/cote du match pulse 1.2s ease-out 2 iterations.
  // type ∈ {cyan, amber, red} → classe variante. Idempotent: nettoyage timeout
  // précédent évite empilement si re-broadcast pendant l'animation.
  var _cfDivergenceTimers = (typeof _cfDivergenceTimers !== 'undefined') ? _cfDivergenceTimers : new Map();
  sseConnection.addEventListener('market_divergence', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.matchId) return;
      // Sanitize matchId (server already truncates, but defense-in-depth)
      const safeId = String(d.matchId).slice(0, 64).replace(/[^a-zA-Z0-9_-]/g, '');
      if (!safeId) return;
      const variant = (d.pulse_type === 'cyan' || d.pulse_type === 'red' || d.pulse_type === 'amber') ? d.pulse_type : 'amber';
      // Cible: cellule edge (data-col=edge) ou cote (.odds-cell) ou row entière fallback.
      const row = document.querySelector('tr[data-match-id="' + safeId + '"]');
      if (!row) return;
      const target = row.querySelector('.edge-cell, [data-col="edge"], .odds-cell') || row;
      // Cleanup previous animation
      const existing = _cfDivergenceTimers.get(safeId);
      if (existing) {
        clearTimeout(existing);
        target.classList.remove('cf-divergence-pulse', 'cyan', 'amber', 'red');
      }
      // Force reflow to restart animation
      void target.offsetWidth;
      target.classList.add('cf-divergence-pulse', variant);
      const timer = setTimeout(() => {
        target.classList.remove('cf-divergence-pulse', 'cyan', 'amber', 'red');
        _cfDivergenceTimers.delete(safeId);
      }, 2600); // 1.2s × 2 iterations + 200ms safety margin
      _cfDivergenceTimers.set(safeId, timer);
    } catch (err) { console.warn('[SSE] market_divergence error', err); }
  });

  // bd 647 — DR Live Pulse (UI-010)
  // SSE event 'dr_spike' → cellule .tn-dr-delta (et fallback cellule DR foot)
  // pulse 1.5s ease-out 1 itération. Couples backend bd 6v0 (broadcastTennisDRSpike).
  var _cfDRPulseTimers = (typeof _cfDRPulseTimers !== 'undefined') ? _cfDRPulseTimers : new Map();
  sseConnection.addEventListener('dr_spike', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.matchId) return;
      const safeId = String(d.matchId).slice(0, 64).replace(/[^a-zA-Z0-9_-]/g, '');
      if (!safeId) return;
      const side = (d.side === 'p1' || d.side === 'p2') ? d.side : 'p1';
      // Cible primaire : ligne tennis du tableau VB (tr[data-match-id]).
      // Sélecteurs possibles : .tn-dr-delta (badge Δ), .tn-dr-val (valeur DR), ou row fallback.
      const row = document.querySelector('tr[data-match-id="' + safeId + '"]') ||
                  document.querySelector('[data-tennis-id="' + safeId + '"]') ||
                  document.querySelector('[data-match="' + safeId + '"]');
      if (!row) return;
      // Préfère badge .tn-dr-delta côté joueur ciblé, sinon premier badge dispo, sinon cellule DR
      const deltaBadges = row.querySelectorAll('.tn-dr-delta');
      let target = null;
      if (deltaBadges.length === 2) {
        target = side === 'p1' ? deltaBadges[0] : deltaBadges[1];
      } else if (deltaBadges.length === 1) {
        target = deltaBadges[0];
      } else {
        target = row.querySelector('.tn-dr-val, .tn-dr, [data-col="dr"]') || row;
      }
      if (!target) return;
      // Cleanup previous animation (idempotent)
      const existing = _cfDRPulseTimers.get(safeId);
      if (existing) {
        clearTimeout(existing);
        target.classList.remove('cf-dr-pulse');
      }
      void target.offsetWidth; // force reflow restart animation
      target.classList.add('cf-dr-pulse');
      const timer = setTimeout(() => {
        target.classList.remove('cf-dr-pulse');
        _cfDRPulseTimers.delete(safeId);
      }, 1700); // 1.5s + 200ms safety
      _cfDRPulseTimers.set(safeId, timer);
    } catch (err) { console.warn('[SSE] dr_spike error', err); }
  });

  // bd 040 — Steam Detector multi-bookmaker (BD-DATA-012)
  // SSE event 'steam_detected' → cellule cote/edge match pulse 1.0s ease-out 2 iter
  // + badge inline STEAM avec tooltip détails (N books · magnitude · severity).
  // Reuse pattern divergence (debounce 30s géré côté serveur via _pulseShouldBroadcast).
  var _cfSteamTimers = (typeof _cfSteamTimers !== 'undefined') ? _cfSteamTimers : new Map();
  sseConnection.addEventListener('steam_detected', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.matchId) return;
      // Sanitize matchId (defense-in-depth: server tronque déjà).
      const safeId = String(d.matchId).slice(0, 64).replace(/[^a-zA-Z0-9_-]/g, '');
      if (!safeId) return;
      const sev = (d.severity === 'low' || d.severity === 'med' || d.severity === 'high') ? d.severity : 'med';
      const dir = (d.direction === 'home' || d.direction === 'draw' || d.direction === 'away') ? d.direction : 'home';
      const nBooks = Math.max(0, Math.min(50, parseInt(d.n_bookmakers) || 0));
      const mag = Math.max(-50, Math.min(50, parseFloat(d.magnitude_avg_pct) || 0));
      const row = document.querySelector('tr[data-match-id="' + safeId + '"]');
      if (!row) return;
      const target = row.querySelector('.edge-cell, [data-col="edge"], .odds-cell') || row;
      // Cleanup previous animation
      const existing = _cfSteamTimers.get(safeId);
      if (existing) {
        clearTimeout(existing);
        target.classList.remove('cf-steam-pulse');
        const old = row.querySelector('.cf-steam-badge[data-steam-temp="1"]');
        if (old) old.remove();
      }
      // Force reflow for restart
      void target.offsetWidth;
      target.classList.add('cf-steam-pulse');
      // Inline badge attaché à la cellule match (.match-cell ou row fallback)
      const labelCell = row.querySelector('.match-cell, [data-col="match"]') || target;
      const badge = document.createElement('span');
      badge.className = 'cf-steam-badge severity-' + sev;
      badge.setAttribute('data-steam-temp', '1');
      const dirLabel = dir === 'home' ? '1' : (dir === 'draw' ? 'N' : '2');
      badge.textContent = '🚂 STEAM ' + dirLabel;
      badge.title = nBooks + ' bookmakers · ' + mag.toFixed(1) + '% · severity ' + sev;
      labelCell.appendChild(badge);
      const timer = setTimeout(() => {
        target.classList.remove('cf-steam-pulse');
        // Garde le badge visible 60s (signal persistant) avant retrait
        setTimeout(() => { if (badge.parentNode) badge.remove(); }, 60000);
        _cfSteamTimers.delete(safeId);
      }, 2200); // 1.0s × 2 iter + 200ms safety
      _cfSteamTimers.set(safeId, timer);
    } catch (err) { console.warn('[SSE] steam_detected error', err); }
  });

  // v11.0 — Badge néon WebSocket BSD (statut connexion)
  sseConnection.addEventListener('ws_status', e => {
    try {
      const d = JSON.parse(e.data);
      updateWsStatusBadge(!!d.connected, d.subs ? d.subs.length : 0, d.pending || 0);
    } catch (err) { console.warn('[SSE] ws_status error', err); }
  });

  // v11.0 — Push stats event frame (~30s, BSD WebSocket schema officiel)
  sseConnection.addEventListener('ws_event', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.id) return;
      const m = allMatches.find(x => x.id === d.id);
      if (!m) return;
      if (d.score) m.live_score = d.score;
      if (d.minute != null) m.live_minute = d.minute;
      if (d.status) m.status = d.status;
      if (d.live_possession)        m.live_possession        = d.live_possession;
      if (d.live_shots)              m.live_shots              = d.live_shots;
      if (d.live_shots_on_target)    m.live_shots_on_target    = d.live_shots_on_target;
      if (d.live_corners)            m.live_corners            = d.live_corners;
      if (d.live_xg)                 m.live_xg                 = d.live_xg;
      if (d.live_big_chances)        m.live_big_chances        = d.live_big_chances;
      // bd 8c5 fix: route shape strict — array Sofa vers live_momentum, objet BSD vers live_momentum_pct
      if (Array.isArray(d.live_momentum)) m.live_momentum = d.live_momentum;
      if (d.live_momentum_pct)       m.live_momentum_pct       = d.live_momentum_pct;
      if (d.live_cards)              m.live_cards              = d.live_cards;
      if (d.live_dangerous_attacks)  m.live_dangerous_attacks  = d.live_dangerous_attacks;
      if (d.live_touches_opp_box)    m.live_touches_opp_box    = d.live_touches_opp_box;
      if (activeMatchTab === 'live' && typeof updateLiveDashboard === 'function') {
        updateLiveDashboard(allMatches);
      }
      if (typeof _liveDetailMatchId !== 'undefined' && _liveDetailMatchId === d.id && typeof refreshLiveDetailModal === 'function') {
        refreshLiveDetailModal(d.id, { force: true }).catch(() => {});
      }
    } catch (err) { console.warn('[SSE] ws_event error', err); }
  });

  // v11.0 — Push cotes live (BSD WebSocket schema officiel)
  sseConnection.addEventListener('ws_odds', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.id) return;
      const m = allMatches.find(x => x.id === d.id);
      if (!m) return;
      m.odds_live = d.odds;
      // Flash visuel sur ligne tableau si cellule cote présente
      const row = document.querySelector('tr[data-match-id="' + d.id + '"]');
      if (row) {
        row.classList.add('ws-odds-flash');
        setTimeout(() => row.classList.remove('ws-odds-flash'), 800);
      }
    } catch (err) { console.warn('[SSE] ws_odds error', err); }
  });

  sseConnection.addEventListener('live_ws', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.id) return;
      var st = _wsState[d.id] || (_wsState[d.id] = { spark: [] });
      if (d.ball) st.ball = d.ball;
      if (d.situation) st.situation = d.situation;
      if (d.pressureH != null) st.pressureH = d.pressureH;
      if (d.pressureA != null) st.pressureA = d.pressureA;
      var intens = (Math.abs(d.pressureH || 0) + Math.abs(d.pressureA || 0)) / 2;
      st.spark.push(Math.max(0, Math.min(100, intens || 0)));
      if (st.spark.length > 30) st.spark = st.spark.slice(-30);

      var m = allMatches.find(function(x){ return x.id === d.id; });
      if (m) {
        if (d.score) m.live_score = d.score;
        if (d.minute != null) m.live_minute = d.minute;
        if (d.status) m.status = d.status;
      }
      // Sparkline ligne table (sans ouvrir le panneau)
      _wsTableSpark(d.id);
      // Flash value sur cote
      if (d.value_flash) _wsCoteFlash(d.id, d.value_flash);
      // Si panneau Live (onglet) ouvert sur ce match → push widgets instant
      if (activeMatchTab === 'live' && d.id === _activeLiveDashMatch && m) {
        _renderLiveWS(m);
        _renderScoreHeader(m);
      }
      // Si MODAL Live Detail ouvert sur ce match → push widgets instant
      if (typeof _liveDetailMatchId !== 'undefined' && _liveDetailMatchId === d.id && m) {
        _renderLiveWSInto('ldm-ws', m);
      }
    } catch (err) { console.warn('[SSE] live_ws error', err); }
  });

  // bd vl02 — Alertes SSE live edge math (favorite_trap + goal_flood)
  // Affiche toast UI top-right avec type-specific icon + couleur + auto-dismiss 8s.
  // Click toast → dismiss. Stack si multiples alertes proches.
  sseConnection.addEventListener('alert_trigger', e => {
    try {
      const d = JSON.parse(e.data);
      if (!d || !d.type) return;
      _showAlertToast(d);
    } catch (err) { console.warn('[SSE] alert_trigger error', err); }
  });

  sseConnection.onopen = () => {
    console.log('[SSE] Connecté — polling 5min désactivé');
    if (autoRefreshTimer) { clearInterval(autoRefreshTimer); autoRefreshTimer = null; }
  };

  sseConnection.onerror = () => {
    // [FIX live] NE PAS close()/null : ça tue la reconnexion native EventSource
    // → SSE mort pour toute la session. On garde la connexion (retry auto
    // navigateur) + filet polling temporaire. onopen relancera et coupera le timer.
    console.warn('[SSE] Erreur transitoire — reconnexion auto + filet polling');
    startAutoRefresh(); // filet de sécurité, levé par onopen si SSE revient
  };
}

async function loadAIScout() {
  try {
    const res = await apiFetch('/api/v1/ai-scout');
    if (!res.ok) return;
    const data = await res.json();
    if (data.error || !data.text) return;
    const panel = document.getElementById('ai-scout-panel');
    const body  = document.getElementById('ai-scout-body');
    const time  = document.getElementById('scout-time');
    const html  = data.text
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/\n/g, '<br>');
    // CTA AI Scout "Combiné du jour" — sub-id daté pour analytics par jour
    const todaySlug = new Date().toISOString().slice(0,10).replace(/-/g, '');
    const scoutHref = buildAffiliateUrl({
      bookmaker: 'best',
      context:   'aiscout_combine_' + todaySlug,
    });
    body.innerHTML = html + `
      <div class="aff-scout-cta" style="margin-top:14px;text-align:right">
        <a class="aff-cta aff-cta--inline" target="_blank" rel="nofollow sponsored noopener" href="${scoutHref}">
          Parier le combiné du jour
        </a>
      </div>`;
    if (data.generated_at) {
      const ago = Math.floor((Date.now() - new Date(data.generated_at).getTime()) / 60000);
      time.textContent = `Généré il y a ${ago} min`;
    }
    panel.style.display = 'block';
  } catch(e) { /* silencieux */ }
}

async function forceRefresh() {
  const btn   = document.getElementById('refresh-btn');
  const icon  = document.getElementById('refresh-icon');
  const label = document.getElementById('refresh-label');

  btn.disabled = true;
  btn.style.opacity = '0.6';
  label.textContent = 'Mise à jour…';
  icon.style.animation = 'spin 1s linear infinite';

  // Ajouter l'animation CSS si absente
  if (!document.getElementById('spin-style')) {
    const s = document.createElement('style');
    s.id = 'spin-style';
    s.textContent = '@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }';
    document.head.appendChild(s);
  }

  try {
    const res = await fetch('/api/v1/refresh', { method: 'POST' });
    const json = await res.json();
    label.textContent = `✓ ${json.matchCount || 0} matchs`;
    setTimeout(() => { label.textContent = "Forcer l'actualisation"; }, 3000);
    await loadMatches();
  } catch(e) {
    label.textContent = '⚠ Erreur';
    setTimeout(() => { label.textContent = "Forcer l'actualisation"; }, 3000);
  } finally {
    btn.disabled = false;
    btn.style.opacity = '1';
    icon.style.animation = 'none';
  }
}

function updateStatusBar(meta) {
  if (!meta) return;
  if (meta.accuracy) globalAccuracy = meta.accuracy; // stocke pour colonne 2
  const label = document.getElementById('status-label');
  const info  = document.getElementById('status-meta');
  const quota = document.getElementById('quota-info');

  const statusMap = {
    'ok':           ['Serveur connecté — Données live', 'var(--green)'],
    'demo':         ['Mode démonstration', 'var(--amber)'],
    'erreur_odds':  ['Erreur API cotes — données démo', 'var(--red)'],
    'quota_epuise': ['Quota API épuisé — données en cache', 'var(--amber)'],
  };
  const [txt, col] = statusMap[meta.status] || ['Serveur actif', 'var(--text2)'];
  label.textContent = txt; label.style.color = col;

  const parts = [];
  if (meta.lastOddsUpdate) {
    const ago = Math.floor((Date.now() - new Date(meta.lastOddsUpdate).getTime()) / 60000);
    parts.push(ago < 60 ? `Cotes: il y a ${ago} min` : `Cotes: il y a ${Math.floor(ago/60)}h`);
  }
  if (meta.lastStatsUpdate) {
    const ago = Math.floor((Date.now() - new Date(meta.lastStatsUpdate).getTime()) / 3600000);
    parts.push(`Stats: il y a ${ago}h`);
  }
  info.textContent = parts.join(' · ');
  if (meta.oddsQuota) quota.textContent = `${meta.oddsQuota} req/mois restantes`;

  // Accuracy pills — style Datafoot (métriques de précision bien visibles)
  const acc = meta.accuracy;
  let pillsEl = document.getElementById('accuracy-pills');
  if (acc?.total_verified > 0) {
    const pills = [];
    if (acc.over25?.rate != null) pills.push({ label:'O2.5', rate: acc.over25.rate, n: acc.over25.sample });
    if (acc.btts?.rate   != null) pills.push({ label:'BTTS', rate: acc.btts.rate,   n: acc.btts.sample   });
    if (acc.edge?.rate   != null) pills.push({ label:'Edge', rate: acc.edge.rate,   n: acc.edge.sample   });
    if (pills.length && pillsEl) {
      pillsEl.innerHTML = `<span style="font-size:10px;color:var(--text3);font-family:var(--font-mono);">Précision backtesting (${acc.total_verified} vérifiés) :</span> ` +
        pills.map(p => {
          const col = p.rate >= 65 ? '#00c45a' : p.rate >= 55 ? '#ffa726' : '#8d9399';
          return `<span style="display:inline-flex;align-items:center;gap:4px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.08);border-radius:20px;padding:2px 10px;font-size:11px;font-family:var(--font-mono);"><span style="color:${col};font-weight:700">${p.rate}%</span><span style="color:var(--text3)">${p.label}</span></span>`;
        }).join('');
      pillsEl.style.display = 'flex';
    }
  }
}

// Démarrer l'auto-refresh quand l'onglet Matchs est chargé
