// ═══════════════════════════════════════════════════════════════════════════════
//  LOGOS ÉQUIPES — FALLBACK + LAZY RESOLVER
// ═══════════════════════════════════════════════════════════════════════════════
const _logoCache = new Map();  // teamName → url|null (session cache)

// Cascade: BSD échoue → essaie AF CDN → essaie Sofa direct → essaie search API
async function teamLogoFallback(imgEl, teamName, teamId, sofaId) {
  imgEl.onerror = null;
  // Essaie le prochain CDN disponible avant de faire un appel réseau
  if (teamId && imgEl.src.includes('bzzoiro')) {
    imgEl.onerror = (e) => teamLogoFallback(e.target, teamName, null, sofaId);
    imgEl.src = `https://media.api-sports.io/football/teams/${teamId}.png`;
    return;
  }
  if (sofaId && !imgEl.src.includes('sofascore')) {
    imgEl.onerror = (e) => teamLogoFallback(e.target, teamName, null, null);
    imgEl.src = `https://api.sofascore.app/api/v1/team/${sofaId}/image`;
    return;
  }
  // Dernier recours — recherche via backend
  if (_logoCache.has(teamName)) {
    const url = _logoCache.get(teamName);
    if (url) { imgEl.src = url; imgEl.style.display = ''; }
    else imgEl.style.display = 'none';
    return;
  }
  try {
    const r = await fetch(`/api/v1/team-logo?name=${encodeURIComponent(teamName)}`);
    const j = await r.json();
    _logoCache.set(teamName, j.url || null);
    if (j.url) { imgEl.src = j.url; imgEl.style.display = ''; }
    else imgEl.style.display = 'none';
  } catch { imgEl.style.display = 'none'; _logoCache.set(teamName, null); }
}

// Résout tous les placeholders .team-logo-pending via /api/v1/team-logo
function resolvePendingLogos() {
  const pending = document.querySelectorAll('.team-logo-pending');
  if (!pending.length) return;
  const obs = new IntersectionObserver((entries, ob) => {
    entries.forEach(async entry => {
      if (!entry.isIntersecting) return;
      const img = entry.target;
      ob.unobserve(img);
      const name = img.dataset.team;
      if (!name) return;
      if (_logoCache.has(name)) {
        const url = _logoCache.get(name);
        if (url) { img.src = url; img.style.display = ''; }
        return;
      }
      try {
        const r = await fetch(`/api/v1/team-logo?name=${encodeURIComponent(name)}`);
        const j = await r.json();
        _logoCache.set(name, j.url || null);
        if (j.url) { img.src = j.url; img.style.display = ''; }
      } catch { _logoCache.set(name, null); }
    });
  }, { rootMargin: '100px' });
  pending.forEach(img => obs.observe(img));
}

