// ═══════════════════════════════════════════════════════════════════════════════
//  LIVE TOP 5 — Recommandations paris en direct (xG momentum + edge)
// ═══════════════════════════════════════════════════════════════════════════════

let lt5Interval = null;

function buildLiveTop5Panel() {
  const panel = document.getElementById('live-top5-panel');
  if (!panel) return;
  const liveMatches = allMatches.filter(m => m.live_score && m.live_minute);
  if (!liveMatches.length) {
    panel.style.display = 'none';
    return;
  }
  panel.style.display = 'block';

  // Score chaque match live: momentum xG + edge residual
  const scored = liveMatches.map(m => {
    const xgH = m.live_xg?.home || 0;
    const xgA = m.live_xg?.away || 0;
    const scoreActual = m.live_score.split('-').map(Number);
    const goalsH = scoreActual[0] || 0;
    const goalsA = scoreActual[1] || 0;
    const xgMomentum = Math.abs(xgH - xgA);
    const underperfH = xgH - goalsH;
    const underperfA = xgA - goalsA;
    const possession = m.live_possession ? Math.abs(m.live_possession.home - m.live_possession.away) : 0;
    const shotsDelta = m.live_shots ? Math.abs(m.live_shots.home - m.live_shots.away) : 0;
    const cornersDelta = m.live_corners ? Math.abs(m.live_corners.home - m.live_corners.away) : 0;
    const edge = m.best_edge?.edge || 0;
    const score = xgMomentum * 3 + (underperfH > 1.5 || underperfA > 1.5 ? 4 : 0) + possession / 10 + shotsDelta / 3 + cornersDelta / 2 + edge * 2;
    const rec = underperfH > 1.5 ? { type: 'over', team: m.home_team, label: `Next goal ${m.home_team}` }
      : underperfA > 1.5 ? { type: 'over', team: m.away_team, label: `Next goal ${m.away_team}` }
      : xgH > 1.5 && xgA > 1.5 ? { type: 'btts', label: 'BTTS Yes' }
      : xgH + xgA > 2.5 ? { type: 'over', label: `Over 2.5 (${(xgH + xgA).toFixed(1)} xG)` }
      : xgH + xgA < 1.0 ? { type: 'under', label: `Under 2.5` }
      : { type: 'hold', label: 'Watch only' };
    return { m, score, rec, xgH, xgA, goalsH, goalsA };
  });

  scored.sort((a, b) => b.score - a.score);
  const top5 = scored.slice(0, 5);

  const body = document.getElementById('lt5-body');
  if (!body) return;

  body.innerHTML = top5.map(({ m, rec, xgH, xgA, goalsH, goalsA }) => {
    const betColor = rec.type === 'over' ? 'var(--green)' : rec.type === 'btts' ? 'var(--amber)' : rec.type === 'under' ? 'var(--blue)' : 'var(--text3)';
    const betBg = rec.type === 'over' ? 'rgba(0,230,118,0.1)' : rec.type === 'btts' ? 'rgba(255,167,38,0.1)' : rec.type === 'under' ? 'rgba(41,182,246,0.1)' : 'transparent';
    return `<div class="lt5-card" onclick="openLiveDetail('${m.id}')">
      <div class="lt5-match">${m.home_team} — ${m.away_team} <span style="color:var(--text3)">(${m.league})</span></div>
      <div class="lt5-score">${goalsH} - ${goalsA} <span style="font-size:10px;color:var(--text3)">(${m.live_minute}′)</span></div>
      <div class="lt5-bet" style="color:${betColor};background:${betBg};">${rec.label}</div>
      <div class="lt5-reason">xG ${safeFixed(xgH, 1)} - ${safeFixed(xgA, 1)}${m.live_possession ? ` · Poss ${m.live_possession.home}%-${m.live_possession.away}%` : ''}</div>
    </div>`;
  }).join('');
}

function renderLiveTop5() {
  buildLiveTop5Panel();
}

function startLiveTop5Refresh() {
  if (lt5Interval) clearInterval(lt5Interval);
  buildLiveTop5Panel();
  lt5Interval = setInterval(() => buildLiveTop5Panel(), 60000);
}

// ═══════════════════════════════════════════════════════════════════════════════
//  LIVE PREDICTIONS — Scénarios prédictifs avec probabilités (Poisson + xG + momentum)
// ═══════════════════════════════════════════════════════════════════════════════

let lpInterval = null;
let lpLastPredictions = null;

async function buildLivePredictionsPanel() {
  const panel = document.getElementById('live-pred-panel');
  const body = document.getElementById('lp-body');
  const sub = document.getElementById('lp-sub');
  if (!panel || !body) return;
  try {
    const res = await apiFetch('/api/v1/live/predictions');
    if (!res.ok) { panel.style.display = 'none'; return; }
    const data = await res.json();
    if (!data.predictions || !data.predictions.length) {
      panel.style.display = 'none';
      return;
    }
    lpLastPredictions = data;
    panel.style.display = 'block';
    if (sub) {
      sub.textContent = `${data.predictions.length} scénarios · ${data.total_live_matches} match${data.total_live_matches > 1 ? 's' : ''} live · ${data.minute_range || ''}e min`;
    }
    body.innerHTML = `<div class="lp-grid">${data.predictions.map((p, i) => {
      const tier = p.tier || 'value';
      const conf = p.confidence || 0;
      const mid = p.matchId || p.id || '';
      const scoreText = typeof p.score === 'object' ? `${p.score.home}-${p.score.away}` : (p.score || '');
      const matchLabel = `${p.home_team} — ${p.away_team}`;
      return `<div class="lp-card" onclick="openLiveDetail('${mid}')" title="Cliquez pour le détail live">
        <div class="lp-card-head">
          <span class="lp-card-icon">${p.icon || '🎯'}</span>
          <span class="lp-card-type ${tier}">${tier === 'safe' ? '🛡 SAFE' : tier === 'medium' ? '📈 MEDIUM' : '💎 VALUE'}</span>
        </div>
        <div class="lp-card-match">${matchLabel}</div>
        <div class="lp-card-score">${scoreText} <span style="color:var(--text3)">(${p.minute || '?'}e · ${p.league || ''})</span></div>
        <div class="lp-card-bet">${p.bet || p.label}</div>
        <div class="lp-card-bar"><div class="lp-card-bar-fill ${tier}" style="width:${conf}%"></div></div>
        <div class="lp-card-prob">
          <span class="prob-val">Proba: ${p.probability || 0}%</span>
          <span class="conf-val">Confiance: ${conf}%</span>
        </div>
        <div class="lp-card-reason">${p.reason || ''}</div>
      </div>`;
    }).join('')}</div>`;
  } catch(e) {
    panel.style.display = 'none';
  }
}

function startLivePredictionsRefresh() {
  if (lpInterval) clearInterval(lpInterval);
  buildLivePredictionsPanel();
  lpInterval = setInterval(() => buildLivePredictionsPanel(), 60000);
}

// ═══════════════════════════════════════════════════════════════════════════════
//  HERO ACCURACY BADGE — Preuve sociale publique (style Datafoot)
// ═══════════════════════════════════════════════════════════════════════════════
async function loadHeroAccuracy() {
  const badge = document.getElementById('hero-accuracy-badge');
  if (!badge) return;
  try {
    const res = await fetch('/api/v1/accuracy/public');
    if (!res.ok) return;
    const data = await res.json();
    const rolling = data.rolling30 || {};
    const total = rolling.sample || 0;
    if (total < 3) return;
    const over25 = rolling.over25?.rate || null;
    const btts = rolling.btts?.rate || null;
    const edge = rolling.edge?.rate || null;
    const rates = [over25, btts, edge].filter(r => r !== null);
    const pct = rates.length ? Math.round(rates.reduce((a, b) => a + b, 0) / rates.length) : 0;
    const pctEl = document.getElementById('accuracy-pct');
    const countEl = document.getElementById('accuracy-count');
    const updatedEl = document.getElementById('accuracy-updated');
    if (pctEl) pctEl.textContent = pct + '%';
    if (countEl) countEl.textContent = total;
    if (updatedEl) {
      const now = new Date();
      updatedEl.textContent = 'Mise à jour: ' + now.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' }) + ' ' + now.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
    }
    const pill = badge.querySelector('.accuracy-pill');
    if (pill) {
      pill.className = 'accuracy-pill ' + (pct >= 60 ? 'accuracy-green' : pct >= 50 ? 'accuracy-amber' : 'accuracy-red');
    }
    badge.style.display = 'flex';
  } catch {}
}

// ═══════════════════════════════════════════════════════════════════════════════
//  AFFILIATION GA — helper buildAffiliateUrl (1st-party redirect /r/ anti-AdBlock)
// ═══════════════════════════════════════════════════════════════════════════════
// Slug client-side aligné serveur (slugifyAff)
function _affSlug(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 40);
}
// Construit URL 1st-party /r/ — le serveur compose sub-id + click_id puis 302 vers bookmaker
// Params attendus:
//   bookmaker : 'winamax' | 'betclic' | ... | 'best' (auto-pick priority serveur)
//   context   : 'row_button' | 'ai_scout' | 'partners_grid' | 'modal_insights' | ...
//   match     : { id, sport_slug, league, home_team, away_team } (optionnel)
//   market    : 'over_2_5' | 'btts_yes' | '1X2_home' | ... (optionnel)
//   selection : libellé court de la sélection cliquée (optionnel)
function buildAffiliateUrl({ bookmaker, context, match, market, selection }) {
  const u = new URL('/r/', location.origin);
  u.searchParams.set('b', String(bookmaker || 'best').toLowerCase());
  u.searchParams.set('c', context || 'unknown');
  if (match) {
    if (match.id)         u.searchParams.set('mid', String(match.id));
    if (match.sport_slug || match.sport)
                          u.searchParams.set('sp',  _affSlug(match.sport_slug || match.sport));
    if (match.league)     u.searchParams.set('lg',  _affSlug(match.league));
    if (match.home_team)  u.searchParams.set('h',   _affSlug(match.home_team));
    if (match.away_team)  u.searchParams.set('a',   _affSlug(match.away_team));
  }
  if (market)    u.searchParams.set('m', _affSlug(market));
  if (selection) u.searchParams.set('s', _affSlug(selection));
  return u.toString();
}

