// ═══════════════════════════════════════════════════════════════════════════════
//  BET BUTTON — Lien affilié dynamique par match (via /r/ 1st-party)
// ═══════════════════════════════════════════════════════════════════════════════
function openBetLink(matchId) {
  const m = (typeof allMatches !== 'undefined' && Array.isArray(allMatches))
    ? allMatches.find(x => x.id === matchId)
    : null;
  const url = buildAffiliateUrl({
    bookmaker: 'best',
    context:   'row_button',
    match:     m || { id: matchId },
  });
  window.open(url, '_blank', 'noopener');
}

function renderTopMatchesGrid(matches) {
  const grid = document.getElementById('top-matches-grid');
  if (!grid) return;
  if (!matches.length) {
    grid.innerHTML = '<div class="tm-empty">Aucun match disponible pour cette période.</div>';
    return;
  }
  grid.innerHTML = matches.map(m => {
    const pick = m.topPick || {};
    const conf = pick.val || 0;
    const time = fmtKickoffTime(m.commence_time);
    const day  = fmtKickoffDate(m.commence_time, { weekday: 'short', day: 'numeric' });
    const leagueShort = (m.league || '').split(' ').map(w => w[0]).join('').slice(0, 4).toUpperCase() || '?';
    const odds = m.best_edge?.odds != null
      ? Number(m.best_edge.odds).toFixed(2)
      : m.odds?.home ? Number(m.odds.home).toFixed(2) : '—';
    const edge = m.best_edge?.edge || 0;
    const badgeText = conf >= 80
      ? `${conf}% conf.`
      : edge > 0 ? `+${safeFixed(edge, 1)}% edge`
      : pick.label || '—';
    const badgeCls = (conf < 60 && edge <= 0) ? 'ppc-badge neutral' : 'ppc-badge';
    return `<div class="ps-pill-card" onclick="goToMatch('${m.id}')">
      <div style="flex:1;min-width:0;overflow:hidden;">
        <div class="ppc-league">${leagueShort} · ${day} ${time}</div>
        <div class="ppc-teams">${m.home_team}<span style="font-weight:400;font-size:12px;color:#aaa;"> vs </span>${m.away_team}</div>
        <div class="ppc-sub">${pick.label || ''}</div>
      </div>
      <div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px;flex-shrink:0;">
        <span class="${badgeCls}">${badgeText}</span>
        <div class="ppc-odds">${odds}</div>
      </div>
    </div>`;
  }).join('');
}

function switchTopMatchesTab(tab, btn) {
  _topMatchesTab = tab;
  _topMatchesLoaded[tab] = false;
  document.querySelectorAll('.tm-tab').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  initAccueilTopMatches();
}

// ═══════════════════════════════════════════════════════════════════════════════
//  LEAGUE HUB BANNER — page Matchs
// ═══════════════════════════════════════════════════════════════════════════════
let _leagueHubCache = {};

async function initLeagueHub(oddsKey) {
  const banner = document.getElementById('league-hub-banner');
  if (!banner) return;
  if (oddsKey === 'all') { banner.style.display = 'none'; return; }
  banner.style.display = 'block';

  if (_leagueHubCache[oddsKey]) { renderLeagueHub(_leagueHubCache[oddsKey]); return; }
  document.getElementById('lh-standings').innerHTML = '<span style="color:var(--text3);font-size:12px;">Chargement…</span>';
  document.getElementById('lh-scorer').innerHTML = '';
  try {
    const r = await apiFetch(`/api/v1/league-hub/${encodeURIComponent(oddsKey)}`);
    if (!r.ok) { banner.style.display = 'none'; return; }
    const data = await r.json();
    _leagueHubCache[oddsKey] = data;
    renderLeagueHub(data);
  } catch { banner.style.display = 'none'; }
}

function renderLeagueHub(data) {
  document.getElementById('lh-league-name').textContent = data.leagueName || '—';
  // Standings
  const standEl = document.getElementById('lh-standings');
  if (!data.teams || !data.teams.length) {
    standEl.innerHTML = '<span style="color:var(--text3);font-size:12px;">Classement indisponible</span>';
  } else {
    standEl.innerHTML = data.teams.map(t => {
      const formDots = (t.form || '').split('').slice(-5).map(c =>
        `<span class="lh-form-dot ${c}"></span>`
      ).join('');
      const ppgColor = t.ppg >= 2 ? 'var(--green)' : t.ppg >= 1.3 ? 'var(--amber)' : 'var(--red)';
      return `<div class="lh-stand-row">
        <span class="lh-rank">${t.rank}</span>
        <span class="lh-name">${t.name}</span>
        <span style="display:flex;gap:3px;align-items:center;margin-right:10px;">${formDots}</span>
        <span style="font-family:var(--font-mono);font-size:11px;color:${ppgColor};">${(t.ppg||0).toFixed(2)}</span>
      </div>`;
    }).join('');
  }
  // Top scorer
  const scorerEl = document.getElementById('lh-scorer');
  if (!data.topScorer) {
    scorerEl.innerHTML = '<div class="lh-scorer-label">TOP BUTEUR</div><div style="color:var(--text3);font-size:11px;">Indisponible</div>';
  } else {
    const s = data.topScorer;
    const photoHtml = s.photo
      ? `<img class="lh-scorer-photo" src="${s.photo}" onerror="this.style.display='none'" alt="">`
      : `<div class="lh-scorer-photo" style="background:var(--bg4);"></div>`;
    scorerEl.innerHTML = `
      <div class="lh-scorer-label">TOP BUTEUR</div>
      ${photoHtml}
      <div class="lh-scorer-name">${s.name}</div>
      <div class="lh-scorer-goals">${s.goals}</div>
      <div class="lh-scorer-team">${s.team}</div>`;
  }
}

// ─── INIT ────────────────────────────────────────────────────────────────────
window.addEventListener('DOMContentLoaded', () => {
  updateNavAuthState();
  // Race guard (ParisScorebis-amc Fix A) : si user a tap "Appliquer" pendant
  // que le parse 26500 lignes complète, son showPage('matchs') a déjà posé le
  // flag ps_user_navigated. On NE le re-route PAS vers accueil — sinon écran
  // accueil + bottom-nav PLUS actif + toggle Nuit (cf. capture bug bd-6cv).
  let _navFlag = null;
  try { _navFlag = sessionStorage.getItem('ps_user_navigated'); } catch (e) {}
  if (!_navFlag) {
    showPage('accueil', document.querySelector('[data-page="accueil"]'));
  }
  initDayFilters();
  initLeagueFilters();
  buildFilterDropdowns();
  // Sport Hub — MOBILE uniquement (< 768px). Desktop = dashboard direct, pas de hub.
  wireSportHub();
  const _hub = document.getElementById('sport-hub');
  if (_hub) {
    if (!(window.matchMedia && window.matchMedia('(min-width:768px)').matches)) {
      _hub.style.display = 'flex';
      _hub.classList.remove('hub-exit');
      hydrateHubCounters();
    } else {
      _hub.style.display = 'none';
    }
  }
});

// ─── A11y : labels/noms garantis sur tous les champs (anti-warnings Chrome) ──
(function ensureA11yLabels() {
  function esc(s) { try { return CSS.escape(s); } catch (e) { return s; } }
  function fix() {
    document.querySelectorAll('input, select, textarea').forEach(el => {
      if (el.type === 'hidden') return;
      const named = (el.id && el.id.trim()) || (el.name && el.name.trim());
      if (el.id && !el.name) el.name = el.id;
      if (!named && !el.id && !el.name) {
        el.name = 'fld-' + Math.random().toString(36).slice(2, 8);
      }
      const hasAria = el.getAttribute('aria-label') || el.getAttribute('aria-labelledby');
      const hasFor  = el.id && document.querySelector('label[for="' + esc(el.id) + '"]');
      if (hasAria || hasFor || el.closest('label')) return;
      let lbl = el.getAttribute('placeholder') || el.getAttribute('title');
      const prev = el.previousElementSibling;
      if (!lbl && prev && prev.tagName === 'LABEL') lbl = prev.textContent;
      if (!lbl) lbl = el.name || el.id || el.type || 'champ';
      el.setAttribute('aria-label', String(lbl).replace(/\s+/g, ' ').trim().slice(0, 80));
    });
    document.querySelectorAll('label').forEach(l => {
      if (l.getAttribute('for') || l.querySelector('input, select, textarea')) return;
      const scope = l.parentElement || document;
      const fld = scope.querySelector('input, select, textarea');
      if (fld) {
        if (!fld.id) fld.id = 'a11y-' + Math.random().toString(36).slice(2, 8);
        l.setAttribute('for', fld.id);
      }
    });
  }
  if (document.readyState !== 'loading') fix();
  else document.addEventListener('DOMContentLoaded', fix);
  // UI dynamique (modals, bascule pages) → re-run léger idempotent
  let _t = null;
  document.addEventListener('click', () => { clearTimeout(_t); _t = setTimeout(fix, 300); }, true);
})();

