// PREDICTIONS — connecté à /api/v1/predictions
async function loadPredictions() {
  const grid = document.getElementById('pred-grid');
  grid.innerHTML = '<div style="color:#888;font-size:13px;padding:20px;">Chargement des prédictions…</div>';
  try {
    const res  = await apiFetch('/api/v1/predictions');
    if (!res.ok) throw new Error();
    const data = await res.json();
    const preds = data.predictions || [];
    if (!preds.length) { grid.innerHTML = '<div style="color:#888;padding:20px;font-size:13px;">Aucune prédiction disponible.</div>'; return; }
    grid.style.display = 'flex';
    grid.style.flexDirection = 'column';
    grid.style.gap = '8px';
    grid.innerHTML = preds.map(p => {
      const day  = fmtKickoffDate(p.commence_time, { weekday:'short', day:'numeric', month:'short' });
      const time = fmtKickoffTime(p.commence_time);
      const league = (p.league || '').split(' ').map(w => w[0]).join('').slice(0,4).toUpperCase() || '?';
      const hw = p.poisson?.homeWin ?? 0;
      const aw = p.poisson?.awayWin ?? 0;
      const dr = p.poisson?.draw ?? 0;
      const o25 = p.poisson?.over25 ?? 0;
      const btts = p.poisson?.btts ?? 0;
      const conf = p.confidence ?? 0;
      const favTeam = hw >= aw ? p.home_team : p.away_team;
      const favPct  = Math.max(hw, aw);
      const favColor = favPct >= 60 ? '#E2001A' : favPct >= 45 ? '#1A1A1A' : '#888';
      const o25Color = o25 >= 60 ? '#E2001A' : o25 >= 45 ? '#1A1A1A' : '#888';
      const confBadgeCls = conf >= 70 ? 'ppc-badge' : conf >= 50 ? 'ppc-badge' : 'ppc-badge neutral';
      const confBadgeStyle = conf >= 70 ? '' : conf >= 50 ? 'background:#1A1A1A;' : '';
      const oddHome = p.odds?.home?.toFixed(2) ?? '—';
      const oddDraw = p.odds?.draw?.toFixed(2) ?? '—';
      const oddAway = p.odds?.away?.toFixed(2) ?? '—';
      const xgStr = (p.expectedGoals?.home != null) ? `xG ${p.expectedGoals.home}–${p.expectedGoals.away}` : '';
      return `<div class="ps-pill-card">
        <div style="flex:1;min-width:0;overflow:hidden;">
          <div class="ppc-league">${league} · ${day} ${time}</div>
          <div class="ppc-teams">${p.home_team}<span style="font-weight:400;font-size:12px;color:#aaa;"> vs </span>${p.away_team}</div>
          <div class="ppc-sub">${p.recommendation ? '→ ' + p.recommendation : (xgStr || '')}</div>
        </div>
        <div style="display:flex;flex-direction:column;align-items:flex-end;gap:5px;flex-shrink:0;min-width:110px;">
          <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;justify-content:flex-end;">
            <span style="font-size:11px;font-weight:700;color:${favColor};">${favTeam.split(' ')[0]} ${favPct}%</span>
            <span style="font-size:11px;font-weight:700;color:${o25Color};">O2.5 ${o25}%</span>
          </div>
          <span class="${confBadgeCls}" style="${confBadgeStyle}">Conf. ${conf}%</span>
          <div style="display:flex;gap:8px;align-items:flex-end;">
            <div style="text-align:center;"><div class="ppc-odds" style="font-size:16px;">${oddHome}</div><div style="font-size:9px;color:#aaa;margin-top:1px;">1</div></div>
            <div style="text-align:center;"><div class="ppc-odds" style="font-size:16px;">${oddDraw}</div><div style="font-size:9px;color:#aaa;margin-top:1px;">N</div></div>
            <div style="text-align:center;"><div class="ppc-odds" style="font-size:16px;">${oddAway}</div><div style="font-size:9px;color:#aaa;margin-top:1px;">2</div></div>
          </div>
          ${xgStr && p.recommendation ? `<div style="font-size:10px;color:#aaa;">${xgStr}</div>` : ''}
        </div>
      </div>`;
    }).join('');
  } catch(e) {
    grid.innerHTML = '<div style="color:#888;padding:20px;font-size:13px;">⚠ Lancez node server.js pour charger les prédictions.</div>';
  }
}

