// ── AI Tipsters — synchro avec STRATEGIES de server.js ────────────────────────
const STRATEGIES_UI = [
  { key: 'BTTS_YES',        label: 'BTTS Oui',              icon: '', tipster: 'L\'Artilleur' },
  { key: 'OVER_2_5',        label: '+2.5 buts',             icon: '', tipster: 'Le Foudroyeur' },
  { key: 'OVER_1_5',        label: '+1.5 buts',             icon: '', tipster: 'Le Prudent' },
  { key: 'UNDER_2_5',       label: '-2.5 buts',             icon: '', tipster: 'Le Gardien' },
  { key: 'HOME_WIN',        label: 'Victoire Domicile',     icon: '', tipster: 'Le Localier' },
  { key: 'AWAY_WIN',        label: 'Victoire Extérieur',    icon: '', tipster: 'L\'Aventurier' },
  { key: 'DRAW',            label: 'Match Nul',             icon: '', tipster: 'Le Diplomate' },
  { key: 'CS_00',           label: 'Score 0-0',             icon: '', tipster: 'Le Sceptique' },
  { key: 'ANGLE_CORNERS',   label: 'Angle Corners',         icon: '', tipster: 'Le Géomètre' },
  { key: 'OVER_6_5_CORNERS', label: 'Over 6.5 Corners',     icon: '', tipster: 'Le Corneriste' },
  { key: 'VERROU_TACTIQUE', label: 'Verrou Tactique (U3.5)',icon: '', tipster: 'Le Verrou' },
  { key: 'GOLDEN_PPG_GAP',  label: 'Golden PPG Gap',        icon: '', tipster: 'L\'Éclaireur' },
  { key: 'DC_HOME',           label: 'Double Chance 1X',      icon: '', tipster: 'Le Couvreur' },
  { key: 'DC_AWAY',           label: 'Double Chance X2',      icon: '', tipster: 'L\'Assureur' },
  { key: 'HT_HOME_FT_HOME',  label: 'Mi-Temps Victoire Dom.', icon: '', tipster: 'Le Sprint' },
  { key: 'HT_UNDER_FT_OVER', label: 'Explosion 2e Mi-Temps',  icon: '', tipster: 'Le Dynamiteur' },
  { key: 'STEAM_DETECTED',   label: 'Steam Multi-Book',       icon: '', tipster: 'Le Sharp' },
];
let currentStrategies = ['BTTS_YES'];
let strategiesPageInitialized = false;
let activeStratLeague = '';
let activeStratConf = 50;

function onStratLeagueChange(val) {
  activeStratLeague = val;
  loadStrategies();
}

function onStratConfChange(val) {
  activeStratConf = parseInt(val) || 50;
  const el = document.getElementById('strat-conf-val');
  if (el) el.textContent = activeStratConf + '%';
  loadStrategies();
}

function resetStratFilters() {
  activeStratLeague = '';
  activeStratConf = 50;
  const sel = document.getElementById('strat-league-select');
  if (sel) sel.value = '';
  const slider = document.getElementById('strat-conf-slider');
  if (slider) slider.value = '50';
  const val = document.getElementById('strat-conf-val');
  if (val) val.textContent = '50%';
  loadStrategies();
}

function openStratHelp() {
  const el = document.getElementById('strat-help-overlay');
  if (el) { el.style.display = 'flex'; document.body.style.overflow = 'hidden'; }
}
function closeStratHelp() {
  const el = document.getElementById('strat-help-overlay');
  if (el) { el.style.display = 'none'; document.body.style.overflow = ''; }
}

function initStrategiesPage() {
  if (strategiesPageInitialized) { loadStrategies(); return; }
  const pills = document.getElementById('strategy-pills');
  pills.innerHTML = STRATEGIES_UI.map(s => {
    const tp = s.tipster ? `<span style="font-size:12px;font-weight:700;display:block;line-height:1.3;">${s.tipster}</span>` : '';
    const sub = `<span style="font-size:10px;opacity:0.65;display:block;">${s.label}</span>`;
    return `<div class="strategy-pill${currentStrategies.includes(s.key) ? ' active' : ''}" data-key="${s.key}" onclick="toggleStrategy('${s.key}')">${tp}${sub}</div>`;
  }).join('');
  const _ssel = document.getElementById('strat-mob');
  if (_ssel) {
    _ssel.innerHTML = STRATEGIES_UI.map(s =>
      `<option value="${s.key}"${s.key === currentStrategies[0] ? ' selected' : ''}>${s.tipster ? s.tipster + ' — ' : ''}${s.label}</option>`
    ).join('');
  }
  strategiesPageInitialized = true;
  loadStrategies();
}

function toggleStrategy(key) {
  const i = currentStrategies.indexOf(key);
  if (i === -1) {
    currentStrategies.push(key);
  } else if (currentStrategies.length > 1) {
    currentStrategies.splice(i, 1);
  }
  document.querySelectorAll('.strategy-pill').forEach(p =>
    p.classList.toggle('active', currentStrategies.includes(p.dataset.key))
  );
  _stratSyncBadge();
  loadStrategies();
}

function selectStrategy(key) {
  // Called from mobile <select> — single-select
  currentStrategies = [key];
  document.querySelectorAll('.strategy-pill').forEach(p => p.classList.toggle('active', p.dataset.key === key));
  const _ssel = document.getElementById('strat-mob');
  if (_ssel && _ssel.value !== key) _ssel.value = key;
  _stratSyncBadge();
  loadStrategies();
}

function _stratSyncBadge() {
  const n = currentStrategies.length;
  const badge = document.getElementById('strat-multi-info');
  if (!badge) return;
  if (n <= 1) { badge.style.display = 'none'; return; }
  const labels = currentStrategies.map(k => STRATEGIES_UI.find(s => s.key === k)?.tipster || k).join(' · ');
  badge.style.display = 'block';
  badge.innerHTML = `<span style="background:rgba(237,28,36,0.10);border:1px solid rgba(237,28,36,0.25);border-radius:20px;padding:3px 10px;color:#E2001A;font-weight:700;font-size:11px;">${n} stratégies actives</span> <span style="margin-left:6px;color:var(--text3);font-size:11px;">${labels}</span>`;
}

// Filtre Famille (mobile Top Stratégies) — pilote état plat + masque pills hors famille
const PS_STRAT_FAMILY = {
  buts:    ['BTTS_YES', 'OVER_2_5', 'OVER_1_5', 'UNDER_2_5', 'CS_00', 'VERROU_TACTIQUE'],
  issue:   ['HOME_WIN', 'AWAY_WIN', 'DRAW', 'DC_HOME', 'DC_AWAY', 'GOLDEN_PPG_GAP'],
  corners: ['ANGLE_CORNERS', 'OVER_6_5_CORNERS'],
  mitemps: ['HT_HOME_FT_HOME', 'HT_UNDER_FT_OVER']
};
function psStratFamily(val) {
  window.psStrategyFilters = window.psStrategyFilters || {};
  window.psStrategyFilters.stratFamily = val;
  const keys = (val && val !== 'all') ? (PS_STRAT_FAMILY[val] || []) : null;
  const pills = document.querySelectorAll('#strategy-pills .strategy-pill');
  pills.forEach(p => { p.style.display = (!keys || keys.includes(p.dataset.key)) ? '' : 'none'; });
  if (keys) {
    currentStrategies = currentStrategies.filter(k => keys.includes(k));
    if (!currentStrategies.length) {
      const first = [...pills].find(p => p.style.display !== 'none');
      if (first) currentStrategies = [first.dataset.key];
    }
    document.querySelectorAll('.strategy-pill').forEach(p =>
      p.classList.toggle('active', currentStrategies.includes(p.dataset.key))
    );
    _stratSyncBadge();
    loadStrategies();
  }
}

function renderStrategySkeletons(n = 6) {
  const grid = document.getElementById('strategy-grid');
  grid.innerHTML = Array.from({ length: n }).map(() => `
    <div class="skel-card">
      <div class="skel-line short"></div>
      <div class="skel-line mid"></div>
      <div class="skel-line tall"></div>
      <div class="skel-line bar"></div>
      <div class="skel-line short"></div>
    </div>
  `).join('');
}

// Seuils de confiance adaptatifs par stratégie (marchés à faible probabilité naturelle)
const CONF_THRESHOLDS = {
  CS_00:           { high: 25, mid: 12 },  // prob naturelle 5-15%
  DRAW:            { high: 35, mid: 25 },  // prob naturelle 15-30%
  UNDER_2_5:       { high: 70, mid: 55 },
  VERROU_TACTIQUE: { high: 72, mid: 58 },
  DC_AWAY:         { high: 65, mid: 50 },  // X2 naturellement plus bas que 1X
  HT_HOME_FT_HOME: { high: 68, mid: 55 },  // proxy homeWin filtré, plage effective 60-85%
  HT_UNDER_FT_OVER:{ high: 65, mid: 50 },  // moyenne over25+under15, signal "match qui s'embrase"
};
function confClass(pct, stratKey) {
  const t = CONF_THRESHOLDS[stratKey] || { high: 75, mid: 60 };
  return pct > t.high ? 'high' : pct >= t.mid ? 'mid' : 'low';
}

// Map strategy key → CSS badge color class
function strategyBadgeClass(key) {
  const m = {
    BTTS_YES: 'btts', OVER_2_5: 'over25', OVER_1_5: 'over15', UNDER_2_5: 'under25',
    VERROU_TACTIQUE: 'under35', HOME_WIN: 'home', AWAY_WIN: 'away', DRAW: 'draw',
    CS_00: 'cs00', ANGLE_CORNERS: 'corners', OVER_6_5_CORNERS: 'corners65', GOLDEN_PPG_GAP: 'ppggap',
    DC_HOME: 'dc', DC_AWAY: 'dc', HT_HOME_FT_HOME: 'hthome', HT_UNDER_FT_OVER: 'htunder',
  };
  return m[key] || 'draw';
}

// Avatar color per strategy badge class
function strategyAvatarColor(badgeCls) {
  const m = { btts:'#00c853', over25:'#ff8f00', over15:'#f9a825', under25:'#0277bd', under35:'#0288d1', home:'#7b1fa2', away:'#c62828', draw:'#616161', cs00:'#546e7a', corners:'#00838f', corners65:'#006064', ppggap:'#f9a825', dc:'#64dd17', hthome:'#ad1457', htunder:'#d84315' };
  return m[badgeCls] || '#616161';
}

// Generate avatar HTML: circle with initials + strategy color
function tipsterAvatar(name, badgeCls) {
  if (!name) return '';
  const initials = name.replace(/^L'|^Le |^La /, '').split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
  const bg = strategyAvatarColor(badgeCls);
  return `<span class="tipster-avatar" style="background:${bg};">${initials}</span>`;
}

function _renderStratCard(m, key) {
  const dateStr = fmtKickoffDate(m.commence_time, { weekday:'short', day:'numeric', month:'short' }) + ' · ' + fmtKickoffTime(m.commence_time);
  const odd = m.odds != null ? Number(m.odds).toFixed(2) : m.implied_odds != null ? `~${Number(m.implied_odds).toFixed(2)}` : '—';
  const edge = m.best_edge?.edge;
  const edgeStr = edge != null ? (edge >= 0 ? '+' : '') + safeFixed(edge, 1) + '%' : null;
  const vi = m.valueIndex ?? 0;
  const ci = m.confidenceIndex ?? m.confidence;
  const confColor = ci >= 80 ? '#E2001A' : ci >= 60 ? '#1A1A1A' : '#888';
  const viColor   = vi >= 70 ? '#E2001A' : vi >= 40 ? '#1A1A1A' : '#888';
  const ui = STRATEGIES_UI.find(s => s.key === key);
  const leagueShort = (m.league || '').split(' ').map(w => w[0]).join('').slice(0,4).toUpperCase() || '?';
  const xg = m.expectedGoals ? `xG ${safeFixed(m.expectedGoals.home, 1)}-${safeFixed(m.expectedGoals.away, 1)}` : '';
  return `<div class="ps-pill-card" onclick="openInsightsById('${m.id}')">
    <div style="flex:1;min-width:0;overflow:hidden;">
      <div class="ppc-league">${leagueShort} · ${dateStr}</div>
      <div class="ppc-teams">${m.home_team}<span style="font-weight:400;font-size:12px;color:#aaa;"> vs </span>${m.away_team}</div>
      <div class="ppc-sub">${ui?.label || key}${xg ? ' · ' + xg : ''}${_modelSrcBadge(m.model_source)}</div>
    </div>
    <div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;flex-shrink:0;">
      <div style="display:flex;gap:10px;align-items:baseline;">
        <div style="text-align:center;">
          <div style="font-size:9px;color:#888;text-transform:uppercase;letter-spacing:.05em;">Conf.</div>
          <div style="font-family:var(--font-head);font-size:20px;font-weight:900;color:${confColor};line-height:1;">${ci}%</div>
        </div>
        <div style="text-align:center;">
          <div style="font-size:9px;color:#888;text-transform:uppercase;letter-spacing:.05em;">Value</div>
          <div style="font-family:var(--font-head);font-size:20px;font-weight:900;color:${viColor};line-height:1;">${vi}%</div>
        </div>
      </div>
      <div style="display:flex;align-items:center;gap:6px;">
        ${edgeStr ? `<span class="ppc-badge">${edgeStr}</span>` : ''}
        <div class="ppc-odds">${odd}</div>
      </div>
      <div style="display:flex;gap:4px;margin-top:2px;">
        <button onclick="event.stopPropagation();openInsightsById('${m.id}')" style="background:#F4F4F4;border:none;border-radius:4px;padding:4px 10px;font-size:11px;color:#1A1A1A;cursor:pointer;font-weight:600;">Stats</button>
        <button onclick="event.stopPropagation();openPowerScore('${m.id}')" style="background:#1A1A1A;border:none;border-radius:4px;padding:4px 10px;font-size:11px;color:#fff;cursor:pointer;font-weight:600;">⚡ PS</button>
      </div>
    </div>
  </div>`;
}

async function loadStrategies() {
  if (currentStrategies.length === 1) return loadStrategy(currentStrategies[0]);
  const grid = document.getElementById('strategy-grid');
  const meta = document.getElementById('strategy-meta');
  meta.innerHTML = '';
  loadAccaPanel(currentStrategies[0]);
  renderStrategySkeletons();
  try {
    const leagueParam = activeStratLeague ? `&league=${encodeURIComponent(activeStratLeague)}` : '';
    const results = await Promise.all(currentStrategies.map(key =>
      apiFetch(`/api/v1/top-strategy?type=${encodeURIComponent(key)}&limit=12&minConfidence=${activeStratConf}${leagueParam}`)
        .then(r => r.ok ? r.json() : { matches: [] })
        .catch(() => ({ matches: [] }))
    ));
    const seen = new Map();
    results.forEach((data, idx) => {
      const key = currentStrategies[idx];
      (data.matches || []).forEach(m => {
        const ci = m.confidenceIndex ?? m.confidence ?? 0;
        const prev = seen.get(m.id);
        if (!prev || ci > (prev.confidenceIndex ?? prev.confidence ?? 0)) {
          seen.set(m.id, { ...m, _stratKey: key });
        }
      });
    });
    const matches = [...seen.values()].sort((a, b) => {
      const ca = a.confidenceIndex ?? a.confidence ?? 0;
      const cb = b.confidenceIndex ?? b.confidence ?? 0;
      return cb - ca;
    });
    const leagueLbl = activeStratLeague ? ` · ${document.getElementById('strat-league-select')?.selectedOptions[0]?.text || activeStratLeague}` : '';
    const labels = currentStrategies.map(k => STRATEGIES_UI.find(s => s.key === k)?.label || k).join(' + ');
    meta.innerHTML = `Stratégies : <strong>${labels}</strong> · ${matches.length} match${matches.length !== 1 ? 's' : ''} avec confiance ≥ ${activeStratConf}%${leagueLbl} · <span style="color:var(--text3)">Trié par confiance ↓</span>`;
    if (!matches.length) {
      grid.innerHTML = `<div class="strat-empty"><div class="ico">🔍</div>Aucun match avec une confiance suffisante pour ces stratégies.<br><span style="color:var(--text3);font-size:12px;">Essayez d'autres stratégies ou revenez plus tard.</span></div>`;
      return;
    }
    grid.innerHTML = matches.map(m => _renderStratCard(m, m._stratKey || currentStrategies[0])).join('');
  } catch (e) {
    grid.innerHTML = `<div class="strat-empty"><div class="ico">⚠</div>Erreur lors du chargement des stratégies multiples.</div>`;
  }
}

async function loadAccaPanel(key) {
  const panel = document.getElementById('acca-panel');
  if (!panel) return;
  panel.style.display = 'none';
  try {
    const res = await apiFetch(`/api/v1/acca?strategy=${encodeURIComponent(key)}&size=3`);
    if (!res.ok) return;
    const d = await res.json();
    if (!d.matches || d.matches.length < 2) return;
    const matchRows = d.matches.map(m => {
      const timeStr = fmtKickoffTime(m.commence_time);
      return `<div class="acca-match">
        <span class="acca-match-teams">${m.home_team} <span style="color:var(--text3);font-weight:400">vs</span> ${m.away_team}</span>
        <span style="display:flex;gap:12px;align-items:center;">
          <span style="color:var(--text3);font-size:11px;">${timeStr}</span>
          <span class="acca-match-prob">${m.prob}%</span>
        </span>
      </div>`;
    }).join('');
    panel.innerHTML = `
      <div class="acca-header">
        <div>
          <div class="acca-title">COMBINE DU JOUR - ${d.label.toUpperCase()}</div>
          <div class="acca-meta">${d.size} matchs · confiance combinée ${d.combinedProb}%</div>
        </div>
      </div>
      <div class="acca-odds">${safeFixed(d.combinedOdds, 2)}<span>cote combinée estimée</span></div>
      ${matchRows}
      <div style="margin-top:10px;font-size:10px;color:var(--text3);">Pari mathématique - responsabilité individuelle. Cotes estimées via modèle probabiliste.</div>
    `;
    panel.style.display = 'block';
  } catch {}
}

async function loadStrategy(key) {
  const grid = document.getElementById('strategy-grid');
  const meta = document.getElementById('strategy-meta');
  meta.innerHTML = '';
  loadAccaPanel(key);
  renderStrategySkeletons();
  try {
    const leagueParam = activeStratLeague ? `&league=${encodeURIComponent(activeStratLeague)}` : '';
    const res = await apiFetch(`/api/v1/top-strategy?type=${encodeURIComponent(key)}&limit=12&minConfidence=${activeStratConf}${leagueParam}`);
    if (!res.ok) {
      grid.innerHTML = `<div class="strat-empty"><div class="ico">⚠️</div>Impossible de charger les matchs (HTTP ${res.status}).</div>`;
      return;
    }
    const data = await res.json();
    const matches = data.matches || [];
    const leagueLbl = activeStratLeague ? ` · ${document.getElementById('strat-league-select')?.selectedOptions[0]?.text || activeStratLeague}` : '';
    meta.innerHTML = `Stratégie : <strong>${data.label || key}</strong> · ${matches.length} match${matches.length > 1 ? 's' : ''} avec confiance ≥ ${activeStratConf}%${leagueLbl} · <span style="color:var(--text3)">Trié par confiance ↓</span>`;

    if (!matches.length) {
      grid.innerHTML = `<div class="strat-empty"><div class="ico">🔍</div>Aucun match avec une confiance suffisante pour cette stratégie aujourd'hui.<br><span style="color:var(--text3);font-size:12px;">Essayez une autre stratégie ou revenez plus tard.</span></div>`;
      return;
    }

    grid.innerHTML = matches.map(m => _renderStratCard(m, key)).join('');
  } catch (e) {
    grid.innerHTML = `<div class="strat-empty"><div class="ico">⚠</div>Lancez <code style="color:var(--text2);">node server.js</code> pour charger les stratégies.</div>`;
  }
}

async function openInsightsById(matchId) {
  if (typeof openInsights !== 'function') return;
  if (!allMatches || !allMatches.find(x => x.id === matchId)) {
    if (!matchesLoaded) { matchesLoaded = true; await loadMatches(); }
  }
  if (!allMatches?.find(x => x.id === matchId)) {
    console.warn('[openInsightsById] match non trouvé après chargement :', matchId);
    return;
  }
  openInsights(matchId);
}

