  const planWrap = document.getElementById('paris-plan-table-wrap');
  const clvWrap = document.getElementById('paris-clv-table-wrap');
  const filtersEl = document.getElementById('paris-filters');
  betsWrap.style.display = (tab === 'open' || tab === 'settled') ? 'block' : 'none';
  cashWrap.style.display = (tab === 'cash') ? 'block' : 'none';
