// bd vl02 — Alertes SSE live edge math toast UI
// Render top-right stack (auto-create container si absent) + auto-dismiss 8s + click-dismiss.
function _showAlertToast(d) {
  if (!d || !d.type) return;
  let stack = document.getElementById('alert-toast-stack');
  if (!stack) {
    stack = document.createElement('div');
    stack.id = 'alert-toast-stack';
    stack.className = 'alert-toast-stack';
    document.body.appendChild(stack);
  }
  const pl = d.payload || {};
  let icon = 'ALERT', title = 'Alerte live', msg = '', typeCls = '';
  if (d.type === 'favorite_trap') {
    icon = 'PIEGE'; title = 'Favori en deficit'; typeCls = 'type-trap';
    const fav = pl.favorite_team || 'Favori';
    const opp = pl.opponent_team || 'Adversaire';
    const edge = pl.best_edge_pct != null ? ' (edge pre-match ' + (pl.best_edge_pct > 0 ? '+' : '') + Number(pl.best_edge_pct).toFixed(1) + '%)' : '';
    msg = fav + ' mene par ' + opp + ' — score ' + (pl.score || '?') + edge;
  } else if (d.type === 'goal_flood') {
    icon = 'BUTS'; title = 'Goal flood 15min'; typeCls = 'type-flood';
    msg = (pl.goals_15min || '3+') + ' buts en 15min — ' + (pl.home_team || 'DOM') + ' vs ' + (pl.away_team || 'EXT') + ' score ' + (pl.score || '?');
  } else {
    title = String(d.type).toUpperCase();
    msg = JSON.stringify(pl).slice(0, 100);
  }
  const t = document.createElement('div');
  t.className = 'alert-toast ' + typeCls;
  t.innerHTML =
    '<div class="alert-toast-bar"></div>' +
    '<div class="alert-toast-body">' +
      '<div class="alert-toast-head">' +
        '<span class="alert-toast-icon">[' + icon + ']</span>' +
        '<span class="alert-toast-title">' + title + '</span>' +
      '</div>' +
      '<div class="alert-toast-msg"></div>' +
      '<div class="alert-toast-meta">minute ' + (pl.minute != null ? pl.minute : '?') + ' • ' + new Date(d.ts || Date.now()).toLocaleTimeString('fr-FR') + '</div>' +
    '</div>';
  // Inject msg en safe text (pas innerHTML pour éviter XSS noms teams)
  t.querySelector('.alert-toast-msg').textContent = msg;
  const dismiss = () => {
    if (t.classList.contains('dismissing')) return;
    t.classList.add('dismissing');
    setTimeout(() => { if (t.parentNode) t.parentNode.removeChild(t); }, 280);
  };
  t.addEventListener('click', dismiss);
  stack.appendChild(t);
  setTimeout(dismiss, 8000);
  // Cap stack à 5 toasts max (drop le plus ancien si >5)
  while (stack.children.length > 5) {
    const oldest = stack.firstElementChild;
    if (oldest && oldest !== t) oldest.parentNode.removeChild(oldest); else break;
  }
}

// bd o6s — Load CLV mini-card sticky footer page Mes Paris
// Pick top strategy active (highest n_bets last 30d) + summary KPIs.
// Affiche/hide selon donnée dispo. Click déjà géré inline onclick HTML.
async function loadCLVMiniCard() {
  const card = document.getElementById('clv-mini-card');
  if (!card) return;
  try {
    const res = await apiFetch('/api/v1/analytics/clv-by-strategy?period=30d');
    if (!res.ok) { card.style.display = 'none'; return; }
    const data = await res.json();
    const rows = (data && data.data) || [];
    if (!rows.length) { card.style.display = 'none'; return; }
    // Pick top strategy par n_bets (proxy "active strategy")
    const top = rows.slice().sort((a, b) => (b.n_bets || 0) - (a.n_bets || 0))[0];
    if (!top || (top.n_bets || 0) === 0) { card.style.display = 'none'; return; }
    const strat = top.strategy || '—';
    const clv = top.clv_mean_pct;
    const nBets = top.n_bets || 0;
    let avgCls = 'flat', verdictCls = 'flat', verdictLbl = 'Flat';
    if (clv != null && Number.isFinite(clv)) {
      if (clv >= 2) { avgCls = 'pos'; verdictCls = 'sharp'; verdictLbl = 'Sharp'; }
      else if (clv <= -2) { avgCls = 'neg'; verdictCls = 'square'; verdictLbl = 'Square'; }
      else { avgCls = 'flat'; verdictCls = 'flat'; verdictLbl = 'Flat'; }
    } else {
      avgCls = ''; verdictCls = 'empty'; verdictLbl = 'N/A';
    }
    const avgStr = (clv == null || !Number.isFinite(clv)) ? '—' : (clv > 0 ? '+' : '') + clv.toFixed(1) + '%';
    const setText = (id, t, cls) => {
      const el = document.getElementById(id); if (!el) return;
      el.textContent = t;
      if (cls != null) el.className = el.className.replace(/\bpos|neg|flat|sharp|square|empty\b/g, '').trim() + ' ' + cls;
    };
    setText('clv-mc-strategy', strat, null);
    const avgEl = document.getElementById('clv-mc-avg');
    if (avgEl) { avgEl.textContent = avgStr; avgEl.className = 'clv-mc-kpi-val ' + (avgCls || ''); }
    setText('clv-mc-sample', String(nBets), null);
    const vEl = document.getElementById('clv-mc-verdict');
    if (vEl) { vEl.textContent = verdictLbl; vEl.className = 'clv-mc-verdict ' + verdictCls; }
    card.style.display = '';
  } catch (_) { card.style.display = 'none'; }
}

// bd cty — Load CLV by strategy 30j (Closing Line Value)
async function loadCLVByStrategy() {
  const tbody = document.getElementById('paris-clv-tbody');
  const empty = document.getElementById('paris-clv-empty');
  const meta = document.getElementById('paris-clv-meta');
  if (!tbody) return;
  const period = (document.getElementById('paris-clv-period') || {}).value || '30d';
  tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:var(--text3);">Chargement…</td></tr>';
  try {
    const res = await apiFetch('/api/v1/analytics/clv-by-strategy?period=' + encodeURIComponent(period));
    if (!res.ok) {
      tbody.innerHTML = '';
      if (empty) { empty.style.display = 'block'; empty.firstChild && (empty.firstChild.textContent = 'Erreur de chargement CLV (HTTP ' + res.status + ').'); }
      return;
    }
    const data = await res.json();
    const rows = data.data || [];
    if (meta) meta.textContent = `${rows.length} stratégies · ${data.period_days}j · ${data.elapsed_ms}ms`;
    if (!rows.length) {
      tbody.innerHTML = '';
      if (empty) { empty.style.display = 'block'; }
      return;
    }
    if (empty) empty.style.display = 'none';
    tbody.innerHTML = rows.map(r => {
      const clv = r.clv_mean_pct;
      const clvCls = clv == null ? '' : (clv >= 2 ? 'bet-pl-pos' : clv <= -2 ? 'bet-pl-neg' : '');
      const clvColor = clv == null ? 'var(--text3)' : (clv >= 2 ? 'var(--green)' : clv <= -2 ? 'var(--red)' : 'var(--amber)');
      const clvStr = clv == null ? '—' : (clv > 0 ? '+' : '') + clv.toFixed(2) + '%';
      const medStr = r.clv_median_pct == null ? '—' : (r.clv_median_pct > 0 ? '+' : '') + r.clv_median_pct.toFixed(2) + '%';
      const wr = r.win_rate_pct == null ? '—' : r.win_rate_pct.toFixed(1) + '%';
      const roi = r.roi_pct == null ? '—' : ((r.roi_pct - 100) > 0 ? '+' : '') + (r.roi_pct - 100).toFixed(1) + '%';
      const spark = renderCLVSparkline(r.sparkline || []);
      return `<tr>
        <td style="font-weight:700;font-family:var(--font-mono);font-size:11px;letter-spacing:.04em;">${escapeHtml(r.strategy)}</td>
        <td style="font-family:var(--font-mono);">${r.n_bets}</td>
        <td class="${clvCls}" style="color:${clvColor};font-weight:700;font-family:var(--font-mono);">${clvStr}</td>
        <td style="font-family:var(--font-mono);color:var(--text2);">${medStr}</td>
        <td style="font-family:var(--font-mono);">${wr}</td>
        <td style="font-family:var(--font-mono);">${roi}</td>
        <td>${spark}</td>
      </tr>`;
    }).join('');
  } catch (e) {
    tbody.innerHTML = '';
    if (empty) empty.style.display = 'block';
  }
}

// Mini sparkline SVG inline (zéro dep) pour tendance CLV
function renderCLVSparkline(points) {
  if (!points || points.length < 2) return '<span style="color:var(--text3);font-size:10px;">—</span>';
  const w = 80, h = 22, pad = 2;
  const vals = points.map(p => p.clv);
  const min = Math.min(...vals, 0);
  const max = Math.max(...vals, 0);
  const range = (max - min) || 1;
  const path = points.map((p, i) => {
    const x = pad + (i * (w - 2 * pad)) / (points.length - 1);
    const y = h - pad - ((p.clv - min) / range) * (h - 2 * pad);
    return (i === 0 ? 'M' : 'L') + x.toFixed(1) + ',' + y.toFixed(1);
  }).join(' ');
  const last = vals[vals.length - 1];
  const color = last >= 2 ? '#00e676' : last <= -2 ? '#ff4d4d' : '#ffa726';
  // Ligne de référence 0
  const yZero = h - pad - ((0 - min) / range) * (h - 2 * pad);
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}" style="vertical-align:middle;">
    <line x1="${pad}" y1="${yZero.toFixed(1)}" x2="${w - pad}" y2="${yZero.toFixed(1)}" stroke="rgba(255,255,255,0.1)" stroke-dasharray="2,2" stroke-width="0.8"/>
    <path d="${path}" stroke="${color}" stroke-width="1.5" fill="none" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
}

function applyParisFilters() {
  parisState.filters = {
    status: document.getElementById('paris-f-status').value,
    bookmaker: document.getElementById('paris-f-bookmaker').value.trim(),
    sport: document.getElementById('paris-f-sport').value,
    market: document.getElementById('paris-f-market').value.trim(),
    team: document.getElementById('paris-f-team').value.trim(),
    from: document.getElementById('paris-f-from').value,
    to: document.getElementById('paris-f-to').value,
  };
  loadUserBets();
}

function buildBetsQueryString() {
  const f = parisState.filters || {};
  const parts = [];
  if (f.status) parts.push('status=' + encodeURIComponent(f.status));
  if (f.bookmaker) parts.push('bookmaker=' + encodeURIComponent(f.bookmaker));
  if (f.sport) parts.push('sport=' + encodeURIComponent(f.sport));
  if (f.market) parts.push('market=' + encodeURIComponent(f.market));
  if (f.team) parts.push('team=' + encodeURIComponent(f.team));
  if (f.from) parts.push('from=' + encodeURIComponent(f.from));
  if (f.to) parts.push('to=' + encodeURIComponent(f.to));
  parts.push('limit=500');
  return parts.join('&');
}

const SPORT_EMOJI = {
  football: '⚽', basketball: '🏀', tennis: '🎾', rugby: '🏉', hockey: '🏒',
  baseball: '⚾', mma: '🥊', boxe: '🥊', cyclisme: '🚴', formula1: '🏎️',
  volleyball: '🏐', handball: '🤾', esports: '🎮', golf: '⛳', autre: '🏆',
};

async function loadUserBets() {
  try {
    const res = await apiFetch('/api/v1/bets?' + buildBetsQueryString());
    if (!res.ok) return;
    const data = await res.json();
    parisState.lastBets = data.bets || [];
    renderUserBetsTable();
  } catch (e) { /* AUTH_REQUIRED already opened modal */ }
}

function renderUserBetsTable() {
  const tbody = document.getElementById('paris-bets-tbody');
  const emptyEl = document.getElementById('paris-empty');
  if (!tbody) return;
  const filtered = parisState.lastBets.filter(b => parisState.tab === 'open' ? b.status === 'pending' : b.status !== 'pending');
  if (!filtered.length) { tbody.innerHTML = ''; emptyEl.style.display = 'block'; return; }
  emptyEl.style.display = 'none';
  const now = Math.floor(Date.now() / 1000);
  tbody.innerHTML = filtered.map(b => {
    const rawTs = b.commence_time || (b.created_at ? b.created_at * 1000 : null);
    const dateStr = fmtKickoffDate(rawTs, { day:'numeric', month:'short', year:'2-digit' }) + ' ' + fmtKickoffTime(rawTs);
    const match = (b.home_team || '?') + ' — ' + (b.away_team || '?');
    const pl = (b.payout_cents !== null && b.payout_cents !== undefined)
      ? `<span class="${b.payout_cents >= 0 ? 'bet-pl-pos' : 'bet-pl-neg'}">${eurFmt(b.payout_cents / 100)}</span>`
      : '<span style="color:var(--text3);">—</span>';
    const settleable = b.status === 'pending' && b.match_id && b.commence_time && (new Date(b.commence_time).getTime() / 1000 + 2 * 3600) < now;
    const rowCls = settleable ? 'bet-row-suggest' : '';
    const actions = b.status === 'pending'
      ? `<button onclick="openSettleModal(${b.id})">Régler</button><button class="danger" onclick="deleteBet(${b.id})">×</button>`
      : `<button class="danger" onclick="deleteBet(${b.id})">×</button>`;
    const sport = b.sport || 'football';
    const sportTag = `<span title="${escapeHtml(sport)}">${SPORT_EMOJI[sport] || '🏆'}</span>`;
    const sourceTag = b.source === 'import' ? ' <span style="font-size:9px;background:rgba(41,182,246,.15);color:var(--blue);padding:1px 4px;border-radius:3px;font-family:var(--font-mono);">IMP</span>' : '';
    return `<tr class="${rowCls}">
      <td>${dateStr}${sourceTag}</td>
      <td style="font-size:16px;">${sportTag}</td>
      <td>${escapeHtml(match)}${b.league ? `<div style="font-size:10px;color:var(--text3);">${escapeHtml(b.league)}</div>` : ''}</td>
      <td>${escapeHtml(b.selection_label)}<div style="font-size:10px;color:var(--text3);">${escapeHtml(b.market)}</div></td>
      <td>${safeFixed(b.odds, 2)}</td>
      <td>${centsToEur(b.stake_cents)}</td>
      <td>${escapeHtml(b.bookmaker)}</td>
      <td><span class="bet-status-pill ${b.status}">${b.status}</span></td>
      <td>${pl}</td>
      <td class="bet-actions">${actions}</td>
    </tr>`;
  }).join('');
}

function escapeHtml(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

async function loadCashTx() {
  try {
    const res = await apiFetch('/api/v1/bankroll/tx');
    if (!res.ok) return;
    const data = await res.json();
    const tbody = document.getElementById('paris-cash-tbody');
    const emptyEl = document.getElementById('paris-cash-empty');
    if (!data.tx || !data.tx.length) { tbody.innerHTML = ''; emptyEl.style.display = 'block'; return; }
    emptyEl.style.display = 'none';
    tbody.innerHTML = data.tx.map(t => {
      const date = new Date(t.occurred_at * 1000).toLocaleDateString('fr-FR', { day:'numeric', month:'short', year:'2-digit' });
      const amount = t.amount_cents / 100;
      const cls = amount >= 0 ? 'bet-pl-pos' : 'bet-pl-neg';
      return `<tr>
        <td>${date}</td>
        <td><span class="bet-status-pill ${t.kind === 'deposit' ? 'won' : t.kind === 'withdrawal' ? 'lost' : 'void'}">${t.kind}</span></td>
        <td><span class="${cls}">${eurFmt(amount)}</span></td>
        <td>${escapeHtml(t.bookmaker || '—')}</td>
        <td>${escapeHtml(t.note || '')}</td>
        <td class="bet-actions"><button class="danger" onclick="deleteCashTx(${t.id})">×</button></td>
      </tr>`;
    }).join('');
  } catch (e) { /* ignore */ }
}

async function loadBankrollSummary() {
  try {
    const res = await apiFetch('/api/v1/bankroll/summary');
    if (!res.ok) return;
    const s = await res.json();
    parisState.summary = s;
    const plCls = s.settled_pl_cents >= 0 ? 'green' : 'red';
    const roiCls = s.roi_pct >= 0 ? 'green' : 'red';
    document.getElementById('paris-kpis').innerHTML = [
      { label: 'Bankroll', val: centsToEur(s.current_cents), color: 'var(--text)' },
      { label: 'Disponible', val: centsToEur(s.free_cents), color: 'var(--blue)', sub: s.open_stake_cents ? `(en jeu : ${centsToEur(s.open_stake_cents)})` : '' },
      { label: 'P&L cumul', val: eurFmt(s.settled_pl_cents / 100), color: 'var(--' + (s.settled_pl_cents >= 0 ? 'green' : 'red') + ')' },
      { label: 'ROI', val: (s.roi_pct >= 0 ? '+' : '') + s.roi_pct + '%', color: 'var(--' + (s.roi_pct >= 0 ? 'green' : 'red') + ')' },
      { label: 'Win Rate', val: (s.win_rate * 100).toFixed(1) + '%', color: 'var(--text2)', sub: `${s.totals.won}W / ${s.totals.lost}L` },
      { label: 'Drawdown max', val: '-' + s.max_drawdown_pct + '%', color: 'var(--amber)', sub: 'risk : -' + s.raw_drawdown_pct + '%' },
      { label: 'Ouverts', val: s.totals.pending, color: 'var(--text2)' },
      { label: 'Longest streak', val: s.longest_win_streak + ' / ' + s.longest_loss_streak, color: 'var(--text2)', sub: 'W / L' },
    ].map(k => `<div class="hist-kpi"><div class="hist-kpi-label">${k.label}</div><div class="hist-kpi-val" style="color:${k.color}">${k.val}</div>${k.sub ? `<div class="hist-kpi-sub">${k.sub}</div>` : ''}</div>`).join('');
    renderUserBankrollChart(s);
  } catch (e) { /* ignore */ }
}

function renderUserBankrollChart(s) {
  const wrap = document.getElementById('paris-chart-wrap');
  if (!wrap) return;
  if (!s.daily_series || !s.daily_series.length) { wrap.style.display = 'none'; return; }
  wrap.style.display = 'block';
  const ctx = document.getElementById('user-bankroll-chart').getContext('2d');
  if (userBankrollChart) { userBankrollChart.destroy(); userBankrollChart = null; }
  const labels = s.daily_series.map(d => new Date(d.date).toLocaleDateString('fr-FR', { day:'numeric', month:'short' }));
  const values = s.daily_series.map(d => d.bankroll_cents / 100);
  const deposits = s.daily_series.map((d, i) => d.deposit_cents > 0 ? { x: i, y: d.bankroll_cents / 100 } : null).filter(Boolean);
  const withdrawals = s.daily_series.map((d, i) => d.withdrawal_cents > 0 ? { x: i, y: d.bankroll_cents / 100 } : null).filter(Boolean);
  userBankrollChart = new Chart(ctx, {
    type: 'line',
    data: {
      labels,
      datasets: [
        { label: 'Bankroll', data: values, borderColor: '#29b6f6', backgroundColor: 'rgba(41,182,246,0.07)', borderWidth: 2, pointRadius: 0, fill: true, tension: 0.3 },
        { label: 'Dépôts', type: 'scatter', data: deposits, backgroundColor: '#00e676', borderColor: '#00e676', pointStyle: 'triangle', pointRadius: 7, showLine: false },
        { label: 'Retraits', type: 'scatter', data: withdrawals, backgroundColor: '#ff4d4d', borderColor: '#ff4d4d', pointStyle: 'triangle', pointRadius: 7, rotation: 180, showLine: false },
      ],
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { labels: { color: '#8d9399', font: { size: 10 }, boxWidth: 12, padding: 12, filter: (li) => li.text !== 'Bankroll' || true } },
        tooltip: { callbacks: { label: c => c.dataset.label + ': ' + safeFixed(c.parsed.y, 2) + ' €' } },
      },
      scales: {
        x: { ticks: { color: '#5a6068', font: { size: 9 }, maxTicksLimit: 10 }, grid: { color: 'rgba(255,255,255,.04)' } },
        y: { ticks: { color: '#5a6068', font: { size: 9 }, callback: v => safeFixed(v, 0) + ' €' }, grid: { color: 'rgba(255,255,255,.04)' } },
      },
    },
  });
}

