function toggleKellyPanel() {
  const p = document.getElementById('bet-kelly-panel');
  const visible = p.style.display !== 'none';
  p.style.display = visible ? 'none' : 'block';
  if (!visible) recomputeKelly();
}

async function recomputeKelly() {
  const prob = parseFloat(document.getElementById('bet-prob').value);
  const odds = parseFloat(document.getElementById('bet-odds').value);
  const bankrollCents = parisState.summary ? parisState.summary.free_cents : 0;
  if (!bankrollCents || bankrollCents <= 0) {
    document.getElementById('k-full').textContent = 'Bankroll = 0';
    document.getElementById('k-half').textContent = '—';
    document.getElementById('k-quarter').textContent = '—';
    document.getElementById('k-edge').textContent = '—';
    return;
  }
  try {
    const res = await apiFetch(`/api/v1/bets/kelly?prob=${prob}&odds=${odds}&bankroll_cents=${bankrollCents}`);
    if (!res.ok) return;
    const k = await res.json();
    document.getElementById('k-full').textContent = centsToEur(k.full_kelly_cents);
    document.getElementById('k-half').textContent = centsToEur(k.half_kelly_cents);
    document.getElementById('k-quarter').textContent = centsToEur(k.quarter_kelly_cents);
    const edge = ((prob * odds - 1) * 100).toFixed(2);
    document.getElementById('k-edge').textContent = edge + '%';
  } catch (e) { /* ignore */ }
}

function applyKelly(level) {
  const map = { full: 'k-full', half: 'k-half', quarter: 'k-quarter' };
  const txt = document.getElementById(map[level]).textContent;
  const num = parseFloat(txt.replace(/[^\d.,-]/g, '').replace(',', '.'));
  if (!isNaN(num) && num > 0) document.getElementById('bet-stake').value = safeFixed(num, 2);
}

async function submitBet() {
  const errEl = document.getElementById('bet-modal-err');
  const btn = document.getElementById('bet-save-btn');
  errEl.style.display = 'none';
  const market = document.getElementById('bet-market').value;
  const selection = document.getElementById('bet-selection').value.trim();
  const odds = parseFloat(document.getElementById('bet-odds').value);
  const stake = parseFloat(document.getElementById('bet-stake').value);
  const bookmaker = document.getElementById('bet-bookmaker').value.trim();
  const matchId = document.getElementById('bet-match-id').value;
  const search = document.getElementById('bet-match-search').value;
  const matchObj = parisState.matchesCache.find(m => `${m.home_team} — ${m.away_team}` === search);
  if (!selection) { errEl.textContent = 'Libellé sélection requis'; errEl.style.display = 'block'; return; }
  if (!odds || odds < 1.01) { errEl.textContent = 'Cote invalide'; errEl.style.display = 'block'; return; }
  if (!stake || stake <= 0) { errEl.textContent = 'Mise invalide'; errEl.style.display = 'block'; return; }
  const probInput = parseFloat(document.getElementById('bet-prob').value);
  const body = {
    match_id: matchId || null,
    home_team: matchObj ? matchObj.home_team : null,
    away_team: matchObj ? matchObj.away_team : null,
    league: document.getElementById('bet-league').value.trim() || null,
    commence_time: matchObj ? matchObj.commence_time : null,
    market,
    selection_label: selection,
    odds,
    stake,
    bookmaker: bookmaker || '1xbet',
    notes: document.getElementById('bet-notes').value.trim() || null,
    model_prob: !isNaN(probInput) ? probInput : null,
    edge_pct: !isNaN(probInput) ? (probInput * odds - 1) * 100 : null,
  };
  btn.disabled = true;
  try {
    const res = await apiFetch('/api/v1/bets', { method: 'POST', body });
    if (!res.ok) { const j = await res.json().catch(() => ({})); errEl.textContent = j.error || 'Erreur ' + res.status; errEl.style.display = 'block'; return; }
    closeBetModal();
    await refreshParisPage();
  } catch (e) {
    errEl.textContent = e.message || 'Erreur réseau';
    errEl.style.display = 'block';
  } finally { btn.disabled = false; }
}

