async function exportBetsCsv() {
  try {
    const res = await apiFetch('/api/v1/bets/export.csv?' + buildBetsQueryString());
    if (!res.ok) { alert('Export impossible'); return; }
    const blob = await res.blob();
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'paris-pariscore-' + new Date().toISOString().slice(0, 10) + '.csv';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  } catch (e) { /* ignore */ }
}

// ─── PLAN BANKROLL ────────────────────────────────────────────────────────
async function loadDailyTracker() {
  try {
    const res = await apiFetch('/api/v1/bankroll/daily-tracker');
    if (!res.ok) return;
    const data = await res.json();
    renderPlanTable(data);
  } catch (e) { /* ignore */ }
}

function renderPlanTable(data) {
  const p = data.plan;
  const tbody = document.getElementById('paris-plan-tbody');
  const sum = document.getElementById('paris-plan-summary');
  const totalValue = data.summary.total_value_cents;
  const targetFinal = data.days.length ? data.days[data.days.length - 1].target_capital_cents : p.starting_capital_cents;
  const gap = totalValue - targetFinal;
  sum.innerHTML = [
    { label: 'Capital départ', val: centsToEur(p.starting_capital_cents), color: 'var(--text2)' },
    { label: 'Capital actuel', val: centsToEur(data.summary.current_capital_cents), color: 'var(--text)' },
    { label: 'Banque cumulée', val: centsToEur(data.summary.cumul_bank_cents), color: 'var(--green)' },
    { label: 'Total (cap. + banque)', val: centsToEur(totalValue), color: gap >= 0 ? 'var(--green)' : 'var(--red)' },
    { label: 'Cible J+' + (data.days.length - 1), val: centsToEur(targetFinal), color: 'var(--blue)' },
    { label: 'Écart cible', val: (gap >= 0 ? '+' : '') + (gap / 100).toFixed(2) + ' €', color: gap >= 0 ? 'var(--green)' : 'var(--red)' },
  ].map(k => `<div class="hist-kpi"><div class="hist-kpi-label">${k.label}</div><div class="hist-kpi-val" style="color:${k.color};font-size:22px;">${k.val}</div></div>`).join('');
  if (!data.days.length) {
    tbody.innerHTML = '';
    document.getElementById('paris-plan-empty').style.display = 'block';
    return;
  }
  document.getElementById('paris-plan-empty').style.display = 'none';
  tbody.innerHTML = data.days.map(d => {
    const date = new Date(d.date).toLocaleDateString('fr-FR', { weekday:'short', day:'numeric', month:'short' });
    const pnlCls = d.daily_pnl_cents >= 0 ? 'bet-pl-pos' : 'bet-pl-neg';
    const gapCls = d.gap_vs_target_cents >= 0 ? 'bet-pl-pos' : 'bet-pl-neg';
    const status = d.hit_target ? '<span class="bet-status-pill won">cible ✓</span>' : (d.daily_pnl_cents === 0 ? '<span class="bet-status-pill void">—</span>' : '<span class="bet-status-pill lost">sous cible</span>');
    return `<tr>
      <td>${date}</td>
      <td>${centsToEur(d.target_capital_cents)}</td>
      <td>${centsToEur(d.actual_capital_cents)}</td>
      <td><span class="${pnlCls}">${eurFmt(d.daily_pnl_cents / 100)}</span></td>
      <td>${centsToEur(d.gain_to_bank_cents)}</td>
      <td>${centsToEur(d.gain_to_capital_cents)}</td>
      <td>${centsToEur(d.cumul_bank_cents)}</td>
      <td><span class="${gapCls}">${(d.gap_vs_target_cents >= 0 ? '+' : '') + (d.gap_vs_target_cents / 100).toFixed(2)} €</span></td>
      <td>${status}</td>
    </tr>`;
  }).join('');
}

async function openPlanModal() {
  if (!psGetToken()) { openAuthModal('login'); return; }
  document.getElementById('plan-modal-err').style.display = 'none';
  try {
    const res = await apiFetch('/api/v1/bankroll/plan');
    if (res.ok) {
      const p = await res.json();
      document.getElementById('plan-capital').value = (p.starting_capital_cents / 100).toFixed(2);
      document.getElementById('plan-target').value = p.daily_target_pct;
      document.getElementById('plan-split').value = p.profit_split_pct;
      document.getElementById('plan-start').value = p.start_date;
      document.getElementById('plan-floor').value = (p.floor_cents / 100).toFixed(2);
    }
  } catch (e) { /* ignore */ }
  document.getElementById('plan-modal').classList.add('open');
}
function closePlanModal() { document.getElementById('plan-modal').classList.remove('open'); }

async function submitPlan() {
  const errEl = document.getElementById('plan-modal-err');
  errEl.style.display = 'none';
  const capital = parseFloat(document.getElementById('plan-capital').value);
  const target = parseFloat(document.getElementById('plan-target').value);
  const split = parseFloat(document.getElementById('plan-split').value);
  const start = document.getElementById('plan-start').value;
  const floor = parseFloat(document.getElementById('plan-floor').value) || 0;
  if (!capital || capital <= 0) { errEl.textContent = 'Capital invalide'; errEl.style.display = 'block'; return; }
  if (isNaN(target) || target < 0) { errEl.textContent = 'Objectif invalide'; errEl.style.display = 'block'; return; }
  if (isNaN(split) || split < 0 || split > 100) { errEl.textContent = 'Split doit être entre 0 et 100'; errEl.style.display = 'block'; return; }
  try {
    const res = await apiFetch('/api/v1/bankroll/plan', { method: 'PUT', body: { starting_capital: capital, daily_target_pct: target, profit_split_pct: split, start_date: start, floor } });
    if (!res.ok) { const j = await res.json().catch(() => ({})); errEl.textContent = j.error || 'Erreur ' + res.status; errEl.style.display = 'block'; return; }
    closePlanModal();
    if (parisState.tab === 'plan') loadDailyTracker();
  } catch (e) {
    errEl.textContent = e.message || 'Erreur réseau';
    errEl.style.display = 'block';
  }
}

// ─── IMPORT CSV BOOKMAKER (sécurisé re-verify mdp) ──────────────────────────
let importReverifyToken = null;

function openImportModal() {
  if (!psGetToken()) { openAuthModal('login'); return; }
  document.getElementById('import-modal-err').style.display = 'none';
  document.getElementById('import-password').value = '';
  document.getElementById('import-csv').value = '';
  document.getElementById('import-file').value = '';
  document.getElementById('import-preview').innerHTML = '';
  document.getElementById('import-step-reverify').style.display = 'block';
  document.getElementById('import-step-upload').style.display = 'none';
  importReverifyToken = null;
  document.getElementById('import-modal').classList.add('open');
  setTimeout(() => document.getElementById('import-password').focus(), 80);
}
function closeImportModal() {
  document.getElementById('import-modal').classList.remove('open');
  importReverifyToken = null;
}

async function submitReverify() {
  const errEl = document.getElementById('import-modal-err');
  errEl.style.display = 'none';
  const pwd = document.getElementById('import-password').value;
  if (!pwd) { errEl.textContent = 'Mot de passe requis'; errEl.style.display = 'block'; return; }
  try {
    const res = await apiFetch('/api/v1/auth/reverify', { method: 'POST', body: { password: pwd } });
    document.getElementById('import-password').value = ''; // clear immédiat
    if (!res.ok) {
      const j = await res.json().catch(() => ({}));
      errEl.textContent = j.error || 'Mot de passe incorrect';
      errEl.style.display = 'block';
      return;
    }
    const j = await res.json();
    importReverifyToken = j.reverify_token;
    document.getElementById('import-step-reverify').style.display = 'none';
    document.getElementById('import-step-upload').style.display = 'block';
  } catch (e) {
    errEl.textContent = e.message || 'Erreur réseau';
    errEl.style.display = 'block';
  }
}

async function readImportFileText() {
  const file = document.getElementById('import-file').files[0];
  if (!file) return document.getElementById('import-csv').value;
  if (file.size > 500 * 1024) throw new Error('Fichier trop gros (max 500 Ko)');
  return await file.text();
}

async function submitImport(dryRun) {
  const errEl = document.getElementById('import-modal-err');
  const previewEl = document.getElementById('import-preview');
  errEl.style.display = 'none';
  if (!importReverifyToken) { errEl.textContent = 'Session de re-vérification expirée. Recommence.'; errEl.style.display = 'block'; return; }
  let csv;
  try { csv = (await readImportFileText() || '').trim(); }
  catch (e) { errEl.textContent = e.message; errEl.style.display = 'block'; return; }
  if (!csv) { errEl.textContent = 'CSV vide (ni fichier ni texte)'; errEl.style.display = 'block'; return; }
  const bookmaker = document.getElementById('import-bookmaker').value;
  try {
    const res = await apiFetch('/api/v1/bets/import', { method: 'POST', body: { csv, default_bookmaker: bookmaker, dry_run: !!dryRun, reverify_token: importReverifyToken, filename: (document.getElementById('import-file').files[0] || {}).name } });
    const j = await res.json();
    if (!res.ok) {
      errEl.textContent = j.error || 'Erreur ' + res.status;
      errEl.style.display = 'block';
      if (j.code === 'REVERIFY_REQUIRED') { importReverifyToken = null; document.getElementById('import-step-reverify').style.display = 'block'; document.getElementById('import-step-upload').style.display = 'none'; }
      return;
    }
    if (dryRun) {
      previewEl.innerHTML = `<div style="margin-top:10px;color:var(--text2);"><strong>${j.rows_parsed}</strong> ligne(s) parsées · <strong>${j.rows_skipped}</strong> erreur(s)</div>
        <div style="max-height:200px;overflow:auto;background:var(--bg3);padding:8px;border-radius:6px;margin-top:6px;font-size:10px;">${(j.preview || []).slice(0,10).map(r => `${SPORT_EMOJI[r.sport]||'🏆'} ${escapeHtml((r.home_team||'?')+' — '+(r.away_team||'?'))} · ${escapeHtml(r.selection_label)} @ ${r.odds} · ${(r.stake_cents/100).toFixed(2)}€ · ${r.status}`).join('<br>')}</div>
        ${j.errors && j.errors.length ? `<div style="color:var(--red);margin-top:6px;font-size:11px;">${j.errors.length} erreur(s) — ex : ${escapeHtml(j.errors[0].reason)} (ligne ${j.errors[0].line})</div>` : ''}`;
    } else {
      previewEl.innerHTML = `<div style="margin-top:10px;color:var(--green);">✓ Import terminé : <strong>${j.rows_inserted}</strong> pari(s) insérés / ${j.rows_parsed} parsés (${j.rows_skipped} erreurs)</div>`;
      importReverifyToken = null; // single-use consumed serveur-side
      setTimeout(() => { closeImportModal(); refreshParisPage(); }, 1500);
    }
  } catch (e) {
    errEl.textContent = e.message || 'Erreur réseau';
    errEl.style.display = 'block';
  }
}

// Close modals on backdrop click
document.addEventListener('click', (e) => {
  ['bet-modal', 'settle-modal', 'cash-modal', 'plan-modal', 'import-modal'].forEach(id => {
    const m = document.getElementById(id);
    if (m && e.target === m) m.classList.remove('open');
  });
});

