// ── Populate league filter dropdown (idempotent) ──────────────────────────
function dhPopulateLeagueOptions(byLeague) {
  const sel = document.getElementById('dh-f-league');
  if (!sel) return;
  const existing = new Set(Array.from(sel.options).map(o => o.value));
  const fresh = byLeague.map(l => l.league);
  // Preserve selection across re-renders
  const selected = new Set(Array.from(sel.selectedOptions).map(o => o.value));
  if (fresh.every(l => existing.has(l)) && existing.size === fresh.length) return;
  sel.innerHTML = fresh.map(l => `<option value="${l}"${selected.has(l) ? ' selected' : ''}>${l}</option>`).join('');
}

// ── Table render ───────────────────────────────────────────────────────────
function _dhMarketPill(label, predicted, predThresh, won) {
  if (predicted == null || predicted < predThresh) return '<span class="dh-pred-pill na">—</span>';
  if (won == null) return `<span class="dh-pred-pill na">${Math.round(predicted)}%</span>`;
  return `<span class="dh-pred-pill ${won ? 'win' : 'loss'}">${Math.round(predicted)}%</span>`;
}

// H3 : tennis-specific row renderer
function _dhRenderTableTennis(data) {
  const tbody = document.getElementById('dh-tbody');
  const matches = data.matches || [];

  tbody.innerHTML = matches.map(m => {
    const dt = fmtKickoffDate(m.commence_time, { day: '2-digit', month: 'short', year: '2-digit' }, '—');
    const r = m.realResult || {};
    const setsScore = (r.sets || []).map(s => s.p1 + '-' + s.p2).join(' ') || '—';
    const winner = r.winner || '—';
    const p = m.predicted || {};
    // Bridge: entries ETL peuvent avoir bsd_prediction sans predicted (patch bd)
    const bp = m.bsd_prediction || {};
    const _bpMl = bp.prob_p1_wins > 0.50 ? m.p1 : (bp.prob_p1_wins < 0.50 ? m.p2 : null);
    const mlPick = p.ml || _bpMl || '—';
    const _effectiveMl = p.ml || _bpMl || null;
    const mlWon = (_effectiveMl && r.winner) ? (_effectiveMl === r.winner ? 1 : 0) : null;
    const set1Pick = p.set1 || '—';
    let set1Won = null;
    if (p.set1 && r.sets?.length) {
      const s1 = r.sets[0];
      const s1Winner = s1.p1 > s1.p2 ? m.p1 : m.p2;
      set1Won = s1Winner === p.set1 ? 1 : 0;
    }
    // Marchés additionnels (≥1 Set, Total Jeux, Aces, Tie-break)
    const dogPick = p.geq1_set_dog || '—';
    let dogWon = null;
    if (p.geq1_set_dog && r.sets?.length) {
      const dogSetsWon = r.sets.filter(s => (p.geq1_set_dog === m.p1 ? s.p1 > s.p2 : s.p2 > s.p1)).length;
      dogWon = dogSetsWon >= 1 ? 1 : 0;
    }
    const tgPick = typeof p.total_games_thr === 'number' ? (p.total_games_over ? 'O ' : 'U ') + p.total_games_thr : '—';
    let tgWon = null;
    if (typeof p.total_games_thr === 'number' && typeof r.total_games === 'number') {
      tgWon = (p.total_games_over ? r.total_games > p.total_games_thr : r.total_games < p.total_games_thr) ? 1 : 0;
    }
    const acesPick = typeof p.aces_thr === 'number' ? 'O ' + p.aces_thr : '—';
    let acesWon = null;
    if (typeof p.aces_thr === 'number' && (typeof r.aces_p1 === 'number' || typeof r.aces_p2 === 'number')) {
      const ta = (r.aces_p1 || 0) + (r.aces_p2 || 0);
      acesWon = ta > p.aces_thr ? 1 : 0;
    }
    const tbPick = typeof p.tie_break === 'boolean' ? (p.tie_break ? 'Oui' : 'Non') : '—';
    let tbWon = null;
    if (typeof p.tie_break === 'boolean' && typeof r.had_tiebreak === 'boolean') {
      tbWon = p.tie_break === r.had_tiebreak ? 1 : 0;
    }

    const pillFor = (label, won) => {
      const cls = won === 1 ? 'win' : won === 0 ? 'loss' : 'na';
      return `<span class="dh-pred-pill ${cls}">${escapeHtml(label)}</span>`;
    };

    return `<tr>
      <td><strong>${escapeHtml(m.p1 || '?')}</strong> – ${escapeHtml(m.p2 || '?')}</td>
      <td>${escapeHtml(m.tournament || m.league || '')}</td>
      <td>${escapeHtml(m.surface || '—')}</td>
      <td>${dt}</td>
      <td>${escapeHtml(setsScore)}</td>
      <td>${pillFor(mlPick, mlWon)}</td>
      <td>${pillFor(set1Pick, set1Won)}</td>
      <td>${pillFor(dogPick, dogWon)}</td>
      <td>${pillFor(tgPick, tgWon)}</td>
      <td>${pillFor(acesPick, acesWon)}</td>
      <td>${pillFor(tbPick, tbWon)}</td>
      <td>${escapeHtml(winner)}</td>
    </tr>`;
  }).join('');

  const totalPages = Math.max(1, Math.ceil(data.total / data.pageSize));
  document.getElementById('dh-pagination').innerHTML = `
    <span>${data.total} matchs · page ${data.page}/${totalPages}</span>
    <span>
      <button type="button" ${data.page <= 1 ? 'disabled' : ''} onclick="dhGoToPage(${data.page - 1})">‹ Préc</button>
      <button type="button" ${data.page >= totalPages ? 'disabled' : ''} onclick="dhGoToPage(${data.page + 1})">Suiv ›</button>
    </span>`;
}

function dhRenderTable(data) {
  const tbody = document.getElementById('dh-tbody');
  const empty = document.getElementById('dh-empty');
  const matches = data.matches || [];
  if (!matches.length) {
    tbody.innerHTML = '';
    if (dhState.sport === 'tennis') {
      empty.innerHTML = `
        <div class="ico">🎾</div>
        <strong style="color:var(--text2);">Tennis archive — scaffold actif</strong><br>
        <span style="font-size:11.5px;color:var(--text3);margin-top:6px;display:inline-block;line-height:1.5;">
          La structure backend est en place (Phase H3).<br>
          L'historique tennis se rempliera progressivement à partir des prochains matchs terminés.<br>
          6 marchés natifs ciblés : Moneyline · Set 1 · ≥1 set · Total jeux · Aces · Tie-break.
        </span>`;
    } else {
      empty.innerHTML = `
        <div class="ico">📊</div>
        Aucun match ne correspond aux filtres.<br>
        <span style="font-size:11px;margin-top:4px;display:block;">Essayez de relâcher un filtre ou changez de période.</span>`;
    }
    empty.style.display = 'block';
    document.getElementById('dh-pagination').innerHTML = '';
    return;
  }
  empty.style.display = 'none';

  if (dhState.sport === 'tennis') {
    return _dhRenderTableTennis(data);
  }

  // Edge raisonnable : [5%, 50%]. Au-delà = data legacy corrompue.
  const DH_EDGE_MIN = 5, DH_EDGE_MAX = 50;
  const edgeOk = (ev) => typeof ev === 'number' && ev >= DH_EDGE_MIN && ev <= DH_EDGE_MAX;

  tbody.innerHTML = matches.map(m => {
    const rs = m.realScore;
    const wasOver25 = rs ? (rs.home + rs.away) > 2.5 : null;
    const wasBTTS = rs ? (rs.home > 0 && rs.away > 0) : null;
    const winnerLabel = rs ? (rs.home > rs.away ? m.home_team : rs.away > rs.home ? m.away_team : 'Nul') : null;
    const evVal = m.predicted?.bestEdgeValue;
    const hasEdgePick = edgeOk(evVal);
    const edgeWon = (hasEdgePick && winnerLabel) ? (winnerLabel === m.predicted.bestEdge ? 1 : 0) : null;

    const dt = fmtKickoffDate(m.commence_time, { day: '2-digit', month: 'short', year: '2-digit' }, '—');
    const scoreCell = rs
      ? `<span class="dh-cell-${(rs.home + rs.away) >= 2 ? 'win' : 'loss'}">${rs.home}-${rs.away}</span>`
      : '<span style="color:var(--text3)">—</span>';

    // Aggregate outcome — respects edge cap
    let issueLabel = '<span style="color:var(--text3);">N/A</span>';
    if (rs) {
      const picks = [];
      if (m.predicted?.over25 > 55 && m.predicted.over25 <= 100) picks.push(wasOver25 ? 1 : 0);
      if (m.predicted?.btts > 55 && m.predicted.btts <= 100) picks.push(wasBTTS ? 1 : 0);
      if (edgeWon != null) picks.push(edgeWon);
      if (picks.length) {
        const w = picks.filter(x => x === 1).length;
        issueLabel = w === picks.length
          ? '<span class="dh-cell-win">✓ ' + w + '/' + picks.length + '</span>'
          : w === 0
          ? '<span class="dh-cell-loss">✗ 0/' + picks.length + '</span>'
          : '<span style="color:var(--amber);font-weight:700;">' + w + '/' + picks.length + '</span>';
      }
    }

    return `<tr>
      <td><strong>${escapeHtml(m.home_team)}</strong> – ${escapeHtml(m.away_team)}</td>
      <td style="color:var(--text2);">${escapeHtml(m.league || '')}</td>
      <td>${dt}</td>
      <td>${scoreCell}</td>
      <td>${_dhMarketPill('O2.5', m.predicted?.over25, 55, wasOver25)}</td>
      <td>${_dhMarketPill('BTTS', m.predicted?.btts, 55, wasBTTS)}</td>
      <td>${hasEdgePick
        ? `<span class="dh-pred-pill ${edgeWon === 1 ? 'win' : edgeWon === 0 ? 'loss' : 'na'}">${escapeHtml(m.predicted.bestEdge)} +${safeFixed(evVal, 1)}%</span>`
        : '<span class="dh-pred-pill na">—</span>'}</td>
      <td>${issueLabel}</td>
    </tr>`;
  }).join('');

  // Pagination
  const totalPages = Math.max(1, Math.ceil(data.total / data.pageSize));
  document.getElementById('dh-pagination').innerHTML = `
    <span>${data.total} matchs · page ${data.page}/${totalPages}</span>
    <span>
      <button type="button" ${data.page <= 1 ? 'disabled' : ''} onclick="dhGoToPage(${data.page - 1})">‹ Préc</button>
      <button type="button" ${data.page >= totalPages ? 'disabled' : ''} onclick="dhGoToPage(${data.page + 1})">Suiv ›</button>
    </span>`;
}

function dhGoToPage(p) {
  dhState.page = p;
  dhRefresh();
}

// ── Charts render ──────────────────────────────────────────────────────────
function _dhDestroyCharts() {
  for (const k of ['pl', 'dd', 'rolling', 'calibration']) {
    if (dhState._charts[k]) { dhState._charts[k].destroy(); dhState._charts[k] = null; }
  }
}

function _dhSliceCohort(pl, days) {
  if (days === 'off') return null;
  if (days === 'all') return pl;
  const n = parseInt(days);
  if (!Number.isFinite(n) || n <= 0) return pl;
  const cutoff = Date.now() - n * 86400000;
  return pl.filter(p => new Date(p.date).getTime() >= cutoff);
}
function _dhRebase(pl) {
  if (!pl?.length) return [];
  const base = pl[0].units;
  return pl.map(p => ({ date: p.date, units: p.units - base }));
}

function dhRenderCharts(series) {
  _dhDestroyCharts();
  if (!series) return;
  const pl = series.pl_cumulative || [];
  const dd = series.drawdown_curve || [];
  const rolling = series.rolling30_wr || [];

  if (pl.length) {
    const ctx = document.getElementById('dh-chart-pl').getContext('2d');
    const final = pl[pl.length - 1].units;
    const lineColor = final >= 0 ? '#10b981' : '#ef4444';
    const fillColor = final >= 0 ? 'rgba(16,185,129,0.07)' : 'rgba(239,68,68,0.07)';

    // R5 — Cohort comparison overlay
    const cohortA = document.getElementById('dh-cohort-a')?.value || 'all';
    const cohortB = document.getElementById('dh-cohort-b')?.value || 'off';
    const sliceA = _dhSliceCohort(pl, cohortA);
    const sliceB = _dhSliceCohort(pl, cohortB);
    const datasets = [];
    // Base series (full)
    if (cohortA === 'off' && cohortB === 'off') {
      datasets.push({ label: 'P/L', data: pl.map(p => p.units), borderColor: lineColor, backgroundColor: fillColor, borderWidth: 2, pointRadius: pl.length > 50 ? 0 : 2, fill: true, tension: 0.25 });
    } else {
      if (sliceA?.length) {
        const reb = _dhRebase(sliceA);
        datasets.push({
          label: `Cohort A — ${cohortA === 'all' ? 'All' : cohortA + 'j'}`,
          data: reb.map(p => ({ x: p.date, y: p.units })),
          borderColor: '#38bdf8',
          backgroundColor: 'rgba(56, 189, 248, 0.10)',
          borderWidth: 2, pointRadius: reb.length > 50 ? 0 : 2, fill: false, tension: 0.25,
        });
      }
      if (sliceB?.length) {
        const reb = _dhRebase(sliceB);
        datasets.push({
          label: `Cohort B — ${cohortB === 'all' ? 'All' : cohortB + 'j'}`,
          data: reb.map(p => ({ x: p.date, y: p.units })),
          borderColor: '#E2001A',
          backgroundColor: 'rgba(226, 0, 26, 0.08)',
          borderWidth: 2, pointRadius: reb.length > 50 ? 0 : 2, fill: false, tension: 0.25,
          borderDash: [5, 4],
        });
      }
    }
    dhState._charts.pl = new Chart(ctx, {
      type: 'line',
      data: { datasets },
      options: { ..._dhChartOpts(v => (v >= 0 ? '+' : '') + v + 'u'),
        plugins: {
          legend: { display: datasets.length > 1, labels: { color: '#cbd5e1', font: { family: 'JetBrains Mono, monospace', size: 10 } } },
          tooltip: { callbacks: { label: c => c.dataset.label + ' : ' + (c.parsed.y >= 0 ? '+' : '') + c.parsed.y + 'u' } },
        },
        scales: {
          x: { type: 'category', ticks: { color: '#5a6068', font: { size: 10 }, maxTicksLimit: 9 }, grid: { color: 'rgba(255,255,255,.04)' } },
          y: { ticks: { color: '#5a6068', font: { size: 10 }, callback: v => (v >= 0 ? '+' : '') + v + 'u' }, grid: { color: 'rgba(255,255,255,.04)' }, border: { dash: [3, 3] } },
        },
      },
    });
  }

  if (dd.length) {
    const ctx = document.getElementById('dh-chart-dd').getContext('2d');
    dhState._charts.dd = new Chart(ctx, {
      type: 'line',
      data: {
        labels: dd.map(p => p.date),
        datasets: [{ data: dd.map(p => -p.dd), borderColor: '#ff4d4d', backgroundColor: 'rgba(255,77,77,0.10)', borderWidth: 2, pointRadius: 0, fill: true, tension: 0.25 }],
      },
      options: _dhChartOpts(v => v + 'u'),
    });
  }

  if (rolling.length) {
    const ctx = document.getElementById('dh-chart-rolling').getContext('2d');
    dhState._charts.rolling = new Chart(ctx, {
      type: 'line',
      data: {
        labels: rolling.map(p => p.date),
        datasets: [{ data: rolling.map(p => Math.round(p.wr * 100)), borderColor: '#38bdf8', backgroundColor: 'rgba(56,189,248,0.08)', borderWidth: 2, pointRadius: 0, fill: true, tension: 0.25 }],
      },
      options: _dhChartOpts(v => v + '%', 0, 100),
    });
  }

  // R6 — Calibration Plot (scatter + diagonal reference)
  const calib = (window._dhLastData?.calibration) || [];
  if (calib.length) {
    const ctxCal = document.getElementById('dh-chart-calibration').getContext('2d');
    const points = calib.filter(c => c.predicted_avg != null && c.realized_rate != null && c.sample >= 3)
      .map(c => ({ x: c.predicted_avg, y: c.realized_rate, sample: c.sample }));
    dhState._charts.calibration = new Chart(ctxCal, {
      type: 'scatter',
      data: {
        datasets: [
          { label: 'Modèle', data: points, backgroundColor: '#38bdf8', borderColor: '#38bdf8', pointRadius: points.map(p => Math.min(3 + Math.sqrt(p.sample), 12)), pointHoverRadius: 14 },
          { label: 'Calibration parfaite', data: [{ x: 0, y: 0 }, { x: 100, y: 100 }], type: 'line', borderColor: 'rgba(148, 163, 184, 0.45)', borderDash: [4, 4], borderWidth: 1.5, pointRadius: 0, fill: false },
        ],
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { labels: { color: '#cbd5e1', font: { family: 'JetBrains Mono, monospace', size: 10 } } },
          tooltip: { callbacks: { label: c => c.dataset.label === 'Modèle' ? `pred ${Math.round(c.parsed.x)}% → realized ${Math.round(c.parsed.y)}% (n=${c.raw.sample})` : null } },
        },
        scales: {
          x: { type: 'linear', min: 0, max: 100, title: { display: true, text: 'Predicted %', color: '#94a3b8', font: { family: 'JetBrains Mono, monospace', size: 10 } }, ticks: { color: '#5a6068', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,.04)' } },
          y: { type: 'linear', min: 0, max: 100, title: { display: true, text: 'Realized %', color: '#94a3b8', font: { family: 'JetBrains Mono, monospace', size: 10 } }, ticks: { color: '#5a6068', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,.04)' } },
        },
      },
    });
  }
}

function _dhChartOpts(fmt, yMin, yMax) {
  return {
    responsive: true, maintainAspectRatio: false,
    plugins: { legend: { display: false }, tooltip: { callbacks: { label: c => fmt(c.parsed.y) } } },
    scales: {
      x: { ticks: { color: '#5a6068', font: { size: 10 }, maxTicksLimit: 9 }, grid: { color: 'rgba(255,255,255,.04)' } },
      y: { ticks: { color: '#5a6068', font: { size: 10 }, callback: fmt }, min: yMin, max: yMax, grid: { color: 'rgba(255,255,255,.04)' }, border: { dash: [3, 3] } },
    },
  };
}

// ── Wire controls ─────────────────────────────────────────────────────────
function _dhWireControls() {
  // Sport toggle (H3 : re-render market chips + show/hide surface + update table cols)
  document.querySelectorAll('#dh-sport-toggle .dh-toggle-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('#dh-sport-toggle .dh-toggle-btn').forEach(b => b.classList.toggle('active', b === btn));
      dhState.sport = btn.dataset.sport;
      dhState.page = 1;
      dhState.markets = DH_MARKETS_BY_SPORT[dhState.sport].map(m => m.key);
      dhState.surfaces = [];
      // Tennis: période par défaut = all (les seeds historiques sont 2024-2025)
      if (dhState.sport === 'tennis') { dhState.period = 'all'; dhState.fromDate = null; dhState.toDate = null; dhState.minProba = 0; dhState.minEV = 0; dhState.confidence = []; dhState.strategies = []; dhState.minOdds = 1.10; dhState.maxOdds = 10.00; dhState.venue = 'all'; }
      else { dhState.period = '90'; dhState.fromDate = null; dhState.toDate = null; dhState.minProba = 55; }
      // Met à jour les boutons période
      document.querySelectorAll('#dh-period-bar .dh-period-btn').forEach(b => b.classList.toggle('active', b.dataset.period === dhState.period));
      // Mise à jour placeholder filtre joueurs selon sport (patch BSD)
      const teamInput = document.getElementById('dh-f-team');
      if (teamInput) teamInput.placeholder = dhState.sport === 'tennis' ? 'Ex: Sinner, Djokovic…' : 'Ex: PSG, Sinner…';
      _dhRenderMarketChips();
      _dhRenderTableHeader();
      document.getElementById('dh-fr-surface').style.display = dhState.sport === 'tennis' ? '' : 'none';
      // Cache les sections foot-only pour le tennis (stratégies, confiance, EV, proba, cotes, venue)
      const isTennis = dhState.sport === 'tennis';
      const hideForTennis = ['dh-f-strategy', 'dh-f-confidence', 'dh-f-ev', 'dh-f-proba', 'dh-f-odds-min', 'dh-f-venue'];
      hideForTennis.forEach(id => {
        const el = document.getElementById(id); if (!el) return;
        const section = el.closest('.dh-fr-section, .dh-fr-row');
        if (section) section.style.display = isTennis ? 'none' : '';
      });
      dhRefresh();
    });
  });

  // Surface chips wiring (initial)
  document.querySelectorAll('#dh-f-surface .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      chip.classList.toggle('active');
      dhState.surfaces = Array.from(document.querySelectorAll('#dh-f-surface .dh-chip.active')).map(c => c.dataset.surface);
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // Initial render market chips (football)
  _dhRenderMarketChips();
  _dhRenderTableHeader();

  // Period buttons
  document.querySelectorAll('#dh-period-bar .dh-period-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('#dh-period-bar .dh-period-btn').forEach(b => b.classList.toggle('active', b === btn));
      dhState.period = btn.dataset.period;
      _dhApplyPeriod();
      document.getElementById('dh-from').value = dhState.fromDate || '';
      document.getElementById('dh-to').value = dhState.toDate || '';
      dhState.page = 1;
      dhRefresh();
    });
  });

  // Custom date pickers
  document.getElementById('dh-from').addEventListener('change', e => {
    dhState.fromDate = e.target.value || null;
    document.querySelectorAll('#dh-period-bar .dh-period-btn').forEach(b => b.classList.remove('active'));
    dhState.page = 1;
    dhRefreshDebounced();
  });
  document.getElementById('dh-to').addEventListener('change', e => {
    dhState.toDate = e.target.value || null;
    document.querySelectorAll('#dh-period-bar .dh-period-btn').forEach(b => b.classList.remove('active'));
    dhState.page = 1;
    dhRefreshDebounced();
  });

  // League multi-select
  document.getElementById('dh-f-league').addEventListener('change', e => {
    dhState.leagues = Array.from(e.target.selectedOptions).map(o => o.value);
    dhState.page = 1;
    dhRefreshDebounced();
  });

  // Team search
  document.getElementById('dh-f-team').addEventListener('input', e => {
    const v = e.target.value.trim();
    dhState.teams = v ? [v] : [];
    dhState.page = 1;
    dhRefreshDebounced(350);
  });

  // Market chips
  document.querySelectorAll('#dh-f-market .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      chip.classList.toggle('active');
      const active = Array.from(document.querySelectorAll('#dh-f-market .dh-chip.active')).map(c => c.dataset.mkt);
      dhState.markets = active;
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // Confidence chips (multi)
  document.querySelectorAll('#dh-f-confidence .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      chip.classList.toggle('active');
      dhState.confidence = Array.from(document.querySelectorAll('#dh-f-confidence .dh-chip.active')).map(c => c.dataset.conf);
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // Outcome chips (single)
  document.querySelectorAll('#dh-f-outcome .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      document.querySelectorAll('#dh-f-outcome .dh-chip').forEach(c => c.classList.toggle('active', c === chip));
      dhState.outcome = chip.dataset.oc;
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // EV slider
  const evRange = document.getElementById('dh-f-ev');
  const evVal = document.getElementById('dh-ev-val');
  evRange.addEventListener('input', () => { evVal.textContent = evRange.value + '%'; });
  evRange.addEventListener('change', () => {
    dhState.minEV = parseFloat(evRange.value);
    dhState.page = 1;
    dhRefreshDebounced();
  });

  // Proba slider
  const prRange = document.getElementById('dh-f-proba');
  const prVal = document.getElementById('dh-pr-val');
  prRange.addEventListener('input', () => { prVal.textContent = prRange.value + '%'; });
  prRange.addEventListener('change', () => {
    dhState.minProba = parseInt(prRange.value);
    dhState.page = 1;
    dhRefreshDebounced();
  });

  // Exclude low WR
  document.getElementById('dh-f-excludelow').addEventListener('change', e => {
    dhState.excludeLowLeagues = !!e.target.checked;
    dhState.page = 1;
    dhRefreshDebounced();
  });

  // R1 — Plage cotes double-slider
  const oddsMin = document.getElementById('dh-f-odds-min');
  const oddsMax = document.getElementById('dh-f-odds-max');
  const oddsMinLbl = document.getElementById('dh-odds-min-val');
  const oddsMaxLbl = document.getElementById('dh-odds-max-val');
  const updOddsLbl = () => { oddsMinLbl.textContent = parseFloat(oddsMin.value).toFixed(2); oddsMaxLbl.textContent = parseFloat(oddsMax.value).toFixed(2); };
  oddsMin.addEventListener('input', () => {
    if (parseFloat(oddsMin.value) > parseFloat(oddsMax.value) - 0.05) oddsMin.value = (parseFloat(oddsMax.value) - 0.05).toFixed(2);
    updOddsLbl();
  });
  oddsMax.addEventListener('input', () => {
    if (parseFloat(oddsMax.value) < parseFloat(oddsMin.value) + 0.05) oddsMax.value = (parseFloat(oddsMin.value) + 0.05).toFixed(2);
    updOddsLbl();
  });
  const onOddsChange = () => {
    dhState.minOdds = parseFloat(oddsMin.value);
    dhState.maxOdds = parseFloat(oddsMax.value);
    dhState.page = 1;
    dhRefreshDebounced();
  };
  oddsMin.addEventListener('change', onOddsChange);
  oddsMax.addEventListener('change', onOddsChange);

  // R1 — Venue chips (single-select)
  document.querySelectorAll('#dh-f-venue .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      document.querySelectorAll('#dh-f-venue .dh-chip').forEach(c => c.classList.toggle('active', c === chip));
      dhState.venue = chip.dataset.venue;
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // R1 — Weekday chips (multi)
  document.querySelectorAll('#dh-f-weekday .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      chip.classList.toggle('active');
      dhState.weekdays = Array.from(document.querySelectorAll('#dh-f-weekday .dh-chip.active')).map(c => c.dataset.wd);
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // R5 — Cohort selectors (re-render chart only, no refetch)
  document.getElementById('dh-cohort-a')?.addEventListener('change', () => {
    if (window._dhLastData?.series) dhRenderCharts(window._dhLastData.series);
  });
  document.getElementById('dh-cohort-b')?.addEventListener('change', () => {
    if (window._dhLastData?.series) dhRenderCharts(window._dhLastData.series);
  });

  // R9 — Weather chips multi-select (scaffold, data dep externe)
  document.querySelectorAll('#dh-f-weather .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      chip.classList.toggle('active');
      dhState.weather = Array.from(document.querySelectorAll('#dh-f-weather .dh-chip.active')).map(c => c.dataset.w);
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // R8 — Backtest Simulator
  document.getElementById('dh-bt-run')?.addEventListener('click', async () => {
    const btn = document.getElementById('dh-bt-run');
    btn.disabled = true; btn.textContent = '⏳ Simulation…';
    const filters = _dhBuildFiltersPayload();
    const staking = document.getElementById('dh-bt-staking').value;
    const startBankroll = parseInt(document.getElementById('dh-bt-bankroll').value) || 100;
    try {
      const r = await apiFetch('/api/v1/history/backtest', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ filters, staking, startBankroll }) });
      if (!r.ok) throw new Error('HTTP ' + r.status);
      const data = await r.json();
      dhRenderBacktestResults(data);
    } catch (e) {
      document.getElementById('dh-bt-results').innerHTML = `<div class="dh-soon-banner"><div class="dh-soon-title">❌ Erreur backtest</div><div class="dh-soon-body">${escapeHtml(e.message || 'Erreur réseau')}</div></div>`;
    }
    btn.disabled = false; btn.textContent = '🧪 Lancer Backtest';
  });
  document.getElementById('dh-bt-save')?.addEventListener('click', async () => {
    const name = document.getElementById('dh-bt-name').value.trim();
    if (!name) { alert('Nom de stratégie requis'); return; }
    const filters = _dhBuildFiltersPayload();
    const staking = document.getElementById('dh-bt-staking').value;
    try {
      const r = await apiFetch('/api/v1/strategies', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name, filters, staking }) });
      if (!r.ok) {
        const err = await r.json().catch(() => ({}));
        throw new Error(err.error || 'HTTP ' + r.status);
      }
      const data = await r.json();
      alert('Stratégie "' + name + '" sauvegardée (id ' + data.id + ').');
    } catch (e) {
      alert('Échec sauvegarde : ' + (e.message || 'Erreur réseau'));
    }
  });

  // Reset
  document.getElementById('dh-reset').addEventListener('click', () => {
    dhState.leagues = []; dhState.teams = [];
    dhState.markets = DH_MARKETS_BY_SPORT[dhState.sport].map(m => m.key);
    dhState.confidence = []; dhState.outcome = 'all'; dhState.minEV = 0;
    dhState.minProba = dhState.sport === 'tennis' ? 0 : 55;
    dhState.excludeLowLeagues = false; dhState.fromDate = null; dhState.toDate = null;
    dhState.period = dhState.sport === 'tennis' ? 'all' : '90'; dhState.page = 1;
    // R1 reset
    dhState.minOdds = 1.10; dhState.maxOdds = 10.00; dhState.venue = 'all'; dhState.weekdays = [];
    // Reflect in DOM
    document.getElementById('dh-f-league').selectedIndex = -1;
    document.getElementById('dh-f-team').value = '';
    document.querySelectorAll('#dh-f-market .dh-chip').forEach(c => c.classList.add('active'));
    document.querySelectorAll('#dh-f-confidence .dh-chip').forEach(c => c.classList.remove('active'));
    document.querySelectorAll('#dh-f-outcome .dh-chip').forEach(c => c.classList.toggle('active', c.dataset.oc === 'all'));
    document.getElementById('dh-f-ev').value = '0'; document.getElementById('dh-ev-val').textContent = '0%';
    document.getElementById('dh-f-proba').value = '55'; document.getElementById('dh-pr-val').textContent = '55%';
    document.getElementById('dh-f-excludelow').checked = false;
    document.getElementById('dh-from').value = ''; document.getElementById('dh-to').value = '';
    // R1 reset DOM
    document.getElementById('dh-f-odds-min').value = '1.10'; document.getElementById('dh-odds-min-val').textContent = '1.10';
    document.getElementById('dh-f-odds-max').value = '10.00'; document.getElementById('dh-odds-max-val').textContent = '10.00';
    document.querySelectorAll('#dh-f-venue .dh-chip').forEach(c => c.classList.toggle('active', c.dataset.venue === 'all'));
    document.querySelectorAll('#dh-f-weekday .dh-chip').forEach(c => c.classList.remove('active'));
    document.querySelectorAll('#dh-period-bar .dh-period-btn').forEach(b => b.classList.toggle('active', b.dataset.period === '90'));
    _dhApplyPeriod();
    dhRefresh();
  });

  // View switch
  document.querySelectorAll('#dh-view-switch .dh-view-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('#dh-view-switch .dh-view-btn').forEach(b => b.classList.toggle('active', b === btn));
      const v = btn.dataset.view;
      dhState.view = v;
      document.getElementById('dh-view-executive').style.display = v === 'executive' ? '' : 'none';
      document.getElementById('dh-view-table').style.display = v === 'table' ? '' : 'none';
      document.getElementById('dh-view-charts').style.display = v === 'charts' ? '' : 'none';
      document.getElementById('dh-view-attribution').style.display = v === 'attribution' ? '' : 'none';
      document.getElementById('dh-view-variance').style.display = v === 'variance' ? '' : 'none';
      document.getElementById('dh-view-backtest').style.display = v === 'backtest' ? '' : 'none';
      document.getElementById('dh-view-strategy').style.display = v === 'strategy' ? '' : 'none';
      if (v === 'charts' || v === 'strategy' || v === 'executive' || v === 'attribution' || v === 'variance' || v === 'table') dhRefresh();
    });
  });

  // H4 : Strategy chips multi-select
  document.querySelectorAll('#dh-f-strategy .dh-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      chip.classList.toggle('active');
      dhState.strategies = Array.from(document.querySelectorAll('#dh-f-strategy .dh-chip.active')).map(c => c.dataset.strat);
      dhState.page = 1;
      dhRefreshDebounced();
    });
  });

  // H5 : Export CSV (avec auth Bearer si présent)
  document.getElementById('dh-export-csv').addEventListener('click', async () => {
    const url = _dhBuildUrl().replace('/history/query', '/history/export.csv');
    try {
      const r = await apiFetch(url);
      if (!r.ok) throw new Error('HTTP ' + r.status);
      const blob = await r.blob();
      const blobUrl = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = blobUrl;
      const cd = r.headers.get('Content-Disposition') || '';
      const m = cd.match(/filename="([^"]+)"/);
      a.download = m ? m[1] : 'historique-pariscore.csv';
      document.body.appendChild(a); a.click();
      setTimeout(() => { URL.revokeObjectURL(blobUrl); a.remove(); }, 1000);
    } catch (e) {
      alert('Export CSV échoué : ' + (e?.message || 'Erreur réseau'));
    }
  });

  // H5 : Drill-down modal — clic ligne table → modal détail
  document.getElementById('dh-tbody').addEventListener('click', (e) => {
    const tr = e.target.closest('tr');
    if (!tr) return;
    const idx = Array.from(tr.parentNode.children).indexOf(tr);
    if (idx < 0) return;
    if (window._dhLastData?.matches?.[idx]) {
      _dhOpenDrillModal(window._dhLastData.matches[idx]);
    }
  });

  // Apply default period now (90j)
  _dhApplyPeriod();
}

function _renderLegacyHistorique(data) {
  // Conserve l'ancien rendu (KPI + chart legacy + table legacy) pour le mode héritage déplié.
  // Cette fonction est appelée en parallèle pour ne pas casser le bloc <details>.
  renderHistorique(data);
}

function renderHistorique(data) {
  const acc     = data.accuracy || {};
  const matches = data.matches  || [];

  const alertEl = document.getElementById('hist-alert');
  if (alertEl && acc.alert) {
    if (acc.alert.triggered) {
      alertEl.style.display = 'block';
      document.getElementById('hist-alert-detail').textContent =
        'Over 2.5: ' + acc.alert.over25 + '% (' + acc.alert.over25_bets + ' paris) · BTTS: ' + acc.alert.btts + '% · Total: ' + acc.alert.total + ' paris';
    } else {
      alertEl.style.display = 'none';
    }
  }

  const kpis = [
    { label: 'Win Rate Over 2.5', val: acc.over25?.rate != null ? acc.over25.rate + '%' : '—', sub: `${acc.over25?.sample || 0} paris tracés`, color: histKpiColor(acc.over25?.rate) },
    { label: 'Win Rate BTTS',     val: acc.btts?.rate   != null ? acc.btts.rate   + '%' : '—', sub: `${acc.btts?.sample   || 0} paris tracés`, color: histKpiColor(acc.btts?.rate) },
    { label: 'Win Rate Edge',     val: acc.edge?.rate   != null ? acc.edge.rate   + '%' : '—', sub: `${acc.edge?.sample   || 0} paris tracés`, color: histKpiColor(acc.edge?.rate) },
    { label: 'Matchs vérifiés',   val: acc.total_verified || 0,                                sub: `${data.total || 0} archivés au total`,    color: 'neutral' },
  ];
  // Rolling 30 badge
  if (acc.rolling30?.sample) {
    kpis.push({
      label: 'Rolling 30 Over 2.5',
      val: acc.rolling30.over25?.rate != null ? acc.rolling30.over25.rate + '%' : '—',
      sub: `${acc.rolling30.sample} derniers`,
      color: histKpiColor(acc.rolling30.over25?.rate),
    });
  }
  document.getElementById('hist-kpis').innerHTML = kpis.map(k => `
    <div class="hist-kpi">
      <div class="hist-kpi-label">${k.label}</div>
      <div class="hist-kpi-val ${k.color}">${k.val}</div>
      <div class="hist-kpi-sub">${k.sub}</div>
    </div>`).join('') + (acc.leagues ? `<div style="grid-column:1/-1;display:flex;gap:8px;flex-wrap:wrap;margin-top:8px;">` +
      Object.entries(acc.leagues).map(([lg, d]) =>
        `<span class="league-badge" title="${lg}">${lg} <b>${d.over25?.rate ?? '—'}%</b> <small>(${d.over25?.sample || 0})</small></span>`
      ).join('') + `</div>` : '');

  renderHistChart(matches);
  renderBttsChart(matches);
  renderAccuracyTrendChart();
  renderBankrollChart();
  renderHistTable(matches);
}

function renderHistChart(matches) {
  const ctx = document.getElementById('hist-chart').getContext('2d');
  if (histChartInstance) { histChartInstance.destroy(); histChartInstance = null; }

  const bets = matches.filter(m => m.verified && m.predicted?.over25 > 55 && m.realScore != null)
                      .slice().reverse();
  if (!bets.length) return;

  let cumul = 0;
  const labels = [], values = [];
  bets.forEach(m => {
    const total = (m.realScore.home || 0) + (m.realScore.away || 0);
    cumul += total > 2.5 ? 1 : -1;
    labels.push(fmtKickoffDate(m.commence_time, { day: 'numeric', month: 'short' }, '—'));
    values.push(cumul);
  });

  const lineColor = cumul >= 0 ? '#00e676' : '#ff4d4d';
  const fillColor = cumul >= 0 ? 'rgba(0,230,118,0.07)' : 'rgba(255,77,77,0.07)';

  histChartInstance = new Chart(ctx, {
    type: 'line',
    data: {
      labels,
      datasets: [{ data: values, borderColor: lineColor, backgroundColor: fillColor, borderWidth: 2,
        pointRadius: values.length > 30 ? 0 : 3, pointHoverRadius: 5, fill: true, tension: 0.3 }],
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: { legend: { display: false }, tooltip: {
        callbacks: { label: c => (c.parsed.y >= 0 ? '+' : '') + c.parsed.y + ' u' }
      }},
      scales: {
        x: { ticks: { color: '#5a6068', font: { size: 10 }, maxTicksLimit: 9 }, grid: { color: 'rgba(255,255,255,.04)' } },
        y: { ticks: { color: '#5a6068', font: { size: 10 }, callback: v => (v >= 0 ? '+' : '') + v },
             grid: { color: 'rgba(255,255,255,.04)' }, border: { dash: [3, 3] } },
      },
    },
  });
}

function renderBttsChart(matches) {
  const el = document.getElementById('hist-btts-chart');
  if (!el) return;
  const ctx = el.getContext('2d');
  if (window.bttsChartInstance) { window.bttsChartInstance.destroy(); window.bttsChartInstance = null; }

  const bets = matches.filter(m => m.verified && m.predicted?.btts > 55 && m.realScore != null).slice().reverse();
  if (!bets.length) { el.parentElement.style.display = 'none'; return; }
  el.parentElement.style.display = 'block';

  let cumul = 0;
  const labels = [], values = [];
  bets.forEach(m => {
    const rs = m.realScore;
    const wasBTTS = (rs.home || 0) > 0 && (rs.away || 0) > 0;
    cumul += wasBTTS ? 1 : -1;
    labels.push(fmtKickoffDate(m.commence_time, { day: 'numeric', month: 'short' }, '—'));
    values.push(cumul);
  });

  const lineColor = cumul >= 0 ? '#00e676' : '#ff4d4d';
  const fillColor = cumul >= 0 ? 'rgba(0,230,118,0.07)' : 'rgba(255,77,77,0.07)';

  window.bttsChartInstance = new Chart(ctx, {
    type: 'line',
    data: {
      labels,
      datasets: [{ data: values, borderColor: lineColor, backgroundColor: fillColor, borderWidth: 2,
        pointRadius: values.length > 30 ? 0 : 3, pointHoverRadius: 5, fill: true, tension: 0.3 }],
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: { legend: { display: false }, tooltip: {
        callbacks: { label: c => (c.parsed.y >= 0 ? '+' : '') + c.parsed.y + ' u' }
      }},
      scales: {
        x: { ticks: { color: '#5a6068', font: { size: 10 }, maxTicksLimit: 9 }, grid: { color: 'rgba(255,255,255,.04)' } },
        y: { ticks: { color: '#5a6068', font: { size: 10 }, callback: v => (v >= 0 ? '+' : '') + v },
             grid: { color: 'rgba(255,255,255,.04)' }, border: { dash: [3, 3] } },
      },
    },
  });
}

let accuracyTrendChart = null;
let bankrollChart = null;

async function renderBankrollChart() {
  const wrap = document.getElementById('bankroll-wrap');
  if (!wrap) return;
  try {
    const res = await fetch('/api/v1/bankroll/simulated');
    if (!res.ok) { wrap.style.display = 'none'; return; }
    const d = await res.json();
    if (!d.bets || !d.bets.length) { wrap.style.display = 'none'; return; }
    wrap.style.display = 'block';

    document.getElementById('bankroll-kpis').innerHTML = [
      { label: 'Bankroll (100u)', val: d.finalBankroll + 'u', color: d.totalPL >= 0 ? 'var(--green)' : 'var(--red)' },
      { label: 'P&L', val: (d.totalPL >= 0 ? '+' : '') + d.totalPL + 'u', color: d.totalPL >= 0 ? 'var(--green)' : 'var(--red)' },
      { label: 'ROI/parl', val: (d.roi >= 0 ? '+' : '') + d.roi + '%', color: d.roi >= 0 ? 'var(--green)' : 'var(--red)' },
      { label: 'Win Rate', val: d.winRate + '%', sub: d.wonBets + '/' + d.totalBets, color: 'var(--text2)' },
      { label: 'Drawdown Max', val: '-' + d.maxDrawdown + '%', color: 'var(--amber)' },
    ].map(k => `<div class="hist-kpi"><div class="hist-kpi-label">${k.label}</div><div class="hist-kpi-val" style="color:${k.color}">${k.val}</div>${k.sub ? `<div class="hist-kpi-sub">${k.sub}</div>` : ''}</div>`).join('');

    const ctx = document.getElementById('hist-bankroll-chart').getContext('2d');
    if (bankrollChart) { bankrollChart.destroy(); bankrollChart = null; }
    const labels = d.bets.map(b => new Date(b.date).toLocaleDateString('fr-FR', { day:'numeric', month:'short' }));
    const values = d.bets.map(b => b.bankroll);
    const startVal = d.startBankroll;
    bankrollChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels,
        datasets: [{
          data: values, borderColor: '#29b6f6', backgroundColor: 'rgba(41,182,246,0.07)',
          borderWidth: 2, pointRadius: 0, fill: true, tension: 0.3,
        }],
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: { callbacks: { label: c => c.parsed.y + 'u (' + d.bets[c.dataIndex].market + ' ' + (d.bets[c.dataIndex].won ? '+1' : '-1') + ')' } }
        },
        scales: {
          x: { ticks: { color: '#5a6068', font: { size: 9 }, maxTicksLimit: 10 }, grid: { color: 'rgba(255,255,255,.04)' } },
          y: { ticks: { color: '#5a6068', font: { size: 9 }, callback: v => v + 'u' }, grid: { color: 'rgba(255,255,255,.04)' } },
        },
      },
    });
  } catch(e) { wrap.style.display = 'none'; }
}

async function renderAccuracyTrendChart() {
  const el = document.getElementById('hist-accuracy-trend');
  if (!el) return;
  const ctx = el.getContext('2d');
  if (accuracyTrendChart) { accuracyTrendChart.destroy(); accuracyTrendChart = null; }
  try {
    const res = await fetch('/api/v1/accuracy/trends?weeks=12');
    if (!res.ok) return;
    const data = await res.json();
    if (!data.length) return;
    document.getElementById('accuracy-trend-wrap').style.display = 'block';
    const labels = data.map(d => d.week.replace('-W', ' S'));
    const over25 = data.map(d => d.over25);
    const btts = data.map(d => d.btts);
    accuracyTrendChart = new Chart(ctx, {
      type: 'bar',
      data: {
        labels,
        datasets: [
          { label: 'Over 2.5', data: over25, backgroundColor: 'rgba(0,230,118,0.5)', borderColor: '#00e676', borderWidth: 1, borderRadius: 3 },
          { label: 'BTTS', data: btts, backgroundColor: 'rgba(41,182,246,0.5)', borderColor: '#29b6f6', borderWidth: 1, borderRadius: 3 },
        ],
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { labels: { color: '#8d9399', font: { size: 10 }, boxWidth: 12, padding: 12 } },
          tooltip: {
            callbacks: {
              label: c => c.dataset.label + ': ' + c.parsed.y + '%  (' + data[c.dataIndex][c.dataset.label === 'Over 2.5' ? 'over25_bets' : 'btts_bets'] + ' paris)'
            }
          }
        },
        scales: {
          x: { ticks: { color: '#5a6068', font: { size: 9 } }, grid: { color: 'rgba(255,255,255,.04)' } },
          y: { min: 0, max: 100, ticks: { color: '#5a6068', font: { size: 9 }, callback: v => v + '%' },
               grid: { color: 'rgba(255,255,255,.04)' } },
        },
      },
    });
  } catch(e) { /* ignore */ }
}

function renderHistTable(matches) {
  const tbody   = document.getElementById('hist-tbody');
  const emptyEl = document.getElementById('hist-empty');
  if (!matches.length) { tbody.innerHTML = ''; emptyEl.style.display = 'block'; return; }
  emptyEl.style.display = 'none';

  tbody.innerHTML = matches.map(m => {
    const dateStr = fmtKickoffDate(m.commence_time, { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' });
    const score   = m.realScore != null
      ? `<span class="hist-score">${m.realScore.home}&nbsp;-&nbsp;${m.realScore.away}</span>`
      : `<span class="hist-score unverified">—</span>`;

    function predBadge(prob, won) {
      if (prob == null) return `<span class="hist-badge skip">—</span>`;
      if (prob <= 55 || won == null) return `<span class="hist-badge skip">${prob}%</span>`;
      return `<span class="hist-badge ${won ? 'win' : 'loss'}">${won ? '✓' : '✗'} ${prob}%</span>`;
    }

    const over25Won = m.realScore != null ? (m.realScore.home + m.realScore.away) > 2.5 : null;
    const bttsWon   = m.realScore != null ? (m.realScore.home > 0 && m.realScore.away > 0) : null;
    const edgeLabel = m.predicted?.bestEdge;
    const edgeVal   = m.predicted?.bestEdgeValue;
    const edgeStr   = edgeLabel
      ? `${edgeLabel}${edgeVal != null ? ' <span style="color:var(--text3);">' + (edgeVal >= 0 ? '+' : '') + safeFixed(edgeVal, 1) + '%</span>' : ''}`
      : '—';

    return `<tr>
      <td>
        <div class="hist-team">${m.home_team}</div>
        <div class="hist-away">${m.away_team}</div>
        <div style="font-size:10px;color:var(--text3);margin-top:2px;">${m.league}</div>
      </td>
      <td class="hist-date">${dateStr}</td>
      <td>${score}</td>
      <td>${predBadge(m.predicted?.over25, over25Won)}</td>
      <td>${predBadge(m.predicted?.btts, bttsWon)}</td>
      <td style="color:var(--text2);font-size:12px;">${edgeStr}</td>
    </tr>`;
  }).join('');
}

// ═══════════════════════════════════════════════════════════════════════════════
//  BACK-TEST UI — Premium/Admin
// ═══════════════════════════════════════════════════════════════════════════════

let _btUserCache = null;

async function _btGetUser() {
  if (_btUserCache) return _btUserCache;
  try {
    const res = await apiFetch('/api/v1/me');
    if (!res.ok) return null;
    _btUserCache = await res.json();
    return _btUserCache;
  } catch { return null; }
}

function checkBacktestAccess() {
  _checkBacktestAccess();
}

async function _checkBacktestAccess() {
  const user = await _btGetUser();
  const section = document.getElementById('backtest-section');
  if (section && user && (user.role === 'premium' || user.role === 'admin')) {
    section.style.display = 'block';
  }
}

async function triggerBacktest() {
  const user = await _btGetUser();
  if (!user || (user.role !== 'premium' && user.role !== 'admin')) {
    document.getElementById('backtest-status').textContent = '⚠ Premium requis';
    return;
  }

  const days = document.getElementById('backtest-days').value;
  const statusEl = document.getElementById('backtest-status');
  statusEl.textContent = '⏳ Back-test en cours…';
  statusEl.style.color = 'var(--amber)';

  try {
    const res = await apiFetch('/api/v1/admin/backtest-bsd', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ days: parseInt(days) })
    });
    const data = await res.json();
    if (data.ok) {
      statusEl.style.color = 'var(--green)';
      statusEl.textContent = `✓ ${data.new_verified} vérifiés sur ${data.days_scanned}j (existants: ${data.already_verified})`;
      if (data.accuracy?.rolling30) {
        const r = data.accuracy.rolling30;
        const over = r.over25 ? `${r.over25.rate}%` : '—';
        const btts = r.btts ? `${r.btts.rate}%` : '—';
        statusEl.textContent += ` · Over: ${over} · BTTS: ${btts}`;
      }
      if (histPageLoaded) initHistoriquePage();
    } else {
      statusEl.style.color = 'var(--red)';
      statusEl.textContent = '⚠ ' + (data.error || 'Erreur inconnue');
    }
  } catch(e) {
    statusEl.style.color = 'var(--red)';
    statusEl.textContent = '⚠ Erreur réseau';
  }
}

// TRENDS — connecté à /api/v1/trends
async function loadTrends() {
  const grid = document.getElementById('trends-grid');
  grid.innerHTML = '<div style="color:#888;font-size:13px;padding:20px;">Chargement des tendances…</div>';
  try {
    const res  = await apiFetch('/api/v1/trends');
    if (!res.ok) throw new Error();
    const data = await res.json();
    if (data.error) throw new Error(data.error);
    const g = data.global;
    const trends = [
      { name:'Les deux équipes marquent', sub:`Probabilité moyenne · ${g.total_matches} matchs`, pct: parseFloat(g.btts_avg), meta: `xG dom ${g.xg_home_avg} · xG ext ${g.xg_away_avg}`, tags: data.by_league.slice(0,3).map(l=>l.league) },
      { name:'+2.5 buts',                sub:'Probabilité moyenne tous matchs',              pct: parseFloat(g.over25_avg), meta: `${data.value_bets_count} value bets actifs (edge >5%)`, tags: data.by_league.slice(0,3).map(l=>l.league) },
    ];
    data.by_league.slice(0, 4).forEach(l => {
      trends.push({ name: l.league, sub:`${l.count} matchs analysés`, pct: parseFloat(l.over25_avg), meta:`BTTS moy: ${l.btts_avg}%`, tags:[] });
    });
    grid.style.display = 'flex';
    grid.style.flexDirection = 'column';
    grid.style.gap = '8px';
    grid.innerHTML = trends.map(t => {
      const pctColor = t.pct >= 55 ? '#E2001A' : t.pct >= 45 ? '#1A1A1A' : '#888';
      const barColor = t.pct >= 55 ? '#E2001A' : '#1A1A1A';
      const tagsHtml = t.tags.length ? `<div style="display:flex;gap:4px;flex-wrap:wrap;margin-top:4px;">${t.tags.map(l=>`<span style="background:#F4F4F4;color:#888;font-size:9px;font-weight:600;padding:2px 7px;border-radius:10px;text-transform:uppercase;letter-spacing:.04em;">${l}</span>`).join('')}</div>` : '';
      return `<div class="ps-pill-card" style="flex-direction:column;align-items:stretch;gap:8px;padding:16px 20px;">
        <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;">
          <div style="flex:1;min-width:0;">
            <div class="ppc-teams" style="font-size:14px;">${t.name}</div>
            <div class="ppc-sub">${t.sub}</div>
          </div>
          <div class="ppc-odds" style="font-size:26px;color:${pctColor};">${t.pct}%</div>
        </div>
        <div style="background:#F4F4F4;border-radius:4px;height:4px;overflow:hidden;">
          <div style="height:4px;border-radius:4px;background:${barColor};width:${Math.min(100,t.pct)}%;transition:width .4s;"></div>
        </div>
        <div style="display:flex;align-items:center;justify-content:space-between;">
          <div style="font-size:11px;color:#888;">${t.meta}</div>
          ${tagsHtml}
        </div>
      </div>`;
    }).join('');
  } catch(e) {
    grid.innerHTML = '<div style="color:#888;padding:20px;font-size:13px;">⚠ Lancez node server.js pour charger les tendances.</div>';
  }
}
// ═══════════════════════════════════════════════════════════════════════════════
//  PAGE GUIDE / DOCUMENTATION
// ═══════════════════════════════════════════════════════════════════════════════
let guideLoaded = false;

function scrollToSection(sectionId) {
  const el = document.getElementById(sectionId);
  if (el) {
    el.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

// Pastille « i » filtre Top stratégies → onglet Guide, section Stratégies
function openStrategiesGuide() {
  try { if (typeof tsClose === 'function') tsClose(); } catch (e) {}
  try {
    if (typeof showPage === 'function') showPage('guide');
  } catch (e) {}
  setTimeout(function () {
    try { scrollToSection('guide-strategies'); } catch (e) {}
  }, 250);
}

// Pastille « ⓘ » module DR Live (colonne 3) → Guide, section Dominance Ratio
function openTennisDRGuide() {
  try { if (typeof showPage === 'function') showPage('guide'); } catch (e) {}
  setTimeout(function () {
    try { scrollToSection('guide-dr'); } catch (e) {}
  }, 250);
}

function initStaticGuideNav() {
  if (guideLoaded) return;
  // Collect all navigable section anchors from the static guide
  const sections = Array.from(document.querySelectorAll(
    '#page-guide h2, #page-guide .gs-article-title'
  ));
  if (!sections.length) return;
  window.guideSections = sections;
  window.guideCurrentSection = 0;
  guideLoaded = true;
  // Sync button states
  const prev = document.getElementById('guide-prev-btn');
  const next = document.getElementById('guide-next-btn');
  if (prev) prev.classList.add('disabled');
  if (next) next.classList.toggle('disabled', sections.length <= 1);
}

function loadGuidePage() {
  if (guideLoaded) return;
  const container = document.getElementById('guide-content');
  const tocContainer = document.getElementById('toc-items');
  if (!container) return;

  fetch('/api/v1/guide')
    .then(res => res.json())
    .then(data => {
      const content = data.content;
      let html = '';
      let tocHtml = '';

      const lines = content.split('\n');
      let inCodeBlock = false;
      let codeContent = [];
      let currentH2 = '';
      let sectionIndex = 0;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];

        if (line.startsWith('```')) {
          if (inCodeBlock) {
            html += `<pre><code>${codeContent.join('\n')}</code></pre>`;
            codeContent = [];
            inCodeBlock = false;
          } else {
            inCodeBlock = true;
          }
          continue;
        }

        if (inCodeBlock) {
          codeContent.push(line);
          continue;
        }

        if (line.startsWith('# ')) {
          continue;
        } else if (line.startsWith('## ')) {
          const title = line.replace('## ', '');
          const slug = title.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
          currentH2 = title;
          tocHtml += `<div class="toc-item chapter" data-section="${slug}">${title}</div>`;
          html += `<h2 id="${slug}">${title}</h2>`;
          sectionIndex++;
        } else if (line.startsWith('### ')) {
          const title = line.replace('### ', '');
          const slug = title.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
          tocHtml += `<div class="toc-item" data-section="${currentH2.toLowerCase().replace(/[^a-z0-9]/g, '-')}-${slug}">${title}</div>`;
          html += `<h3 id="${currentH2.toLowerCase().replace(/[^a-z0-9]/g, '-')}-${slug}">${title}</h3>`;
        } else if (line.startsWith('| ')) {
          if (!html.includes('<table>')) {
            html += '<table>';
          }
          if (line.includes('---')) continue;
          const cols = line.split('|').filter(c => c.trim());
          const isHeader = i > 0 && lines[i-1].includes('---');
          if (isHeader) {
            html += '<thead><tr>';
            cols.forEach(c => html += `<th>${c.trim()}</th>`);
            html += '</tr></thead><tbody>';
          } else {
            html += '<tr>';
            cols.forEach(c => html += `<td>${c.trim()}</td>`);
            html += '</tr>';
          }
          if (i < lines.length - 1 && !lines[i+1].startsWith('|')) {
            html += '</tbody></table>';
          }
        } else if (line.startsWith('- **')) {
          const match = line.match(/^- \*\*([^*]+)\*\*:?\s*(.*)$/);
          if (match) {
            html += `<div class="guide-card"><div class="guide-card-label">${match[1]}</div><div class="guide-card-desc">${match[2]}</div></div>`;
          }
        } else if (line.startsWith('- ')) {
          html += `<li>${line.replace('- ', '')}</li>`;
        } else if (/^!\[.*\]\(.*\)$/.test(line)) {
          const match = line.match(/^!\[([^\]]*)\]\(([^)]+)\)$/);
          if (match) {
            html += `<img src="${match[2]}" alt="${match[1]}" style="max-width:100%;height:auto;border-radius:8px;margin:12px 0;">`;
          }
        } else if (/^---+$/.test(line) || /^___+$/.test(line)) {
          html += '<hr style="border:none;border-top:1px solid var(--border);margin:16px 0;">';
        } else if (/^\d+\.\s\[.+\]\(#.+\)$/.test(line)) {
          // Markdown link style: 1. [Text](#anchor)
          const match = line.match(/^\d+\.\s\[([^\]]+)\]\(([^)]+)\)$/);
          if (match) {
            const text = match[1];
            const anchor = match[2];
            html += `<a href="#${anchor}" class="toc-link" data-anchor="${anchor}">${text}</a>`;
          }
        } else if (/^\d+\.\s/.test(line)) {
          html += `<li>${line.replace(/^\d+\.\s/, '')}</li>`;
        } else if (line.trim()) {
          let processed = line
            .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
            .replace(/\*([^*]+)\*/g, '<em>$1</em>')
            .replace(/`([^`]+)`/g, '<code>$1</code>');
          if (processed.includes('<code>') || processed.includes('<strong>') || processed.includes('<em>')) {
            html += `<p>${processed}</p>`;
          } else if (processed.length > 50) {
            html += `<p>${processed}</p>`;
          }
        }
      }

      html = html.replace(/<li>/g, '<ul><li>').replace(/<\/li>(?=<li>)/g, '</li></ul><ul><li>').replace(/<\/li>(?=<p>)/g, '</li></ul>');

      container.innerHTML = html;
      if (tocContainer) tocContainer.innerHTML = tocHtml;

      // Stocker le contenu original pour la recherche
      window.guideRawContent = content;

      document.querySelectorAll('.toc-item').forEach(item => {
        item.addEventListener('click', () => {
          const section = item.dataset.section;
          const el = document.getElementById(section);
          if (el) {
            el.scrollIntoView({ behavior: 'smooth', block: 'start' });
            document.querySelectorAll('.toc-item').forEach(t => t.classList.remove('active'));
            item.classList.add('active');
          }
        });
      });

      // === RECHERCHE GUIDE ===
      const searchInput = document.getElementById('guide-search');
      if (searchInput) {
        let searchResultsContainer = document.createElement('div');
        searchResultsContainer.className = 'guide-search-results';
        searchInput.parentNode.appendChild(searchResultsContainer);

        searchInput.addEventListener('input', function() {
          const query = this.value.toLowerCase().trim();
          if (query.length < 2) {
            searchResultsContainer.classList.remove('active');
            return;
          }

          const lines = content.split('\n');
          const matches = [];
          let currentSection = '';

          lines.forEach((line, idx) => {
            if (line.startsWith('## ')) currentSection = line.replace('## ', '');
            if (line.toLowerCase().includes(query) && !line.startsWith('|') && !line.startsWith('```')) {
              const preview = line.replace(/[*#`]/g, '').trim().substring(0, 80);
              matches.push({ section: currentSection, line: preview, index: idx });
            }
          });

          if (matches.length === 0) {
            searchResultsContainer.innerHTML = '<div class="guide-search-no-results">Aucun résultat trouvé</div>';
          } else {
            searchResultsContainer.innerHTML = matches.slice(0, 8).map(m => 
              `<div class="guide-search-result-item" data-index="${m.index}">
                <strong>${m.section}</strong><br>
                <span>${m.line.replace(new RegExp('('+query+')', 'gi'), '<mark>$1</mark>')}</span>
              </div>`
            ).join('');
          }
          searchResultsContainer.classList.add('active');

          // Click sur résultat -> scroll vers section
          searchResultsContainer.querySelectorAll('.guide-search-result-item').forEach(item => {
            item.addEventListener('click', () => {
              const idx = parseInt(item.dataset.index);
              // Trouver le h2 ou h3 le plus proche avant cet index
              let targetId = '';
              for (let i = idx; i >= 0; i--) {
                if (lines[i].startsWith('## ')) {
                  const title = lines[i].replace('## ', '');
                  targetId = title.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
                  break;
                }
              }
              const el = document.getElementById(targetId);
              if (el) {
                el.scrollIntoView({ behavior: 'smooth', block: 'start' });
                // Highlight temporaire
                el.style.transition = 'background 0.3s';
                el.style.background = 'rgba(41,182,246,0.15)';
                setTimeout(() => el.style.background = '', 1500);
              }
              searchResultsContainer.classList.remove('active');
              searchInput.value = '';
            });
          });
        });

        // Fermer recherche en dehors
        document.addEventListener('click', function(e) {
          if (!searchInput.contains(e.target) && !searchResultsContainer.contains(e.target)) {
            searchResultsContainer.classList.remove('active');
          }
        });
      }

      // Clic sur liens TOC markdown
      document.querySelectorAll('.toc-link').forEach(link => {
        link.addEventListener('click', function(e) {
          e.preventDefault();
          const anchor = this.dataset.anchor;
          const el = document.getElementById(anchor);
          if (el) {
            el.scrollIntoView({ behavior: 'smooth', block: 'start' });
            el.style.transition = 'background 0.3s';
            el.style.background = 'rgba(41,182,246,0.15)';
            setTimeout(() => el.style.background = '', 1500);
          }
        });
      });

      // === CALCULATRICES GUIDE ===
      const calcPanel = document.createElement('div');
      calcPanel.className = 'guide-calc-panel';
      calcPanel.innerHTML = `
        <div class="guide-calc-title">🧮 Outils de Calcul</div>
        <div class="guide-calc-tabs">
          <button class="guide-calc-tab active" data-tab="margin">Marge</button>
          <button class="guide-calc-tab" data-tab="odds">Cotes</button>
          <button class="guide-calc-tab" data-tab="payout">Gain</button>
        </div>
        
        <!-- Calculatrice Marge -->
        <div class="guide-calc-section active" data-section="margin">
          <div class="guide-calc-label">Cote Domicile</div>
          <input type="number" class="guide-calc-input" id="calc-margin-h" placeholder="ex: 1.85" step="0.01">
          <div class="guide-calc-label" style="margin-top:8px">Cote Nul</div>
          <input type="number" class="guide-calc-input" id="calc-margin-d" placeholder="ex: 3.40" step="0.01">
          <div class="guide-calc-label" style="margin-top:8px">Cote Exterieur</div>
          <input type="number" class="guide-calc-input" id="calc-margin-a" placeholder="ex: 4.50" step="0.01">
          <button class="guide-calc-btn" onclick="calcMargin()" style="width:100%;margin-top:12px">Calculer la marge</button>
          <div id="calc-margin-result" class="guide-calc-result"></div>
        </div>

        <!-- Convertisseur Cotes -->
        <div class="guide-calc-section" data-section="odds">
          <div class="guide-calc-label">Cote Decimale</div>
          <input type="number" class="guide-calc-input" id="calc-odds-dec" placeholder="ex: 2.50" step="0.01">
          <button class="guide-calc-btn" onclick="calcOdds()" style="width:100%;margin-top:12px">Convertir</button>
          <div id="calc-odds-result" class="guide-calc-result"></div>
        </div>

        <!-- Calculateur Gain -->
        <div class="guide-calc-section" data-section="payout">
          <div class="guide-calc-label">Cote</div>
          <input type="number" class="guide-calc-input" id="calc-payout-odds" placeholder="ex: 2.00" step="0.01">
          <div class="guide-calc-label" style="margin-top:8px">Mise (€)</div>
          <input type="number" class="guide-calc-input" id="calc-payout-stake" placeholder="ex: 100" step="1">
          <button class="guide-calc-btn" onclick="calcPayout()" style="width:100%;margin-top:12px">Calculer</button>
          <div id="calc-payout-result" class="guide-calc-result"></div>
        </div>
      `;

      // Insert calculators at top of content
      container.insertBefore(calcPanel, container.firstChild);

      // Tab switching
      calcPanel.querySelectorAll('.guide-calc-tab').forEach(tab => {
        tab.addEventListener('click', function() {
          calcPanel.querySelectorAll('.guide-calc-tab').forEach(t => t.classList.remove('active'));
          calcPanel.querySelectorAll('.guide-calc-section').forEach(s => s.classList.remove('active'));
          this.classList.add('active');
          calcPanel.querySelector('[data-section="' + this.dataset.tab + '"]').classList.add('active');
        });
      });

      // === GLOSSAIRE FLOTTANT ===
      const glossaryTerms = [
        { term: 'EV (Expected Value)', def: 'Valeur attendue - Profit moyen attendu par unite misee. EV = (probabilité de gain × gain) - (probabilité de perte × mise)' },
        { term: 'ELO', def: 'Système de classement de la force des équipes. Échelle: 1500 (débutant) à 2500+ (élite mondiale)' },
        { term: 'xG (Expected Goals)', def: 'Nombre de buts attendus basé sur la qualité des occasions. xG = somme des probabilités de chaque tir' },
        { term: 'PPG', def: 'Points Par Match - Moyenne de points obtenus par match' },
        { term: 'Overround', def: 'Marge du bookmaker - Surplus par rapport à 100% des probabilités' },
        { term: 'BTTS', def: 'Both To Score - Les deux équipes marquent au moins un but' },
        { term: 'Draw No Bet', def: 'Victoire avec remboursement si match nul' },
        { term: 'Handicap', def: 'Avantage ou désavantage de points ajouté au score final' },
        { term: 'Arbitrage', def: 'Mise sur tous les résultats pour garantir un profit quelle que soit l\'issue' },
        { term: 'Value Bet', def: 'Pari où la probabilité réelle est supérieure à la probabilité implicite de la cote' }
      ];

      const helpBtn = document.createElement('button');
      helpBtn.className = 'guide-help-btn';
      helpBtn.innerHTML = '?';
      helpBtn.title = 'Glossaire';
      document.body.appendChild(helpBtn);

      const helpPanel = document.createElement('div');
      helpPanel.className = 'guide-help-panel';
      helpPanel.innerHTML = `
        <div class="guide-help-header">📖 Glossaire Rapide</div>
        <div class="guide-help-search">
          <input type="text" id="help-search-input" placeholder="Rechercher un terme...">
        </div>
        <div class="guide-help-list" id="help-list"></div>
      `;
      document.body.appendChild(helpPanel);

      // Populate glossary
      const renderGlossary = (filter = '') => {
        const filtered = glossaryTerms.filter(t => t.term.toLowerCase().includes(filter.toLowerCase()) || t.def.toLowerCase().includes(filter.toLowerCase()));
        document.getElementById('help-list').innerHTML = filtered.map(t => `
          <div class="guide-help-item" onclick="document.getElementById('help-search-input').value='${t.term}';renderGlossary('${t.term}')">
            <div class="guide-help-term">${t.term}</div>
            <div class="guide-help-def">${t.def}</div>
          </div>
        `).join('');
      };
      renderGlossary();

      // Search glossary
      document.getElementById('help-search-input').addEventListener('input', function() {
        renderGlossary(this.value);
      });

      // Toggle panel
      helpBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        helpPanel.classList.toggle('open');
      });

      document.addEventListener('click', function(e) {
        if (!helpBtn.contains(e.target) && !helpPanel.contains(e.target)) {
          helpPanel.classList.remove('open');
        }
      });

      // === NAVIGATION AMELIOREE ===
      // Ajouter progress et breadcrumb
      const allH2 = container.querySelectorAll('h2');
      const totalSections = allH2.length;
      
      // Breadcrumb
      const breadcrumb = document.createElement('div');
      breadcrumb.className = 'guide-nav-breadcrumb';
      breadcrumb.innerHTML = '<a href="#" onclick="showPage(\'home\');return false;">Home</a> / Guide / <span id="current-section">Introduction</span>';
      container.insertBefore(breadcrumb, container.firstChild);

      // Progress bar
      const progress = document.createElement('div');
      progress.className = 'guide-nav-progress';
      progress.innerHTML = `<span>Progression</span><div class="guide-nav-progress-bar"><div class="guide-nav-progress-fill" id="guide-progress-fill" style="width:8%"></div></div><span id="guide-progress-text">1/${totalSections}</span>`;
      container.insertBefore(progress, breadcrumb.nextSibling);

      // Track scroll for progress
      container.addEventListener('scroll', function() {
        const scrollTop = container.scrollTop;
        const scrollHeight = container.scrollHeight - container.clientHeight;
        const progressPct = scrollHeight > 0 ? Math.round((scrollTop / scrollHeight) * 100) : 0;
        const sectionPct = Math.max(8, Math.min(100, 8 + (progressPct * 0.85)));
        document.getElementById('guide-progress-fill').style.width = sectionPct + '%';
        
        // Update current section name
        let currentSection = 'Introduction';
        allH2.forEach((h2, i) => {
          const rect = h2.getBoundingClientRect();
          if (rect.top <= 100) {
            currentSection = h2.textContent;
            document.getElementById('guide-progress-text').textContent = (i + 1) + '/' + totalSections;
          }
        });
        document.getElementById('current-section').textContent = currentSection;
      });

      // Add navigation arrows at bottom
      const navArrows = document.createElement('div');
      navArrows.className = 'guide-nav-arrows';
      
      const prevBtn = document.createElement('a');
      prevBtn.className = 'guide-nav-arrow disabled';
      prevBtn.id = 'guide-prev-btn';
      prevBtn.innerHTML = '← Précédent';
      prevBtn.onclick = function() { guideNavigate(-1); return false; };
      
      const nextBtn = document.createElement('a');
      nextBtn.className = 'guide-nav-arrow';
      nextBtn.id = 'guide-next-btn';
      nextBtn.innerHTML = 'Suivant →';
      nextBtn.onclick = function() { guideNavigate(1); return false; };
      
      navArrows.appendChild(prevBtn);
      navArrows.appendChild(nextBtn);
      container.appendChild(navArrows);

      // Store h2 elements for navigation
      window.guideSections = Array.from(allH2);

      // Update nav buttons state
      window.guideCurrentSection = 0;
      const updateNavButtons = () => {
        prevBtn.classList.toggle('disabled', window.guideCurrentSection === 0);
        nextBtn.classList.toggle('disabled', window.guideCurrentSection >= window.guideSections.length - 1);
      };
      updateNavButtons();

      guideLoaded = true;
    })
    .catch(e => {
      container.innerHTML = '<div class="guide-loading" style="color:var(--red);">Erreur chargement guide. Assurez-vous que le serveur est actif.</div>';
    });
}

// FONCTIONS CALCULATRICES ET NAVIGATION GUIDE
function calcMargin(){var h=parseFloat(document.getElementById('calc-margin-h').value);var d=parseFloat(document.getElementById('calc-margin-d').value);var a=parseFloat(document.getElementById('calc-margin-a').value);var r=document.getElementById('calc-margin-result');if(!h||!d||!a){r.innerHTML='Entrez les 3 cotes';r.classList.remove('negative');return}var total=(1/h)+(1/d)+(1/a);var margin=((total-1)*100).toFixed(2);r.innerHTML='Marge: <strong>'+margin+'%</strong>';r.classList.toggle('negative',parseFloat(margin)>7)}
function calcOdds(){var d=parseFloat(document.getElementById('calc-odds-dec').value);var r=document.getElementById('calc-odds-result');if(!d||d<=1){r.innerHTML='Cote invalide';return}var imp=(1/d*100).toFixed(1);var frac=d>=2?(d-1)+'/1':'1/'+(1/(d-1)).toFixed(2);var us=d>=2?Math.round((d-1)*100):Math.round(-100/(d-1));r.innerHTML='Dec:'+d+' | Implicite:'+imp+'% | Frac:'+frac+' | US:'+(us>0?'+':'')+us}
function calcPayout(){var o=parseFloat(document.getElementById('calc-payout-odds').value);var s=parseFloat(document.getElementById('calc-payout-stake').value);var r=document.getElementById('calc-payout-result');if(!o||!s||o<=1){r.innerHTML='Valeurs invalides';return}var profit=((o-1)*s).toFixed(2);var total=(o*s).toFixed(2);r.innerHTML='Profit: +'+profit+'€ | Total: '+total+'€'}
function guideNavigate(d){if(!window.guideSections)return;window.guideCurrentSection=Math.max(0,Math.min(window.guideSections.length-1,(window.guideCurrentSection||0)+d));window.guideSections[window.guideCurrentSection].scrollIntoView({behavior:'smooth',block:'start'});var p=document.getElementById('guide-prev-btn');var n=document.getElementById('guide-next-btn');if(p)p.classList.toggle('disabled',window.guideCurrentSection===0);if(n)n.classList.toggle('disabled',window.guideCurrentSection>=window.guideSections.length-1)}

// ═══════════════════════════════════════════════════════════════════════════════
//  DASHBOARD MES ALERTES
// ═══════════════════════════════════════════════════════════════════════════════
let alertesPageInit = false;

function initAlertesPage() {
  const user = psGetUser();
  const gate = document.getElementById('al-login-gate');
  const dash = document.getElementById('al-dashboard');
  if (!gate || !dash) return;
  if (!user) {
    gate.style.display = 'block';
    dash.style.display = 'none';
    return;
  }
  gate.style.display = 'none';
  dash.style.display = 'block';
  // chips market toggle
  document.querySelectorAll('#al-markets .al-chip').forEach(c => {
    c.addEventListener('click', () => c.classList.toggle('active'));
  });
  if (!alertesPageInit) { alertesPageInit = true; loadAlertConfig(); }
}

async function loadAlertConfig() {
  // 1. Miroir localStorage — préchargement instantané chatId
  try {
    const cached = JSON.parse(localStorage.getItem('ps_alert_prefs') || '{}');
    const chatEl0 = document.getElementById('al-chatid');
    if (chatEl0 && cached.chatId) chatEl0.value = cached.chatId;
  } catch {}
  // 2. Fetch DB authoritative
  try {
    const r = await apiFetch('/api/v1/alerts/config');
    if (!r.ok) return;
    const p = await r.json();
    const chatEl  = document.getElementById('al-chatid');
    const toggle  = document.getElementById('al-enabled-toggle');
    const label   = document.getElementById('al-enabled-label');
    const edgeEl  = document.getElementById('al-edge-slider');
    const edgeVal = document.getElementById('al-edge-val');
    const probaEl = document.getElementById('al-proba-slider');
    const probaVal= document.getElementById('al-proba-val');
    const leagSel = document.getElementById('al-league-select');
    if (chatEl)  chatEl.value  = p.chatId  || '';
    if (edgeEl)  { edgeEl.value  = p.edgeMin  ?? 8;  edgeVal.textContent  = (p.edgeMin  ?? 8)  + '%'; }
    if (probaEl) { probaEl.value = p.probaMin ?? 55; probaVal.textContent = (p.probaMin ?? 55) + '%'; }
    if (toggle && label) {
      toggle.classList.toggle('on', !!p.enabled);
      label.textContent = p.enabled ? 'Alertes actives' : 'Alertes désactivées';
      label.style.color = p.enabled ? 'var(--green)' : 'var(--text2)';
    }
    if (leagSel && p.leagues?.length) leagSel.value = p.leagues[0] || '';
    const mkts = p.markets || [];
    document.querySelectorAll('#al-markets .al-chip').forEach(c => {
      c.classList.toggle('active', mkts.includes(c.dataset.mkt));
    });
    // v9.9.5 — alertes live momentum/pressure
    const liveTog = document.getElementById('al-live-toggle');
    const liveLab = document.getElementById('al-live-label');
    if (liveTog && liveLab) {
      liveTog.classList.toggle('on', !!p.liveEnabled);
      liveLab.textContent = p.liveEnabled ? 'Activées' : 'Désactivées';
      liveLab.style.color = p.liveEnabled ? 'var(--green)' : 'var(--text2)';
    }
    const intEl = document.getElementById('al-intensity-slider');
    const intVal = document.getElementById('al-intensity-val');
    if (intEl && intVal) { intEl.value = p.intensityMin ?? 70; intVal.textContent = (p.intensityMin ?? 70) + '/100'; }
    const prEl = document.getElementById('al-pressure-slider');
    const prVal = document.getElementById('al-pressure-val');
    if (prEl && prVal) { prEl.value = p.pressureDeltaMin ?? 35; prVal.textContent = (p.pressureDeltaMin ?? 35); }
    loadAlertHistory();
  } catch {}
}

function toggleAlertEnabled() {
  const toggle = document.getElementById('al-enabled-toggle');
  const label  = document.getElementById('al-enabled-label');
  if (!toggle) return;
  const on = toggle.classList.toggle('on');
  label.textContent = on ? 'Alertes actives' : 'Alertes désactivées';
  label.style.color = on ? 'var(--green)' : 'var(--text2)';
}

function toggleAlertLiveEnabled() {
  const toggle = document.getElementById('al-live-toggle');
  const label  = document.getElementById('al-live-label');
  if (!toggle) return;
  const on = toggle.classList.toggle('on');
  label.textContent = on ? 'Activées' : 'Désactivées';
  label.style.color = on ? 'var(--green)' : 'var(--text2)';
}

async function testTelegramAlert() {
  const chatId = (document.getElementById('al-chatid')?.value || '').trim();
  const btn = document.getElementById('al-test-btn');
  const msg = document.getElementById('al-test-msg');
  if (!msg || !btn) return;
  if (!chatId) {
    msg.textContent = '⚠️ Saisissez votre Chat ID avant de tester';
    msg.style.color = 'var(--amber)';
    msg.style.display = 'inline-block';
    setTimeout(() => { msg.style.display = 'none'; }, 4000);
    return;
  }
  btn.disabled = true;
  const originalLabel = btn.textContent;
  btn.textContent = '⏳ Envoi…';
  try {
    const r = await apiFetch('/api/v1/alerts/test', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chatId }),
    });
    const data = await r.json().catch(() => ({}));
    if (r.ok) {
      msg.textContent = '✓ Message envoyé — vérifiez Telegram';
      msg.style.color = 'var(--green)';
    } else {
      msg.textContent = '✗ ' + (data.error || 'Échec de l\'envoi');
      msg.style.color = 'var(--red)';
    }
  } catch {
    msg.textContent = '✗ Erreur réseau — serveur injoignable';
    msg.style.color = 'var(--red)';
  } finally {
    btn.disabled = false;
    btn.textContent = originalLabel;
    msg.style.display = 'inline-block';
    setTimeout(() => { msg.style.display = 'none'; }, 5000);
  }
}

async function saveAlertConfig() {
  const chatId   = (document.getElementById('al-chatid')?.value || '').trim();
  const enabled  = document.getElementById('al-enabled-toggle')?.classList.contains('on') || false;
  const liveEnabled = document.getElementById('al-live-toggle')?.classList.contains('on') || false;
  const edgeMin  = parseFloat(document.getElementById('al-edge-slider')?.value)  || 0;
  const probaMin = parseInt(document.getElementById('al-proba-slider')?.value) || 50;
  const intensityMin = parseInt(document.getElementById('al-intensity-slider')?.value) || 70;
  const pressureDeltaMin = parseInt(document.getElementById('al-pressure-slider')?.value) || 35;
  const markets  = [...document.querySelectorAll('#al-markets .al-chip.active')].map(c => c.dataset.mkt);
  const leagVal  = document.getElementById('al-league-select')?.value || '';
  const leagues  = leagVal ? [leagVal] : [];
  try {
    const r = await apiFetch('/api/v1/alerts/config', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ enabled, chatId, edgeMin, probaMin, markets, leagues, liveEnabled, intensityMin, pressureDeltaMin }),
    });
    if (!r.ok) throw new Error();
    try { localStorage.setItem('ps_alert_prefs', JSON.stringify({ chatId, enabled, liveEnabled })); } catch {}
    const msg = document.getElementById('al-save-msg');
    if (msg) { msg.style.display = 'inline'; setTimeout(() => msg.style.display = 'none', 2500); }
  } catch { alert('Erreur lors de la sauvegarde. Vérifiez que le serveur est lancé.'); }
}

async function loadAlertHistory() {
  const el = document.getElementById('al-history');
  if (!el) return;
  try {
    const r = await apiFetch('/api/v1/alerts/history');
    if (!r.ok) throw new Error();
    const data = await r.json();
    const hist = data.history || [];
    if (!hist.length) {
      el.innerHTML = '<div style="color:var(--text3);font-size:13px;padding:12px 0;">Aucune alerte envoyée pour l\'instant. Les alertes sont déclenchées automatiquement lors du refresh des cotes.</div>';
      return;
    }
    el.innerHTML = hist.map(h => {
      const dt = new Date(h.ts).toLocaleString('fr-FR', { weekday:'short', day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' });
      const rows = (h.matches || []).map(m =>
        `<div class="al-history-match"><strong>${m.home_team} vs ${m.away_team}</strong> · ${m.league}<span class="al-history-edge">+${(m.edge||0).toFixed(1)}%</span></div>`
      ).join('');
      return `<div class="al-history-entry"><div class="al-history-time">${dt} · ${h.count} value bet${h.count>1?'s':''}</div>${rows}</div>`;
    }).join('');
  } catch {
    el.innerHTML = '<div style="color:var(--text3);font-size:13px;padding:12px 0;">Lancez node server.js pour accéder à l\'historique.</div>';
  }
}

