// MATCHDAY PASS — logique acces & achat
const MATCHDAY_KEY = 'ps_matchday_token';
const MATCHDAY_EXP = 'ps_matchday_exp';

function hasMatchdayAccess() {
  const exp = parseInt(localStorage.getItem(MATCHDAY_EXP) || '0', 10);
  return !!localStorage.getItem(MATCHDAY_KEY) && exp > Math.floor(Date.now() / 1000);
}

function initMatchdayBanner() {
  const banner = document.getElementById('matchday-banner');
  if (!banner) return;
  // Masquer pour les utilisateurs déjà pro/admin (pas besoin du matchday pass)
  const accM = (typeof psAccess === 'function') ? psAccess() : { footPro: false };
  banner.style.display = (hasMatchdayAccess() || accM.footPro) ? 'none' : 'flex';
}

async function buyMatchdayPass() {
  try {
    const r = await fetch('/api/v1/checkout/matchday', { method: 'POST' });
    const data = await r.json();
    if (data.url) {
      if (data.session_id) sessionStorage.setItem('ps_stripe_session', data.session_id);
      window.location.href = data.url;
    } else {
      alert(data.error || 'Erreur lors de la creation du paiement.');
    }
  } catch(e) {
    alert('Impossible de contacter le serveur de paiement.');
  }
}

// bd s77m — Abonnement Pro mensuel/annuel via Stripe Checkout subscription
async function buyProSubscription(plan, billing) {
  if (!psGetToken()) {
    if (typeof openAuthModal === 'function') openAuthModal('register');
    else alert('Inscription requise pour souscrire.');
    return;
  }
  try {
    const res = await apiFetch('/api/v1/payments/create-checkout-session', {
      method: 'POST',
      body: { plan: plan || 'pro_all', billing: billing || 'monthly' },
    });
    const data = await res.json();
    if (data.url) {
      window.location.href = data.url;
    } else {
      alert(data.error || 'Erreur lors de la création du paiement.');
    }
  } catch(e) {
    if (e && e.status === 401) return; // openAuthModal déjà ouvert par apiFetch
    alert('Impossible de contacter le serveur de paiement.');
  }
}

// Customer Portal Stripe (self-service annulation/upgrade)
async function openBillingPortal() {
  if (!psGetToken()) { if (typeof openAuthModal === 'function') openAuthModal('login'); return; }
  try {
    const res = await apiFetch('/api/v1/payments/customer-portal', { method: 'POST' });
    const data = await res.json();
    if (data.url) window.location.href = data.url;
    else alert(data.error || 'Aucun abonnement actif.');
  } catch(e) {
    if (e && e.status === 401) return;
    alert('Impossible d\'ouvrir le portail client.');
  }
}

// Polling post-Stripe subscription return — refresh JWT pour récupérer nouveau rôle
(async function checkSubscriptionReturn() {
  const q = new URLSearchParams(window.location.search);
  if (q.get('subscription') !== 'success') return;
  window.history.replaceState({}, '', window.location.pathname);
  if (!psGetToken()) return;
  let tries = 0;
  const poll = async () => {
    tries++;
    try {
      const res = await fetch('/api/v1/auth/me', { headers: { 'Authorization': 'Bearer ' + psGetToken() } });
      const d = await res.json();
      if (d && d.role && d.role.startsWith('pro')) {
        if (d.token_refreshed && d.token) psSetToken(d.token);
        if (typeof showNotification === 'function') showNotification('Abonnement actif ! Bienvenue dans la version Pro.', 'green');
        if (typeof updateNavAuthState === 'function') updateNavAuthState();
        return;
      }
    } catch(e) {}
    if (tries < 8) setTimeout(poll, 1500);
  };
  setTimeout(poll, 1500);
})();

// Polling apres retour Stripe (?matchday=success)
(async function checkMatchdayReturn() {
  if (new URLSearchParams(window.location.search).get('matchday') !== 'success') return;
  const sessionId = sessionStorage.getItem('ps_stripe_session');
  if (!sessionId) return;
  window.history.replaceState({}, '', window.location.pathname);
  let tries = 0;
  const poll = async () => {
    tries++;
    try {
      const r = await fetch('/api/v1/matchday/status?session_id=' + sessionId);
      const d = await r.json();
      if (d.active && d.token) {
        localStorage.setItem(MATCHDAY_KEY, d.token);
        localStorage.setItem(MATCHDAY_EXP, d.expires_at);
        sessionStorage.removeItem('ps_stripe_session');
        initMatchdayBanner();
        showNotification('Matchday Pass active ! Acces Pro pendant 24h.', 'green');
        return;
      }
    } catch(e) {}
    if (tries < 6) setTimeout(poll, 2000);
  };
  setTimeout(poll, 1500);
})();

// ─── ACCESS ENGINE — verrous par sport/tier (Phase 1 client) ───────────────
// Rôles JWT : freemium | matchday | matchday_foot | matchday_tennis |
//             pro_foot | pro_tennis | pro_all | premium(legacy=pro_all) | admin
function psAccess() {
  const u = (typeof psGetUser === 'function') ? psGetUser() : null;
  const role = (u && u.role) || 'guest';
  let footPro = false, tennisPro = false;
  if (role === 'admin' || role === 'premium' || role === 'pro_all') { footPro = true; tennisPro = true; }
  else if (role === 'pro_foot') footPro = true;
  else if (role === 'pro_tennis') tennisPro = true;
  else if (role === 'matchday' || role === 'matchday_foot') footPro = true;
  else if (role === 'matchday_tennis') tennisPro = true;
  // Pass Matchday localStorage (legacy = foot)
  if (typeof hasMatchdayAccess === 'function' && hasMatchdayAccess()) footPro = true;
  // Fenêtre test gratuite : ven 15/05/2026 → lun 18/05/2026 inclus (compte connecté = accès total)
  if (u) {
    const _now = Date.now();
    if (_now >= Date.parse('2026-05-15T00:00:00+02:00') && _now < Date.parse('2026-05-19T00:00:00+02:00')) {
      footPro = true; tennisPro = true;
    }
  }
  // Bypass dev local : accès complet sur localhost/127.0.0.1 (jamais actif en production)
  if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
    footPro = true; tennisPro = true;
  }
  return {
    role, loggedIn: !!u,
    footPro, tennisPro,
    anyPro: footPro || tennisPro,
    footAccess: true,          // tableau foot = niveau gratuit (inscription requise)
    tennisAccess: tennisPro    // tennis = uniquement Pro Tennis / Pro 2 sports
  };
}

// Pages toujours ouvertes (marketing / compte / doc)
const PS_OPEN_PAGES = ['accueil', 'tarifs', 'parametres', 'guide'];

// Retourne null si autorisé, sinon { need:'register'|'pro', sport? }
function psPageBlocked(pageId) {
  if (PS_OPEN_PAGES.includes(pageId)) return null;
  const a = psAccess();
  if (pageId === 'matchs') return a.loggedIn ? null : { need: 'register' };
  if (pageId === 'tennis') return a.tennisAccess ? null : { need: 'pro', sport: 'tennis' };
  return a.anyPro ? null : { need: 'pro' };
}

function renderLockedPage(pageId, block) {
  // Defensive (ParisScorebis-amc Fix B) : showPage set déjà dataset.page mais
  // si renderLockedPage est appelé indépendamment, garder body cohérent — sinon
  // bottom-nav wrap utilise pageId obsolète et active __more au lieu du sport.
  document.body.dataset.page = pageId;
  document.querySelectorAll('div[data-page]').forEach(el => el.style.display = 'none');
  let host = document.getElementById('page-locked');
  if (!host) {
    host = document.createElement('div');
    host.id = 'page-locked';
    host.setAttribute('data-page', 'locked');
    document.querySelector('main')?.appendChild(host) || document.body.appendChild(host);
  }
  const isReg = block.need === 'register';
  const title = isReg ? 'Inscription requise' : 'Module réservé Pro';
  const sub = isReg
    ? 'Créez votre compte gratuit pour accéder au tableau des matchs.'
    : (block.sport === 'tennis'
        ? 'Le module Tennis est inclus dans Pro Tennis et Pro Foot &amp; Tennis.'
        : 'Ce module est réservé aux abonnés Pro et Matchday Pass.');
  host.style.display = 'flex';
  try { window.scrollTo(0, 0); } catch (e) {}
  host.innerHTML = `
    <section class="section fade-up visible" style="text-align:center;max-width:560px;margin:60px auto;">
      <div style="font-size:46px;margin-bottom:14px;">🔒</div>
      <div class="section-title">${title}</div>
      <div class="section-sub" style="margin:10px auto 26px;">${sub}</div>
      <div style="display:flex;gap:12px;justify-content:center;flex-wrap:wrap;">
        ${isReg
          ? `<button class="price-btn price-btn-green" style="padding:12px 22px;" onclick="openAuthModal('register')">Créer mon compte →</button>`
          : `<button class="price-btn price-btn-green" style="padding:12px 22px;" onclick="showPage('tarifs')">Voir les offres →</button>
             <button class="price-btn price-btn-amber" style="padding:12px 22px;" onclick="buyMatchdayPass()">Matchday Pass 1,50€</button>`}
        <button class="price-btn price-btn-ghost" style="padding:12px 22px;" onclick="openAuthModal('login')">Se connecter</button>
      </div>
    </section>`;
  document.querySelectorAll('.nav-links a').forEach(a => a.classList.remove('active'));
  const l = document.querySelector(`.nav-links a[data-page="${pageId}"]`);
  if (l) l.classList.add('active');
}

// Onglets toujours visibles — cadenas 🔒 si non accessible (clic → page verrou)
function psSyncNav() {
  const a = psAccess();
  document.querySelectorAll('.nav-links a[data-page]').forEach(link => {
    const p = link.getAttribute('data-page');
    link.style.display = '';
    let locked = false;
    if (PS_OPEN_PAGES.includes(p) || p === 'matchs') locked = false;
    else if (p === 'tennis') locked = !a.tennisAccess;
    else locked = !a.anyPro;
    if (!link.dataset.label) link.dataset.label = link.textContent.replace(/^🔒\s*/, '');
    link.textContent = (locked ? '🔒 ' : '') + link.dataset.label;
    link.classList.toggle('nav-locked', locked);
  });
}

// MODAL — inscription obligatoire : tout CTA "compte" → vrai formulaire register
function openModal() {
  if (typeof openAuthModal === 'function') openAuthModal('register');
  else document.getElementById('modal').classList.add('open');
}
function closeModal() { document.getElementById('modal').classList.remove('open'); }

// SCROLL ANIMATIONS
const observer = new IntersectionObserver((entries) => {
  entries.forEach(e => { if(e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.1 });
