// ── Deep Analysis Pro — Terminal SSE ─────────────────────────────────────────
let _deepEvt = null;
let _deepText = '';
let _deepMatchId = null;
let _deepTimestamp = null;
let _deepProData = null;

function refreshDeepAnalysis() {
  const matchId = _deepMatchId;
  if (!matchId) return;
  if (_deepEvt) { _deepEvt.close(); _deepEvt = null; }
  _deepText = '';
  _deepMatchId = null;
  document.getElementById('deep-content').innerHTML = '';
  openDeepAnalysis(matchId, null, true);
}

function openDeepAnalysis(matchId, e, force) {
  if (e) { e.preventDefault(); e.stopPropagation(); }

  // #5 — Disable bouton immédiatement, anti-double-clic
  const btn = e ? (e.currentTarget || e.target) : null;
  const _reenableBtn = () => {
    if (btn) { btn.disabled = false; btn.textContent = 'AI-AL'; }
  };
  if (btn && !force) {
    if (btn.disabled) return;
    btn.disabled = true;
    btn.textContent = '…';
  }

  const match = allMatches.find(m => m.id === matchId);
  const label = match ? `${match.home_team} vs ${match.away_team}` : matchId;

  document.getElementById('deep-match-label').textContent = label;
  document.getElementById('deep-match-label').dataset.matchId = matchId;
  document.body.style.overflow = 'hidden';
  document.getElementById('deep-modal').classList.add('open');

  // Same match already analysed — show render directly, no re-fetch
  if (!force && _deepMatchId === matchId && _deepText) {
    _reenableBtn();
    const term = document.getElementById('deep-terminal');
    term.style.display = 'none';
    document.getElementById('deep-mode-bar').style.display = 'flex';
    switchDeepMode('render');
    return;
  }

  // New match or forced refresh — reset state
  if (_deepEvt) { _deepEvt.close(); _deepEvt = null; }
  _deepText = '';
  _deepMatchId = matchId;

  document.getElementById('deep-mode-bar').style.display = 'none';
  document.getElementById('deep-content').style.display = 'none';
  document.getElementById('deep-content').innerHTML = '';
  // Reset header UI + I4/I5
  const confBadge = document.getElementById('dp-confidence-badge');
  confBadge.style.display = 'none'; confBadge.className = 'dp-conf-badge';
  const tsEl = document.getElementById('dp-timestamp');
  tsEl.style.display = 'none'; tsEl.textContent = '';
  document.getElementById('dp-divergence-block').style.display = 'none';
  document.getElementById('dp-divergence-block').innerHTML = '';
  document.getElementById('dp-pro-panel').classList.remove('visible');
  document.getElementById('dp-btn-pro')?.classList.remove('active');
  _deepProData = null;

  const term = document.getElementById('deep-terminal');
  term.style.display = 'block';
  term.textContent = '> AI-AL — Terminal d\'analyse Pariscore\n> Connexion au moteur IA…\n> Injection des données du match : ' + label + '\n\n';

  // I2 — Quick Scout pré-analyse (<100ms)
  fetch('/api/v1/quick-scout/' + encodeURIComponent(matchId))
    .then(r => r.json())
    .then(scout => {
      let line = '> Scout :';
      if (scout.topSignal) line += '  Signal → ' + scout.topSignal;
      if (scout.edge)      line += '  |  Edge → ' + scout.edge;
      line += '  |  Fiabilité : ' + scout.confidence + '/100 [' + scout.dataQuality + ']';
      term.textContent += line + '\n\n';
    })
    .catch(() => {});

  let headerDone = false;
  const streamUrl = '/api/v1/deep-analysis-stream/' + encodeURIComponent(matchId) + (force ? '?force=1' : '');
  _deepEvt = new EventSource(streamUrl);

  // I1/I4/I5 — meta event handler
  _deepEvt.addEventListener('meta', ev => {
    try {
      const meta = JSON.parse(ev.data);
      // I1 — confidence badge
      const badge = document.getElementById('dp-confidence-badge');
      badge.textContent = meta.confidence + '/100';
      badge.className = 'dp-conf-badge ' + (meta.confidence >= 71 ? 'good' : meta.confidence >= 41 ? 'mid' : 'low');
      badge.style.display = 'inline-flex';
      term.textContent += '> Fiabilité données : ' + meta.confidence + '/100 (' + meta.dataQuality + ')\n\n';
      // I4 — divergences marché
      if (meta.divergences && meta.divergences.length) {
        const divBlock = document.getElementById('dp-divergence-block');
        divBlock.innerHTML = meta.divergences.map(d =>
          `<div class="dp-div-row">
            <span class="dp-div-badge ${d.gap > 0 ? 'up' : 'down'}">DIVERGENCE ${d.gap > 0 ? '+' : ''}${d.gap}%</span>
            <span style="color:var(--text2)">${dpEsc(d.label)}</span>
            <span style="color:var(--text3)">Modèle ${d.poisson}% vs marché ${d.implied}%</span>
          </div>`
        ).join('');
        divBlock.style.display = 'flex';
        term.textContent += '> ' + meta.divergences.length + ' divergence(s) marché détectée(s)\n\n';
      }
      // I5 — Pro panel data
      if (meta.lambda || meta.ev1x2) {
        _deepProData = meta;
        renderProPanel(meta);
      }
    } catch {}
  });

  _deepEvt.addEventListener('chunk', ev => {
    const { text } = JSON.parse(ev.data);
    if (!headerDone) { term.textContent += '> Analyse reçue :\n\n'; headerDone = true; }
    _deepText += text;
    term.textContent += text;
    term.scrollTop = term.scrollHeight;
  });

  _deepEvt.addEventListener('done', ev => {
    _deepEvt.close(); _deepEvt = null;
    _reenableBtn();
    let providerName = '';
    try { const d = JSON.parse(ev.data); providerName = d.provider || ''; } catch {}
    // U6 — timestamp
    _deepTimestamp = new Date();
    const tsEl2 = document.getElementById('dp-timestamp');
    tsEl2.textContent = 'Analysé à ' + _deepTimestamp.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
    tsEl2.style.display = 'block';
    term.textContent += '\n\n> Analyse complète.' + (providerName ? ' [via ' + providerName + ']' : '');
    const bar = document.getElementById('deep-mode-bar');
    if (providerName) bar.dataset.provider = providerName;
    bar.style.display = 'flex';
  });

  _deepEvt.addEventListener('error', ev => {
    _deepEvt.close(); _deepEvt = null;
    _reenableBtn();
    let msg = 'Connexion interrompue';
    try { msg = JSON.parse(ev.data).message; } catch {}
    term.textContent += '\n\n> ERREUR : ' + msg;
    document.getElementById('deep-mode-bar').style.display = 'flex';
  });

  _deepEvt.onerror = () => {
    if (_deepEvt?.readyState === EventSource.CLOSED) return;
    _reenableBtn();
    term.textContent += '\n\n> Connexion SSE perdue.';
    document.getElementById('deep-mode-bar').style.display = 'flex';
  };
}

function switchDeepMode(mode) {
  const term    = document.getElementById('deep-terminal');
  const content = document.getElementById('deep-content');
  const btnT    = document.getElementById('dp-btn-terminal');
  const btnR    = document.getElementById('dp-btn-render');
  if (mode === 'terminal') {
    term.style.display = 'block';
    content.style.display = 'none';
    btnT.classList.add('active'); btnR.classList.remove('active');
  } else {
    term.style.display = 'none';
    content.style.display = 'block';
    btnT.classList.remove('active'); btnR.classList.add('active');
    if (!content.innerHTML.trim() && _deepText) renderDeepAnalysis(_deepText);
  }
}

function closeDeepAnalysis() {
  if (_deepEvt) { _deepEvt.close(); _deepEvt = null; }
  document.getElementById('deep-modal').classList.remove('open');
  document.body.style.overflow = '';
}

function renderProPanel(meta) {
  const p = meta.poisson || {};
  const ev = meta.ev1x2 || {};
  const λ = meta.lambda || {};
  const odds = meta.odds || {};
  const rows = [
    { label: 'Victoire dom', poisson: p.homeWin, ev: ev.home, odds: odds.home },
    { label: 'Nul',          poisson: p.draw,    ev: ev.draw,  odds: odds.draw },
    { label: 'Victoire ext', poisson: p.awayWin, ev: ev.away,  odds: odds.away },
    { label: 'Over 2.5',     poisson: p.over25,  ev: null,     odds: null },
    { label: 'BTTS',         poisson: p.btts,    ev: null,     odds: null },
  ];
  const tableRows = rows.map(r => {
    const evClass = r.ev == null ? '' : r.ev > 0 ? ' class="ev-pos"' : ' class="ev-neg"';
    const evStr = r.ev == null ? '—' : (r.ev > 0 ? '+' : '') + r.ev + '%';
    return `<tr>
      <td>${dpEsc(r.label)}</td>
      <td>${r.poisson != null ? r.poisson + '%' : '—'}</td>
      <td>${r.odds != null ? r.odds : '—'}</td>
      <td${evClass}>${evStr}</td>
    </tr>`;
  }).join('');
  document.getElementById('dp-pro-content').innerHTML = `
    <table class="dp-pro-table">
      <thead><tr><th>Marché</th><th>Proba</th><th>Cote</th><th>EV%</th></tr></thead>
      <tbody>${tableRows}</tbody>
    </table>
    ${λ.home != null ? `<div style="margin-top:10px;font:11px var(--font-mono);color:var(--text3)">λ domicile : ${λ.home} | λ extérieur : ${λ.away}</div>` : ''}
  `;
}

function toggleProMode() {
  const panel = document.getElementById('dp-pro-panel');
  const btn = document.getElementById('dp-btn-pro');
  const active = panel.classList.toggle('visible');
  btn.classList.toggle('active', active);
  if (active && _deepProData) renderProPanel(_deepProData);
}

function updateKellyAmounts() {
  const bankroll = parseFloat(document.getElementById('dp-bankroll-input').value) || 0;
  document.querySelectorAll('.dp-kelly-tag[data-kelly]').forEach(el => {
    const pct = parseFloat(el.dataset.kelly);
    const euros = bankroll > 0 ? (pct / 100 * bankroll).toFixed(0) : null;
    const base = '📐 Mise recommandée : ' + safeFixed(pct, 1) + '%';
    el.innerHTML = euros ? `${base} <span class="dp-kelly-eur">→ €${euros}</span>` : base;
  });
}

// ── Helpers ─────────────────────────────────────────────────────────────────
function dpEsc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function dpBold(s) { return s.replace(/\*\*(.+?)\*\*/g,'<strong style="color:#c0392b;font-weight:700">$1</strong>').replace(/\*(.+?)\*/g,'<em>$1</em>'); }

function renderDeepAnalysis(text) {
  // === MOUCHARD frontend : trace présence section Revue de Presse ===
  const hasRevue = /REVUE\s+DE\s+PRESSE/i.test(text || '');
  if (!hasRevue) {
    console.warn('[AI-AL] Section "REVUE DE PRESSE" absente du texte brut reçu — le LLM a ignoré la consigne OU cache obsolète.');
  } else {
    console.log('[AI-AL] Section "REVUE DE PRESSE" détectée dans le texte brut ✓');
  }
  // Chirurgical emoji strip — remove any emoji the AI slipped through
  text = text.replace(/[\u{1F000}-\u{1FFFF}\u{2600}-\u{27BF}\u{1FA00}-\u{1FAFF}\u{FE00}-\u{FEFF}\u{20D0}-\u{20FF}]/gu, '').trim();
  text = text.replace(/##[^\n]*SCRIPT TELEGRAM[\s\S]*?(?=\n##|\n\[DIRECTIVES|$)/i, '').trim();

  // ── Split code blocks out first ──────────────────────────────────────────
  const segments = text.split(/(```[\s\S]*?```)/g);
  let html = '';

  segments.forEach(seg => {
    if (seg.startsWith('```')) {
      if (/^```telegram/i.test(seg)) return;
      const code = seg.replace(/^```[^\n]*\n?/, '').replace(/\n?```$/, '').trim();
      html += `<div class="dp-code-block">
        <div class="dp-code-label">Code</div>
        <pre class="dp-code-pre">${dpEsc(code)}<button class="dp-code-copy" onclick="dpCopy(this)">Copier</button></pre>
      </div>`;
      return;
    }

    // ── Parse line by line ────────────────────────────────────────────────
    const lines = seg.split('\n');
    let i = 0;
    let currentSection = 0;   // 1=entête 2=power 3=analyse 4=top5 paris 5=revue presse 6=verdict
    let betListOpen = false;
    let pressListOpen = false;
    let probaBlockOpen = false;
    let pendingPara = '';

    const flushPara = () => {
      if (pendingPara.trim()) {
        const cls = currentSection === 6 ? 'dp-verdict-body' : 'dp-body';
        html += `<p class="${cls}">${dpBold(dpEsc(pendingPara.trim()))}</p>`;
        pendingPara = '';
      }
    };
    const closeBlocks = () => {
      if (betListOpen)   { html += '</div>'; betListOpen = false; }
      if (pressListOpen) { html += '</div>'; pressListOpen = false; }
      if (probaBlockOpen){ html += '</div>'; probaBlockOpen = false; }
    };

    while (i < lines.length) {
      const raw = lines[i];
      const line = raw.trim();
      i++;

      if (!line) { flushPara(); continue; }

      // ── Press item DETECTION PRIORITAIRE (section 5) — avant section header
      // Tolère "1. **Média** : "Citation"", "1. *Média*: Citation", "1. **Média** — citation", quotes droites/courbes
      if (currentSection === 5) {
        const pressStripped = line.replace(/^[-•\*]\s*/, '');
        const pressM = pressStripped.match(/^\d+\s*[\.\)]\s*[\*_]{0,2}\s*([^*_\n:—–-]{2,80}?)\s*[\*_]{0,2}\s*[:：—–-]\s*[«"'""''`]?\s*(.+?)\s*[»"'""''`]?\.?\s*$/);
        if (pressM) {
          flushPara();
          const media = pressM[1].trim().replace(/^[\*_]+|[\*_]+$/g, '');
          let quote = pressM[2].trim().replace(/^[«"'""''`]+/, '').replace(/[»"'""''`]+\.?$/, '');
          html += `<div class="dp-press-item">
            <div class="dp-press-media">${dpEsc(media)}</div>
            <div class="dp-press-quote">«&nbsp;${dpBold(dpEsc(quote))}&nbsp;»</div>
          </div>`;
          continue;
        }
      }

      // ── Section header: "1. TITRE", "**1. TITRE**", "## 1. TITRE", "**1.** TITRE", "###1. TITRE" ──
      // Sanitization agressive : strip tous les marqueurs markdown au début/intérieur du préfixe
      let cleanLine = line
        .replace(/^#+\s*/, '')                  // # ## ###
        .replace(/^\*+\s*/, '')                 // ** au début
        .replace(/\*+$/, '')                    // ** à la fin
        .replace(/^(\d+)\s*\*+\s*\.\s*/, '$1. ')// "**5.**" → "5."
        .replace(/^(\d+)\s*\.\s*\*+\s*/, '$1. ')// "5. **" → "5. "
        .trim();
      const secM = cleanLine.match(/^(\d+)\s*[\.\)]\s*\*{0,2}\s*(.*)/);
      if (secM) {
        flushPara(); closeBlocks();
        const num = parseInt(secM[1]);
        currentSection = num;
        // Strip markdown emphasis dans le titre pour rendu propre
        const titleRaw = secM[2].replace(/\*+/g, '').replace(/^\s*[:：]\s*$/, '').trim();

        // Section 1 = match title (render as big heading)
        if (num === 1) {
          const matchTitle = titleRaw.replace(/^EN-T[ÊE]TE DU MATCH\s*:\s*/i, '').trim();
          html += `<div class="dp-match-title">${dpEsc(matchTitle)}</div>`;
        } else if (num === 5) {
          // Section 5 = REVUE DE PRESSE — header customisé avec icône presse
          html += `<div class="dp-section-hdr">
            <span class="dp-section-num">${num}</span>
            <span class="dp-section-title">📰 Revue de presse — Avis médias</span>
          </div>`;
        } else {
          html += `<div class="dp-section-hdr">
            <span class="dp-section-num">${num}</span>
            <span class="dp-section-title">${dpEsc(titleRaw)}</span>
          </div>`;
        }

        // Section 4 = MES 5 PARIS
        if (num === 4) {
          html += '<div class="dp-bet-list">';
          betListOpen = true;
        }
        // Section 5 = REVUE DE PRESSE — ouvre le container press list
        if (num === 5) {
          html += '<div class="dp-press-list">';
          pressListOpen = true;
        }
        continue;
      }

      // ── Power Score lines (section 2) ─────────────────────────────────────
      if (currentSection === 2) {
        const domM = line.match(/^(.+?)\s*\(Dom(?:icile)?\)\s*:\s*(\d+)\/100/i);
        const extM = line.match(/^(.+?)\s*\(Ext(?:érieur)?\)\s*:\s*(\d+)\/100/i);
        if (domM || extM) {
          // Open wrapper on first score
          if (domM) html += '<div class="dp-powerscore-wrap">';
          const m = domM || extM;
          const team = m[1].trim();
          const score = parseInt(m[2]);
          const ctx  = domM ? 'Domicile' : 'Extérieur';
          html += `<div class="dp-score-card2">
            <div class="dsc-name">${dpEsc(team)} <span style="color:var(--text3);font-weight:400">(${ctx})</span></div>
            <div class="dsc-val">${score}<span class="dsc-denom">/100</span></div>
            <div class="dsc-bar"><div class="dsc-fill" style="width:${score}%"></div></div>
          </div>`;
          if (extM) html += '</div>'; // close wrapper after away
          continue;
        }
      }

      // ── Sub-labels in section 3: "Le Duel Tactique :", "La Synthèse…" ───
      if (currentSection === 3) {
        const subM = line.match(/^((?:Le |La |L'|L')[^:]{3,50})\s*:\s*(.*)/);
        if (subM) {
          flushPara();
          const label = subM[1].trim();
          const rest  = subM[2].trim();
          html += `<div class="dp-sub-label">${dpEsc(label)}</div>`;
          if (rest) pendingPara = rest;
          continue;
        }
      }

      // ── Bet lines (section 4): emoji prefix, optional leading "- " ──────
      if (currentSection === 4) {

        const stripped = line.replace(/^-\s*/, '');
        const isBetLine = /^[\u{1F000}-\u{1FFFF}\u{2600}-\u{27BF}]/u.test(stripped) || /^\*\*.+?\*\*\s*:/.test(stripped);
        if (isBetLine) {
          flushPara();
          const colonIdx = stripped.indexOf(':');
          if (colonIdx > 0) {
            const label   = stripped.slice(0, colonIdx).replace(/\*\*/g, '').trim();
            const content = stripped.slice(colonIdx + 1).trim();
            html += `<div class="dp-bet-card">
              <div class="dp-bet-label">${dpEsc(label)}</div>
              <div class="dp-bet-body">${dpBold(dpEsc(content))}</div>
            </div>`;
          } else {
            html += `<div class="dp-bet-card"><div class="dp-bet-body">${dpBold(dpEsc(stripped))}</div></div>`;
          }
          continue;
        }
      }

      // Press items (section 5) déjà traités en priorité au début de la boucle.

      // ── Default: accumulate as paragraph text ─────────────────────────
      pendingPara += (pendingPara ? ' ' : '') + line;
    }

    flushPara();
    closeBlocks();
  });

  // Fallback: if parser produced nothing, render as plain styled paragraphs
  if (!html.trim()) {
    html = text.split(/\n{2,}/).filter(p => p.trim()).map(para =>
      `<p class="dp-body">${dpBold(dpEsc(para.trim()))}</p>`
    ).join('');
  }

  const content = document.getElementById('deep-content');
  content.innerHTML = html;
  content.style.display = 'block';



  // Animate Power Score bars
  requestAnimationFrame(() => {
    content.querySelectorAll('.dsc-fill').forEach(bar => {
      const target = bar.style.width;
      bar.style.width = '0';
      requestAnimationFrame(() => { bar.style.width = target; });
    });
  });
}

function dpCopy(btn) {
  const pre = btn.closest('pre');
  // Get text without button text
  const clone = pre.cloneNode(true);
  clone.querySelectorAll('button').forEach(b => b.remove());
  navigator.clipboard.writeText(clone.textContent.trim()).then(() => {
    btn.textContent = 'Copié !';
    setTimeout(() => { btn.textContent = 'Copier'; }, 2200);
  });
}

document.addEventListener('keydown', e => {
  if (e.key === 'Escape' && document.getElementById('deep-modal').classList.contains('open')) closeDeepAnalysis();
  if (e.key === 'Escape' && document.getElementById('strat-help-overlay')?.style.display !== 'none') closeStratHelp();
});

/* ── Theme toggle — dark/light (bd z55o rollback v3.2) ── */
(function() {
  const STORAGE_KEY = 'ps-theme-override';

  function shouldBeDark() {
    try { return localStorage.getItem(STORAGE_KEY) === 'dark'; } catch(_) { return false; }
  }

  function applyTheme(dark) {
    if (dark) {
      document.body.classList.add('dark-theme');
      document.body.removeAttribute('data-cf-light');
    } else {
      document.body.classList.remove('dark-theme');
      document.body.setAttribute('data-cf-light', '1');
    }
    try { localStorage.setItem(STORAGE_KEY, dark ? 'dark' : 'light'); } catch(_) {}
    const label = dark ? '☀ Jour' : '☾ Nuit';
    const btn = document.getElementById('theme-toggle');
    if (btn) { btn.textContent = label; btn.style.display = ''; }
    const btnM = document.getElementById('theme-toggle-m');
    if (btnM) { btnM.textContent = label; btnM.style.display = ''; }
  }

  function init() {
    applyTheme(shouldBeDark());
  }

  window.toggleTheme = function() {
    applyTheme(!document.body.classList.contains('dark-theme'));
  };

  // bd 21m7 / rlhf — Module audio alertes trading (state tracking transitions positives)
  // Joue son UNIQUEMENT sur Rouge/Neutre→Jaune ou Jaune→Vert (positives), pas sur cellule
  // simplement verte. Autoplay-safe: requiert UI unlock (toggle) + Promise wrap.
  // Couvre 3 indicateurs: intensity (live), verdict (Conseils IA top pick), confidence
  // (BSD confidence_badge.level), edge (Market Edge best_edge.edge).
  window._psAudio = window._psAudio || {
    enabled: localStorage.getItem('cf_audio_enabled') === '1',
    ctx: null,
    lastPlay: 0,
    // Map keyed par "<matchId>::<type>" → 'red'|'amber'|'green'
    // types: 'intensity' | 'verdict' | 'confidence' | 'edge'
    prevTiers: new Map(),
    THROTTLE_MS: 1500, // anti-spam — 1 son max par fenetre 1500ms
    queue: [],         // file pour decalage 200ms entre sons consecutifs (max 3)
    queueTimer: null,
  };
  function _psIntensityTier(v) {
    if (v == null || isNaN(v)) return 'red';
    if (v >= 60) return 'green';
    if (v >= 30) return 'amber';
    return 'red';
  }
  window._psIntensityTier = _psIntensityTier;
  // bd rlhf — Mapping universel valeur→tier selon type indicateur.
  // verdict = top pick Conseils IA % (75+ vert, 60-74 jaune)
  // confidence = % conf BSD ou level deja calcule
  // edge = best_edge.edge en % (5+ vert, 2+ jaune)
  function _psTierFromValue(value, type) {
    if (value == null) return 'red';
    if (typeof value === 'string') {
      // confidence_badge.level direct : 'green'|'amber'|'red'
      var s = String(value).toLowerCase();
      if (s === 'green' || s === 'amber' || s === 'red') return s;
    }
    var v = Number(value);
    if (isNaN(v)) return 'red';
    if (type === 'edge') {
      if (v >= 5) return 'green';
      if (v >= 2) return 'amber';
      return 'red';
    }
    if (type === 'verdict') {
      if (v >= 75) return 'green';
      if (v >= 60) return 'amber';
      return 'red';
    }
    if (type === 'confidence') {
      if (v >= 70) return 'green';
      if (v >= 50) return 'amber';
      return 'red';
    }
    return _psIntensityTier(v);
  }
  window._psTierFromValue = _psTierFromValue;
  function _psAudioUnlock() {
    if (window._psAudio.ctx) return window._psAudio.ctx;
    try {
      const Ctor = window.AudioContext || window.webkitAudioContext;
      if (!Ctor) return null;
      window._psAudio.ctx = new Ctor();
      // iOS unlock : courte note silencieuse
      const osc = window._psAudio.ctx.createOscillator();
      const g = window._psAudio.ctx.createGain();
      g.gain.value = 0;
      osc.connect(g); g.connect(window._psAudio.ctx.destination);
      osc.start(); osc.stop(window._psAudio.ctx.currentTime + 0.01);
      return window._psAudio.ctx;
    } catch (e) { console.warn('[Audio] unlock failed:', e.message); return null; }
  }
  // Joue 2 notes courtes (BIP montant pour amber, BIP plus aigu pour green).
  window.playTradingAlert = function(toTier) { return playTradingAlert(toTier); };
  function playTradingAlert(toTier) {
    if (!window._psAudio.enabled) return;
    const now = Date.now();
    if (now - window._psAudio.lastPlay < window._psAudio.THROTTLE_MS) return; // anti-spam
    const ctx = window._psAudio.ctx;
    if (!ctx) return; // pas encore unlock
    window._psAudio.lastPlay = now;
    try {
      const freqs = toTier === 'green' ? [660, 990] : [440, 660]; // green plus aigu
      const playNote = (freq, start, dur, vol = 0.18) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = 'sine';
        osc.frequency.value = freq;
        gain.gain.setValueAtTime(0, ctx.currentTime + start);
        gain.gain.linearRampToValueAtTime(vol, ctx.currentTime + start + 0.02);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + start + dur);
        osc.connect(gain); gain.connect(ctx.destination);
        osc.start(ctx.currentTime + start);
        osc.stop(ctx.currentTime + start + dur + 0.05);
      };
      const playPromise = ctx.resume && ctx.resume();
      const fire = () => { playNote(freqs[0], 0, 0.15); playNote(freqs[1], 0.13, 0.18); };
      // Autoplay-safe : si resume retourne Promise, attendre puis fire avec silent catch
      if (playPromise && typeof playPromise.then === 'function') {
        playPromise.then(fire).catch(e => console.warn('[Audio] resume blocked:', e.message));
      } else { fire(); }
    } catch (e) { console.warn('[Audio] play failed:', e.message); }
  }
  // bd rlhf — Helper interne : log transition tier sur un indicateur, retourne true si
  // transition positive (rouge/neutral→amber ou amber→green) qui doit declencher son.
  const _PS_ORDER = { red: 0, amber: 1, green: 2 };
  function _psApplyTransition(matchId, type, newTier) {
    if (!matchId || !type) return false;
    const key = matchId + '::' + type;
    const prev = window._psAudio.prevTiers.get(key);
    window._psAudio.prevTiers.set(key, newTier);
    if (!prev) return false; // 1er enregistrement, pas de transition
    return _PS_ORDER[newTier] > _PS_ORDER[prev];
  }
  // bd rlhf — File de lecture decalee : si plusieurs transitions arrivent dans
  // la meme tick render, joue 1 son tout de suite puis decale les suivants de
  // 200ms (max 3 sons par burst). Le throttle THROTTLE_MS reste actif au sein
  // de playTradingAlert pour eviter spam global.
  function _psEnqueueAlert(tier) {
    if (!window._psAudio.enabled) return;
    window._psAudio.queue.push(tier);
    if (window._psAudio.queueTimer) return; // deja en cours de drain
    const drain = () => {
      const next = window._psAudio.queue.shift();
      if (!next) { window._psAudio.queueTimer = null; return; }
      playTradingAlert(next);
      // Limite a 3 sons par burst pour eviter saturation
      if (window._psAudio.queue.length > 2) window._psAudio.queue.length = 2;
      window._psAudio.queueTimer = setTimeout(drain, 200);
    };
    drain();
  }
  // Detecte transition pour un match donne (sur live_intensity courant) et trigger son si positive.
  window.psCheckIntensityTransition = function(matchId, newIntensity) { return psCheckIntensityTransition(matchId, newIntensity); };
  function psCheckIntensityTransition(matchId, newIntensity) {
    if (!matchId) return;
    const newTier = _psIntensityTier(newIntensity);
    if (_psApplyTransition(matchId, 'intensity', newTier)) {
      _psEnqueueAlert(newTier);
    }
  }
  // bd rlhf — Orchestrateur transitions multi-indicateurs (Conseils IA / Confiance /
  // Market Edge) appele par renderMatches() pour chaque match. Lit etat precedent,
  // calcule nouveau tier par type, declenche son si transition positive.
  // Args: m=match object, p=poisson, edgeValue=number (best_edge.edge)
  window.psCheckIndicatorTransitions = function(m, p, edgeValue) { return psCheckIndicatorTransitions(m, p, edgeValue); };
  function psCheckIndicatorTransitions(m, p, edgeValue) {
    if (!m || !m.id || !window._psAudio.enabled) return;
    try {
      // 1) Verdict Conseils IA : top pick 1X2 (max homeWin/draw/awayWin)
      if (p && (p.homeWin != null || p.draw != null || p.awayWin != null)) {
        const topPick = Math.max(Number(p.homeWin) || 0, Number(p.draw) || 0, Number(p.awayWin) || 0);
        const tVerdict = _psTierFromValue(topPick, 'verdict');
        if (_psApplyTransition(m.id, 'verdict', tVerdict)) _psEnqueueAlert(tVerdict);
      }
      // 2) Confidence BSD : confidence_badge.level direct (green/amber/red) ou conf_pct
      const cb = m.confidence_badge;
      if (cb && cb.level) {
        const tConf = _psTierFromValue(cb.level, 'confidence');
        if (_psApplyTransition(m.id, 'confidence', tConf)) _psEnqueueAlert(tConf);
      } else if (cb && cb.conf_pct != null) {
        const tConf = _psTierFromValue(cb.conf_pct, 'confidence');
        if (_psApplyTransition(m.id, 'confidence', tConf)) _psEnqueueAlert(tConf);
      }
      // 3) Market Edge : best_edge.edge (>=5 vert, >=2 jaune)
      if (edgeValue != null && !isNaN(edgeValue)) {
        const tEdge = _psTierFromValue(edgeValue, 'edge');
        if (_psApplyTransition(m.id, 'edge', tEdge)) _psEnqueueAlert(tEdge);
      }
    } catch (e) { /* silencieux : ne casse pas le rendu */ }
  }
  // Toggle UI exposé global : appelable depuis bouton "🔊 Alertes sonores"
  window.psToggleAudioAlerts = function() {
    window._psAudio.enabled = !window._psAudio.enabled;
    localStorage.setItem('cf_audio_enabled', window._psAudio.enabled ? '1' : '0');
    if (window._psAudio.enabled) _psAudioUnlock();
    if (typeof showNotification === 'function') {
      showNotification(window._psAudio.enabled ? '🔊 Alertes sonores activées' : '🔇 Alertes sonores désactivées', 'green');
    }
    // Met a jour bouton si present
    document.querySelectorAll('[data-audio-toggle]').forEach(b => {
      b.textContent = window._psAudio.enabled ? '🔊' : '🔇';
      b.setAttribute('title', window._psAudio.enabled ? 'Alertes sonores actives — cliquer pour désactiver' : 'Alertes sonores désactivées — cliquer pour activer');
    });
    return window._psAudio.enabled;
  };

  // Goal Horn Sound - Goal Horn Stadium Style
  window.playGoalHorn = function() {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const playNote = (freq, start, dur, vol = 0.3) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = 'sawtooth';
        osc.frequency.value = freq;
        gain.gain.setValueAtTime(0, ctx.currentTime + start);
        gain.gain.linearRampToValueAtTime(vol, ctx.currentTime + start + 0.02);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + start + dur);
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start(ctx.currentTime + start);
        osc.stop(ctx.currentTime + start + dur);
      };
      // Classic stadium goal horn - two notes
      playNote(220, 0, 0.3, 0.25);
      playNote(330, 0.25, 0.5, 0.3);
    } catch(e) {
      console.warn('[GoalHorn] Sound unavailable:', e.message);
    }
  };

  /* Re-check toutes les 5 min si pas d'override manuel */
  setInterval(() => {
    if (localStorage.getItem(STORAGE_KEY) === null) applyTheme(shouldBeDark());
  }, 5 * 60 * 1000);

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();


(function () {
  'use strict';
  // Skip si pas mobile-v2 (zero impact desktop V1)
  if (!document.documentElement.classList.contains('ps-mobile-v2')) return;

  /* ========== C7 HAPTICS helper _psHaptic(pattern) ==========
     Wrap navigator.vibrate avec patterns nommes + no-op si API absente.
     iOS Safari ne supporte PAS vibrate API (Android only) — no-op gracieux. */
  var HAPTIC_PATTERNS = {
    tap: 8,
    select: [10],
    success: [20, 40, 20],
    warning: [40, 60, 40],
    error: [60, 80, 60, 80, 60],
    valueAlert: [20, 40, 20, 40, 20],
    goalAlert: [50, 80, 50, 80, 50]
  };
  window._psHaptic = function (patternName) {
    try {
      if (!navigator.vibrate) return false;
      var pattern = (typeof patternName === 'string') ? HAPTIC_PATTERNS[patternName] : patternName;
      if (!pattern) return false;
      // User opt-out via localStorage
      try { if (localStorage.getItem('ps_haptic_disabled') === '1') return false; } catch (e) {}
      navigator.vibrate(pattern);
      return true;
    } catch (e) { return false; }
  };

  /* ========== C6 PAN & ZOOM helper _psPanZoom(el, opts) ==========
     Touch handlers pinch-zoom + pan + double-tap toggle. Zero-dep,
     pointerdown/move/up + transform matrix. */
  function _psPanZoom(frame, opts) {
    opts = opts || {};
    var content = frame.querySelector('.pz-content');
    if (!content) {
      // Auto-wrap children into .pz-content si absent
      content = document.createElement('div');
      content.className = 'pz-content';
      while (frame.firstChild) content.appendChild(frame.firstChild);
      frame.appendChild(content);
    }
    var state = { scale: 1, x: 0, y: 0, startScale: 1, startX: 0, startY: 0, startD: 0, startCx: 0, startCy: 0, pointers: new Map(), lastTap: 0 };
    var MIN = opts.min || 1;
    var MAX = opts.max || 2.5;

    // Add zoom indicator
    if (!frame.querySelector('.pz-zoom-indicator')) {
      var zi = document.createElement('div');
      zi.className = 'pz-zoom-indicator';
      zi.textContent = '1.0×';
      frame.appendChild(zi);
    }
    var zoomIndicator = frame.querySelector('.pz-zoom-indicator');

    function applyTransform() {
      content.style.transform = 'translate(' + state.x + 'px, ' + state.y + 'px) scale(' + state.scale + ')';
      if (state.scale > 1.05) frame.classList.add('pz-zoomed');
      else frame.classList.remove('pz-zoomed');
      zoomIndicator.textContent = state.scale.toFixed(1) + '×';
    }

    function getDistance(p1, p2) {
      var dx = p1.x - p2.x, dy = p1.y - p2.y;
      return Math.sqrt(dx * dx + dy * dy);
    }
    function getCenter(p1, p2) {
      return { x: (p1.x + p2.x) / 2, y: (p1.y + p2.y) / 2 };
    }

    frame.addEventListener('pointerdown', function (e) {
      state.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
      frame.setPointerCapture(e.pointerId);
      frame.classList.add('pz-dragging');

      if (state.pointers.size === 1) {
        // Single pointer = pan ou double-tap detection
        var now = Date.now();
        if (now - state.lastTap < 300) {
          // Double-tap = zoom toggle
          state.scale = state.scale > 1.05 ? 1 : 2.5;
          state.x = 0; state.y = 0;
          frame.classList.remove('pz-dragging');
          content.style.transition = 'transform 240ms cubic-bezier(0.32, 0.72, 0, 1)';
          applyTransform();
          setTimeout(function () { content.style.transition = ''; }, 250);
          if (window._psHaptic) window._psHaptic('tap');
          state.lastTap = 0;
        } else {
          state.lastTap = now;
          state.startX = state.x; state.startY = state.y;
        }
      } else if (state.pointers.size === 2) {
        // Pinch start
        var pts = Array.from(state.pointers.values());
        state.startD = getDistance(pts[0], pts[1]);
        var c = getCenter(pts[0], pts[1]);
        state.startCx = c.x; state.startCy = c.y;
        state.startScale = state.scale;
        state.startX = state.x; state.startY = state.y;
      }
    });

    frame.addEventListener('pointermove', function (e) {
      if (!state.pointers.has(e.pointerId)) return;
      state.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });

      if (state.pointers.size === 1 && state.scale > 1.05) {
        // Pan (only if zoomed)
        var ptr = state.pointers.get(e.pointerId);
        var startPtr = { x: 0, y: 0 };
        // Pas de startPtr stocke — approximation simple via delta from last frame
        // Pour MVP, just track move delta
      } else if (state.pointers.size === 2) {
        var pts = Array.from(state.pointers.values());
        var d = getDistance(pts[0], pts[1]);
        var c = getCenter(pts[0], pts[1]);
        var scaleFactor = d / state.startD;
        state.scale = Math.max(MIN, Math.min(MAX, state.startScale * scaleFactor));
        state.x = state.startX + (c.x - state.startCx);
        state.y = state.startY + (c.y - state.startCy);
        applyTransform();
      }
    });

    frame.addEventListener('pointerup', function (e) {
      state.pointers.delete(e.pointerId);
      try { frame.releasePointerCapture(e.pointerId); } catch (_) {}
      if (state.pointers.size === 0) {
        frame.classList.remove('pz-dragging');
        // Snap zoom < 1 back to 1
        if (state.scale < MIN) {
          state.scale = MIN; state.x = 0; state.y = 0;
          content.style.transition = 'transform 240ms cubic-bezier(0.32, 0.72, 0, 1)';
          applyTransform();
          setTimeout(function () { content.style.transition = ''; }, 250);
        }
      }
    });
    frame.addEventListener('pointercancel', function (e) {
      state.pointers.delete(e.pointerId);
      try { frame.releasePointerCapture(e.pointerId); } catch (_) {}
      frame.classList.remove('pz-dragging');
    });

    // Hint visuel first-time
    try {
      if (!localStorage.getItem('ps_pz_hint_seen')) {
        var hint = document.createElement('div');
        hint.className = 'pz-hint visible';
        hint.textContent = '↔ Pincez pour zoomer';
        frame.appendChild(hint);
        setTimeout(function () {
          hint.classList.remove('visible');
          setTimeout(function () { hint.remove(); }, 300);
          try { localStorage.setItem('ps_pz_hint_seen', '1'); } catch (e) {}
        }, 3000);
      }
    } catch (e) {}
  }
  window._psPanZoom = _psPanZoom;

  /* ========== AUTO-WIRING au boot ========== */
  function autoWire() {
    // Auto-haptic sur tap bottom-nav
    var bn = document.getElementById('bottom-nav');
    if (bn) {
      bn.addEventListener('click', function (e) {
        var link = e.target.closest('a');
        if (link) window._psHaptic && window._psHaptic('tap');
      }, { passive: true });
    }

    // Auto-haptic sur tap nav top
    var topNav = document.querySelector('nav:not(#bottom-nav)');
    if (topNav) {
      topNav.addEventListener('click', function (e) {
        var btn = e.target.closest('button, a');
        if (btn) window._psHaptic && window._psHaptic('select');
      }, { passive: true });
    }

    // Auto-pan-zoom RG bracket
    var rgBracket = document.querySelector('#page-rg .rg-bracket-wrap');
    if (rgBracket && !rgBracket.classList.contains('pz-frame')) {
      rgBracket.classList.add('pz-frame');
      try { _psPanZoom(rgBracket); } catch (e) { console.warn('[pz] RG bracket init fail:', e.message); }
    }

    // Observer pour rg-bracket cree dynamiquement (loadRolandGarros async)
    var rgPage = document.getElementById('page-rg');
    if (rgPage && window.MutationObserver) {
      var obs = new MutationObserver(function () {
        var bracket = rgPage.querySelector('.rg-bracket-wrap:not(.pz-frame)');
        if (bracket) {
          bracket.classList.add('pz-frame');
          try { _psPanZoom(bracket); } catch (e) {}
        }
      });
      obs.observe(rgPage, { childList: true, subtree: true });
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', autoWire);
  } else {
    autoWire();
  }

  // Expose toggle pour user opt-out haptic via UI/console
  window.psToggleHaptic = function () {
    try {
      var disabled = localStorage.getItem('ps_haptic_disabled') === '1';
      if (disabled) {
        localStorage.removeItem('ps_haptic_disabled');
        return 'haptic ENABLED';
      } else {
        localStorage.setItem('ps_haptic_disabled', '1');
        return 'haptic DISABLED';
      }
    } catch (e) { return 'error: ' + e.message; }
  };

  /* ========== Phase C — Density toggle + Theme switcher ==========
     Apply data-density + data-theme from localStorage. Inject settings
     panel UI into bn-more-sheet "Plus" drawer. */

  function applySettings() {
    try {
      var density = localStorage.getItem('ps_density') || 'comfortable';
      var theme = localStorage.getItem('ps_theme') || 'auto';
      if (['compact', 'comfortable', 'spacious'].indexOf(density) > -1) {
        document.documentElement.setAttribute('data-density', density);
      }
      if (['auto', 'cream', 'obsidian'].indexOf(theme) > -1) {
        document.documentElement.setAttribute('data-theme', theme);
      }
    } catch (e) {}
  }
  applySettings();

  function injectSettings() {
    var sheet = document.getElementById('bn-more-sheet');
    if (!sheet || sheet.querySelector('.sui-settings')) return;
    var grid = sheet.querySelector('.bn-more-grid');
    if (!grid) return;

    var currentDensity = document.documentElement.getAttribute('data-density') || 'comfortable';
    var currentTheme = document.documentElement.getAttribute('data-theme') || 'auto';

    var panel = document.createElement('div');
    panel.className = 'sui-settings';
    panel.setAttribute('role', 'group');
    panel.setAttribute('aria-label', 'Reglages affichage');
    panel.innerHTML = [
      '<div class="sui-settings-group">',
      '  <span class="sui-settings-label">Densite</span>',
      '  <div class="sui-segmented" role="radiogroup" data-sui-group="density">',
      '    <button class="sui-seg-btn" type="button" role="radio" data-sui-value="compact" aria-pressed="' + (currentDensity === 'compact') + '">Compact</button>',
      '    <button class="sui-seg-btn" type="button" role="radio" data-sui-value="comfortable" aria-pressed="' + (currentDensity === 'comfortable') + '">Confort</button>',
      '    <button class="sui-seg-btn" type="button" role="radio" data-sui-value="spacious" aria-pressed="' + (currentDensity === 'spacious') + '">Spacieux</button>',
      '  </div>',
      '</div>',
      '<div class="sui-settings-group">',
      '  <span class="sui-settings-label">Theme</span>',
      '  <div class="sui-segmented" role="radiogroup" data-sui-group="theme">',
      '    <button class="sui-seg-btn" type="button" role="radio" data-sui-value="auto" aria-pressed="' + (currentTheme === 'auto') + '">Auto OS</button>',
      '    <button class="sui-seg-btn" type="button" role="radio" data-sui-value="cream" aria-pressed="' + (currentTheme === 'cream') + '">Cream</button>',
      '    <button class="sui-seg-btn" type="button" role="radio" data-sui-value="obsidian" aria-pressed="' + (currentTheme === 'obsidian') + '">Obsidian</button>',
      '  </div>',
      '</div>'
    ].join('');

    // Insert AVANT le grid existant
    grid.parentNode.insertBefore(panel, grid);

    // Click handlers segmented buttons
    panel.addEventListener('click', function (e) {
      var btn = e.target.closest('.sui-seg-btn');
      if (!btn) return;
      var groupEl = btn.closest('.sui-segmented');
      var group = groupEl.getAttribute('data-sui-group');
      var value = btn.getAttribute('data-sui-value');
      if (!group || !value) return;
      // Update aria-pressed (radio behavior)
      groupEl.querySelectorAll('.sui-seg-btn').forEach(function (b) {
        b.setAttribute('aria-pressed', b === btn ? 'true' : 'false');
      });
      // Apply + persist
      try { localStorage.setItem('ps_' + group, value); } catch (err) {}
      document.documentElement.setAttribute('data-' + group, value);
      // Haptic feedback
      if (window._psHaptic) window._psHaptic('select');
    }, { passive: true });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', injectSettings);
  } else {
    injectSettings();
  }

  // Expose console helpers
  window.psSetDensity = function (v) {
    if (['compact', 'comfortable', 'spacious'].indexOf(v) === -1) return 'invalid';
    try { localStorage.setItem('ps_density', v); } catch (e) {}
    document.documentElement.setAttribute('data-density', v);
    return 'density set: ' + v;
  };
  window.psSetTheme = function (v) {
    if (['auto', 'cream', 'obsidian'].indexOf(v) === -1) return 'invalid';
    try { localStorage.setItem('ps_theme', v); } catch (e) {}
    document.documentElement.setAttribute('data-theme', v);
    return 'theme set: ' + v;
  };
})();


// ── COMPARATEUR DE COTES ──────────────────────────────────────────────────────
let _compFeed = null;          // [{id,sport,league,home_team,away_team,commence_time,best1,bestN,best2,anj1,nbBooks,trj,surebet,valuebet,decote}]
let _compLoaded = false;
let _compMarket = '1N2';
let _compMode = 'all';
let _compCurrentId = null;
const SPORT_LBL = { football: '⚽ Football', tennis: '🎾 Tennis', basketball: '🏀 Basket' };

// ── Logos bookmakers (favicon service — clé normalisée → domaine) ──────────────
const BK_DOMAINS = {
  winamax:'winamax.fr', betclic:'betclic.fr', unibet:'unibet.fr', pmu:'pmu.fr',
  parionssport:'enligne.parionssport.fdj.fr', parionssportfdj:'enligne.parionssport.fdj.fr',
  fdj:'enligne.parionssport.fdj.fr', zebet:'zebet.fr', bwin:'bwin.fr', netbet:'netbet.fr',
  vbet:'vbet.fr', genybet:'genybet.fr', partouche:'partouchesport.fr', partouchesport:'partouchesport.fr',
  pokerstars:'pokerstars.fr', feelingbet:'feelingbet.fr', francepari:'france-pari.fr', betsson:'betsson.com',
  bet365:'bet365.com', '1xbet':'1xbet.com', onexbet:'1xbet.com', pinnacle:'pinnacle.com',
  pinnaclesports:'pinnacle.com', betfair:'betfair.com', betfairexchange:'betfair.com',
};
function bkKeyNorm(s) {
  return String(s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]/g, '');
}
function bkDomain(nameOrKey) {
  const k = bkKeyNorm(nameOrKey);
  if (!k) return null;
  if (BK_DOMAINS[k]) return BK_DOMAINS[k];
  const hit = Object.keys(BK_DOMAINS).find(d => k.includes(d) || d.includes(k));
  return hit ? BK_DOMAINS[hit] : null;
}
// Renvoie <img>+placeholder. cls: classe CSS. sz: taille px du favicon.
function compBkLogo(nameOrKey, cls, sz) {
  cls = cls || 'comp-bk-logo';
  sz = sz || 64;
  const dom = bkDomain(nameOrKey);
  const init = (String(nameOrKey || '?').replace(/[^A-Za-z0-9]/g, '') || '?').slice(0, 2).toUpperCase();
  const phCls = cls + '-placeholder';
  if (dom) {
    return `<img class="${cls}" src="https://www.google.com/s2/favicons?domain=${dom}&sz=${sz}" alt="${nameOrKey}" title="${nameOrKey}" loading="lazy" onerror="this.style.display='none';this.nextElementSibling.style.display='inline-flex'"><span class="${phCls}" style="display:none">${init}</span>`;
  }
  return `<span class="${phCls}" title="${nameOrKey}">${init}</span>`;
}
// Logo "sous la cote" — n'affiche RIEN si la source n'est pas un vrai bookmaker connu
function compOddBk(nameOrKey) {
  return bkDomain(nameOrKey) ? `<span class="comp-odd-bk">${compBkLogo(nameOrKey,'comp-odd-bk-img',32)}</span>` : '';
}

function applyCompTheme() {
  const root = document.getElementById('comp-root');
  if (!root) return;
  const dark = localStorage.getItem('ps_comp_theme') === 'dark';
  root.classList.toggle('comp-dark', dark);
  root.classList.toggle('comp-light', !dark);
  const b = document.getElementById('comp-theme-btn');
  if (b) b.textContent = dark ? '☀ Thème clair' : '◐ Thème L\'Équipe';
}
function toggleCompTheme() {
  const cur = localStorage.getItem('ps_comp_theme') === 'dark';
  localStorage.setItem('ps_comp_theme', cur ? 'light' : 'dark');
  applyCompTheme();
}

function setCompMode(mode, el) {
  _compMode = mode;
  document.querySelectorAll('#comp-mode-chips .comp-chip').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  renderCompGrid();
}

function setCompMarket(market, el) {
  _compMarket = market;
  document.querySelectorAll('.comp-market-tab').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  else {
    const t = document.querySelector(`.comp-market-tab[data-market="${market}"]`);
    if (t) t.classList.add('active');
  }
  if (_compCurrentId) loadComparateur(_compCurrentId);
}

async function forceRefreshComparateur() {
  const status = document.getElementById('comp-status');
  if (status) status.textContent = '⏳ Actualisation serveur...';
  try {
    await fetch('/api/v1/refresh', { method: 'POST' });
    _compLoaded = false;
    await initComparateur(true);
  } catch (e) {
    if (status) status.textContent = 'Erreur actualisation';
  }
}

async function initComparateur(force) {
  applyCompTheme();
  if (_compLoaded && !force) { renderCompGrid(); return; }
  _compLoaded = true;
  const status = document.getElementById('comp-status');
  if (status) status.textContent = 'Chargement des matchs...';
  try {
    const r = await fetch('/api/v1/comparateur/feed');
    const data = await r.json();
    _compFeed = Array.isArray(data.matches) ? data.matches : [];
    const sportSel = document.getElementById('comp-f-sport');
    if (sportSel) {
      const cur = sportSel.value;
      sportSel.innerHTML = '<option value="">Tous sports</option>' +
        (data.sports || []).map(s => `<option value="${s}">${SPORT_LBL[s] || s}</option>`).join('');
      sportSel.value = cur;
    }
    if (status) status.textContent = `${_compFeed.length} matchs · ${new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'})}`;
    renderCompGrid();
  } catch (e) {
    if (status) status.textContent = 'Erreur chargement matchs';
    const g = document.getElementById('comp-grid');
    if (g) g.innerHTML = '<div class="comp-empty">❌ Erreur chargement — réessayez</div>';
  }
}

function _compDayKey(d) {
  const x = new Date(d), n = new Date();
  const md = new Date(x.getFullYear(), x.getMonth(), x.getDate());
  const m0 = new Date(n.getFullYear(), n.getMonth(), n.getDate());
  const diff = Math.round((md - m0) / 86400000);
  if (diff <= 0) return 'today';
  if (diff === 1) return 'tomorrow';
  if (diff === 2) return 'j2';
  return 'later';
}

function renderCompGrid() {
  const g = document.getElementById('comp-grid');
  if (!g || !_compFeed) return;
  const sport = document.getElementById('comp-f-sport')?.value || '';
  const day   = document.getElementById('comp-f-day')?.value || 'all';
  const sort  = document.getElementById('comp-f-sort')?.value || 'time';
  const q     = (document.getElementById('comp-f-q')?.value || '').toLowerCase().trim();

  let list = _compFeed.slice();
  if (sport) list = list.filter(m => m.sport === sport);
  if (day !== 'all') list = list.filter(m => _compDayKey(m.commence_time) === day);
  if (q) list = list.filter(m => (m.home_team + ' ' + m.away_team).toLowerCase().includes(q));
  if (_compMode === 'surebet') list = list.filter(m => m.surebet != null);
  else if (_compMode === 'value') list = list.filter(m => m.valuebet != null && m.valuebet >= 3);
  else if (_compMode === 'decote') list = list.filter(m => m.decote != null);

  if (sort === 'trj') list.sort((a, b) => (b.trj || 0) - (a.trj || 0));
  else if (sort === 'books') list.sort((a, b) => (b.nbBooks || 0) - (a.nbBooks || 0));
  else list.sort((a, b) => new Date(a.commence_time) - new Date(b.commence_time));

  if (!list.length) {
    g.innerHTML = '<div class="comp-empty">Aucun match pour ces filtres.</div>';
    return;
  }

  const esc = s => String(s == null ? '' : s).replace(/[&<>"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
  const od = v => v ? Number(v).toFixed(2) : '—';
  const head = `<div class="comp-grow comp-ghead"><div>Heure</div><div>Match</div><div style="text-align:center">1</div><div style="text-align:center">N</div><div style="text-align:center">2</div><div style="text-align:center">TRJ</div><div style="text-align:right">Books</div></div>`;

  let html = '', curLeague = null;
  for (const m of list) {
    if (m.league !== curLeague) {
      curLeague = m.league;
      const cnt = list.filter(x => x.league === curLeague).length;
      html += `<div class="comp-gleague">${SPORT_LBL[m.sport] ? SPORT_LBL[m.sport].slice(0,2) : ''} ${esc(curLeague)} <span style="color:var(--cq-mut);font-weight:600;">· ${cnt}</span></div>` + head;
    }
    const dt = new Date(m.commence_time);
    const hm = dt.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
    const dm = dt.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' });
    const flags = [];
    if (m.anj1) flags.push('<span class="comp-gflag anj">ANJ</span>');
    if (m.surebet != null) flags.push(`<span class="comp-gflag sb" title="Arbitrage +${m.surebet}%">SURE</span>`);
    if (m.valuebet != null && m.valuebet >= 3) flags.push(`<span class="comp-gflag vb" title="Edge ${m.valuebet}%">VALUE</span>`);
    if (m.decote != null) flags.push(`<span class="comp-gflag dc" title="Cote 1 ${m.decote}">DÉCOTE</span>`);
    html += `<div class="comp-grow" onclick="openCompDetail('${m.id}')">
      <div class="comp-gtime">${dm}<b>${hm}</b></div>
      <div class="comp-gteams">${esc(m.home_team)} <span style="color:var(--cq-mut)">v</span> ${esc(m.away_team)}<small>${esc(m.league)}</small></div>
      <div class="comp-godd best">${od(m.best1)}${m.best1 ? compOddBk(m.bk1) : ''}</div>
      <div class="comp-godd">${od(m.bestN)}${m.bestN ? compOddBk(m.bkN) : ''}</div>
      <div class="comp-godd best">${od(m.best2)}${m.best2 ? compOddBk(m.bk2) : ''}</div>
      <div class="comp-gtrj">${m.trj != null ? m.trj + '%' : '—'}</div>
      <div class="comp-gflags">${flags.join('')}<span class="comp-gnb">${m.nbBooks}</span></div>
    </div>`;
  }
  g.innerHTML = html;
}

function openCompDetail(matchId) {
  _compCurrentId = matchId;
  document.getElementById('comp-list-view').style.display = 'none';
  document.getElementById('comp-detail-view').style.display = '';
  loadComparateur(matchId);
}
function closeCompDetail() {
  _compCurrentId = null;
  document.getElementById('comp-detail-view').style.display = 'none';
  document.getElementById('comp-list-view').style.display = '';
  renderCompGrid();
}

async function loadComparateur(matchId) {
  if (!matchId) return;
  const status = document.getElementById('comp-status');
  const content = document.getElementById('comp-content');
  content.innerHTML = '<div class="comp-empty">⏳ Chargement des cotes...</div>';
  try {
    const r = await fetch(`/api/v1/comparateur/${encodeURIComponent(matchId)}?market=${_compMarket}`);
    const d = await r.json();
    content.innerHTML = renderComparateur(d);
  } catch (e) {
    content.innerHTML = '<div class="comp-empty">❌ Erreur chargement — réessayez</div>';
  }
}

function renderComparateur(d) {
  const { home_team, away_team, commence_time, league, fair, rows, avgRow, market, poisson, wfv, ic, surebet, oddsHistory } = d;
  if (!rows || !rows.length) {
    return '<div class="comp-empty">Aucune cote multi-bookmakers disponible pour ce match.<br><small>Les cotes détaillées sont collectées au cycle suivant (toutes les 12h).</small></div>';
  }

  const dt = new Date(commence_time);
  const dateStr = dt.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
  const timeStr = dt.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
  const mkt = market || '1N2';

  // ── Helpers ──
  function fmtOdd(val, isBest) {
    if (!val) return '<td style="color:#ccc">—</td>';
    return isBest
      ? `<td><strong class="comp-best-odd">${safeFixed(val, 2)}</strong></td>`
      : `<td>${safeFixed(val, 2)}</td>`;
  }
  function fmtPayout(p) {
    if (!p) return '<td style="color:#ccc">—</td>';
    const cls = p >= 98 ? 'comp-payout-hi' : p >= 96 ? 'comp-payout-mid' : 'comp-payout-lo';
    return `<td class="${cls}">${safeFixed(p, 1)}%</td>`;
  }
  function deltaSpan(delta) {
    if (delta == null || delta === 0) return '';
    const sign = delta > 0 ? '+' : '';
    const cls  = delta > 0 ? 'comp-delta-up' : 'comp-delta-dn';
    return `<span class="comp-delta ${cls}">(${sign}${safeFixed(delta, 2)})</span>`;
  }

  function bkLogoHTML(r) {
    if (r.isAvg) return '';
    return compBkLogo(r.key || r.title, 'comp-bk-logo', 64);
  }
  function bkBadge(r) {
    if (r.isAvg) return '';
    return r.isANJ ? '<span class="comp-badge-anj">ANJ</span>' : '<span class="comp-badge-nonanj">non-ANJ</span>';
  }
  function nameCell(r) {
    return `<td><div class="comp-bk-name">${bkLogoHTML(r)}${r.title}${bkBadge(r) ? ' ' + bkBadge(r) : ''}</div></td>`;
  }
  function sepRow(span) {
    return `<tr class="comp-sep-row"><td colspan="${span}">Bookmakers non agréés en France — informatif uniquement</td></tr>`;
  }
  function avgTr(cells) {
    return avgRow ? `<tr class="comp-avg-row"><td><div class="comp-bk-name">Moyenne du Marché</div></td>${cells}</tr>` : '';
  }
  function wfvTr(cells) {
    return wfv ? `<tr class="comp-wfv-row"><td><div class="comp-bk-name" title="Moyenne pondérée no-vig par liquidité book">Val. Marché Pondérée</div></td>${cells}</tr>` : '';
  }
  function poissonFallback(label, prob) {
    return `<div class="comp-wrap"><div class="comp-header"><div>
        <div class="comp-header-title">${home_team} vs ${away_team}</div>
        <div class="comp-meta">${league} · ${dateStr} à ${timeStr}</div>
      </div></div>
      <div style="padding:24px 20px;background:#fff;text-align:center;color:#666;font-size:.9rem;">
        Cotes ${label} non disponibles pour ce match (prochain cycle dans 12h).${prob != null ? `<br><strong>Probabilité modèle : ${label} = ${prob}%</strong>` : ''}
      </div></div>`;
  }

  // ── IC badge ──
  let icBadge = '';
  if (ic != null) {
    const icPct = Math.round(ic * 100);
    const icCls = icPct >= 80 ? 'comp-ic-high' : icPct >= 60 ? 'comp-ic-mid' : 'comp-ic-low';
    const icLbl = icPct >= 80 ? 'Consensus fort' : icPct >= 60 ? 'Consensus moyen' : 'Marché divisé';
    icBadge = `<span class="comp-ic-badge ${icCls}" title="Indice de Consensus — mesure l'accord entre bookmakers">IC ${icPct}% — ${icLbl}</span>`;
  }
  const surebetBadge = surebet != null ? `<span class="comp-surebet-badge" title="Arbitrage détecté — couverture rentable">ARBI +${safeFixed(surebet, 2)}%</span>` : '';

  // ── Market sections ──
  function buildOUSection(lineStr, ovField, unField, payField, probField) {
    const bestOv = Math.max(...rows.map(r => r[ovField] || 0));
    const bestUn = Math.max(...rows.map(r => r[unField] || 0));
    const bestP  = Math.max(...rows.map(r => r[payField] || 0));
    if (!rows.some(r => r[ovField])) return { noData: true, prob: poisson?.[probField] };
    const thead = `<tr>
      <th style="min-width:220px;text-align:left;">Bookmaker</th>
      <th>+ ${lineStr} buts (Over)</th><th>- ${lineStr} buts (Under)</th><th>Payout</th>
    </tr>`;
    const bestRow_ = `<tr class="comp-best-row">
      <td><div class="comp-bk-name">Meilleure cote</div></td>
      <td><strong class="comp-best-odd">${bestOv ? safeFixed(bestOv, 2) : '—'}</strong></td>
      <td><strong class="comp-best-odd">${bestUn ? safeFixed(bestUn, 2) : '—'}</strong></td>
      <td class="comp-payout-hi"><strong>${bestP ? safeFixed(bestP, 1) + '%' : '—'}</strong></td>
    </tr>`;
    const rr = (r, cls='') => `<tr class="${cls}">${nameCell(r)}
      ${fmtOdd(r[ovField], r[ovField] === bestOv && bestOv > 0)}
      ${fmtOdd(r[unField], r[unField] === bestUn && bestUn > 0)}
      ${fmtPayout(r[payField])}</tr>`;
    const anjR = rows.filter(r => r.isANJ), nonR = rows.filter(r => !r.isANJ);
    const data = anjR.map(r => rr(r)).join('')
      + (nonR.length ? sepRow(4) + nonR.map(r => rr(r, 'non-anj')).join('') : '')
      + avgTr(fmtOdd(avgRow?.[ovField], false) + fmtOdd(avgRow?.[unField], false) + fmtPayout(avgRow?.payout));
    return { thead, bestRow: bestRow_, dataRows: data };
  }

  function buildSingleSection(label, field) {
    const best = Math.max(...rows.map(r => r[field] || 0));
    const thead = `<tr>
      <th style="min-width:220px;text-align:left;">Bookmaker</th>
      <th>${label}</th>
    </tr>`;
    const bestRow_ = `<tr class="comp-best-row">
      <td><div class="comp-bk-name">Meilleure cote</div></td>
      <td><strong class="comp-best-odd">${best ? safeFixed(best, 2) : '—'}</strong></td>
    </tr>`;
    const rr = (r, cls='') => `<tr class="${cls}">${nameCell(r)}${fmtOdd(r[field], r[field] === best && best > 0)}</tr>`;
    const anjR = rows.filter(r => r.isANJ), nonR = rows.filter(r => !r.isANJ);
    const data = anjR.map(r => rr(r)).join('')
      + (nonR.length ? sepRow(2) + nonR.map(r => rr(r, 'non-anj')).join('') : '')
      + avgTr(fmtOdd(avgRow?.[field], false));
    return { thead, bestRow: bestRow_, dataRows: data };
  }

  let thead, bestRow, dataRows;

  if (mkt === 'OU15') {
    const res = buildOUSection('1.5', 'over15', 'under15', 'payoutOU15', 'over15');
    if (res.noData) return poissonFallback('Over/Under 1.5', res.prob ?? null);
    ({ thead, bestRow, dataRows } = res);

  } else if (mkt === 'OU25') {
    const res = buildOUSection('2.5', 'over25', 'under25', 'payoutOU', 'over25');
    if (res.noData) return poissonFallback('Over/Under 2.5', poisson?.over25);
    ({ thead, bestRow, dataRows } = res);

  } else if (mkt === 'OU35') {
    const res = buildOUSection('3.5', 'over35', 'under35', 'payoutOU35', 'over35');
    if (res.noData) return poissonFallback('Over/Under 3.5', poisson?.over35);
    ({ thead, bestRow, dataRows } = res);

  } else if (mkt === 'BTTS') {
    const bestYes = Math.max(...rows.map(r => r.bttsYes || 0));
    const bestNo  = Math.max(...rows.map(r => r.bttsNo  || 0));
    const bestP   = Math.max(...rows.map(r => r.payoutBTTS || 0));
    if (!rows.some(r => r.bttsYes)) return poissonFallback('BTTS', poisson?.btts);
    thead = `<tr>
      <th style="min-width:220px;text-align:left;">Bookmaker</th>
      <th>Les deux marquent — Oui</th><th>Les deux marquent — Non</th><th>Payout</th>
    </tr>`;
    bestRow = `<tr class="comp-best-row">
      <td><div class="comp-bk-name">Meilleure cote</div></td>
      <td><strong class="comp-best-odd">${bestYes ? safeFixed(bestYes, 2) : '—'}</strong></td>
      <td><strong class="comp-best-odd">${bestNo ? safeFixed(bestNo, 2) : '—'}</strong></td>
      <td class="comp-payout-hi"><strong>${bestP ? safeFixed(bestP, 1) + '%' : '—'}</strong></td>
    </tr>`;
    const rr = (r, cls='') => `<tr class="${cls}">${nameCell(r)}
      ${fmtOdd(r.bttsYes, r.bttsYes === bestYes && bestYes > 0)}
      ${fmtOdd(r.bttsNo,  r.bttsNo  === bestNo  && bestNo  > 0)}
      ${fmtPayout(r.payoutBTTS)}</tr>`;
    const anjR = rows.filter(r => r.isANJ), nonR = rows.filter(r => !r.isANJ);
    dataRows = anjR.map(r => rr(r)).join('')
      + (nonR.length ? sepRow(4) + nonR.map(r => rr(r, 'non-anj')).join('') : '')
      + avgTr(fmtOdd(avgRow?.bttsYes, false) + fmtOdd(avgRow?.bttsNo, false) + fmtPayout(avgRow?.payout));

  } else if (mkt === 'DC') {
    const best1X  = Math.max(...rows.map(r => r.dc1X || 0));
    const bestX2  = Math.max(...rows.map(r => r.dcX2 || 0));
    const best12  = Math.max(...rows.map(r => r.dc12 || 0));
    if (!rows.some(r => r.dc1X || r.dcX2)) return poissonFallback('Double Chance', null);
    thead = `<tr>
      <th style="min-width:220px;text-align:left;">Bookmaker</th>
      <th>1X — Dom. ou Nul</th><th>X2 — Ext. ou Nul</th><th>12 — Dom. ou Ext.</th>
    </tr>`;
    bestRow = `<tr class="comp-best-row">
      <td><div class="comp-bk-name">Meilleure cote</div></td>
      <td><strong class="comp-best-odd">${best1X ? safeFixed(best1X, 2) : '—'}</strong></td>
      <td><strong class="comp-best-odd">${bestX2 ? safeFixed(bestX2, 2) : '—'}</strong></td>
      <td><strong class="comp-best-odd">${best12 ? safeFixed(best12, 2) : '—'}</strong></td>
    </tr>`;
    const rr = (r, cls='') => `<tr class="${cls}">${nameCell(r)}
      ${fmtOdd(r.dc1X, r.dc1X === best1X && best1X > 0)}
      ${fmtOdd(r.dcX2, r.dcX2 === bestX2 && bestX2 > 0)}
      ${fmtOdd(r.dc12, r.dc12 === best12 && best12 > 0)}</tr>`;
    const anjR = rows.filter(r => r.isANJ), nonR = rows.filter(r => !r.isANJ);
    dataRows = anjR.map(r => rr(r)).join('')
      + (nonR.length ? sepRow(4) + nonR.map(r => rr(r, 'non-anj')).join('') : '')
      + avgTr(fmtOdd(avgRow?.dc1X, false) + fmtOdd(avgRow?.dcX2, false) + fmtOdd(avgRow?.dc12, false));

  } else if (mkt === 'HOME_WIN') {
    ({ thead, bestRow, dataRows } = buildSingleSection(`Victoire ${home_team}`, 'home'));
  } else if (mkt === 'DRAW') {
    ({ thead, bestRow, dataRows } = buildSingleSection('Match Nul', 'draw'));
  } else if (mkt === 'AWAY_WIN') {
    ({ thead, bestRow, dataRows } = buildSingleSection(`Victoire ${away_team}`, 'away'));

  } else {
    // 1N2 (default) — with WFV row + Surebet + Delta
    const anjRows = rows.filter(r => r.isANJ), nonAnjRows = rows.filter(r => !r.isANJ);
    const bestHome   = Math.max(...rows.map(r => r.home || 0));
    const drawVals   = rows.map(r => r.draw).filter(v => v);
    const bestDraw   = drawVals.length ? Math.max(...drawVals) : null;
    const bestAway   = Math.max(...rows.map(r => r.away || 0));
    const bestPayout = Math.max(...rows.map(r => r.payout || 0));

    const dH = oddsHistory?.deltaHome, dD = oddsHistory?.deltaHome != null ? oddsHistory.deltaDraw : null, dA = oddsHistory?.deltaAway;
    const deltaInfo = oddsHistory ? `<span style="font-size:.72rem;color:#888;margin-left:6px;">Δ vs ${oddsHistory.ageMin}min ago</span>` : '';

    thead = `<tr>
      <th style="min-width:220px;text-align:left;">Bookmaker</th>
      <th>1 — ${home_team}</th><th>N</th><th>2 — ${away_team}</th><th>Payout</th>
    </tr>`;
    const bkOf = (field, val) => { if (!val) return ''; const r = rows.find(x => x[field] === val && !x.isAvg && x.key !== '_best'); return r ? compOddBk(r.key || r.title) : ''; };
    bestRow = `<tr class="comp-best-row">
      <td><div class="comp-bk-name">Meilleure cote${deltaInfo}</div></td>
      <td><strong class="comp-best-odd">${safeFixed(bestHome, 2)}</strong>${deltaSpan(dH)}${bkOf('home', bestHome)}</td>
      <td><strong class="comp-best-odd">${bestDraw ? safeFixed(bestDraw, 2) : '—'}</strong>${deltaSpan(dD)}${bkOf('draw', bestDraw)}</td>
      <td><strong class="comp-best-odd">${safeFixed(bestAway, 2)}</strong>${deltaSpan(dA)}${bkOf('away', bestAway)}</td>
      <td class="comp-payout-hi"><strong>${safeFixed(bestPayout, 1)}%</strong></td>
    </tr>`;
    const rr = (r, cls='') => `<tr class="${cls}">${nameCell(r)}
      ${fmtOdd(r.home, r.home === bestHome)}
      ${fmtOdd(r.draw, bestDraw !== null && r.draw === bestDraw)}
      ${fmtOdd(r.away, r.away === bestAway)}
      ${fmtPayout(r.payout)}</tr>`;

    // WFV row: convert prob to fair odd
    const wfvCells = wfv
      ? `<td>${wfv.home > 0 ? (1/wfv.home).toFixed(2) : '—'}</td>`
        + `<td>${wfv.draw > 0 ? (1/wfv.draw).toFixed(2) : '—'}</td>`
        + `<td>${wfv.away > 0 ? (1/wfv.away).toFixed(2) : '—'}</td><td>—</td>` : '';

    let fairSection = '';
    if (fair) {
      const toF = p => p && p > 0 ? (1/p).toFixed(2) : '—';
      fairSection = `<tr class="comp-fair-row">
        <td><div class="comp-bk-name">Cote modèle (no-vig)</div></td>
        <td>${toF(fair.home)}</td><td>${toF(fair.draw)}</td><td>${toF(fair.away)}</td><td>—</td>
      </tr>`;
    }

    const phRows = ['Bet365 (FR)', 'Bookmakers Belgique', 'Bookmakers Suisse']
      .map(n => `<tr class="comp-ph-row"><td><div class="comp-bk-name">${n}</div></td><td>—</td><td>—</td><td>—</td><td>bientôt</td></tr>`)
      .join('');
    dataRows = anjRows.map(r => rr(r)).join('')
      + (nonAnjRows.length ? `<tr class="comp-sep-row"><td colspan="5">Bookmakers non agréés en France — aucun lien de redirection</td></tr>` + nonAnjRows.map(r => rr(r, 'non-anj')).join('') : '')
      + `<tr class="comp-sep-row"><td colspan="5">Sources non disponibles — intégration ultérieure</td></tr>` + phRows
      + avgTr(fmtOdd(avgRow?.home, false) + fmtOdd(avgRow?.draw, false) + fmtOdd(avgRow?.away, false) + fmtPayout(avgRow?.payout))
      + wfvTr(wfvCells)
      + fairSection;
  }

  const fallbackBanner = d._fallback
    ? `<div style="background:#FFF8E1;border-left:4px solid #FFA726;padding:10px 16px;font-size:.82rem;color:#6D4C00;">
        <strong>Données partielles</strong> — cotes multi-bookmakers non disponibles (ligue secondaire). Cycle suivant dans 12h.
       </div>`
    : '';

  return `
  <div class="comp-wrap">
    ${fallbackBanner}
    <div class="comp-header">
      <div>
        <div class="comp-header-title">${home_team} vs ${away_team}</div>
        <div class="comp-meta">${league} · ${dateStr} à ${timeStr}</div>
      </div>
      <div class="comp-header-badges">${icBadge}${surebetBadge}</div>
    </div>
    <div style="overflow-x:auto;">
    <table class="comp-table">
      <thead>${thead}</thead>
      <tbody>${bestRow}${dataRows}</tbody>
    </table>
    </div>
  </div>`;
}

/* ═══════════════════════════════════════════════════════════════════════
   MOBILE — bottom nav, drawer, cartes matchs, chips, PWA
   Tout est inerte sur desktop (CSS masque les éléments).
   ═══════════════════════════════════════════════════════════════════════ */
(function () {
  var MQ = window.matchMedia('(max-width: 768px)');
  function isMobile() { return MQ.matches; }

  /* — Bottom nav : navigation — */
  window.bnGo = function (page, el) {
    if (page === '__more') { bnOpenMore(); return; }
    if (page === '__live') {
      // Onglet Live = page matchs + sous-onglet live
      if (typeof showPage === 'function') showPage('matchs');
      try {
        var lt = document.querySelector('[onclick*="setMatchTab(\'live\'"]');
        if (lt) lt.click();
        else if (typeof setMatchTab === 'function') setMatchTab('live');
      } catch (e) {}
      bnSetActive('__live');
      bnCloseMore();
      return;
    }
    bnCloseMore();
    if (typeof showPage === 'function') showPage(page);
    bnSetActive(page);
  };
  function bnSetActive(page) {
    document.querySelectorAll('#bottom-nav a').forEach(function (a) {
      a.classList.toggle('active', a.dataset.page === page);
    });
  }
  // Sync bottom-nav quand on navigue via showPage (top nav, code, etc.)
  if (typeof window.showPage === 'function') {
    var _origShowPage = window.showPage;
    window.showPage = function (pageId, linkEl) {
      var r = _origShowPage.apply(this, arguments);
      try {
        var bnPages = ['matchs', 'tennis', 'strategies', 'paris'];
        bnSetActive(bnPages.indexOf(pageId) >= 0 ? pageId : '__more');
      } catch (e) {}
      try { window.psWrapWideTables(); setTimeout(window.psWrapWideTables, 600); } catch (e) {}
      return r;
    };
  }

  /* — Audit form : tables larges → scroll horizontal (mobile only) — */
  function _wrapScroll(sel) {
    document.querySelectorAll(sel).forEach(function (t) {
      var p = t.parentNode;
      if (!p || (p.classList && p.classList.contains('tbl-scroll'))) return;
      var w = document.createElement('div');
      w.className = 'tbl-scroll';
      p.insertBefore(w, t);
      w.appendChild(t);
    });
  }
  window.psWrapWideTables = function () {
    if (!isMobile()) return;
    try {
      _wrapScroll('#tennis-vb-table, #tennis-live-table, .tex-table, ' +
        '#page-paris .hist-table, #page-historique .hist-table, ' +
        '#page-predictions .bm-table');
    } catch (e) {}
  };

  /* — Drawer "Plus" — */
  window.bnOpenMore = function () {
    document.getElementById('bn-more-overlay').classList.add('open');
    document.getElementById('bn-more-sheet').classList.add('open');
    bnSetActive('__more');
  };
  window.bnCloseMore = function () {
    var o = document.getElementById('bn-more-overlay');
    var s = document.getElementById('bn-more-sheet');
    if (o) o.classList.remove('open');
    if (s) s.classList.remove('open');
  };

  /* — Lot E : bottom-sheet « Filtres » (relocalise les rows desktop) — */
  var _mfsMoved = false;
  function _mfsRelocate() {
    if (_mfsMoved) return;
    var body = document.getElementById('mfs-body');
    if (!body) return;
    // Rows visibles à relocaliser dans le bottom-sheet mobile (ordre = affichage).
    // Maj v10.43 : topn-filter-row (Top stratégies + slider Confiance) AJOUTÉ ;
    // period-kickoff-row (fusion) ; league-filter-row exclu (display:none) ; edge supprimé.
    ['day-filter-row', 'topn-filter-row', 'period-kickoff-row', 'adv-filter-row'].forEach(function (id) {
      var el = document.getElementById(id);
      if (el) body.appendChild(el); // déplace (handlers délégués → intacts)
    });
    _mfsMoved = true;
  }
  window.openMobFilters = function () {
    _mfsRelocate();
    var o = document.getElementById('mob-filter-overlay');
    var s = document.getElementById('mob-filter-sheet');
    if (o) o.classList.add('open');
    if (s) s.classList.add('open');
    window.mfsSyncCount();
  };
  window.closeMobFilters = function () {
    var o = document.getElementById('mob-filter-overlay');
    var s = document.getElementById('mob-filter-sheet');
    if (o) o.classList.remove('open');
    if (s) s.classList.remove('open');
    // Force re-render des cartes mobile + feedback visuel : la nappe « Filtres »
    // ne déclenchait aucune confirmation, l'utilisateur perd la main (cf. bug
    // mobile 2026-05-19).
    try {
      if (typeof renderMatches === 'function' && typeof allMatches !== 'undefined'
          && Array.isArray(allMatches)) {
        renderMatches(allMatches);
      }
    } catch (e) {}
    try {
      if (typeof showNotification === 'function') showNotification('Filtres appliqués', 'green');
    } catch (e) {}
  };
  window.mfsSyncCount = function () {
    var c = document.getElementById('mfs-count');
    var src = document.getElementById('mob-bet-count');
    if (c && src) c.textContent = src.textContent || '—';
  };
  // Relocalise dès le chargement en mobile (rows hors-flux tant que sheet fermée)
  if (isMobile()) { try { _mfsRelocate(); } catch (e) {} }

  /* — Live badge sur bottom-nav (sync depuis le badge table existant) — */
  window.bnSyncLiveBadge = function (n) {
    var b = document.getElementById('bn-live-badge');
    if (!b) return;
    n = parseInt(n) || 0;
    b.textContent = n;
    b.style.display = n > 0 ? '' : 'none';
  };

  /* — Chips presets : pilotent les filtres existants — */
  window.mobChip = function (key, el) {
    var on = !el.classList.contains('on');
    el.classList.toggle('on', on);
    try {
      if (key === 'live') {
        var lt = document.querySelector('[onclick*="setMatchTab(\'' + (on ? 'live' : 'all') + '\'"]');
        if (lt) lt.click(); else if (typeof setMatchTab === 'function') setMatchTab(on ? 'live' : 'all');
      } else if (key === 'edge5') {
        if (typeof activeEdge !== 'undefined') { activeEdge = on ? 5 : 0; }
        _mobRerender();
      } else if (key === 'today') {
        var db = document.getElementById('day-btn-0');
        var da = document.querySelector('[data-day="all"]');
        if (on && db) db.click(); else if (da) da.click();
      } else if (key === 'o25') {
        if (typeof activeO25Min !== 'undefined') { activeO25Min = on ? 55 : 0; }
        _mobRerender();
      } else if (key === 'btts') {
        // tri BTTS descendant comme proxy "meilleurs BTTS"
        if (typeof setSort === 'function') setSort(on ? 'poisson_btts' : null);
        _syncSortSel();
      } else if (key === 'fav') {
        if (typeof activeFavFilter !== 'undefined') { activeFavFilter = on; }
        _mobRerender();
      }
    } catch (e) { console.warn('mobChip', key, e); }
  };

  /* — Filtre rapide en dropdown (remplace les chips) — */
  window.mobQuickSel = function (val) {
    try {
      document.querySelectorAll('#mob-chips .mob-chip.on').forEach(function (b) { b.click(); });
      if (val) {
        var t = document.querySelector('#mob-chips .mob-chip[data-mchip="' + val + '"]');
        if (t) t.click();
      }
    } catch (e) { console.warn('mobQuickSel', e); }
  };

  /* — Sélecteur de tri mobile — */
  window.mobSetSort = function (val) {
    try {
      if (val === 'time') { if (typeof setSort === 'function') setSort(null); }
      else if (val === 'edge') {
        // pas de sortKey edge natif : on trie le tableau filtré côté carte
        if (typeof setSort === 'function') setSort(null);
        _mobSortMode = 'edge';
        _mobRerender();
        return;
      }
      else if (typeof setSort === 'function') setSort(val);
      _mobSortMode = null;
    } catch (e) {}
  };
  var _mobSortMode = 'edge';
  function _syncSortSel() {
    var s = document.getElementById('mob-sort-sel');
    if (s && typeof sortKey !== 'undefined' && sortKey) s.value = sortKey;
  }
  function _mobRerender() {
    if (typeof renderMatches === 'function' && typeof allMatches !== 'undefined') {
      renderMatches(allMatches);
    }
  }

  /* — Helpers rendu carte — */
  function esc(s) {
    return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
      .replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
  }
  function fmtTime(m) {
    try {
      var d = (typeof parseKickoff === 'function') ? parseKickoff(m.commence_time) : new Date(m.commence_time);
      if (!d || isNaN(d)) return '--:--';
      return d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris' });
    } catch (e) { return '--:--'; }
  }
  function isLive(m) {
    try { return typeof isMatchInProgress === 'function' ? isMatchInProgress(m) : false; }
    catch (e) { return false; }
  }

  /* — Rendu des cartes (consomme la liste DÉJÀ filtrée+triée par renderMatches) — */
  window.renderMobileCards = function (filtered) {
    var box = document.getElementById('vb-cards');
    if (!box) return;
    if (!isMobile()) { box.innerHTML = ''; return; }
    var list = Array.isArray(filtered) ? filtered.slice() : [];

    // Tri "edge" si demandé via le sélecteur mobile (sinon on respecte l'ordre reçu)
    if (_mobSortMode === 'edge') {
      list.sort(function (a, b) {
        return (b.best_edge && b.best_edge.edge || 0) - (a.best_edge && a.best_edge.edge || 0);
      });
    }

    var cnt = document.getElementById('mob-bet-count');
    if (cnt) {
      var vb = list.filter(function (m) { return (m.best_edge && m.best_edge.edge || 0) > 0; }).length;
      cnt.textContent = list.length + ' match' + (list.length > 1 ? 's' : '') +
        (vb > 0 ? ' · ' + vb + ' value' : '');
    }

    if (!list.length) {
      // Fix V7 ParisScorebis-amc : si 0 match affiché alors que allMatches >50,
      // le user est piégé par des filtres trop restrictifs (cas DIAG mobile :
      // 214 matchs disponibles mais o25-slider à 8% → mc-empty). Ajout CTA
      // inline qui reset tous les filtres sans ouvrir la nappe.
      var total = (typeof allMatches !== 'undefined' && Array.isArray(allMatches))
        ? allMatches.length : 0;
      var resetCta = (total > 50)
        ? '<button type="button" onclick="(function(){var b=document.getElementById(\'adv-reset-btn\');if(b)b.click();var s=document.getElementById(\'o25-slider\');if(s){s.value=0;s.dispatchEvent(new Event(\'input\',{bubbles:true}));s.dispatchEvent(new Event(\'change\',{bubbles:true}));}var v=document.getElementById(\'o25-val\');if(v)v.textContent=\'0%\';})();" '
          + 'style="margin-top:10px;background:var(--accent);color:#fff;border:none;border-radius:8px;padding:10px 18px;font-family:var(--font-head);font-weight:700;font-size:13px;text-transform:uppercase;cursor:pointer;">'
          + '✕ Réinitialiser les filtres (' + total + ' matchs disponibles)</button>'
        : '';
      box.innerHTML = '<div class="mc-empty">Aucun match pour ces filtres.<br>' + resetCta + '</div>';
      return;
    }

    function buildCard(m) {
      var live = isLive(m);
      var sc = m.live_score;
      var po = m.poisson || {};
      var edge = m.best_edge && typeof m.best_edge.edge === 'number' ? m.best_edge.edge : null;
      var edgeCls = edge == null ? 'neg' : (edge >= 5 ? 'hot' : (edge > 0 ? '' : 'neg'));
      var edgeTxt = edge == null ? '—' : (edge > 0 ? '+' : '') + safeFixed(edge, 1) + '%';
      var o = m.odds || {};
      var be = m.best_edge || {};
      // Verdict décision (edge dévigé — tiers transparents)
      var vC, vT;
      if (edge == null)      { vC = 'na';  vT = 'DATA —'; }
      else if (edge >= 5)    { vC = 'go';  vT = 'VALUE'; }
      else if (edge >= 1.5)  { vC = 'try'; vT = 'À TENTER'; }
      else if (edge > 0)     { vC = 'neu'; vT = 'NEUTRE'; }
      else                   { vC = 'no';  vT = 'ÉVITER'; }
      var pickTxt = be.label ? ' ' + esc(String(be.label)).toUpperCase() : '';
      function oddCell(k, lbl) {
        var v = o[k];
        var best = be.label && (
          (k === 'home' && /dom|1|home/i.test(be.label)) ||
          (k === 'draw' && /nul|x|draw/i.test(be.label)) ||
          (k === 'away' && /ext|2|away/i.test(be.label))
        );
        return '<div class="mc-odd' + (best ? ' best' : '') + '"><b>' + lbl + '</b>' +
          (v ? Number(v).toFixed(2) : '—') + '</div>';
      }
      var rkH = m.home_rank ? '<span class="mc-rk">#' + esc(m.home_rank) + '</span>' : '';
      var rkA = m.away_rank ? '<span class="mc-rk">#' + esc(m.away_rank) + '</span>' : '';
      var scH = sc ? '<span class="mc-sc">' + esc((sc.home != null ? sc.home : '-')) + '</span>' : '';
      var scA = sc ? '<span class="mc-sc">' + esc((sc.away != null ? sc.away : '-')) + '</span>' : '';
      var timeTxt = live
        ? (esc(m.live_minute ? m.live_minute + "'" : 'LIVE'))
        : fmtTime(m);

      var st = m.stats || {}, sh = st.home || {}, sa = st.away || {};
      function num(v, d) { return (v == null || isNaN(v)) ? '—' : (typeof d === 'number' ? Number(v).toFixed(d) : v); }
      function pct(v) { return v == null || isNaN(v) ? '—' : Math.round(v) + '%'; }
      function wrate(s) {
        var w = +s.wins || 0, dr = +s.draws || 0, l = +s.losses || 0, t = w + dr + l;
        return t ? Math.round(w / t * 100) + '%' : '—';
      }
      var bestPick = be.label ? esc(String(be.label)) : '—';
      var bestOdds = be.odds ? Number(be.odds).toFixed(2) : (be.bestOdds ? Number(be.bestOdds).toFixed(2) : '');
      var reco = (vC === 'go' || vC === 'try')
        ? bestPick + (bestOdds ? ' @ ' + bestOdds : '') + ' · ' + edgeTxt + ' edge'
        : (vC === 'neu' ? 'Pas d\'edge net — prudence' : 'Aucune valeur — éviter');
      var detail =
        '<div class="mc-detail">' +
          '<div class="mcd-reco mc-v-' + vC + '"><b>' + vT + '</b> ' + reco + '</div>' +
          '<div class="mcd-grid">' +
            '<div class="mcd-c"><span>PPG D/E</span><b>' + num(sh.ppg, 2) + ' / ' + num(sa.ppg, 2) + '</b></div>' +
            '<div class="mcd-c"><span>Win% D/E</span><b>' + wrate(sh) + ' / ' + wrate(sa) + '</b></div>' +
            '<div class="mcd-c"><span>Buts m. D/E</span><b>' + num(sh.avgScored, 2) + ' / ' + num(sa.avgScored, 2) + '</b></div>' +
            '<div class="mcd-c"><span>Buts e. D/E</span><b>' + num(sh.avgConceded, 2) + ' / ' + num(sa.avgConceded, 2) + '</b></div>' +
            '<div class="mcd-c"><span>1 N 2</span><b>' + pct(po.homeWin) + ' · ' + pct(po.draw) + ' · ' + pct(po.awayWin) + '</b></div>' +
            '<div class="mcd-c"><span>O1.5/2.5/3.5</span><b>' + pct(po.over15) + ' · ' + pct(po.over25) + ' · ' + pct(po.over35) + '</b></div>' +
            '<div class="mcd-c"><span>BTTS</span><b>' + pct(po.btts) + '</b></div>' +
            '<div class="mcd-c"><span>Edge dévigé</span><b>' + edgeTxt + '</b></div>' +
          '</div>' +
          '<button class="mcd-more" onclick="event.stopPropagation();mcOpen(\'' + esc(m.id) + '\')">Analyse complète →</button>' +
        '</div>';
      var isFav = (typeof favoriteMatchIds !== 'undefined' && favoriteMatchIds && favoriteMatchIds.has)
        ? favoriteMatchIds.has(m.id) : false;
      var rankChip = (m.home_rank && m.away_rank)
        ? '<span class="mc-chip">' + esc(m.home_rank) + 'e v ' + esc(m.away_rank) + 'e</span>' : '';
      return (
        '<div class="mc" onclick="mcToggle(this)">' +
          '<div class="mc-top">' +
            '<span class="mc-verdict mc-v-' + vC + '">' + vT + '</span>' +
            '<span class="mc-league">' + esc(m.league || m.sport || '') + '</span>' +
            rankChip +
            '<span class="mc-time' + (live ? ' live' : '') + '">' + timeTxt + '</span>' +
            '<button class="mc-star' + (isFav ? ' active' : '') + '" aria-label="Favori" ' +
              'onclick="event.stopPropagation();toggleFavorite(\'' + esc(m.id) + '\',this)">★</button>' +
            '<span class="mc-chev">›</span>' +
          '</div>' +
          (vC === 'go' || vC === 'try'
            ? '<div class="mc-pick mc-v-' + vC + '">→ ' + edgeTxt + ' edge dévigé' + (pickTxt ? ' ·' + pickTxt : '') + '</div>'
            : '') +
          '<div class="mc-teams">' +
            '<div class="mc-team">' + rkH + '<span>' + esc(m.home_team) + '</span>' + scH + '</div>' +
            '<div class="mc-team">' + rkA + '<span>' + esc(m.away_team) + '</span>' + scA + '</div>' +
          '</div>' +
          (function(){ try { return (typeof renderPredBets==='function') ? renderPredBets(m) : ''; } catch(e){ return ''; } })() +
          '<div class="mc-metrics">' +
            '<div class="mc-cell edge ' + edgeCls + '"><div class="mc-k">Edge</div><div class="mc-v">' + edgeTxt + '</div></div>' +
            '<div class="mc-cell"><div class="mc-k">O2.5</div><div class="mc-v">' + (po.over25 != null ? Math.round(po.over25) + '%' : '—') + '</div></div>' +
            '<div class="mc-cell"><div class="mc-k">BTTS</div><div class="mc-v">' + (po.btts != null ? Math.round(po.btts) + '%' : '—') + '</div></div>' +
            '<div class="mc-cell"><div class="mc-k">1N2</div><div class="mc-v">' + (po.homeWin != null ? Math.round(po.homeWin) + '%' : '—') + '</div></div>' +
          '</div>' +
          '<div class="mc-bottom">' +
            '<div class="mc-odds">' + oddCell('home', '1') + oddCell('draw', 'N') + oddCell('away', '2') + '</div>' +
            '<button class="mc-track" onclick="event.stopPropagation();mcTrack(\'' + esc(m.id) + '\')">+ Suivre</button>' +
          '</div>' +
          detail +
        '</div>'
      );
    }

    // ── Lot B+C : bande "Paris du jour" + Top value bets curatées ──
    var valueList = list.filter(function (m) {
      return m.best_edge && typeof m.best_edge.edge === 'number' && m.best_edge.edge > 0;
    }).sort(function (a, b) { return b.best_edge.edge - a.best_edge.edge; });
    var TOPN = 6;
    var topPicks = valueList.slice(0, TOPN);
    var topIds = {};
    topPicks.forEach(function (m) { topIds[m.id] = 1; });

    var html = '';
    if (topPicks.length) {
      html +=
        '<div class="mc-cta-band">' +
          '<div class="mc-cta-l">' +
            '<div class="mc-cta-t">PARIS DU JOUR</div>' +
            '<div class="mc-cta-s">' + topPicks.length + ' value bet' + (topPicks.length > 1 ? 's' : '') +
              ' · edge dévigé positif</div>' +
          '</div>' +
          '<div class="mc-cta-badge">+' + topPicks[0].safeFixed(best_edge.edge, 1) + '%</div>' +
        '</div>';
      html += '<div class="mc-grp mc-grp-top">★ Top value — sélection PariScore</div>';
      topPicks.forEach(function (m) { html += buildCard(m); });
      html += '<div class="mc-grp mc-grp-all" id="mc-all-anchor">Tous les matchs</div>';
    } else {
      html +=
        '<div class="mc-cta-band mc-cta-empty">' +
          '<div class="mc-cta-l">' +
            '<div class="mc-cta-t">PARIS DU JOUR</div>' +
            '<div class="mc-cta-s">Aucun value bet sur ces filtres — liste complète ci-dessous</div>' +
          '</div>' +
        '</div>';
    }

    // ── P3 : Favoris + raccourci Alertes ──
    var favSet = (typeof favoriteMatchIds !== 'undefined' && favoriteMatchIds && favoriteMatchIds.has)
      ? favoriteMatchIds : null;
    var favs = favSet ? list.filter(function (m) { return !topIds[m.id] && favSet.has(m.id); }) : [];
    if (favs.length) {
      html += '<div class="mc-acc mc-sec open" data-grp="__fav">' +
        '<button type="button" class="mc-grp mc-acc-h mc-sec-h">' +
          '<span class="mc-acc-name">★ Favoris</span>' +
          '<span class="mc-acc-meta">' + favs.length + '<span class="mc-acc-car">▾</span></span>' +
        '</button>' +
        '<div class="mc-acc-body">' + favs.map(buildCard).join('') + '</div></div>';
    }
    html += '<button type="button" class="mc-sec-link" ' +
      'onclick="event.stopPropagation();showPage(\'alertes\')">🔔 Mes alertes &rsaquo;</button>';

    // ── P1 : hiérarchie Pays → Ligue (accordéons imbriqués) + badge qualité ──
    function leagueQuality(items) {
      var s = 0, n = 0;
      items.forEach(function (m) {
        if (m.best_edge && typeof m.best_edge.edge === 'number') { s += m.best_edge.edge; n++; }
      });
      var a = n ? s / n : null;
      if (a == null) return { c: 'na', t: '—' };
      if (a >= 4)   return { c: 'hi',  t: '⚡ Excellent' };
      if (a >= 1.5) return { c: 'ok',  t: 'Bon' };
      if (a > 0)    return { c: 'mid', t: 'Moyen' };
      return { c: 'lo', t: 'Faible' };
    }
    var ctry = {}, ctryOrder = [];
    list.forEach(function (m) {
      if (topIds[m.id]) return;
      var c = (m.country || m.league || m.sport || '—');
      if (!ctry[c]) { ctry[c] = { name: c, sport: m.sport, leagues: {}, lgOrder: [], n: 0 }; ctryOrder.push(c); }
      var C = ctry[c];
      var lg = (m.league || '—');
      if (!C.leagues[lg]) { C.leagues[lg] = { name: lg, items: [] }; C.lgOrder.push(lg); }
      C.leagues[lg].items.push(m); C.n++;
    });
    ctryOrder.forEach(function (cn) {
      var C = ctry[cn];
      var ck = 'C|' + C.name;
      var cCol = window._mcCollapsed && window._mcCollapsed[ck];
      var flag = (typeof flagImg === 'function') ? flagImg(C.sport) : '';
      html += '<div class="mc-acc mc-ctry' + (cCol ? '' : ' open') + '" data-grp="' + esc(ck) + '">' +
        '<button type="button" class="mc-grp mc-acc-h mc-ctry-h">' +
          '<span class="mc-acc-name">' + flag + ' ' + esc(C.name) + '</span>' +
          '<span class="mc-acc-meta">' + C.n + '<span class="mc-acc-car">▾</span></span>' +
        '</button>' +
        '<div class="mc-acc-body">';
      C.lgOrder.forEach(function (ln) {
        var L = C.leagues[ln];
        var lk = ck + '|' + L.name;
        var lCol = window._mcCollapsed && window._mcCollapsed[lk];
        var q = leagueQuality(L.items);
        html += '<div class="mc-acc mc-lg' + (lCol ? '' : ' open') + '" data-grp="' + esc(lk) + '">' +
          '<button type="button" class="mc-grp mc-acc-h mc-lg-h">' +
            '<span class="mc-acc-name">' + esc(L.name) +
              ' <span class="mc-lq mc-lq-' + q.c + '">' + q.t + '</span></span>' +
            '<span class="mc-acc-meta">' + L.items.length + '<span class="mc-acc-car">▾</span></span>' +
          '</button>' +
          '<div class="mc-acc-body">' + L.items.map(buildCard).join('') + '</div>' +
        '</div>';
      });
      html += '</div></div>';
    });
    box.innerHTML = html;
    try { if (typeof window.mfsSyncCount === 'function') window.mfsSyncCount(); } catch (e) {}
  };

  // Accordéons groupes : clic en-tête = ouvrir/fermer (état mémorisé)
  window._mcCollapsed = window._mcCollapsed || {};
  document.addEventListener('click', function (e) {
    var h = e.target && e.target.closest ? e.target.closest('.mc-acc-h') : null;
    if (!h) return;
    var acc = h.closest('.mc-acc');
    if (!acc) return;
    var open = acc.classList.toggle('open');
    var g = acc.getAttribute('data-grp');
    if (g) { if (open) delete window._mcCollapsed[g]; else window._mcCollapsed[g] = 1; }
  });

  /* — Tap carte → panneau décision inline (ouvrir/fermer) — */
  window.mcToggle = function (el) {
    if (!el) return;
    el.classList.toggle('mc-open');
  };

  /* — Lien "Analyse complète" → détail modal existant — */
  window.mcOpen = function (id) {
    try {
      if (typeof openInsights === 'function') { openInsights(id); return; }
      if (typeof openMatchDetail === 'function') { openMatchDetail(id); return; }
    } catch (e) { console.warn('mcOpen', e); }
  };
  /* — Bouton "+ Suivre" → pré-remplit le modal Mes Paris — */
  window.mcTrack = function (id) {
    try {
      var m = (typeof allMatches !== 'undefined' ? allMatches : []).find(function (x) { return x.id === id; });
      if (typeof openBetModal === 'function') { openBetModal(m || null); return; }
      if (typeof openNewBetModal === 'function') { openNewBetModal(m || null); return; }
      // Fallback : aller sur Mes Paris
      if (typeof showPage === 'function') showPage('paris');
    } catch (e) { console.warn('mcTrack', e); }
  };

  /* — Skeletons pendant le 1er chargement — */
  window.mobShowSkeletons = function () {
    var box = document.getElementById('vb-cards');
    if (!box || !isMobile()) return;
    box.innerHTML = '<div class="mc-skel"></div><div class="mc-skel"></div><div class="mc-skel"></div><div class="mc-skel"></div>';
  };

  /* — Re-render cartes si on bascule desktop↔mobile — */
  MQ.addEventListener('change', function () {
    if (typeof renderMatches === 'function' && typeof allMatches !== 'undefined' && allMatches.length) {
      renderMatches(allMatches);
    }
  });

  /* — PWA : enregistrement service worker — */
  if ('serviceWorker' in navigator) {
    window.addEventListener('load', function () {
      navigator.serviceWorker.register('/sw.js').catch(function (e) {
        console.warn('SW register échec', e);
      });
    });
  }

  /* ── PWA Install Prompt UI (bd ParisScorebis-e7l polish) ──
     Capture beforeinstallprompt event Chrome/Edge Android + Edge desktop.
     Display custom install button quand criteria PWA installable rencontres.
     iOS Safari ne fire pas beforeinstallprompt → fallback manual instructions. */
  (function () {
    var deferredPrompt = null;
    var INSTALL_KEY = 'cf_pwa_install_dismissed';
    var IS_STANDALONE = window.matchMedia('(display-mode: standalone)').matches
      || window.navigator.standalone === true;

    if (IS_STANDALONE) return; // already installed

    function createInstallButton() {
      if (document.querySelector('.cf-pwa-install-btn')) return;
      var btn = document.createElement('button');
      btn.className = 'cf-pwa-install-btn';
      btn.type = 'button';
      btn.setAttribute('aria-label', 'Installer PariScore comme app');
      btn.innerHTML = '<span class="cf-pwa-icon">⬇</span><span class="cf-pwa-label">Installer PariScore</span><span class="cf-pwa-close" data-dismiss="1" aria-label="Plus tard">×</span>';
      btn.style.cssText = 'position:fixed;bottom:calc(76px + env(safe-area-inset-bottom,0));right:14px;z-index:9500;display:inline-flex;align-items:center;gap:8px;padding:10px 14px;font-family:Inter,sans-serif;font-size:13px;font-weight:700;color:#0a0d0f;background:linear-gradient(135deg,#38bdf8,#4ade80);border:0;border-radius:24px;box-shadow:0 6px 16px rgba(0,0,0,.35),0 0 12px rgba(56,189,248,.45);cursor:pointer;transition:transform .15s ease,box-shadow .15s ease;';
      btn.addEventListener('click', function (e) {
        if (e.target && e.target.getAttribute('data-dismiss') === '1') {
          try { localStorage.setItem(INSTALL_KEY, String(Date.now())); } catch (_) {}
          btn.remove();
          return;
        }
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        deferredPrompt.userChoice.then(function (choice) {
          if (choice && choice.outcome === 'accepted') {
            try { localStorage.setItem('cf_pwa_installed', '1'); } catch (_) {}
            btn.remove();
          } else {
            try { localStorage.setItem(INSTALL_KEY, String(Date.now())); } catch (_) {}
          }
          deferredPrompt = null;
        });
      });
      document.body.appendChild(btn);
    }

    /* Skip 7 jours apres dismiss user */
    function isDismissedRecently() {
      try {
        var d = parseInt(localStorage.getItem(INSTALL_KEY) || '0', 10);
        return d && (Date.now() - d) < 7 * 24 * 3600 * 1000;
      } catch (_) { return false; }
    }

    window.addEventListener('beforeinstallprompt', function (e) {
      e.preventDefault();
      deferredPrompt = e;
      if (!isDismissedRecently()) {
        /* Delay 3s pour ne pas etre intrusif au boot */
        setTimeout(createInstallButton, 3000);
      }
    });

    window.addEventListener('appinstalled', function () {
      try { localStorage.setItem('cf_pwa_installed', '1'); } catch (_) {}
      var btn = document.querySelector('.cf-pwa-install-btn');
      if (btn) btn.remove();
    });
  })();

  /* ── Push Notification scaffold (bd ParisScorebis-e7l) ──
     Demande permission + subscribe Web Push API. Disabled par defaut
     (privacy). Activate via window.cfEnablePushNotifications().
     Backend endpoint /api/v1/push/subscribe a creer pour stocker
     subscriptions (sprint dedie + VAPID keys). */
  (function () {
    if (!('serviceWorker' in navigator) || !('PushManager' in window)) return;
    /* Expose pour user opt-in manuel via UI button futur */
    window.cfEnablePushNotifications = async function () {
      try {
        var perm = await Notification.requestPermission();
        if (perm !== 'granted') {
          console.warn('[PWA Push] permission refusée:', perm);
          return false;
        }
        var reg = await navigator.serviceWorker.ready;
        /* bd nwk6 — Fetch VAPID public key depuis backend (override CF_VAPID si defini) */
        var vapidKey = window.CF_VAPID_PUBLIC_KEY || null;
        if (!vapidKey) {
          try {
            var vkRes = await fetch('/api/v1/push/vapid-key');
            if (vkRes.ok) {
              var vk = await vkRes.json();
              if (vk && vk.publicKey) vapidKey = _b64UrlToUint8(vk.publicKey);
            }
          } catch (_) {}
        }
        if (!vapidKey) {
          console.warn('[PWA Push] VAPID public key non configuree — abandon');
          return false;
        }
        var subscription = await reg.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: vapidKey
        });
        var token = (typeof psGetToken === 'function' ? psGetToken() : null) || localStorage.getItem('ps_user_token');
        var resp = await fetch('/api/v1/push/subscribe', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': token ? 'Bearer ' + token : ''
          },
          body: JSON.stringify(subscription)
        });
        if (!resp.ok) throw new Error('push subscribe API failed: ' + resp.status);
        localStorage.setItem('cf_push_enabled', '1');
        console.log('[PWA Push] enabled OK');
        return true;
      } catch (e) {
        console.warn('[PWA Push] erreur:', e.message);
        return false;
      }
    };
    window.cfDisablePushNotifications = async function () {
      try {
        var reg = await navigator.serviceWorker.ready;
        var sub = await reg.pushManager.getSubscription();
        if (sub) {
          await sub.unsubscribe();
          var token = (typeof psGetToken === 'function' ? psGetToken() : null) || localStorage.getItem('ps_user_token');
          await fetch('/api/v1/push/unsubscribe', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': token ? 'Bearer ' + token : ''
            },
            body: JSON.stringify({ endpoint: sub.endpoint })
          });
        }
        localStorage.removeItem('cf_push_enabled');
        return true;
      } catch (e) {
        console.warn('[PWA Push] unsubscribe erreur:', e.message);
        return false;
      }
    };
    // bd nwk6 — Helper: base64url string → Uint8Array (requis par applicationServerKey)
    function _b64UrlToUint8(b64url) {
      var padding = '='.repeat((4 - b64url.length % 4) % 4);
      var base64 = (b64url + padding).replace(/-/g, '+').replace(/_/g, '/');
      var raw = atob(base64);
      var out = new Uint8Array(raw.length);
      for (var i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
      return out;
    }
  })();

  /* — Au boot : skeletons si on arrive direct sur matchs en mobile — */
  document.addEventListener('DOMContentLoaded', function () {
    if (isMobile()) mobShowSkeletons();
    bnSetActive('matchs');
  });
})();


(function () {
  'use strict';

  /* ── UI-003 — Mode Dual Trading / Analyse toggle ── */
  function cfApplyMode(mode) {
    var m = (mode === 'trading') ? 'trading' : 'analyse';
    document.body.setAttribute('data-cf-mode', m);
    try { localStorage.setItem('cf_mode', m); } catch (e) {}
    document.querySelectorAll('.cf-mode-toggle button').forEach(function (b) {
      b.classList.toggle('active', b.getAttribute('data-cf-mode') === m);
    });
  }
  function cfBuildModeToggle() {
    if (document.querySelector('.cf-mode-toggle')) return;
    var html = ''
      + '<div class="cf-mode-toggle" role="tablist" aria-label="Mode d\'affichage du tableau">'
      + '  <button type="button" data-cf-mode="trading" role="tab" title="Mode Trading: 4-5 colonnes prioritaires (Pro)">Trading</button>'
      + '  <button type="button" data-cf-mode="analyse" role="tab" title="Mode Analyse: layout complet">Analyse</button>'
      + '</div>';
    /* Insert before #vb-table wrapper in matchs + before #tennis-vb-table in tennis */
    var anchors = [
      { sel: '#page-matchs #filter-console', mode: 'foot' },
      { sel: '#page-tennis #tennis-valuebets-section', mode: 'tennis' }
    ];
    anchors.forEach(function (a) {
      var el = document.querySelector(a.sel);
      if (!el || el.querySelector('.cf-mode-toggle')) return;
      var tmp = document.createElement('div');
      tmp.style.cssText = 'display:flex;justify-content:flex-end;padding:6px 12px 0;';
      tmp.innerHTML = html;
      el.parentNode.insertBefore(tmp, el);
    });
    document.querySelectorAll('.cf-mode-toggle button').forEach(function (b) {
      b.addEventListener('click', function () {
        cfApplyMode(b.getAttribute('data-cf-mode'));
      });
    });
  }

  /* ── UI-004 — Tennis Filters Accordion ── */
  function cfBuildTennisFilterAccordion() {
    var page = document.querySelector('#page-tennis');
    if (!page) return;
    /* Find the filter row containers — each is the parent <div> of one filter group */
    var filterGroups = page.querySelectorAll('.tnc-ms-pop, [data-filter], #tennis-vb-sort, #tennis-vb-live-only, #tennis-vb-elo-only, #tennis-vb-positive-ev, #tennis-vb-hide-finished');
    /* Strategy: mark the parent <div style="display:flex;…"> of NON-essential filters as extra.
       Essential (keep visible always): Tour (data-filter="tour"), Surface (data-filter="surface"), Live label. */
    var essentialFilters = new Set(['tour', 'surface']);
    page.querySelectorAll('[data-filter]').forEach(function (btn) {
      var f = btn.getAttribute('data-filter');
      if (!f || essentialFilters.has(f)) return;
      var row = btn.closest('div[style*="display:flex"]');
      if (row && !row.hasAttribute('data-cf-filter-extra')) {
        row.setAttribute('data-cf-filter-extra', 'true');
      }
    });
    /* Sort, multi-comp, search, checkboxes: mark all as extra except live */
    page.querySelectorAll('#tennis-vb-comp, #tennis-vb-sort, #tnc-ms-btn, .tvb-search, #tennis-vb-elo-only, #tennis-vb-positive-ev, #tennis-vb-hide-finished').forEach(function (el) {
      var row = el.closest('div[style*="display:flex"]') || el.closest('label');
      if (row && !row.hasAttribute('data-cf-filter-extra')) {
        row.setAttribute('data-cf-filter-extra', 'true');
      }
    });

    /* Insert toggle button */
    if (page.querySelector('.cf-tennis-filters-toggle')) return;
    var container = page.querySelector('#tennis-valuebets-section');
    if (!container) return;
    var btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'cf-tennis-filters-toggle';
    btn.innerHTML = '<span class="cf-ft-label">Plus de filtres</span> <span class="cf-ft-count" data-cf-ft-count style="display:none;">0</span> <span class="cf-ft-arrow">▼</span>';
    btn.addEventListener('click', function () {
      var expanded = document.body.getAttribute('data-cf-tennis-filters') === 'expanded';
      if (expanded) {
        document.body.removeAttribute('data-cf-tennis-filters');
        btn.querySelector('.cf-ft-label').textContent = 'Plus de filtres';
      } else {
        document.body.setAttribute('data-cf-tennis-filters', 'expanded');
        btn.querySelector('.cf-ft-label').textContent = 'Moins de filtres';
      }
    });
    /* Insert at top right of filter zone */
    var filterZone = container.querySelector('[style*="flex-wrap"]') || container;
    var wrap = document.createElement('div');
    wrap.style.cssText = 'display:flex;justify-content:flex-end;padding:6px 0;';
    wrap.appendChild(btn);
    filterZone.parentNode.insertBefore(wrap, filterZone);

    /* Update active filter counter periodically */
    function refreshCount() {
      if (!window._tennisVbFilters) return;
      var f = window._tennisVbFilters;
      var n = 0;
      ['comp', 'strategy', 'tier'].forEach(function (k) { if (f[k] && f[k] !== 'ALL') n++; });
      if (f.q) n++;
      if (f.sort && f.sort !== 'time') n++;
      var cnt = document.querySelector('[data-cf-ft-count]');
      if (!cnt) return;
      if (n > 0) { cnt.style.display = ''; cnt.textContent = String(n); }
      else { cnt.style.display = 'none'; }
    }
    setInterval(refreshCount, 1500);
  }

  /* ── UI-012 — Profils filtres sauvegardés (tennis) ── */
  var CF_PROFILE_KEY = 'cf_tennis_profiles';
  function cfReadProfiles() {
    try { return JSON.parse(localStorage.getItem(CF_PROFILE_KEY) || '[]'); }
    catch (e) { return []; }
  }
  function cfWriteProfiles(arr) {
    try { localStorage.setItem(CF_PROFILE_KEY, JSON.stringify(arr || [])); } catch (e) {}
  }
  function cfSnapshotCurrentTennisFilters() {
    var f = window._tennisVbFilters || {};
    return {
      tour: f.tour || 'ALL',
      surface: f.surface || 'ALL',
      tier: f.tier || 'ALL',
      strategy: f.strategy || 'ALL',
      comp: f.comp || 'ALL',
      sort: f.sort || 'time',
      q: f.q || '',
      live_only: !!document.querySelector('#tennis-vb-live-only')?.checked,
      elo_only: !!document.querySelector('#tennis-vb-elo-only')?.checked,
      positive_ev: !!document.querySelector('#tennis-vb-positive-ev')?.checked,
      hide_finished: !!document.querySelector('#tennis-vb-hide-finished')?.checked,
      cf_mode: document.body.getAttribute('data-cf-mode') || 'analyse'
    };
  }
  function cfApplyTennisProfile(profile) {
    if (!profile || !profile.filters) return false;
    var f = profile.filters;
    if (window._tennisVbFilters) {
      window._tennisVbFilters.tour = f.tour || 'ALL';
      window._tennisVbFilters.surface = f.surface || 'ALL';
      window._tennisVbFilters.tier = f.tier || 'ALL';
      window._tennisVbFilters.strategy = f.strategy || 'ALL';
      window._tennisVbFilters.comp = f.comp || 'ALL';
      window._tennisVbFilters.sort = f.sort || 'time';
      window._tennisVbFilters.q = f.q || '';
    }
    /* Reflect in DOM controls */
    var setChk = function (id, val) { var el = document.querySelector('#' + id); if (el) el.checked = !!val; };
    setChk('tennis-vb-live-only', f.live_only);
    setChk('tennis-vb-elo-only', f.elo_only);
    setChk('tennis-vb-positive-ev', f.positive_ev);
    setChk('tennis-vb-hide-finished', f.hide_finished);
    var sortSel = document.querySelector('#tennis-vb-sort'); if (sortSel) sortSel.value = f.sort || 'time';
    var searchInput = document.querySelector('#tennis-vb-search'); if (searchInput) searchInput.value = f.q || '';
    /* Reflect filter button active state */
    document.querySelectorAll('.tennis-vb-filter-btn').forEach(function (b) {
      var key = b.getAttribute('data-filter'); var val = b.getAttribute('data-value');
      var match = f[key] && f[key] === val;
      b.classList.toggle('is-active', !!match);
    });
    if (f.cf_mode) cfApplyMode(f.cf_mode);
    /* Trigger re-render */
    if (typeof window.renderTennisValueBets === 'function') {
      window.renderTennisValueBets(window._tennisVbLastFetch || []);
    }
    return true;
  }
  function cfBuildProfilesModal() {
    if (document.querySelector('#cf-profiles-modal')) return;
    var modal = document.createElement('div');
    modal.id = 'cf-profiles-modal';
    modal.className = 'cf-modal';
    modal.style.cssText = 'display:none;position:fixed;inset:0;z-index:9998;background:rgba(0,0,0,.65);backdrop-filter:blur(6px);align-items:center;justify-content:center;padding:24px;';
    modal.innerHTML =
      '<div class="cf-modal-box" style="background:#0b1220;border:1px solid #38bdf8;border-radius:14px;padding:24px;width:100%;max-width:480px;color:#e8eaed;font-family:Inter,sans-serif;">'
      +   '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">'
      +     '<h3 style="margin:0;font-family:Syne,sans-serif;font-size:18px;letter-spacing:.04em;text-transform:uppercase;">Mes profils</h3>'
      +     '<button type="button" class="cf-modal-close" style="background:transparent;border:0;color:#94a3b8;font-size:20px;cursor:pointer;">×</button>'
      +   '</div>'
      +   '<div id="cf-profiles-list" style="display:flex;flex-direction:column;gap:8px;"></div>'
      +   '<div style="margin-top:18px;display:flex;gap:8px;">'
      +     '<input type="text" id="cf-profile-name" placeholder="Nom du profil (ex: Clay GS Live)" style="flex:1;background:#0f172a;border:1px solid #1e293b;color:#e8eaed;padding:8px 12px;border-radius:8px;font-family:DM Mono,monospace;font-size:12px;">'
      +     '<button type="button" id="cf-profile-save-btn" style="background:linear-gradient(135deg,rgba(56,189,248,.25),rgba(56,189,248,.10));border:1px solid rgba(56,189,248,.50);color:#38bdf8;padding:8px 14px;border-radius:8px;font-family:DM Mono,monospace;font-size:11px;font-weight:700;text-transform:uppercase;cursor:pointer;">Sauvegarder</button>'
      +   '</div>'
      +   '<div style="margin-top:12px;font-size:11px;color:#64748b;font-family:DM Mono,monospace;">Capture: filtres tennis, sort, mode Trading/Analyse.</div>'
      + '</div>';
    document.body.appendChild(modal);
    modal.querySelector('.cf-modal-close').addEventListener('click', function () { modal.style.display = 'none'; });
    modal.addEventListener('click', function (e) { if (e.target === modal) modal.style.display = 'none'; });
    document.querySelector('#cf-profile-save-btn').addEventListener('click', function () {
      var nameInput = document.querySelector('#cf-profile-name');
      var name = (nameInput.value || '').trim() || ('Profil ' + (new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })));
      var profiles = cfReadProfiles();
      profiles.push({ name: name, filters: cfSnapshotCurrentTennisFilters(), ts: Date.now() });
      cfWriteProfiles(profiles);
      nameInput.value = '';
      cfRefreshProfilesList();
    });
  }
  function cfRefreshProfilesList() {
    var list = document.querySelector('#cf-profiles-list');
    if (!list) return;
    var profiles = cfReadProfiles();
    if (!profiles.length) {
      list.innerHTML = '<div style="font-size:12px;color:#64748b;font-family:DM Mono,monospace;padding:12px;text-align:center;border:1px dashed #1e293b;border-radius:8px;">Aucun profil sauvegardé. Configurez vos filtres puis cliquez Sauvegarder.</div>';
      return;
    }
    list.innerHTML = profiles.map(function (p, i) {
      var f = p.filters || {};
      var summary = [];
      if (f.surface && f.surface !== 'ALL') summary.push(f.surface);
      if (f.tier && f.tier !== 'ALL') summary.push(f.tier);
      if (f.tour && f.tour !== 'ALL') summary.push(f.tour);
      if (f.live_only) summary.push('LIVE');
      if (f.positive_ev) summary.push('EV+');
      if (f.cf_mode === 'trading') summary.push('Trading');
      var sumStr = summary.length ? summary.join(' · ') : 'Tous filtres';
      return '<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:#0f172a;border:1px solid #1e293b;border-radius:8px;">'
        + '<div style="flex:1;min-width:0;">'
        +   '<div style="font-weight:700;font-size:13px;color:#e8eaed;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + (p.name || 'Profil') + '</div>'
        +   '<div style="font-size:10px;color:#64748b;font-family:DM Mono,monospace;margin-top:2px;">' + sumStr + '</div>'
        + '</div>'
        + '<button type="button" data-cf-profile-apply="' + i + '" style="background:linear-gradient(135deg,rgba(74,222,128,.20),rgba(74,222,128,.05));border:1px solid rgba(74,222,128,.45);color:#4ade80;padding:5px 10px;border-radius:6px;font-family:DM Mono,monospace;font-size:10px;font-weight:700;text-transform:uppercase;cursor:pointer;">Charger</button>'
        + '<button type="button" data-cf-profile-delete="' + i + '" style="background:transparent;border:1px solid rgba(255,56,86,.40);color:#ff3856;padding:5px 9px;border-radius:6px;font-family:DM Mono,monospace;font-size:10px;font-weight:700;cursor:pointer;">×</button>'
        + '</div>';
    }).join('');
    list.querySelectorAll('[data-cf-profile-apply]').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var idx = parseInt(btn.getAttribute('data-cf-profile-apply'), 10);
        var profiles = cfReadProfiles();
        if (profiles[idx]) {
          cfApplyTennisProfile(profiles[idx]);
          document.querySelector('#cf-profiles-modal').style.display = 'none';
        }
      });
    });
    list.querySelectorAll('[data-cf-profile-delete]').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var idx = parseInt(btn.getAttribute('data-cf-profile-delete'), 10);
        var profiles = cfReadProfiles();
        profiles.splice(idx, 1);
        cfWriteProfiles(profiles);
        cfRefreshProfilesList();
      });
    });
  }
  function cfOpenProfilesModal() {
    cfBuildProfilesModal();
    cfRefreshProfilesList();
    var m = document.querySelector('#cf-profiles-modal');
    if (m) m.style.display = 'flex';
  }
  function cfBuildProfilesTrigger() {
    var container = document.querySelector('#page-tennis #tennis-valuebets-section');
    if (!container || container.querySelector('.cf-profiles-trigger')) return;
    var btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'cf-tennis-filters-toggle cf-profiles-trigger';
    btn.style.marginLeft = '8px';
    btn.innerHTML = '⭐ Profils';
    btn.addEventListener('click', cfOpenProfilesModal);
    var anchor = container.querySelector('.cf-tennis-filters-toggle');
    if (anchor && anchor.parentNode) {
      anchor.parentNode.appendChild(btn);
    } else {
      container.insertBefore(btn, container.firstChild);
    }
  }

  /* ── UI-017 — Time-to-kickoff chips (T-Xh Ym) ── */
  function cfFormatT2K(deltaMs) {
    if (deltaMs <= 0) return null;
    var s = Math.floor(deltaMs / 1000);
    var h = Math.floor(s / 3600);
    var m = Math.floor((s % 3600) / 60);
    var d = Math.floor(h / 24);
    if (d >= 2) return 'J+' + d;
    if (h >= 24) return 'J+1';
    if (h >= 1) return 'T-' + h + 'h' + (m < 10 ? '0' : '') + m;
    if (m >= 1) return 'T-' + m + 'min';
    return 'T-' + s + 's';
  }
  function cfRefreshT2K() {
    var now = Date.now();
    var chips = document.querySelectorAll('[data-cf-t2k]');
    chips.forEach(function (chip) {
      var iso = chip.getAttribute('data-cf-t2k');
      if (!iso) { chip.style.display = 'none'; return; }
      var ts = Date.parse(iso);
      if (isNaN(ts)) { chip.style.display = 'none'; return; }
      var delta = ts - now;
      var label = cfFormatT2K(delta);
      if (label === null) { chip.style.display = 'none'; return; }
      chip.textContent = label;
      /* color: red <30min, amber <2h, blue <24h, neutral else */
      var cls = 'cf-t2k cf-t2k-far';
      if (delta < 30 * 60 * 1000) cls = 'cf-t2k cf-t2k-imminent';
      else if (delta < 2 * 3600 * 1000) cls = 'cf-t2k cf-t2k-soon';
      else if (delta < 24 * 3600 * 1000) cls = 'cf-t2k cf-t2k-today';
      chip.className = cls;
      chip.style.display = '';
    });
  }

  /* ── Bootstrap ── */
  function cfBootstrap() {
    /* restore saved mode */
    var saved = 'analyse';
    try { saved = localStorage.getItem('cf_mode') || 'analyse'; } catch (e) {}
    cfApplyMode(saved);
    cfBuildModeToggle();
    cfBuildTennisFilterAccordion();
    /* Re-attempt builders after possible SPA navigation (page-locked → page-matchs) */
    var attempts = 0;
    var iv = setInterval(function () {
      attempts++;
      cfBuildModeToggle();
      cfBuildTennisFilterAccordion();
      cfBuildProfilesTrigger();
      cfRefreshT2K();
      if (attempts > 20) clearInterval(iv);
    }, 750);
    /* Steady T2K refresh — once per 30s once page settled */
    /* QA fix MIN-8 (rapport_qa_foot_tennis.md): stocker handle + clear avant créer pour éviter double interval */
    if (window._cfT2kInterval) { clearInterval(window._cfT2kInterval); }
    window._cfT2kInterval = setInterval(cfRefreshT2K, 30 * 1000);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', cfBootstrap);
  } else {
    cfBootstrap();
  }

  /* expose for debug */
  window.cfApplyMode = cfApplyMode;

  /* ── QA MAJ-4 fix — Multi-tab localStorage sync (rapport_qa_foot_tennis.md) ── */
  /* Listen 'storage' event pour reflechir changements entre onglets:
     - cf_mode (Trading/Analyse) toggle
     - cf_tennis_profiles (modal profils)
     - ps_fav (favoris foot/tennis) */
  window.addEventListener('storage', function (e) {
    if (!e || !e.key) return;
    try {
      if (e.key === 'cf_mode') {
        cfApplyMode(e.newValue || 'analyse');
      } else if (e.key === 'cf_tennis_profiles') {
        /* Refresh modal list si ouvert */
        var modalOpen = document.querySelector('#cf-profiles-modal');
        if (modalOpen && modalOpen.style.display === 'flex') {
          cfRefreshProfilesList();
        }
      } else if (e.key === 'ps_fav' && typeof window.favoriteMatchIds !== 'undefined') {
        /* Resync favs Set + trigger re-render foot */
        try {
          window.favoriteMatchIds = new Set(JSON.parse(e.newValue || '[]'));
          if (typeof window.renderMatches === 'function' && Array.isArray(window._matchsLastFetch)) {
            window.renderMatches(window._matchsLastFetch);
          }
        } catch (_) {}
      }
    } catch (_) {}
  });
})();

// ═══════════════════════════════════════════════════════════════════════════════
// CS2 / Counter-Strike 2 — tab logic
// Route: GET /api/v1/cs2/matches
// ═══════════════════════════════════════════════════════════════════════════════
(function () {
  'use strict';

  // ── State ────────────────────────────────────────────────────────────────
  var _cs2Timer      = null;
  var _cs2Filter     = 'all';
  var _cs2LastData   = [];
  var _cs2Loaded     = false;
  var CS2_POLL_MS    = 30 * 1000;
  var _cs2Stickers   = {};   // teamName.lower() → { image, name, team }
  var _cs2Highlights = [];   // all highlights from ByMykel
  var _berserkData   = { recent: [], upcoming: [] };
  var _liquipediaData= [];
  var _tier3Loaded   = false;
  var _cs2EnrichTimer1 = null;
  var _cs2EnrichTimer2 = null;

  // ── Public API ────────────────────────────────────────────────────────────
  window.initCs2Page = function () {
    if (_cs2Loaded && !window._cs2ForceRefresh) {
      _applyCs2Filter();
      _startCs2Poll();
      return;
    }
    window._cs2ForceRefresh = false;
    _cs2Loaded = true;
    _renderCs2Skeleton();
    _fetchAndRender();
    _startCs2Poll();
    // Preload ByMykel static data (fire-and-forget)
    _preloadCs2Static();
    // Preload tier-3 league data
    if (!_tier3Loaded) { _tier3Loaded = true; _loadTier3Data(); }
  };

  window.stopCs2Page = function () {
    if (_cs2Timer) { clearInterval(_cs2Timer); _cs2Timer = null; }
  };

  window.setCs2Filter = function (filter, btn) {
    _cs2Filter = filter;
    document.querySelectorAll('.cs2-pill').forEach(function (b) {
      b.classList.toggle('active', b.dataset.cs2f === filter);
    });
    _applyCs2Filter();
  };

  // ── View mode toggle ──────────────────────────────────────────────────────
  var _cs2ViewMode = 'dashboard'; // default = dashboard for quick betting
  window.setCs2View = function (mode, btn) {
    _cs2ViewMode = mode;
    document.querySelectorAll('.cs2-view-btn').forEach(function (b) {
      b.classList.toggle('active', b.dataset.view === mode);
    });
    _applyCs2Filter();
  };

  window.cs2ForceRefresh = function () {
    window._cs2ForceRefresh = true;
    initCs2Page();
  };

  window.cs2PlayClip = function (idx, btn, videoUrl, title) {
    var card = btn.closest('.cs2-card');
    if (!card) return;
    var player = card.querySelector('.cs2-hl-player');
    if (!player) return;
    var vid = player.querySelector('video');
    if (!vid) return;
    // Toggle off if same clip
    if (player.style.display !== 'none' && vid.src === videoUrl) {
      player.style.display = 'none';
      vid.pause();
      return;
    }
    vid.src = videoUrl;
    player.style.display = 'block';
    vid.play().catch(function () {});
    // Highlight active button
    card.querySelectorAll('.cs2-hl-btn').forEach(function (b) { b.classList.remove('active'); });
    btn.classList.add('active');
  };

  // ── Internal ─────────────────────────────────────────────────────────────
  function _startCs2Poll() {
    if (_cs2Timer) clearInterval(_cs2Timer);
    _cs2Timer = setInterval(_fetchAndRender, CS2_POLL_MS);
  }

  function _preloadCs2Static() {
    // Stickers index
    if (Object.keys(_cs2Stickers).length === 0) {
      fetch('/api/v1/cs2/stickers', { cache: 'force-cache' })
        .then(function (r) { return r.json(); })
        .then(function (j) {
          if (j && j.byTeam) {
            _cs2Stickers = j.byTeam;
            _applyCs2Filter(); // re-render with stickers
          }
        }).catch(function () {});
    }
    // Highlights index (all — we filter per card)
    if (_cs2Highlights.length === 0) {
      fetch('/api/v1/cs2/highlights', { cache: 'force-cache' })
        .then(function (r) { return r.json(); })
        .then(function (j) {
          if (j && Array.isArray(j.highlights)) {
            _cs2Highlights = j.highlights;
            _applyCs2Filter(); // re-render with highlights
          }
        }).catch(function () {});
    }
  }

  // ── Sticker lookup ───────────────────────────────────────────────────────
  function _cs2FindSticker(teamName) {
    if (!teamName || !_cs2Stickers) return null;
    var key = teamName.toLowerCase();
    if (_cs2Stickers[key]) return _cs2Stickers[key];
    // Partial match
    var keys = Object.keys(_cs2Stickers);
    for (var i = 0; i < keys.length; i++) {
      if (key.includes(keys[i]) || keys[i].includes(key)) return _cs2Stickers[keys[i]];
    }
    return null;
  }

  // ── Enrichment fetch (form + H2H + players + map winrate) ───────────────
  var _cs2EnrichCache = {}; // key t1|t2 → enrichment
  function _fetchEnrichment(matchId, t1, t2, map) {
    var cacheKey = t1 + '|' + t2;
    if (_cs2EnrichCache[cacheKey]) {
      _renderEnrichmentInCard(matchId, _cs2EnrichCache[cacheKey], map);
      return;
    }
    var url = '/api/v1/cs2/enrich?team1=' + encodeURIComponent(t1) +
              '&team2=' + encodeURIComponent(t2) +
              (map ? '&map=' + encodeURIComponent(map) : '');
    fetch(url, { cache: 'no-store' })
      .then(function (r) { return r.json(); })
      .then(function (j) {
        var e = j && j.enrichment ? j.enrichment : null;
        if (e) { _cs2EnrichCache[cacheKey] = e; _renderEnrichmentInCard(matchId, e, map); }
      }).catch(function () {});
  }

  function _renderEnrichmentInCard(matchId, e, map) {
    var card = document.querySelector('[data-cs2-match-id="' + matchId + '"]');
    if (!card || !e) return;

    // Form pills
    function formPills(formData, side) {
      if (!formData || !formData.form) return '';
      var el = card.querySelector('.cs2-form-pills-' + side);
      if (!el) return '';
      el.innerHTML = formData.form.slice(-7).map(function (r) {
        var col = r === 'W' ? '#00e676' : r === 'L' ? '#ff4d4d' : '#5a6068';
        return '<span style="display:inline-block;width:7px;height:7px;border-radius:50%;background:' + col + ';margin:0 1px;" title="' + r + '"></span>';
      }).join('');
      return '';
    }
    formPills(e.team1, 't1');
    formPills(e.team2, 't2');

    // H2H badge
    var h2hEl = card.querySelector('.cs2-h2h-badge');
    if (h2hEl && e.h2h) {
      h2hEl.textContent = 'H2H ' + e.h2h.t1wins + '–' + e.h2h.t2wins;
      h2hEl.style.display = 'inline';
    }

    // Streak badges
    function streakBadge(team, side) {
      var el = card.querySelector('.cs2-streak-' + side);
      if (!el || team.streak == null) return;
      var val = team.streak;
      el.textContent = (val > 0 ? '+' : '') + val;
      el.style.color = val > 0 ? '#00e676' : val < 0 ? '#ff4d4d' : '#8d9399';
      el.style.display = 'inline';
    }
    streakBadge(e.team1, 't1');
    streakBadge(e.team2, 't2');

    // Map winrate bar (HLTV or BSD)
    if (map && e.map_winrate && (e.map_winrate.source === 'hltv' || e.map_winrate.source === 'bsd')) {
      var mwEl = card.querySelector('.cs2-map-winrate-bar');
      if (mwEl) {
        var w1 = e.map_winrate.team1;
        var w2 = e.map_winrate.team2;
        if (w1 != null || w2 != null) {
          var flag1 = w1 != null && w2 != null && Math.abs(w1 - w2) >= 20 ? ' ✓' : '';
          var srcBadge = e.map_winrate.source === 'bsd' ? '<span style="font-size:8px;color:var(--blue,#29b6f6);margin-left:3px;">BSD</span>' : '';
          mwEl.innerHTML = '<span style="color:var(--text3);font-size:9px;">WR ' + map + ':</span> ' +
            (w1 != null ? '<span style="color:' + (w1>=60?'#00e676':w1>=45?'#ffa726':'#ff4d4d') + '">' + w1 + '%</span>' : '<span style="color:var(--text3)">?</span>') +
            '<span style="color:var(--text3);margin:0 3px;">vs</span>' +
            (w2 != null ? '<span style="color:' + (w2>=60?'#00e676':w2>=45?'#ffa726':'#ff4d4d') + '">' + w2 + '%</span>' : '<span style="color:var(--text3)">?</span>') +
            '<span style="color:#00e676;font-weight:700;">' + flag1 + '</span>' + srcBadge;
          // CT/T side row (BSD only)
          if (e.map_winrate.source === 'bsd' && e.map_winrate.team1_ct_wr != null) {
            mwEl.innerHTML += '<br><span style="color:var(--text3);font-size:8px;">CT ' +
              '<span style="color:#29b6f6;">' + e.map_winrate.team1_ct_wr + '%</span>' +
              ' vs <span style="color:#29b6f6;">' + e.map_winrate.team2_ct_wr + '%</span>' +
              '  T <span style="color:#ffa726;">' + e.map_winrate.team1_t_wr + '%</span>' +
              ' vs <span style="color:#ffa726;">' + e.map_winrate.team2_t_wr + '%</span></span>';
          }
          mwEl.style.display = 'flex';
        }
      }
    }

    // Top player ratings
    function playerRatings(players, side) {
      var el = card.querySelector('.cs2-players-' + side);
      if (!el || !players || !players.length) return;
      el.innerHTML = players.slice(0, 3).map(function (p) {
        var col = p.rating >= 1.2 ? '#00e676' : p.rating >= 1.0 ? '#ffa726' : '#8d9399';
        return '<span title="' + p.name + ' — ADR:' + p.adr + ' KAST:' + (p.kast||'?') + '" style="font-size:9px;color:var(--text3);white-space:nowrap;">' +
          p.name + ' <span style="color:' + col + ';font-weight:700;">' + (p.rating || '?') + '</span></span>';
      }).join('<span style="color:var(--bg4);margin:0 3px;">·</span>');
      el.style.display = 'flex';
    }
    playerRatings(e.team1.players, 't1');
    playerRatings(e.team2.players, 't2');
  }

  // ── Over Rounds model async fetch ────────────────────────────────────────
  var _cs2ModelCache = {}; // key → model result
  function _fetchMapOverModel(matchId, t1, t2, map, domId) {
    var cacheKey = t1 + '|' + t2 + '|' + map;
    if (_cs2ModelCache[cacheKey] !== undefined) {
      _renderModelInDom(domId, _cs2ModelCache[cacheKey]);
      return;
    }
    var url = '/api/v1/cs2/map-model?team1=' + encodeURIComponent(t1) +
              '&team2=' + encodeURIComponent(t2) +
              '&map=' + encodeURIComponent(map);
    fetch(url, { cache: 'no-store' })
      .then(function (r) { return r.json(); })
      .then(function (j) {
        var model = j && j.model ? j.model : null;
        _cs2ModelCache[cacheKey] = model;
        _renderModelInDom(domId, model);
      }).catch(function () {
        _cs2ModelCache[cacheKey] = null;
        var el = document.getElementById(domId);
        if (el) el.style.display = 'none';
      });
  }

  function _renderModelInDom(domId, model) {
    var el = document.getElementById(domId);
    if (!el) return;
    if (!model) { el.style.display = 'none'; return; }
    var signalCls = model.signal === 'OVER' ? 'cs2-signal-over' : 'cs2-signal-under';
    var confColor = model.confidence === 'HIGH' ? '#00e676' : model.confidence === 'MED' ? '#ffa726' : '#8d9399';
    el.style.opacity = '1';
    el.innerHTML =
      '<span style="color:var(--text3);font-size:9px;">moy ' + model.predicted + ' rds</span> ' +
      '<span class="' + signalCls + '">' + model.signal + ' ' + model.line + '</span> ' +
      '<span style="font-size:9px;color:' + confColor + ';">' + model.confidence + '</span>';
  }

  // ── Highlight lookup ─────────────────────────────────────────────────────
  function _cs2FindHighlights(t1name, t2name) {
    if (!_cs2Highlights.length) return [];
    var n1 = (t1name || '').toLowerCase();
    var n2 = (t2name || '').toLowerCase();
    return _cs2Highlights.filter(function (h) {
      var h0 = (h.team0 || '').toLowerCase();
      var h1 = (h.team1 || '').toLowerCase();
      var m1 = n1 && (h0.includes(n1) || h1.includes(n1) || n1.includes(h0) || n1.includes(h1));
      var m2 = n2 && (h0.includes(n2) || h1.includes(n2) || n2.includes(h0) || n2.includes(h1));
      return m1 || m2;
    }).slice(0, 3);
  }

  function _fetchAndRender() {
    fetch('/api/v1/cs2/matches', { cache: 'no-store' })
      .then(function (r) { return r.json(); })
      .then(function (json) {
        if (json && json.bsd_status === 'disabled') {
          _renderCs2AddonDisabled();
          return;
        }
        _cs2LastData = (json && Array.isArray(json.matches)) ? json.matches : [];
        _updateCs2Status(json);
        _applyCs2Filter();
      })
      .catch(function (e) {
        console.warn('[CS2]', e.message);
        _renderCs2Error();
      });
  }

  function _renderCs2AddonDisabled() {
    var grid = document.getElementById('cs2-grid');
    if (!grid) return;
    grid.innerHTML = '<div style="grid-column:1/-1;max-width:600px;margin:32px auto;background:var(--bg2);border:1px solid rgba(255,167,38,0.4);border-radius:12px;padding:28px 28px 24px;">' +
      '<div style="font-size:32px;margin-bottom:12px;">⚠️</div>' +
      '<div style="font-family:Syne,sans-serif;font-weight:800;font-size:20px;color:var(--text);margin-bottom:8px;">BSD CS2 Addon non activé</div>' +
      '<div style="font-family:\'Instrument Sans\',sans-serif;font-size:14px;color:var(--text2);line-height:1.6;margin-bottom:20px;">' +
        'Le feed CS2 live nécessite l\'addon <strong>Bzzoiro Sports CS2</strong> ($5/mo).<br>' +
        'Envoie un email à l\'équipe BSD pour l\'activer sur ton compte.' +
      '</div>' +
      '<div style="background:var(--bg3);border-radius:8px;padding:14px 16px;font-family:\'DM Mono\',monospace;font-size:12px;color:var(--text2);">' +
        '<div style="color:var(--text3);font-size:10px;margin-bottom:8px;text-transform:uppercase;letter-spacing:0.06em;">Template email</div>' +
        '<div style="margin-bottom:4px;"><span style="color:var(--text3);">À :</span> <span style="color:#29b6f6;">support@bzzoiro.com</span></div>' +
        '<div style="margin-bottom:4px;"><span style="color:var(--text3);">Objet :</span> Activation CS2 addon — compte [ton email]</div>' +
        '<div style="color:var(--text3);margin-top:8px;font-size:11px;">' +
          'Bonjour, je voudrais activer l\'addon CS2/CSGO sur mon compte Bzzoiro Sports ($5/mo).' +
          ' Pourriez-vous l\'activer ? Merci.' +
        '</div>' +
      '</div>' +
      '<div style="margin-top:16px;display:flex;gap:10px;flex-wrap:wrap;">' +
        '<a href="mailto:support@bzzoiro.com?subject=Activation%20CS2%20addon&body=Bonjour%2C%20je%20voudrais%20activer%20l\'addon%20CS2%2FCSGO%20sur%20mon%20compte%20Bzzoiro%20Sports%20(%245%2Fmo).%20Merci." ' +
           'style="display:inline-flex;align-items:center;gap:6px;padding:9px 18px;background:#FF6B00;color:#fff;border-radius:7px;text-decoration:none;font-family:\'Instrument Sans\',sans-serif;font-weight:600;font-size:13px;">📧 Envoyer l\'email</a>' +
        '<a href="https://sports.bzzoiro.com/pricing/" target="_blank" rel="noopener" ' +
           'style="display:inline-flex;align-items:center;gap:6px;padding:9px 18px;background:var(--bg3);color:var(--text);border:1px solid var(--bg4);border-radius:7px;text-decoration:none;font-family:\'Instrument Sans\',sans-serif;font-size:13px;">🌐 bzzoiro.com/pricing</a>' +
      '</div>' +
    '</div>';
  }

  function _applyCs2Filter() {
    var matches = _cs2LastData;
    if (_cs2Filter === 'live')     matches = matches.filter(function (m) { return m.is_live; });
    if (_cs2Filter === 'prematch') matches = matches.filter(function (m) { return !m.is_live && m.status !== 'finished'; });
    if (_cs2ViewMode === 'dashboard') {
      renderCs2Dashboard(matches);
    } else {
      renderCs2Matches(matches);
    }
  }

  function _updateCs2Status(json) {
    var bar = document.getElementById('cs2-status-bar');
    if (!bar) return;
    var total = _cs2LastData.length;
    var live  = _cs2LastData.filter(function (m) { return m.is_live; }).length;
    bar.textContent = total > 0
      ? (total + ' matchs · ' + live + ' live · mis à jour ' + _cs2FmtTime(new Date()))
      : 'Aucun match disponible — BSD CSGO addon requis';
    var badge = document.getElementById('cs2-live-badge');
    if (badge) badge.style.display = live > 0 ? 'inline-flex' : 'none';
  }

  function _renderCs2Skeleton() {
    var grid = document.getElementById('cs2-grid');
    if (!grid) return;
    grid.innerHTML = '<div class="cs2-skel"></div><div class="cs2-skel"></div><div class="cs2-skel"></div>';
  }

  function _renderCs2Error() {
    var grid = document.getElementById('cs2-grid');
    if (!grid) return;
    grid.innerHTML = '<div class="cs2-empty" style="grid-column:1/-1;">' +
      '<div class="cs2-empty-icon">⚠️</div>' +
      '<div class="cs2-empty-msg">Impossible de charger les matchs CS2</div>' +
      '<div class="cs2-empty-sub">Vérifiez que le BSD CSGO addon est activé ($5/mo) sur votre compte Bzzoiro</div>' +
      '<button onclick="cs2ForceRefresh()" style="margin-top:14px;padding:8px 18px;background:#FF6B00;color:#fff;border:0;border-radius:6px;cursor:pointer;font-family:\'Instrument Sans\',sans-serif;font-size:13px;">Réessayer</button>' +
      '</div>';
  }

  // ── Render ────────────────────────────────────────────────────────────────
  window.renderCs2Matches = function (matches) {
    var grid = document.getElementById('cs2-grid');
    if (!grid) return;

    if (!matches || matches.length === 0) {
      var label = _cs2Filter === 'live' ? 'en cours' : _cs2Filter === 'prematch' ? 'à venir' : 'disponible';
      grid.innerHTML = '<div class="cs2-empty">' +
        '<div class="cs2-empty-icon">🎮</div>' +
        '<div class="cs2-empty-msg">Aucun match CS2 ' + label + '</div>' +
        '<div class="cs2-empty-sub">Prochaines compétitions : ESL Pro League · PGL Major · BLAST Premier</div>' +
        '</div>';
      return;
    }

    var html = '';
    for (var i = 0; i < matches.length; i++) {
      html += _buildCs2Card(matches[i]);
    }
    grid.innerHTML = html;
  };

  function _mapDots(n1, n2, bo) {
    var toWin = Math.ceil((bo || 3) / 2);
    var h = '<div class="cs2-map-dots"><div class="cs2-dots-side">';
    for (var _i = 0; _i < toWin; _i++) h += '<span class="cs2-dot' + (_i < n1 ? ' d-t1' : '') + '"></span>';
    h += '</div><span class="cs2-dot-sep"></span><div class="cs2-dots-side">';
    for (var _j = 0; _j < toWin; _j++) h += '<span class="cs2-dot' + (_j < n2 ? ' d-t2' : '') + '"></span>';
    return h + '</div></div>';
  }

  function _buildCs2Card(m) {
    var isLive = !!m.is_live;
    var t1     = m.team1      || {};
    var t2     = m.team2      || {};
    var maps   = m.maps_score || {};
    var rounds = m.round_score|| {};
    var odds   = m.odds       || {};
    var mapAdv = m.map_advantage || null;

    // ── ByMykel stickers ─────────────────────────────────────────────────
    var stk1 = _cs2FindSticker(t1.name);
    var stk2 = _cs2FindSticker(t2.name);
    var clips = _cs2FindHighlights(t1.name, t2.name);

    // ── Team logo ────────────────────────────────────────────────────────
    function teamLogo(team) {
      if (team.logo) {
        return '<div class="cs2-team-logo-wrap">' +
          '<img class="cs2-team-logo" src="' + _esc(team.logo) +
          '" alt="' + _esc(team.name) + '" onerror="this.style.display=\'none\'" loading="lazy"/>' +
          '</div>';
      }
      return '<div class="cs2-team-logo-wrap"><span style="font-size:18px;">🏢</span></div>';
    }

    // ── Sticker badge ─────────────────────────────────────────────────────
    function stickerBadge(stk) {
      if (!stk || !stk.image) return '';
      return '<img class="cs2-sticker-badge" src="' + _esc(stk.image) +
        '" alt="' + _esc(stk.name) + '" title="' + _esc(stk.name) +
        '" onerror="this.style.display=\'none\'" loading="lazy"/>';
    }

    // ── HLTV rank ────────────────────────────────────────────────────────
    function rankTag(team) {
      var rank = typeof team === 'object' ? team.hltv_rank : team;
      var elo  = typeof team === 'object' ? team.elo_rating : null;
      var peak = typeof team === 'object' ? team.elo_peak : null;
      if (rank) return '<div class="cs2-hltv">HLTV #' + rank + (elo ? ' <span style="color:var(--blue,#29b6f6);font-size:8px;">⚡' + elo + '</span>' : '') + '</div>';
      if (elo)  return '<div class="cs2-hltv" style="color:var(--blue,#29b6f6);" title="BSD ELO (peak:' + (peak||'?') + ')">⚡ELO ' + elo + '</div>';
      return '';
    }

    // ── Score center ─────────────────────────────────────────────────────
    var scoreHtml, subHtml = '';
    if (maps.team1 != null && maps.team2 != null) {
      scoreHtml = _mapDots(maps.team1, maps.team2, m.best_of || 3);
      if (isLive && rounds.team1 != null) {
        subHtml = '<div class="cs2-round-score"><span class="cs2-rds-t1">' + rounds.team1 + '</span>' +
          '<span style="color:var(--text3,#5a6068);margin:0 2px">–</span>' +
          '<span class="cs2-rds-t2">' + rounds.team2 + '</span>' +
          '<span style="color:var(--text3,#5a6068);margin-left:3px;font-size:9px">rds</span></div>';
      }
    } else if (isLive && rounds.team1 != null && rounds.team2 != null) {
      scoreHtml = '<div class="cs2-map-score"><span class="cs2-rds-t1">' + rounds.team1 +
        '</span><span style="color:var(--text3,#5a6068)">–</span><span class="cs2-rds-t2">' +
        rounds.team2 + '</span></div>';
      subHtml   = '<div class="cs2-round-score">rds en cours</div>';
    } else {
      scoreHtml = '<div class="cs2-vs-txt">BO' + (m.best_of || 3) + '</div>';
      if (m.scheduled) {
        subHtml = '<div class="cs2-round-score">' + _cs2FmtMatchTime(new Date(m.scheduled)) + '</div>';
      }
    }

    // ── Map bar + Over Rounds model ───────────────────────────────────────
    var mapBarHtml = '';
    if (m.current_map) {
      var valueFlag = (mapAdv && mapAdv.value_flag)
        ? '<span class="cs2-value-flag">' + _esc(mapAdv.value_flag) + '</span>' : '';
      var mapNumTag = m.map_number
        ? '<span class="cs2-map-num" style="margin-left:4px;opacity:.6;">M' + m.map_number + '</span>' : '';
      var mapCls = 'map-' + (m.current_map).toLowerCase().replace(/[^a-z]/g, '');
      var advCls = mapAdv && mapAdv.advantage !== 'neutral'
        ? (mapAdv.advantage === 'team1' ? ' adv-t1' : ' adv-t2') : '';
      var modelId = 'cs2-model-' + _esc(m.id);
      mapBarHtml = '<div class="cs2-map-bar ' + mapCls + advCls + '">' +
        '<span class="cs2-map-label">🗺 ' + _esc(m.current_map) + '</span>' +
        mapNumTag + valueFlag +
        '<span class="cs2-over-model" id="' + modelId + '" style="margin-left:auto;opacity:.5;font-size:10px;">…</span>' +
        '</div>';
      _fetchMapOverModel(m.id, t1.name, t2.name, m.current_map, modelId);
    }

    // ── Odds ─────────────────────────────────────────────────────────────
    var oddsHtml;
    if (odds.team1 != null || odds.team2 != null) {
      var best = (odds.team1 && odds.team2)
        ? (Number(odds.team1) < Number(odds.team2) ? 1 : 2) : 0;
      oddsHtml = '<div class="cs2-odds-row">';
      if (odds.team1 != null) {
        oddsHtml += '<span class="cs2-odd' + (best === 1 ? ' best' : '') + '">' +
          Number(odds.team1).toFixed(2) + '</span>';
      }
      if (odds.team2 != null) {
        oddsHtml += '<span class="cs2-odd' + (best === 2 ? ' best' : '') + '">' +
          Number(odds.team2).toFixed(2) + '</span>';
      }
      oddsHtml += '</div>';
    } else {
      oddsHtml = '<span style="font-family:\'DM Mono\',monospace;font-size:10px;color:var(--text3)">Cotes N/A</span>';
    }

    // ── Time label ───────────────────────────────────────────────────────
    var timeHtml = isLive
      ? '<span class="cs2-live-pill"><span class="cs2-ldot"></span>LIVE</span>'
      : (m.scheduled
          ? '<span class="cs2-time">' + _cs2FmtMatchTime(new Date(m.scheduled)) + '</span>'
          : '');

    // ── Tour logo ────────────────────────────────────────────────────────
    var tourLogo = m.tournament_logo
      ? '<img class="cs2-tour-logo" src="' + _esc(m.tournament_logo) +
        '" alt="" onerror="this.style.display=\'none\'" loading="lazy"/>'
      : '<span style="font-size:13px;flex-shrink:0;">🏆</span>';

    // Trigger enrichment fetch async
    _fetchEnrichment(m.id, t1.name, t2.name, m.current_map || null);

    return '<div class="cs2-card' + (isLive ? ' is-live' : '') + '" data-cs2-match-id="' + _esc(m.id) + '">' +
      '<div class="cs2-card-head">' +
        tourLogo +
        '<span class="cs2-tour-name">' + _esc(m.tournament) + '</span>' +
        '<span class="cs2-format">BO' + (m.best_of || 3) + '</span>' +
        (isLive ? '<span class="cs2-live-pill"><span class="cs2-ldot"></span>LIVE</span>' : '') +
      '</div>' +
      '<div class="cs2-vs-row">' +
        '<div class="cs2-team">' +
          teamLogo(t1) +
          '<div class="cs2-team-info">' +
            '<div class="cs2-team-name">' + stickerBadge(stk1) + _esc(t1.name || 'TBD') +
              '<span class="cs2-streak-t1" style="display:none;font-family:\'DM Mono\',monospace;font-size:9px;margin-left:4px;"></span>' +
            '</div>' +
            rankTag(t1) +
            '<div class="cs2-form-pills-t1" style="margin-top:3px;display:flex;gap:1px;"></div>' +
            '<div class="cs2-players-t1" style="display:none;gap:4px;flex-wrap:wrap;margin-top:2px;"></div>' +
          '</div>' +
        '</div>' +
        '<div class="cs2-center">' +
          scoreHtml + subHtml +
          '<div style="margin-top:4px;"><span class="cs2-h2h-badge" style="display:none;font-family:\'DM Mono\',monospace;font-size:9px;color:var(--text3);"></span></div>' +
        '</div>' +
        '<div class="cs2-team t2">' +
          teamLogo(t2) +
          '<div class="cs2-team-info">' +
            '<div class="cs2-team-name">' + _esc(t2.name || 'TBD') + stickerBadge(stk2) +
              '<span class="cs2-streak-t2" style="display:none;font-family:\'DM Mono\',monospace;font-size:9px;margin-left:4px;"></span>' +
            '</div>' +
            rankTag(t2) +
            '<div class="cs2-form-pills-t2" style="margin-top:3px;display:flex;gap:1px;justify-content:flex-end;"></div>' +
            '<div class="cs2-players-t2" style="display:none;gap:4px;flex-wrap:wrap;justify-content:flex-end;margin-top:2px;"></div>' +
          '</div>' +
        '</div>' +
      '</div>' +
      mapBarHtml +
      '<div class="cs2-map-winrate-bar" style="display:none;align-items:center;gap:4px;font-family:\'DM Mono\',monospace;font-size:10px;padding:3px 12px 5px;"></div>' +
      _buildHighlightSection(clips) +
      '<div class="cs2-card-foot">' + oddsHtml + timeHtml + '</div>' +
    '</div>';
  }

  // ── Tier 3 league data loaders ───────────────────────────────────────────
  function _loadTier3Data() {
    fetch('/api/v1/cs2/berserk/matches', { cache: 'no-store' })
      .then(function(r){ return r.json(); })
      .then(function(j){
        if (j && j.recent) {
          _berserkData = { recent: j.recent, upcoming: j.upcoming || [] };
          _refreshTier3Section();
        }
      }).catch(function(){});
    fetch('/api/v1/cs2/liquipedia/matches', { cache: 'no-store' })
      .then(function(r){ return r.json(); })
      .then(function(j){
        if (j && Array.isArray(j.matches)) {
          _liquipediaData = j.matches;
          _refreshTier3Section();
        }
      }).catch(function(){});
  }

  function _refreshTier3Section() {
    var el = document.getElementById('cs2-tier3-section');
    if (el) el.innerHTML = _buildTier3Html();
  }

  function _buildTier3Html() {
    var html = '';

    // ── Berserk League (1v1) ──────────────────────────────────────────────
    var bAll = (_berserkData.upcoming || []).concat(_berserkData.recent || []).slice(0, 15);
    if (bAll.length > 0) {
      html += '<div class="cs2-dash-section">' +
        '<div class="cs2-dash-section-title">⚔️ Berserk League <span class="cs2-tier3-badge">1v1 · MR12 · BO1</span></div>' +
        '<div class="cs2-dash-wrap"><table class="cs2-dash-table"><thead><tr>' +
        '<th>#</th><th>Joueur 1</th><th>Score</th><th>Joueur 2</th><th>Statut</th></tr></thead><tbody>';
      bAll.forEach(function(m) {
        var scoreStr = m.score ? (m.score.p1 + '–' + m.score.p2) : '–';
        var statusBadge = m.status === 'finished'
          ? '<span style="color:#8d9399;font-size:9px;">FIN</span>'
          : '<span style="color:#ffa726;font-size:9px;font-weight:700;">À VENIR</span>';
        var winnerStyle1 = m.winner === m.player1 ? 'color:#00e676;font-weight:700;' : '';
        var winnerStyle2 = m.winner === m.player2 ? 'color:#00e676;font-weight:700;' : '';
        html += '<tr class="cs2-dash-row">' +
          '<td style="font-family:\'DM Mono\',monospace;font-size:10px;color:var(--text3);">#' + (m.match_num||'') + '</td>' +
          '<td style="font-weight:600;' + winnerStyle1 + '">' + _esc(m.player1) + '</td>' +
          '<td style="font-family:\'DM Mono\',monospace;font-size:14px;font-weight:700;text-align:center;">' + scoreStr + '</td>' +
          '<td style="font-weight:600;' + winnerStyle2 + '">' + _esc(m.player2) + '</td>' +
          '<td>' + statusBadge + '</td>' +
        '</tr>';
      });
      html += '</tbody></table></div></div>';
    }

    // ── Liquipedia Tier 3 (FRAG TAP, Exort, etc.) ────────────────────────
    if (_liquipediaData.length > 0) {
      // Group by tournament
      var byTour = {};
      _liquipediaData.forEach(function(m) {
        var t = m.tournament || 'CS2';
        if (!byTour[t]) byTour[t] = [];
        byTour[t].push(m);
      });
      Object.keys(byTour).forEach(function(tname) {
        var tMatches = byTour[tname];
        html += '<div class="cs2-dash-section">' +
          '<div class="cs2-dash-section-title">🏆 ' + _esc(tname) + ' <span class="cs2-tier3-badge">Liquipedia</span></div>' +
          '<div class="cs2-dash-wrap"><table class="cs2-dash-table"><thead><tr>' +
          '<th>Équipe 1</th><th>Maps</th><th>Équipe 2</th><th>Résultat</th></tr></thead><tbody>';
        tMatches.slice(0, 20).forEach(function(m) {
          var ms = m.maps_score;
          var scoreStr = ms ? (ms.team1 + '–' + ms.team2) : '?–?';
          var winner1 = ms && ms.team1 > ms.team2;
          var winner2 = ms && ms.team2 > ms.team1;
          html += '<tr class="cs2-dash-row">' +
            '<td style="font-weight:600;' + (winner1?'color:#00e676;':'') + '">' + _esc(m.team1) + '</td>' +
            '<td style="font-family:\'DM Mono\',monospace;font-size:14px;font-weight:700;text-align:center;">' + scoreStr + '</td>' +
            '<td style="font-weight:600;' + (winner2?'color:#00e676;':'') + '">' + _esc(m.team2) + '</td>' +
            '<td style="font-family:\'DM Mono\',monospace;font-size:10px;color:' + (m.status==='finished'?'#8d9399':'#ffa726') + ';">' + _esc(m.status||'—') + '</td>' +
          '</tr>';
        });
        html += '</tbody></table></div></div>';
      });
    }

    if (!html) return '<div style="padding:20px 16px;color:var(--text3);font-family:\'DM Mono\',monospace;font-size:11px;">⏳ Chargement ligues Tier 3…</div>';
    return html;
  }

  // ═══════════════════════════════════════════════════════════════════════
  // CS2 BETTING DASHBOARD — KPI table view for fast bet decisions
  // ═══════════════════════════════════════════════════════════════════════

  // ── Compute KPI signals for one match ──────────────────────────────────
  function _cs2BettingSignals(m) {
    var e = _cs2EnrichCache[(m.team1.name || '') + '|' + (m.team2.name || '')];
    var model = _cs2ModelCache[(m.team1.name||'')+'|'+(m.team2.name||'')+'|'+(m.current_map||'')];
    var signals = [];

    // 1. Win probability (BSD ML)
    if (m.prediction) {
      var p1 = m.prediction.team1_win_prob || 0;
      var p2 = m.prediction.team2_win_prob || 0;
      var maxP = Math.max(p1, p2);
      var favTeam = p1 >= p2 ? m.team1.name : m.team2.name;
      if (maxP >= 0.65) signals.push({ key:'prob', label: favTeam + ' ' + Math.round(maxP*100) + '%', color:'green', val: maxP });
      else if (maxP >= 0.55) signals.push({ key:'prob', label: Math.round(maxP*100) + '%', color:'amber', val: maxP });
      else signals.push({ key:'prob', label:'50/50', color:'grey', val: maxP });
    }

    // 2. Team 1 form
    if (e && e.team1 && e.team1.form) {
      var wr1 = e.team1.form.winrate || 0;
      var f1 = e.team1.form.form || [];
      signals.push({ key:'form1', label: f1.slice(-5).join(''), color: wr1>=65?'green':wr1>=45?'amber':'red', val: wr1 });
    }

    // 3. Team 2 form
    if (e && e.team2 && e.team2.form) {
      var wr2 = e.team2.form.winrate || 0;
      var f2 = e.team2.form.form || [];
      signals.push({ key:'form2', label: f2.slice(-5).join(''), color: wr2>=65?'green':wr2>=45?'amber':'red', val: wr2 });
    }

    // 4. H2H
    if (e && e.h2h && e.h2h.n >= 3) {
      var tot = e.h2h.t1wins + e.h2h.t2wins;
      var r = tot > 0 ? e.h2h.t1wins / tot : 0.5;
      signals.push({ key:'h2h', label: e.h2h.t1wins + '–' + e.h2h.t2wins, color: r>=0.65?'green':r<=0.35?'red':'amber', val: r });
    }

    // 5. Map winrate (HLTV or BSD)
    if (e && e.map_winrate && (e.map_winrate.source === 'hltv' || e.map_winrate.source === 'bsd') && e.map_winrate.team1 != null) {
      var diff = (e.map_winrate.team1||50) - (e.map_winrate.team2||50);
      var src = e.map_winrate.source === 'bsd' ? '⚡' : '';
      signals.push({ key:'mapwr', label: src + e.map_winrate.team1 + '% vs ' + e.map_winrate.team2 + '%', color: Math.abs(diff)>=20?'green':'amber', val: diff });
      // CT/T side advantage signal (BSD only)
      if (e.map_winrate.source === 'bsd' && e.map_winrate.team1_ct_wr != null) {
        var ctDiff = (e.map_winrate.team1_ct_wr||50) - (e.map_winrate.team2_ct_wr||50);
        if (Math.abs(ctDiff) >= 15) {
          signals.push({ key:'ctside', label: 'CT:' + e.map_winrate.team1_ct_wr + '%vs' + e.map_winrate.team2_ct_wr + '%', color: ctDiff >= 15 ? 'green' : ctDiff <= -15 ? 'red' : 'amber', val: ctDiff });
        }
      }
    }

    // 6. Over Rounds model
    if (model && model.line) {
      signals.push({ key:'over', label: model.signal + ' ' + model.line, color: model.confidence==='HIGH'?'green':model.confidence==='MED'?'amber':'grey', val: model.predicted });
    }

    return { signals: signals, enrichment: e, model: model };
  }

  // ── Auto-verdict from signals ──────────────────────────────────────────
  function _cs2Verdict(signals) {
    if (!signals.length) return { txt: '⏳ Chargement…', cls: 'cs2-verdict-hold' };
    var greens = signals.filter(function(s){ return s.color==='green'; }).length;
    var reds   = signals.filter(function(s){ return s.color==='red';   }).length;
    var n = signals.length;
    if (greens >= 3 && reds === 0) return { txt: '🟢 BET FORT',   cls: 'cs2-verdict-strong' };
    if (greens >= 2 && reds <= 1)  return { txt: '🟡 BET LÉGER',  cls: 'cs2-verdict-mild' };
    if (reds   >= 3)               return { txt: '🔴 SKIP',       cls: 'cs2-verdict-skip' };
    if (reds   >= 2 && greens < 2) return { txt: '🔴 ÉVITER',     cls: 'cs2-verdict-skip' };
    return { txt: '⚪ HOLD', cls: 'cs2-verdict-hold' };
  }

  // ── Render KPI signal badge ───────────────────────────────────────────
  function _kpiBadge(sig) {
    var col = sig.color === 'green' ? '#00e676' : sig.color === 'red' ? '#ff4d4d' : sig.color === 'amber' ? '#ffa726' : '#5a6068';
    var bg  = sig.color === 'green' ? 'rgba(0,230,118,0.10)' : sig.color === 'red' ? 'rgba(255,77,77,0.10)' : sig.color === 'amber' ? 'rgba(255,167,38,0.10)' : 'rgba(90,96,104,0.10)';
    return '<span style="display:inline-flex;align-items:center;padding:2px 6px;border-radius:4px;border:1px solid ' + col + ';background:' + bg + ';color:' + col + ';font-family:\'DM Mono\',monospace;font-size:9px;font-weight:700;white-space:nowrap;">' + _esc(sig.label) + '</span>';
  }

  // ── Main dashboard renderer ───────────────────────────────────────────
  window.renderCs2Dashboard = function (matches) {
    var grid = document.getElementById('cs2-grid');
    if (!grid) return;

    if (!matches || !matches.length) {
      grid.innerHTML = '<div class="cs2-empty"><div class="cs2-empty-icon">🎮</div><div class="cs2-empty-msg">Aucun match disponible</div></div>';
      return;
    }

    var live    = matches.filter(function(m){ return m.is_live; });
    var prematch= matches.filter(function(m){ return !m.is_live && m.status !== 'finished'; });

    function section(title, list) {
      if (!list.length) return '';
      var rows = list.map(function(m) {
        var kd    = _cs2BettingSignals(m);
        var verdict = _cs2Verdict(kd.signals);
        var e = kd.enrichment;
        var model = kd.model;

        // Score / time
        var scoreCell = '';
        if (m.is_live) {
          var ms = m.maps_score || {};
          var rs = m.round_score || {};
          scoreCell = '<span class="cs2-rds-t1" style="font-family:\'DM Mono\',monospace;font-size:13px;font-weight:700;">' + (ms.team1!=null?ms.team1:'—') + '</span>' +
            '<span style="color:var(--text3,#5a6068)">–</span>' +
            '<span class="cs2-rds-t2" style="font-family:\'DM Mono\',monospace;font-size:13px;font-weight:700;">' + (ms.team2!=null?ms.team2:'—') + '</span>' +
            (rs.team1!=null ? '<br><span style="font-size:9px;"><span class="cs2-rds-t1">' + rs.team1 + '</span><span style="color:var(--text3,#5a6068)">–</span><span class="cs2-rds-t2">' + rs.team2 + '</span> rds</span>' : '');
        } else if (m.scheduled) {
          scoreCell = '<span style="font-family:\'DM Mono\',monospace;font-size:11px;color:var(--text2);">' + _cs2FmtMatchTime(new Date(m.scheduled)) + '</span>';
        }

        // Map + over model cell
        var mapCell = m.current_map
          ? '<span style="font-family:\'DM Mono\',monospace;font-size:10px;color:var(--text2);">' + _esc(m.current_map) + '</span>' +
            (model ? '<br>' + _kpiBadge({ label: model.signal + ' ' + model.line, color: model.confidence==='HIGH'?'green':model.confidence==='MED'?'amber':'grey' }) : '')
          : (model ? _kpiBadge({ label: model.signal + ' ' + model.line, color: model.confidence==='HIGH'?'green':'amber' }) : '<span style="color:var(--text3);font-size:10px;">—</span>');

        // Odds cell
        var odds = m.odds || {};
        var oddsCell = (odds.team1 != null && odds.team2 != null)
          ? '<span style="font-family:\'DM Mono\',monospace;font-size:11px;">' +
            Number(odds.team1).toFixed(2) + '<span style="color:var(--text3);margin:0 4px;">vs</span>' +
            Number(odds.team2).toFixed(2) + '</span>'
          : '<span style="color:var(--text3);font-size:10px;">—</span>';

        // Form cells (team1 last 5 as dots)
        function formDots(formArr) {
          if (!formArr) return '<span style="color:var(--text3);font-size:10px;">—</span>';
          return formArr.slice(-5).map(function(r){
            var c = r==='W'?'#00e676':r==='L'?'#ff4d4d':'#5a6068';
            return '<span style="display:inline-block;width:7px;height:7px;border-radius:50%;background:'+c+';margin:0 1px;" title="'+r+'"></span>';
          }).join('');
        }
        var f1 = e && e.team1 && e.team1.form ? e.team1.form.form : null;
        var f2 = e && e.team2 && e.team2.form ? e.team2.form.form : null;

        // KPI signals row (all except form)
        var kpiCells = kd.signals
          .filter(function(s){ return s.key !== 'form1' && s.key !== 'form2'; })
          .map(function(s){ return _kpiBadge(s); }).join(' ');

        // Team names with rank (HLTV or BSD ELO)
        function teamLabel(t) {
          var rankHtml = '';
          if (t.hltv_rank) {
            rankHtml = ' <span style="font-size:9px;color:var(--text3);">#'+t.hltv_rank+'</span>';
          } else if (t.elo_rating) {
            rankHtml = ' <span style="font-size:9px;color:var(--blue,#29b6f6);" title="BSD ELO (peak:'+( t.elo_peak||'?')+')">⚡'+t.elo_rating+'</span>';
          }
          return _esc(t.name) + rankHtml;
        }

        // Prediction confidence badge
        var probCell = m.prediction
          ? _kpiBadge(kd.signals.find(function(s){return s.key==='prob';}) || { label:'—', color:'grey' })
          : '<span style="color:var(--text3);font-size:10px;">—</span>';

        return '<tr class="cs2-dash-row' + (m.is_live ? ' cs2-dash-live' : '') + '">' +
          '<td class="cs2-dash-score">' + scoreCell + '</td>' +
          '<td class="cs2-dash-teams">' +
            '<div class="cs2-dash-t1">' + teamLabel(m.team1) + '</div>' +
            '<div class="cs2-dash-t2">' + teamLabel(m.team2) + '</div>' +
            '<div style="font-family:\'DM Mono\',monospace;font-size:9px;color:var(--text3);margin-top:1px;">' + _esc(m.tournament) + '</div>' +
          '</td>' +
          '<td class="cs2-dash-odds">' + oddsCell + '</td>' +
          '<td class="cs2-dash-prob">' + probCell + '</td>' +
          '<td class="cs2-dash-form">' +
            '<div style="margin-bottom:2px;">' + formDots(f1) + '</div>' +
            '<div>' + formDots(f2) + '</div>' +
          '</td>' +
          '<td class="cs2-dash-map">' + mapCell + '</td>' +
          '<td class="cs2-dash-kpi">' + (kpiCells || '<span style="color:var(--text3);font-size:10px;">⏳</span>') + '</td>' +
          '<td class="cs2-dash-verdict"><span class="cs2-verdict-badge ' + verdict.cls + '">' + verdict.txt + '</span></td>' +
        '</tr>';
      }).join('');

      return '<div class="cs2-dash-section">' +
        '<div class="cs2-dash-section-title">' + (list.some(function(m){return m.is_live;}) ? '🔴 LIVE' : '📅 PRÉ-MATCH') + ' <span style="color:var(--text3);font-size:11px;">(' + list.length + ')</span></div>' +
        '<div class="cs2-dash-wrap"><table class="cs2-dash-table">' +
        '<thead><tr>' +
        '<th>Score / Heure</th><th>Match</th><th>Cotes</th><th>Prob ML</th>' +
        '<th>Forme<br><span style="font-size:8px;font-weight:400;">T1 / T2 last 5</span></th>' +
        '<th>Map / Rounds</th><th>Signaux KPI</th><th>VERDICT</th>' +
        '</tr></thead><tbody>' + rows + '</tbody></table></div></div>';
    }

    var html = '';
    if (live.length)     html += section('LIVE', live);
    if (prematch.length) html += section('PREMATCH', prematch);
    // Tier 3 leagues section (Berserk + Liquipedia)
    html += '<div id="cs2-tier3-section">' + _buildTier3Html() + '</div>';
    grid.innerHTML = html;

    // Trigger async enrichment + model fetches for all matches
    matches.forEach(function(m) {
      if (m.team1 && m.team2) {
        _fetchEnrichment(m.id, m.team1.name, m.team2.name, m.current_map || null);
        if (m.current_map) _fetchMapOverModel(m.id, m.team1.name, m.team2.name, m.current_map, null);
      }
    });
    // Re-render after enrichment loads (using existing poll)
    if (_cs2EnrichTimer1) clearTimeout(_cs2EnrichTimer1);
    if (_cs2EnrichTimer2) clearTimeout(_cs2EnrichTimer2);
    _cs2EnrichTimer1 = setTimeout(function() { _applyCs2Filter(); }, 3000);
    _cs2EnrichTimer2 = setTimeout(function() { _applyCs2Filter(); }, 8000);
  };

  // ── Helpers ───────────────────────────────────────────────────────────────
  function _buildHighlightSection(clips) {
    if (!clips || clips.length === 0) return '';
    var html = '<div class="cs2-highlights-bar">' +
      '<span class="cs2-hl-label">🎬 Highlights</span>';
    for (var i = 0; i < clips.length; i++) {
      var c = clips[i];
      var label = (c.name || '').replace(/^Souvenir Charm \| [^|]+ \| /, '').replace('Double Kill', '2K').replace('Triple Kill', '3K').replace('Quadruple Kill', '4K').replace('Ace', 'ACE');
      html += '<button class="cs2-hl-btn" onclick="cs2PlayClip(' + i + ',this,' + JSON.stringify(c.video) + ',' + JSON.stringify(c.name) + ')" title="' + _esc(c.name) + '">' +
        _esc(label) + '</button>';
    }
    html += '</div>' +
      '<div class="cs2-hl-player" id="cs2-hl-player-' + Date.now() + '" style="display:none;">' +
        '<video class="cs2-hl-video" controls playsinline muted preload="none">' +
        '</video>' +
        '<button class="cs2-hl-close" onclick="this.closest(\'.cs2-hl-player\').style.display=\'none\';this.previousElementSibling.pause()">✕</button>' +
      '</div>';
    return html;
  }

  function _esc(s) {
    return String(s || '')
      .replace(/&/g,'&amp;').replace(/</g,'&lt;')
      .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function _cs2FmtTime(d) {
    return d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
  }

  function _cs2FmtMatchTime(d) {
    if (isNaN(d)) return '';
    var now     = new Date();
    var dayDiff = Math.floor((d - now) / 86400000);
    var t       = d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
    if (dayDiff < 0)  return d.toLocaleDateString('fr-FR', { day:'2-digit', month:'short' }) + ' ' + t;
    if (dayDiff === 0) return "Aujourd'hui " + t;
    if (dayDiff === 1) return 'Demain ' + t;
    return d.toLocaleDateString('fr-FR', { day:'2-digit', month:'short' }) + ' ' + t;
  }

})();

// ─── Tennis Alerts History — onglet page-tennis-alerts ───────────────────────
async function loadTennisAlerts() {
  const typeF = (document.getElementById('ta-filter-type') || {}).value || '';
  const outF  = (document.getElementById('ta-filter-outcome') || {}).value || '';
  const res = await apiFetch('/api/v1/tennis/alerts/history?limit=300');
  if (!res || !res.alerts) return;
  const kpiEl = document.getElementById('ta-kpis');
  if (kpiEl) {
    kpiEl.innerHTML = res.stats.map(s => `
      <div style="background:var(--bg2);border:1px solid var(--bg4);border-radius:8px;padding:12px 16px;min-width:160px">
        <div style="font-size:11px;color:var(--text2);margin-bottom:4px">${s.alert_type.replace(/_/g,' ')} · ${(s.bet_type||'').replace(/_/g,' ')}</div>
        <div style="font-size:22px;font-weight:700;color:${s.win_pct>=55?'var(--green)':s.win_pct>=45?'var(--amber)':'var(--red)'}">${s.win_pct!=null?s.win_pct+'%':'—'}</div>
        <div style="font-size:11px;color:var(--text3)">${s.win}W · ${s.loss}L · ${s.pending}⏳ (${s.total} total)</div>
      </div>`).join('');
  }
  const tbody = document.getElementById('ta-tbody');
  if (!tbody) return;
  let rows = res.alerts;
  if (typeF) rows = rows.filter(r => r.alert_type === typeF);
  if (outF)  rows = rows.filter(r => r.outcome === outF);
  if (!rows.length) { tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;color:var(--text2)">Aucune alerte</td></tr>'; return; }
  const typeLabel = { break_set:'🎯 Break', under_jeu:'📐 Under Jeu', oddspapi_prematch:'📡 OddsPapi', live_set_score:'⚡ Live' };
  tbody.innerHTML = rows.map(r => {
    const dt = new Date(r.fired_at).toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'});
    const oc = r.outcome==='WIN'?'✅ WIN':r.outcome==='LOSS'?'❌ LOSS':'⏳';
    const ocColor = r.outcome==='WIN'?'var(--green)':r.outcome==='LOSS'?'var(--red)':'var(--text2)';
    return `<tr>
      <td style="font-size:11px;color:var(--text2)">${dt}</td>
      <td><span style="font-size:11px">${typeLabel[r.alert_type]||r.alert_type}</span></td>
      <td style="font-size:12px">${r.player1||'?'} vs ${r.player2||'?'}</td>
      <td style="font-size:11px;color:var(--text2)">${r.tournament||'—'}</td>
      <td style="text-align:center">S${r.set_num||'?'}</td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.dr_set!=null?Number(r.dr_set).toFixed(2):'—'}</td>
      <td><span style="font-size:11px;font-weight:600">${(r.bet_type||'—').replace(/_/g,' ')}</span></td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.bet_odds!=null?Number(r.bet_odds).toFixed(2):'—'}</td>
      <td style="text-align:center">${r.bet_conf!=null?r.bet_conf+'%':'—'}</td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.score_at_alert||'—'}</td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.set_score_final||'⏳'}</td>
      <td style="font-weight:700;color:${ocColor}">${oc}</td>
    </tr>`;
  }).join('');
}

function switchAlertTab(tab, btn) {
  document.querySelectorAll('.ta-subtab').forEach(b => {
    b.style.borderBottomColor = 'transparent';
    b.style.color = 'var(--text2)';
    b.style.fontWeight = 'normal';
  });
  btn.style.borderBottomColor = 'var(--green)';
  btn.style.color = 'var(--text)';
  btn.style.fontWeight = '600';
  document.getElementById('ta-pane-tennis').style.display = tab === 'tennis' ? '' : 'none';
  document.getElementById('ta-pane-foot').style.display = tab === 'foot' ? '' : 'none';
  if (tab === 'foot') loadFootAlerts();
}

async function loadFootAlerts() {
  const typeF = document.getElementById('fa-filter-type')?.value || '';
  const outF  = document.getElementById('fa-filter-outcome')?.value || '';
  const res = await apiFetch('/api/v1/foot/alerts/history?limit=300');
  if (!res || !res.alerts) return;
  const kpiEl = document.getElementById('fa-kpis');
  if (kpiEl) {
    kpiEl.innerHTML = res.stats.map(s => `
      <div style="background:var(--bg2);border:1px solid var(--bg4);border-radius:8px;padding:12px 16px;min-width:160px">
        <div style="font-size:11px;color:var(--text2);margin-bottom:4px">${s.alert_type.replace(/_/g,' ')} · ${(s.bet_pick||'—').slice(0,20)}</div>
        <div style="font-size:22px;font-weight:700;color:${s.win_pct>=55?'var(--green)':s.win_pct>=45?'var(--amber)':'var(--red)'}">${s.win_pct!=null?s.win_pct+'%':'—'}</div>
        <div style="font-size:11px;color:var(--text3)">${s.win}W · ${s.loss}L · ${s.pending}⏳ (${s.total} total)</div>
      </div>`).join('');
  }
  const tbody = document.getElementById('fa-tbody');
  if (!tbody) return;
  let rows = res.alerts;
  if (typeF) rows = rows.filter(r => r.alert_type === typeF);
  if (outF)  rows = rows.filter(r => r.outcome === outF);
  if (!rows.length) { tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;color:var(--text2)">Aucune alerte</td></tr>'; return; }
  tbody.innerHTML = rows.map(r => {
    const dt = new Date(r.fired_at).toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'});
    const oc = r.outcome==='WIN'?'✅ WIN':r.outcome==='LOSS'?'❌ LOSS':'⏳';
    const ocColor = r.outcome==='WIN'?'var(--green)':r.outcome==='LOSS'?'var(--red)':'var(--text2)';
    const typeLabel = {'live_intensity':'🔥 Intensité','live_pressure':'📈 Pression','live_poisson':'📐 Poisson','morning_picks':'🌅 Morning','xg_intensity':'⚡ xG'}[r.alert_type]||r.alert_type;
    return `<tr>
      <td style="font-size:11px;color:var(--text2)">${dt}</td>
      <td><span style="font-size:11px">${typeLabel}</span></td>
      <td style="font-size:12px">${r.home_team||'?'} vs ${r.away_team||'?'}</td>
      <td style="font-size:11px;color:var(--text2)">${r.league||'—'}</td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.live_score||'—'}</td>
      <td style="text-align:center">${r.live_minute!=null?r.live_minute+"'":'—'}</td>
      <td style="font-size:11px;color:var(--text2)">${r.trigger_kind||'—'} ${r.trigger_value!=null?r.trigger_value:''}</td>
      <td style="font-size:12px;font-weight:600">${r.bet_pick||'—'}</td>
      <td style="text-align:center">${r.bet_prob!=null?r.bet_prob+'%':'—'}</td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.bet_odds!=null?r.bet_odds.toFixed(2):'—'}</td>
      <td style="text-align:center;font-family:var(--font-mono)">${r.final_score||'⏳'}</td>
      <td style="font-weight:700;color:${ocColor}">${oc}</td>
    </tr>`;
  }).join('');
}

